INSERT INTO public.photos VALUES (22366, 'Plaza de La Seo 1965', 'Foto: Gerardo Sancho, 1965. Antigua plaza de La Seo, antiguos usuarios. La Samaritana ya no est├í, pero al sol se est├í igual. Tras la fuente, la calle Ram├│n Cu├®llar. Fuente: AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21306707675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21306707675.webp', 'https://www.flickr.com/photos/zaragozaantigua/21306707675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
