INSERT INTO public.photos VALUES (21385, 'R├¡o Ebro 1915', 'Aspecto de la riada del Ebro los d├¡as 13 y 14 de abril de 1915. Al fondo, tras el paseo de la ribera, la torre de San Pablo. Fuente: Revista La Hormiga de Oro.', 1915, 1915, 1915, 'Anos 10', 'CASCO HIST├ôRICO', 41.65864200, -0.88221200, '0101000020E6100000A87004A9143BECBFD2E28C614ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18932401970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18932401970.webp', 'https://www.flickr.com/photos/zaragozaantigua/18932401970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23822, 'El Ebro y el Pilar 1904', 'Foto coloreada tomada desde la Arboleda de Macanaz, con la barca de sirga "del t├¡o Toni" que cruzaba el r├¡o Ebro y el Pilar al fondo. Fuente: www.facebook.com/photo.php?fbid=10203195617251095&set...', 1904, 1904, 1904, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19200869931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19200869931.webp', 'https://www.flickr.com/photos/zaragozaantigua/19200869931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25437, 'Crecida del Ebro 1948', 'Foto: Miguel Mar├¡n Chivite. Vista de la bas├¡lica del Pilar desde la Arboleda de Macanaz, en el punto en el que se acced├¡a a la Pasarela que un├¡a este punto con las inmediaciones del Torre├│n de la Zuda. El aspecto anegado se debe a la en├®sima crecida o avenida del r├¡o Ebro a su paso por la ciudad. Fuente: Archivo ABC.', 1948, 1948, 1948, 'Anos 40', 'CASCO HIST├ôRICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24841426385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24841426385.webp', 'https://www.flickr.com/photos/zaragozaantigua/24841426385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22643, 'Vista San Juan de los Panetes c.1974', 'Foto: Jes├║s Monreal. Vista desde el Pilar de la zona de San Juan de los Panetes (derecha) y su entorno. Arriba a la izquierda, el Mercado Central. En el centro, la Cruz de los Ca├¡dos. Fuente: rafaelcastillejo.com', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20522456288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20522456288.webp', 'https://www.flickr.com/photos/zaragozaantigua/20522456288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24676, 'Plaza de C├®sar Augusto c.1972', 'Plaza de C├®sar Augusto y plaza del Pilar. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22754073717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22754073717.webp', 'https://www.flickr.com/photos/zaragozaantigua/22754073717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21141, 'Construcci├│n puente de Hierro 1894', 'Construcci├│n del puente del Pilar o de Hierro de Zaragoza, en 1894.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65538400, -0.87090200, '0101000020E6100000F7AB00DF6DDEEBBF2C29779FE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871889038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871889038.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871889038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21928, 'Vista a├®rea Coso Bajo a├▒os 40', 'Archivo Municipal. 1927 (dataci├│n improbable que aparece en la ficha t├®cnica del Archivo). Un vuelo a motor captura desde el Barrio de Jes├║s el cuadrante al este del decumano maximo romano, desde el nov├¡simo S. Vicente de Pa├║l (a la derecha) apenas comenzado a construir los nuevos edificios que lo delimitar├ín, hasta m├ís all├í del Huerva (a la izquierda). Inmediatamente, el Ebro, el Puente de Hierro, el Paseo del Ebro (actual Echegaray y Caballero), la Plaza Tener├¡as con el enorme Dep├│sito de Autom├│viles del Ej├®rcito, y el final del Coso Bajo, donde destaca la mole de la Universidad Literaria de la Magdalena, tal y como luc├¡a desde la profunda reforma de 1846. A su izquierda, parte del antiguo Barrio de la Seo (barrio del siglo XII y construcciones de los siglos XVI-XVIII), con un cat├ílogo de viales muy remozado por la impostaci├│n de S. Vicente de Pa├║l, afectando total o parcialmente al Postigo al Ebro, calleja del Conde Alperche, callizo de La Rosa, calle del Garro, callizo del Retiro, calle del Silencio, calle Palafox, callizo de Don Mor├¡n, placeta de Li├▒├ín, calle Juan de Arag├│n, placeta de Segovia, plaza de Clariana, plaza del Reino.... Junto al Huerva, a la izquierda, el campo de f├║tbol de la Torre de Bruil, o de la calle Asalto, activo desde 1924 y con capacidad para 6000 aficionados, donde jugaba el "Zaragoza F.C." Muy cerca, la f├íbrica de regaliz ZARA, y el "Corral de Abastos de Intendencia" (actual parque "Corral de la le├▒a"). El Puente de S. Jos├® abre la Pza. de San Miguel (visible arriba del todo) hacia Miguel Servet y el Camino del Bajo Arag├│n. Ya al otro lado del Huerva, la enorme superficie de los lavaderos (y tendederos) "de la Puerta del Duque". Inmediata, la harinera del Pilar. Finalmente, visual de la enorme estructura de la Tercera Comandancia de Intendencia del Ej├®rcito, sito sobre las ruinas del anterior Convento de San Jos├®, que hasta comienzos del siglo XX fue Penal de convictos que redim├¡an sus penas cosiendo trajes. Incluido en la setentera "Op', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65528600, -0.87298300, '0101000020E6100000D3D85E0B7AEFEBBF69C36169E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14873165933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14873165933.webp', 'https://www.flickr.com/photos/zaragozaantigua/14873165933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25155, 'Calle Retiro a├▒os 30', '"Calles del Retiro y Grillo". Acuarela de Ambrosio Ruste mostrando la calle del Retiro, con el final de la de Pallaruelo. La del Grillo queda a la derecha, fuera de plano. Estas callejas se situar├¡an hoy en el entorno de la calle del Boter├│n. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65457800, -0.87318900, '0101000020E61000002043C70E2AF1EBBF2E573F36C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627378113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627378113.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627378113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
