INSERT INTO public.photos VALUES (25564, 'Ribera del Ebro 1981', 'Una gran gr├║a ha logrado rescatar del pozo de San L├ízaro al autob├║s ca├¡do en 1971. Es mayo de 1981 y los bomberos y dem├ís operarios implicados posan alegres ante los restos del veh├¡culo. Al fondo, el puente del Pilar. Fuente: Heraldo de Arag├│n.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.65809700, -0.87442300, '0101000020E6100000BED87BF145FBEBBF404CC2853CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31600480723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31600480723.webp', 'https://www.flickr.com/photos/zaragozaantigua/31600480723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
