INSERT INTO public.photos VALUES (21271, 'Campo Sepulcro 1900', 'El desde antiguo triangular Campo Sepulcro, era un espacio de fluido tr├ínsito al suroeste de la ciudad, entre el muro de rejola, la puerta del Portillo, y los conventos extramuros de los Agustinos descalzos, y de los Trinitarios, adem├ís de enlazar con los caminos hacia Calatayud y Daroca. Tras la instalaci├│n de la cercana estaci├│n de ferrocarril de la compa├▒├¡a MZA, que pronto tomar├¡a su nombre, esta zona conoci├│ una notable variedad de usos, como espacio de desfiles y alardes militares, para probanza y exhibici├│n de ingenios volanderos (cometas), estadio de "football amateur"... y como estudio fotogr├ífico al aire libre. En la imagen, posado de "Plut├│n", caballo ganador del concurso de ganado celebrado en las fiestas del Pilar. Junto a ├®l, su propietario (Mam├®s Lafita), de Fuentes de Ebro. Al fondo, tras el arbolado paseo de Mar├¡a Agust├¡n, la c├║pula de la Casa de la Misericordia. Fuente: Foto Pasiego, Revista "Iris" (Barcelona).', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65283200, -0.89287600, '0101000020E6100000F6436CB07092ECBF21E4BCFF8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22369464911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22369464911.webp', 'https://www.flickr.com/photos/zaragozaantigua/22369464911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
