INSERT INTO public.photos VALUES (24890, 'Ambulatorio Ram├│n y Cajal 1964', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 20/4/1964. Edificio del Ambulatorio Ram├│n y Cajal en el paseo Mar├¡a Agust├¡n 12-14 de Zaragoza, reci├®n inaugurado.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65084400, -0.88914300, '0101000020E61000005AF44E05DC73ECBF1F662FDB4ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024198307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024198307.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024198307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
