INSERT INTO public.photos VALUES (21498, 'Avenida de Madrid c.1920', 'Imagen de la procesi├│n que con motivo de la Virgen del Carmen (16 de julio), organizaba la comunidad de Carmelitas Descalzos del convento de Delicias. La procesi├│n transita por la Avenida de Madrid, a├║n sin adoquinar. Un coche de la serie de los 20, l├¡nea de Delicias, al paso de la procesi├│n. Desde 1897, y hasta 1944, los Carmelitas Descalzos se localizaron en el prestado convento de Delicias.', 1920, 1920, 1920, 'Anos 20', 'DELICIAS', 41.65425200, -0.90183300, '0101000020E6100000A1832EE1D0DBECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15372656173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15372656173.webp', 'https://www.flickr.com/photos/zaragozaantigua/15372656173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
