INSERT INTO public.photos VALUES (22468, 'Av. de Marina Moreno c.1965', 'Una pareja de trolebuses londinenses BUT Q-1 de dos pisos de la l├¡nea Ciudad Jard├¡n coinciden debido a la aver├¡a del de la izquierda, mientras los pasajeros transbordan al de la derecha, que se internar├í luego por la calle de Juan Bruil para continuar su trayecto. De fondo edilicio, construcci├│n anexa al antiguo Hotel Regina, que ser├í derribado en 1966, y a la izquierda traseras de los hotelitos de ese lado de la plaza de Arag├│n.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64830100, -0.88327500, '0101000020E610000016FBCBEEC943ECBF677BF486FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33134559740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33134559740.webp', 'https://www.flickr.com/photos/zaragozaantigua/33134559740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
