INSERT INTO public.photos VALUES (21069, 'Coso Alto 1871', '"Arco erigido en el Coso por el comercio en loor de S. M.", 1871. Dibujo alusivo al viaje de Amadeo I de Saboya a Zaragoza en 1871. Vemos un ef├¡mero arco conmemorativo en el Coso Alto, con uno de los torreones de la Audiencia al fondo.', 1871, 1871, 1871, 'Siglo XIX', 'CENTRO', 41.65378700, -0.88358800, '0101000020E6100000E46A64575A46ECBF65C6DB4AAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19011201652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19011201652.webp', 'https://www.flickr.com/photos/zaragozaantigua/19011201652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25169, 'Calle Galo Ponte 1980', 'Dibujo centrado en los restos del esquinero edificio entre la calle de Galo Ponte, antigua de la Audiencia, y m├ís antigua Subida de los Gigantes, y un despejado Coso alto, a la derecha. Justo a la izquierda, algunos balcones de la Audiencia, junto a la que el autor ha tomado los apuntes del natural. Desde ese momento, y hasta la fecha, el derribo se ha completado felizmente, y el solar sigue en productivo barbecho inmobiliario, a la espera de tiempos nuevos, tiempos salvajes.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65381300, -0.88334600, '0101000020E610000064ADA1D45E44ECBF8E59F624B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32501628372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32501628372.webp', 'https://www.flickr.com/photos/zaragozaantigua/32501628372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25703, 'Iglesia de Santiago c.1974', 'Iglesia de Santiago desde la plaza de Salamero. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65253500, -0.88478600, '0101000020E61000004FADBEBA2A50ECBF683F524486D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22805590719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22805590719.webp', 'https://www.flickr.com/photos/zaragozaantigua/22805590719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25713, 'General Sanjurjo 1976', 'Imagen de la antigua calle del General Sanjurjo, luego parte de la gran avenida de C├®sar Augusto como moderno sumatorio vial para tr├ífico rodado, adem├ís, de las antiguas calles de Cerd├ín, Escuelas P├¡as, Azoque, una parte de Capit├ín Portol├®s, la plaza de San Ildefonso, y algunas bocacalles, como Ser├│n. Destaca por su soledad moment├ínea, a la derecha, la mole de un gran hotel con su gran medianera como privilegiada plataforma publicitaria, y a la izquierda, la fachada del luego tristemente c├®lebre Gran Teatro Fleta, y el acceso a la plaza de Salamero, antigua de Santa Fe. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65220200, -0.88521300, '0101000020E61000003ECF9F36AA53ECBF6231EA5A7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30386624885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30386624885.webp', 'https://www.flickr.com/photos/zaragozaantigua/30386624885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22994, 'Museo Pablo Serrano a├▒os 90', 'Vista a├®rea del entorno de los antiguos Talleres del Hogar Pignatelli (desde 1994 "Fundaci├│n Museo Pablo Serrano", y desde 1995, "Instituto Aragon├®s de Arte y Cultura Contempor├íneos Pablo Serrano"), en el paseo de Mar├¡a Agust├¡n 20. Fuente visual: www.facebook.com/photo.php?fbid=542402152581479&set=p...', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65157300, -0.89006500, '0101000020E6100000410E4A98697BECBF72FA7ABE66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22141678588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22141678588.webp', 'https://www.flickr.com/photos/zaragozaantigua/22141678588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23256, 'F├íbrica de regaliz Tur c.1900', 'Vista de la entrada de la f├íbrica de regaliz Flor, Carenou y Tur en la calle Asalto de Zaragoza, entre el actual parque Corral de la Le├▒a y el r├¡o Huerva. En primer plano, la acequia que pasaba entre los terrenos que fueron viveros y almac├®n de abastos del ej├®rcito, y la factor├¡a. A la derecha, consulado franc├®s de Zaragoza. Fuente: www.facebook.com/photo.php?fbid=635699779865162&set=g...', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64863900, -0.87183600, '0101000020E6100000F0366F9C14E6EBBF80F44D9A06D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21134866226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21134866226.webp', 'https://www.flickr.com/photos/zaragozaantigua/21134866226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21816, 'Pl. de la Constituci├│n a├▒os 30', 'Grupo de ciudadanos al sol de la plaza de la Constituci├│n, apostados en los vanos del Caf├® Gambrinus. A la izquierda, la Diputaci├│n Provincial. Fuente: www.facebook.com/photo.php?fbid=10206629484601419&set...', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65234100, -0.88153600, '0101000020E61000009BE447FC8A35ECBF836BEEE87FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31117803651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31117803651.webp', 'https://www.flickr.com/photos/zaragozaantigua/31117803651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21958, 'P.┬║ Independencia a├▒os 40', 'Paseo de la Independencia en los primeros a├▒os 40. A la derecha, calle de San Miguel y Restaurante Peninsular. Al fondo, plaza de Espa├▒a. Fuente: Instant├íneas zaragozanas, CAZAR, 1982.', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.65124500, -0.88181400, '0101000020E61000004DF564FED137ECBF7E5704FF5BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20075070438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20075070438.webp', 'https://www.flickr.com/photos/zaragozaantigua/20075070438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22549, 'P.┬║ de la Independencia c.1972', 'Postal nocturna del paseo de la Independencia, con la plaza de Espa├▒a al fondo, cuando sus r├│tulos de ne├│n, y el reci├®n inaugurado edificio de Galer├¡as Preciados (1971) iluminando el entorno. Esta empresa fue adquirida en 1995 por otra empresa enga├▒osamente de corte ingl├®s. Fuente visual: www.delcampe.net/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65106600, -0.88166500, '0101000020E610000011E4A0849936ECBFCEC4742156D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023110161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023110161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023110161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25125, 'Zaragoza 1809', 'Louis-Albert-Guislain (Bar├│n de Bacler D''Albe), y Godefroy Engelmann, Ca. 1830. "Fais-toi vieille, nous ne sommes pas des ogres: Des soldats fran├ºais touillaient dans les ruines de Sarragosse, ils trouvent deux enfants cach├®s sous une voute et perissant de faim. Ils leur donnet leurs vivres." Durante las guerras peninsulares de 1808-1809, el militar franc├®s Louis-Albert-Guislain visita Espa├▒a en dos ocasiones. La primera (abril-mayo 1808), como responsable del "Cabinet Topographique de lÔÇÖEmpereur". La segunda, acompa├▒ando a Napole├│n durante la campa├▒a de noviembre 1808-enero 1809. En ellas, realiza croquis de los lugares recorridos, observa escenas y escucha el relato de algunos de los protagonistas. Con esta informaci├│n, prepara una obra gr├ífica que publicar├í posteriormente, con grabados de escenas a la moda rom├íntica (ruinas y elementos arquitect├│nicos, vegetaci├│n...) que, como en este caso, incluye una singular muestra de propaganda al estilo de la de los Sitios, pero desde la trinchera contraria (una especie de "agitprop contraSitial"). As├¡, el descriptivo t├¡tulo "Mira, anciana, no somos ogros", introduce un intento de humanizar a las tropas francesas que sitiaban primero, y ocuparon despu├®s, la ciudad de Zaragoza. Al probable relato oral de los soldados implicados, se suma la expl├¡cita voluntad pol├¡tica en reflejarlo gr├íficamente para la posteridad, convenientemente escenificado. As├¡, en un desolado paisaje urbano de ruinas y escombros no identificados (┬┐cerca del convento de San Francisco?), unos soldados imperiales se topan con dos fam├®licos ni├▒os a los que dan sus propios v├¡veres, mientras la probable madre de las criaturas gesticula entre asustada y agradecida. Se trata de una imagen muy querida en la iconograf├¡a p├║blica de todos los ej├®rcitos ocupantes: la pl├ística, oficial y condescendiente benignidad castrense para con los ind├¡genas civiles de los territorios ocupados, una vez derrotados. En este caso, adem├ís, tras una doble derrota: las dos ocupaciones ', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16093613925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16093613925.webp', 'https://www.flickr.com/photos/zaragozaantigua/16093613925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25323, 'P.┬║ de la Independencia 1982', 'Esquina de la calle de San Miguel con el paseo de la Independencia, en 1982. Fuente: Agencia EFE.', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.65134900, -0.88165300, '0101000020E610000000732D5A8036ECBF23A46E675FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23996739964.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23996739964.webp', 'https://www.flickr.com/photos/zaragozaantigua/23996739964/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21436, 'Arco de San Roque 1911', 'Foto: Grasa. Unos cuantos guardias civiles custodian desde la plazuela de San Roque los inmuebles y el arco hom├│nimo, durante la huelga general revolucionaria del verano de 1911. Al fondo, el restaurante del Hotel Oriente, en el Coso Alto. Fuente: Revista Blanco y Negro, 24-9-1911.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65319900, -0.88277900, '0101000020E6100000060FD3BEB93FECBFD4635B069CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40166715840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40166715840.webp', 'https://www.flickr.com/photos/zaragozaantigua/40166715840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21877, 'Calle Alfonso a├▒os 30', 'Vista del chafl├ín del caf├® Moderno, entre el Coso Alto y la calle de Alfonso I, a la derecha. Fuente: HA.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65321800, -0.88223200, '0101000020E61000006F826F9A3E3BECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43890526765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43890526765.webp', 'https://www.flickr.com/photos/zaragozaantigua/43890526765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22596, 'Calle Azoque 1970', 'Imagen circunstancial de la calle Azoque, y de la plaza de N┬¬ S┬¬ del Carmen. La intenci├│n del fot├│grafo era capturar el vallado solar chaflanero entre el minimalista callej├│n de San Jer├│nimo y la plaza, antes de que fuera construido: un pedazo de la antigua Morer├¡a que cambiaba de aspecto. Desde luego que lo consigui├│, como tambi├®n plasmar uno de los escasos testimonios gr├íficos de algunos de los edificios de la antigua plaza del Carmen, de finales del siglo XVIII, aunque su planta b├ísica lo fuera del XV y XVI. As├¡, aparece un pedazo del antiguo complejo del Convento-Colegio de las Recogidas, un a├▒o antes de que las Carmelitas Terciarias, que lo gestionaban, se unieran a las Carmelitas Misioneras Teresianas. A su lado, el n┬║ 5 de la plaza ya era una reciente mutaci├│n desarrollista, en la que lo que no ten├¡a de ancho, lo estir├│ en vertical como si fuera material pl├ístico. El n┬║ 8 manten├¡a a├║n una digna veteran├¡a. Y en el n┬║ 9, esquinera con la antigua calle Juego de la Pelota, la joya que fuera antigua casa del siglo XVII de don Eugenio Samper, profundamente remodelada en el XVIII, y que a finales de siglo era de Pedro Cort├®s y Larraz, Arzobispo de Guatemala que termin├│ siendo Obispo de Tortosa, por lo que esta casa desde entonces era conocida como "del Obispo". Su planta, imponente fachada y amplio patio interior dejaban claro que se trataba de una "casona" de esas que dicen que Zaragoza ten├¡a tantas. Por sus paredes transcurrieron interesantes historias locales, hasta que sus ultim├¡simos propietarios decidieron aplicarle la piqueta para levantar sobre su solar la cosa que hoy hay. El exterminio de los edificios dieciochescos ("viejos", "antiguallas", "caducos") fue radical y concienzudo: s├│lo quedan las fotos. Fuente visual: Archivo Municipal. Gerardo Sancho Ramo. Noviembre 1970.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65113400, -0.88457100, '0101000020E610000036AE7FD7674EECBF26A8E15B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17511061076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17511061076.webp', 'https://www.flickr.com/photos/zaragozaantigua/17511061076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23282, 'Calle de Alfonso I a├▒os 20', 'AHPZ-Archivo Mora, Juan Mora Insa. "Zaragoza. Calle de Alfonso."', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65292100, -0.88207100, '0101000020E6100000220038F6EC39ECBF91EF52EA92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14890233806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14890233806.webp', 'https://www.flickr.com/photos/zaragozaantigua/14890233806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25235, 'Plaza de Para├¡so 2008', 'Toma de la plaza de Para├¡so y su fuente central en 2008, antes de que en 2011 se remodelase para dar paso al tranv├¡a. Fuente: Wikipedia.', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.64710100, -0.88565600, '0101000020E6100000983270404B57ECBFBD1AA034D4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15011999188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15011999188.webp', 'https://www.flickr.com/photos/zaragozaantigua/15011999188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23500, 'Juventudes Libertarias en el Coso, 1936', 'Mayo de 1936. Congreso de la CNT en Zaragoza. Las Juventudes Libertarias de Cuatro Caminos (Madrid) posan con su pancarta junto al arco de San Roque, en el Coso.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65322500, -0.88264000, '0101000020E6100000AD86C43D963EECBFFDF675E09CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14969472802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14969472802.webp', 'https://www.flickr.com/photos/zaragozaantigua/14969472802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23518, 'Coso Alto 1936', 'Desfile por el Coso Alto, a la altura del arco de San Roque, de miembros de "Acci├│n Ciudadana" de Zaragoza, organizaci├│n paramilitar de la derecha extrema local fundada para mantener el nuevo orden establecido tras el golpe del 18-19 de julio de 1936.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65332700, -0.88266300, '0101000020E6100000B874CC79C63EECBF014C1938A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30727341530.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30727341530.webp', 'https://www.flickr.com/photos/zaragozaantigua/30727341530/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24489, 'Paseo Independencia 1971', 'Postal publicitaria de los grandes almacenes Galer├¡as Preciados, inaugurados en 1971 en el paseo de la Independencia 11. En 1995, este comercio pas├│ a ser propiedad de su competidor, El Corte Ingl├®s. Fuente visual: www.zaragozaayeryhoy.com/', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24796603875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24796603875.webp', 'https://www.flickr.com/photos/zaragozaantigua/24796603875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25368, 'P┬║ de la Independencia c.1916', 'Imagen capturada en el bulevar del paseo de la Independencia posiblemente un festivo d├¡a. Al fondo, el Quiosco de la M├║sica emplazado originalmente en el recinto de la exposici├│n Hispano-Francesa de 1908, trasladado al paseo en 1912 a la altura de las calles de C├ídiz (a la izquierda) y la de Jer├│nimo Zurita (a la derecha). Desde entonces vertebr├│ el paseo hasta su vuelta a la plaza de Castelar en 1927.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65110200, -0.88215700, '0101000020E6100000C5FF1D51A13AECBF1B2E724F57D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51019362787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51019362787.webp', 'https://www.flickr.com/photos/zaragozaantigua/51019362787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21495, 'Cabezo de Buenavista 1923', 'AHPZ. Gabriel Faci. 1923. "Paisaje nevado." La nieve ca├¡da difumina los contornos, suaviza el paisaje. Con la nieve tambi├®n se precipita un silencio dif├¡cil de definir. Todo es distinto. Mientras un tremendo temporal pasaba por encima del Reino de Espa├▒a, en el primero de los inviernos de la Dictadura de Primo de Rivera, gente curiosa se iba al sur, donde estaba proyectado hacer un gran parque, al que tendr├¡a que conducir un nuevo y moderno vial denominado "Gran V├¡a", sobre un cubierto r├¡o Huerva. Pero la cosa estaba bastante parada. De momento, s├│lo estaban garantizadas las buenas vistas desde el Cabezo. Abajo, entre la nieve, una leve vista del oscuro cauce de la acequia de las Adulas, contorne├índose desde su toma de agua del Canal, muy cerca de donde cinco a├▒os despu├®s se levantar├í el Rinc├│n de Goya. Otra l├¡nea de ├írboles, un poco m├ís al fondo, se├▒ala el cauce del Huerva.', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.63133000, -0.89516000, '0101000020E6100000DAFE959526A5ECBFE97DE36BCFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15270757968.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15270757968.webp', 'https://www.flickr.com/photos/zaragozaantigua/15270757968/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21578, 'Puente de Santa Isabel c.1923', 'Paso de carro con cuadr├║pedos, proveniente del barrio de Santa Isabel, transitando por el puente de Santa Isabel sobre el r├¡o G├íllego en direcci├│n a Zaragoza. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1923, 1923, 1923, 'Anos 20', 'EL RABAL', 41.67108200, -0.84225800, '0101000020E6100000766B990CC7F3EABF9677D503E6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24276819414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24276819414.webp', 'https://www.flickr.com/photos/zaragozaantigua/24276819414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23742, 'Puente sobre el G├íllego 1895', 'Puente colgado sobre el r├¡o G├íllego.', 1895, 1895, 1895, 'Siglo XIX', 'EL RABAL', 41.67091400, -0.84202800, '0101000020E6100000081F4AB4E4F1EABFDB368C82E0D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14777528109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14777528109.webp', 'https://www.flickr.com/photos/zaragozaantigua/14777528109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24805, 'Estaci├│n del Norte 2011', 'Recreaci├│n infogr├ífica del proyecto de Olano y Mendo Arquitectos para el entorno de la Estaci├│n del Norte, en 2011. En el centro, la calle de Perdiguera. Al fondo, la Seo sin chapitel y el Pilar. No se ejecut├│. Fuente: www.facebook.com/Olano-y-Mendo-Arquitectos-SLP-1624010171...', 2011, 2011, 2011, 'Siglo XXI', 'EL RABAL', 41.66012900, -0.87193600, '0101000020E6100000D28F8653E6E6EBBF1212691B7FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33660909496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33660909496.webp', 'https://www.flickr.com/photos/zaragozaantigua/33660909496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21628, 'Calle de Corral├® 1929', 'Imagen capturada durante las fiestas del barrio de Jes├║s y centrada en un reparto del "pan de los pobres" organizado por la Confraternidad de San Antonio, posiblemente en la calle de Corral├®. Al fondo, la calle de Valima├▒a. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'EL RABAL', 41.65838300, -0.86968800, '0101000020E61000002028B7ED7BD4EBBF069FE6E445D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37740464626.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37740464626.webp', 'https://www.flickr.com/photos/zaragozaantigua/37740464626/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22381, 'Vista a├®rea Casablanca 1964', 'Vista a├®rea parcial del barrio de Casablanca, con el Canal Imperial al fondo, el Stadium Casablanca, la V├¡a Ib├®rica, la subestaci├│n de El├®ctricas Reunidas derribada en agosto de 2016... En primer t├®rmino, campos de cultivo. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'CASABLANCA', 41.62551300, -0.90523600, '0101000020E6100000ED2DE57CB1F7ECBF861C5BCF10D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22316448195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22316448195.webp', 'https://www.flickr.com/photos/zaragozaantigua/22316448195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23401, 'Valdespartera 2006', 'Vista a├®rea del barrio de Valdespartera de Zaragoza, en abril de 2006. La zona est├í urbanizada ya, para cometer el atentado urbano hoy perpetrado. Fuente: Zaragoza 1908-2008. FCC.', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.62082500, -0.92026700, '0101000020E610000028D192C7D372EDBF05C58F3177CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15091522363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15091522363.webp', 'https://www.flickr.com/photos/zaragozaantigua/15091522363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23431, 'C.┬¬ de Valencia 1911', 'Imagen capturada durante la intensa nevada que el d├¡a 14 de enero de 1911 cubri├│ con un manto blanco la ciudad de Zaragoza. El fot├│grafo Freudenthal centra su objetivo en la Fuente de los Incr├®dulos en su tradicional ubicaci├│n junto a la carretera de Valencia e inmediata al apeadero de la l├¡nea del ferrocarril de Cari├▒ena, que en la imagen queda a la izquierda y fuera de plano.', 1911, 1911, 1911, 'Anos 10', 'CASABLANCA', 41.62857100, -0.90794900, '0101000020E6100000EDF2AD0FEB0DEDBF651BB80375D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51774835206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51774835206.webp', 'https://www.flickr.com/photos/zaragozaantigua/51774835206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22187, 'Parque Primo de Rivera 1959', 'Posado en el monumento a la Exposici├│n Hispano-Francesa de 1908 de los miembros del Club Ciclista Iberia, antes de la salida de una excursi├│n. Este club deportivo naci├│ en 1924 como Secci├│n Ciclista del Iberia Sport Club, pasando a ser independiente en 1934. Fuente: www.clubciclistaiberia.com', 1959, 1959, 1959, 'Anos 50', 'CASABLANCA', 41.63061300, -0.89634200, '0101000020E6100000DAFF006BD5AEECBF5AB741EDB7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32071550314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32071550314.webp', 'https://www.flickr.com/photos/zaragozaantigua/32071550314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25181, 'Seminario Metropolitano 1943', 'Dibujo incluido en el anteproyecto del nuevo Seminario Metropolitano de Zaragoza firmado por Santiago Lagunas Mayand├¡a, Casimiro Lanaja Bel y Manuel Mart├¡nez de Ubago, inspirado en formas historicistas neorrom├ínicas y neog├│ticas, y con capacidad para 400 aspirantes a sacerdotes. En 1945 su coloc├│ su primera piedra, y ser├¡a inaugurado en 1952.', 1943, 1943, 1943, 'Anos 40', 'CASABLANCA', 41.63586000, -0.91004100, '0101000020E6100000C39CA04D0E1FEDBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49414491933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49414491933.webp', 'https://www.flickr.com/photos/zaragozaantigua/49414491933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24843, 'Canal Imperial 1922', 'Imagen capturada en la orilla norte del tramo del Canal Imperial de Arag├│n, desde el camino que en paralelo transcurre a la altura de Valdefierro, e inmediatamente anterior al denominado Puente-Acueducto de la Acequia del Medio que, de iguales dimensiones que el de Pedrola, conduce agua del r├¡o Huerva y que originalmente abastec├¡a a las acequias del Medio, del Plano y del Brazal del Fierro.', 1922, 1922, 1922, 'Anos 20', 'CASABLANCA', 41.63503400, -0.92681000, '0101000020E61000006362F3716DA8EDBF8DEC4ACB48D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51940704552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51940704552.webp', 'https://www.flickr.com/photos/zaragozaantigua/51940704552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25938, 'Graveras de La Paz 1977', 'Esta es una de esas tremendas im├ígenes que era posible captar en el guetto de las "Graveras", de las "Chabolas", porque sus denominaciones eran varias (y la mayor parte, denigrantes) en lo que hoy es el Parque de La Paz. La denominaci├│n de "graveras" respond├¡a al hecho de ser, desde antiguo, lugares de extracci├│n de ├íridos ("grava") para obras. Desde los a├▒os 50 del pasado esta zona se convirti├│ en un asentamiento de chabolas, hasta 1979, cuando, con la recuperaci├│n de la democracia, desde el Ayuntamiento se exploraron f├│rmulas, algunas de ellas muy problem├íticas, err├íticas, y mejorables, para darle una soluci├│n a esta indignidad, felizmente superada, aunque chabolas sigue habiendo en la ciudad. Hubo que esperar a 1982 para ver transformarse esta zona en lo que hoy es. El objetivo fotogr├ífico nos sit├║a en un elevado punto, en la actual parte alta de la Rotonda Villa de Pau, desde el que podemos vislumbrar el Puente de San Viator sobre el Canal, a la derecha. De la Pasarela peatonal met├ílica del mismo nombre s├│lo se aprecia el arranque. La imponente mole de la f├íbrica "ALUMALSA" queda al otro lado del Canal, adem├ís de edificios tan representativos como la Escuela Julio Cejador Frauca, y el Convento de las Monjas del Casal, con su caracter├¡stica espada├▒a. Al fondo, emergiendo t├¡midamente del tejado de "ALUMALSA", apenas vemos el remate de la neocl├ísica c├║pula de la iglesia de San Fernando. Justo a continuaci├│n, los tremebundos macrobloques de la acera izquierda de Terrazas de Cu├®llar-Pintor Mar├¡n Bag├╝├®s, que dejan como enanitos a los m├ís veteranos conjuntos de la acera derecha. Fuente visual: "La evoluci├│n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62865100, -0.87869700, '0101000020E610000069FCC22B491EECBF81CCCEA277D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14855646151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14855646151.webp', 'https://www.flickr.com/photos/zaragozaantigua/14855646151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22350, 'Stadium Venecia c.1968', 'Foto: Colecci├│n Sergio Joven. Vista a├®rea del Stadium Venecia, en la calle Fray Juli├ín Garc├®s del barrio de Torrero. Promovido por Acci├│n Cat├│lica, fue inaugurado en 1966. Fuente: rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.62519300, -0.89005400, '0101000020E61000004791B586527BECBF1558005306D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20531256240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20531256240.webp', 'https://www.flickr.com/photos/zaragozaantigua/20531256240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24908, 'Fosa Com├║n 1919', 'Foto Cepero. Reci├®n instalado mausoleo del escultor Jos├® Bueno para la fosa com├║n del cementerio cat├│lico de Torrero de Zaragoza. Fuente: La Esfera, 12 de julio de 1919.', 1919, 1919, 1919, 'Anos 10', 'TORRERO', 41.62159800, -0.88347000, '0101000020E610000068E89FE06245ECBF27A1F48590CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20029364152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20029364152.webp', 'https://www.flickr.com/photos/zaragozaantigua/20029364152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25942, 'Plaza de las Canteras 1984', 'Foto Arturo Burgos, 1984. Vista de la plaza de las Canteras del barrio de Torrero, tomada desde el inicio de la calle de Fray Juli├ín Garc├®s. Al fondo, la avenida de Am├®rica. Fuente: Zaragoza, sus calles y su historia, 1984.', 1984, 1984, 1984, 'Anos 80', 'TORRERO', 41.63173700, -0.88547300, '0101000020E610000056B60F79CB55ECBF2A560DC2DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18812265184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18812265184.webp', 'https://www.flickr.com/photos/zaragozaantigua/18812265184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25947, 'Cementerio c.1920', 'Vista del interior del cementerio de Torrero, con su entrada al fondo. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'TORRERO', 41.62272000, -0.88770700, '0101000020E6100000CAC4AD821868ECBF5648F949B5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24618952160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24618952160.webp', 'https://www.flickr.com/photos/zaragozaantigua/24618952160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25957, 'Pinares de Venecia 1996', 'En el mes de marzo de 1996 se realiz├│ una acampada en los terrenos de los Pinares de Venecia por los que estaba proyectado que pasase el Tercer Cintur├│n de ronda de la ciudad. Particip├│ m├ís de un millar de personas, convocadas por la Coordinadora Venecia-Torrero-La Paz contra el Tercer Cintur├│n, con los lemas de ÔÇ£No al Tercer Cintur├│nÔÇØ y ÔÇ£Salvemos el pinar, salvemos el CanalÔÇØ, que ofrec├¡a un trazado alternativo menos agresivo con el entorno. En la imagen, parte de los acampados ensaya acciones de resistencia pasiva para el caso de que comiencen las obras. Al final, el trazado alternativo fue desestimado y la nueva v├¡a pas├│ por donde estaba previsto, a partir de 2003.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62461100, -0.89255300, '0101000020E6100000454B1E4FCB8FECBF66DCD440F3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50367967793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50367967793.webp', 'https://www.flickr.com/photos/zaragozaantigua/50367967793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25944, 'Cabezo Cortado 1978', 'El Cabezo Cortado ha sido el mirador natural del barrio desde que gravas, arenas y arcillas, producto de la sedimentaci├│n del Ebro, se dispusieron durante el Terciario en una terraza de varios metros de espesor sobre yesos y limos, y conformaron una elevaci├│n desde la que la vista de la ciudad era estupenda. ├ôleos, apuntes, fotograf├¡as, incluso documentales, han surgido de la contemplaci├│n desde su cumbre. Esto era lo normal. Esta imagen no hace eso, y enfoca justo al otro lado, hacia el Canal Imperial, su ribera, y el Barrio de la Paz. En primer t├®rmino, llaman la atenci├│n los humanos grupos entre los pinos de la ladera, como si se tratase de un parque o zona verde al uso. Ya no se ven estas cosas desde hace tiempo, desde que se dej├│ degradar el Cabezo hasta su actual situaci├│n, en que da mucha penica. Con un poco de voluntad pol├¡tica se pod├¡a adecentar y dignificar, sin mucho costo. Ser├¡a, adem├ís, una buena pedagog├¡a porque, aun en los tiempos del wifi, el tuiter, del face, del ipod, del..., es minor├¡a quien conoce esta zona. Al otro lado del Canal, imagen del Colegio de San Viator y la continuidad de las "Graveras" cuando eran consideradas por ciertos sectores como peor que adentrarse en territorio sioux (en el supuesto, adem├ís, de que ser sioux fuera malo). A este lado del Canal, muy al fondo, las moles de los bloques de otras Terrazas, la de Pina, hoy Cu├®llar, y los restos de la f├íbrica Alumalsa. Casi ya fuera de plano, a la derecha, los bloques de la peculiar urbanizaci├│n de la parcela de la calle Melilla n┬║ 28, reci├®n estrenaditos. Hac├¡a apenas un a├▒o, no muy lejos de aqu├¡, un polic├¡a armada hab├¡a disparado de muerte a un obrero en paro por hacer una pintada que dec├¡a "Trabajo s├¡ Polic├¡a no", y un esbozo de hoz y martillo. Una calle cercana lleva desde hace no mucho el nombre del asesinado: Miguel Vicente Basanta L├│pez. Fuente visual: "La evoluci├│n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1978, 1978, 1978, 'Anos 70', 'TORRERO', 41.63025500, -0.87297300, '0101000020E6100000F04FA91265EFEBBFFB912232ACD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20076476729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20076476729.webp', 'https://www.flickr.com/photos/zaragozaantigua/20076476729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22109, 'Tudor 1953', 'A├®rea vista de la Factor├¡a de la Sociedad Espa├▒ola del Acumulador Tudor, en las enormes y recientes instalaciones de la carretera de Navarra donde estaba ubicada desde 1946. As├¡ ser├í hasta 1989. En la parte inferior, sobre la carretera de Logro├▒o, el puente de paso del ferrocarril de Caminreal. Un segundo puente, m├ís inmediato, se qued├│ en inacabado proyecto de "bypass" de conexi├│n hacia Casetas. Fuente visual: Arxiu Nacional de Catalunya.', 1953, 1953, 1953, 'Anos 50', 'OLIVER-VALDEFIERRO', 41.65974100, -0.92102300, '0101000020E610000051A4FB390579EDBF486AA16472D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21979037130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21979037130.webp', 'https://www.flickr.com/photos/zaragozaantigua/21979037130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24830, 'Calle de San Vicente Ferrer a├▒os 60', 'Calle de San Vicente Ferrer en el barrio del Oliver de Zaragoza. A la izquierda, murete del colegio p├║blico Fernando el Cat├│lico. Al fondo, peque├▒as edificaciones que a├║n siguen en pie en 2014 en la calle de Antonio de Leyva. Fuente: www.facebook.com/photo.php?fbid=10203293020151893&set...', 1960, 1960, 1969, 'Anos 60', 'OLIVER-VALDEFIERRO', 41.65135800, -0.92685000, '0101000020E6100000F085C954C1A8EDBF76FEEDB25FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15307175656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15307175656.webp', 'https://www.flickr.com/photos/zaragozaantigua/15307175656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22771, 'Ctra. de Madrid 1979', 'Editorial Luis Vives en sus nuevas instalaciones dise├▒adas por Joaqu├¡n Maggioni Casadevall en la carretera de Madrid km 315,700. Al fondo, verde entorno del Barrio Oliver que m├ís adelante ser├í adecuado como hom├│nimo parque, tambi├®n llamado del Oeste. A la derecha, el Centro Santo ├üngel de Atades, inaugurado en 1969. Fuera de plano y hacia la derecha, el reformatorio El Buen Pastor, con el que confrontaba al otro lado de la carretera.', 1979, 1979, 1979, 'Anos 70', 'OLIVER-VALDEFIERRO', 41.64648600, -0.93328900, '0101000020E6100000EEED96E480DDEDBF33A9A10DC0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33537238213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33537238213.webp', 'https://www.flickr.com/photos/zaragozaantigua/33537238213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21735, 'Vista a├®rea y humo c.1931', 'Vista a├®rea con la Industrial Qu├¡mica en primer plano, echando humo. Abajo a la derecha, la Aljafer├¡a, y sobre ├®sta la plaza de toros. El r├¡o Ebro, a la izquierda, es cruzado por el puente del Ferrocarril de la Almozara. Al fondo, el puente de Piedra y el Pilar. Entre el humo, la torre de San Pablo y la c├║pula de Santiago. Arriba a la izquierda, el r├¡o G├íllego.', 1931, 1931, 1931, 'Anos 30', 'LA ALMOZARA', 41.66104500, -0.89517500, '0101000020E6100000304CA60A46A5ECBF9817601F9DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21385980869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21385980869.webp', 'https://www.flickr.com/photos/zaragozaantigua/21385980869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22755, 'C.┬║ de la Almozara 1978', 'Interesante imagen del oficioso aparcadero intermodal habilitado a la entrada del literal camino de la Almozara, capturada a la altura de la calle de Monegros (a la izquierda), con el fondo del moderno bloque del paseo de M┬¬ Agust├¡n chaflanero con la calle de Santa Luc├¡a. Al fondo, a la derecha, edificios del complejo de la Compa├▒├¡a Industrial Agr├¡cola, recayentes al mar de v├¡as y a la Industrial Qu├¡mica. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.66026600, -0.89518000, '0101000020E6100000A110018750A5ECBF9354A69883D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32748624250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32748624250.webp', 'https://www.flickr.com/photos/zaragozaantigua/32748624250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23085, 'Pabell├│n de Espa├▒a 2007', 'Construcci├│n del Pabell├│n de Espa├▒a de la Expo 2008 de Zaragoza, obra de Francisco "Patxi" Mangado. Fuente: picasaweb.google.com/CHELUYS', 2007, 2007, 2007, 'Siglo XXI', 'LA ALMOZARA', 41.66859700, -0.89802600, '0101000020E610000072A59E05A1BCECBF139A249694D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19345835593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19345835593.webp', 'https://www.flickr.com/photos/zaragozaantigua/19345835593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24550, 'La Qu├¡mica c.1978', 'Apartadero ferroviario de La Industrial Qu├¡mica de Zaragoza. A la derecha, el edificio de piensos CIA que ser├í derribado en 1992. Fondo Biblioteca Rafael Andolz.', 1978, 1978, 1978, 'Anos 70', 'LA ALMOZARA', 41.65840100, -0.89569400, '0101000020E61000004A26A77686A9ECBFAC53E57B46D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14941626071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14941626071.webp', 'https://www.flickr.com/photos/zaragozaantigua/14941626071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26054, 'Avenida Tenor Fleta 1984', 'Foto: Tom├ís Mora Ruata. Vista de la avenida del Tenor Fleta, con el colegio de los Agustinos al fondo y la entrada de la calle de Uncastillo a la derecha. Fuente: www.facebook.com/photo.php?fbid=1536701036358009&set=...', 1984, 1984, 1984, 'Anos 80', 'SAN JOS├ë', 41.63962200, -0.88073400, '0101000020E61000005D35CF11F92EECBFACE63922DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32253731215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32253731215.webp', 'https://www.flickr.com/photos/zaragozaantigua/32253731215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24457, 'Camino de San Jos├® 1925', 'Talleres del yesaire y decorador Enrique Cubero. Edificio obra de Francisco Albi├▒ana, en el antiguo camino de San Jos├® 155. Fuente: La Esfera 609, 1925.', 1925, 1925, 1925, 'Anos 20', 'SAN JOS├ë', 41.63579500, -0.87930400, '0101000020E610000055BE67244223ECBFECFA05BB61D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19604893413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19604893413.webp', 'https://www.flickr.com/photos/zaragozaantigua/19604893413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25759, 'Jard├¡n de la Memoria 1992', 'Imagen en altura, capturada desde los altos bloques de la calle pintor Mar├¡n Bag├╝├®s, posiblemente su n├║mero 8, con el aspecto del reci├®n inaugurado "Parque de la Memoria", en el barrio de San Jos├®. Estos aterrazados terrenos formaron parte de las extensas instalaciones de la antigua f├íbrica textil de D├ímaso Pina, y tras su derribo, fueron calificadas como espacio edificable para levantar necesarios rascacielos. La presi├│n vecinal para conseguir que esto fuera una zona verde, con notables dificultades, largos a├▒os de lucha, y demediado resultado, hall├│ eco municipal, hasta llegar al resultado de la imagen. El terrible solanar, con el natural crecimiento de los nuevos ├írboles, configura un espacio interior de apariencia hoy bien distinta, m├ís amable. Sobre el acusado desnivel del terreno, y con una ins├│lita atenci├│n a los requerimientos vecinales del momento, se actu├│ definiendo una serie de referencias emblem├íticas y representativas de la historia del barrio: entre otros, y en primer t├®rmino, el monumento a la "Ba├▒ista", de Carlos Ochoa, el estanque de "Cantarranas", y un recuerdo del trazado de la antigua acequia de Ontanar, tres fogonazos del pasado ligado al agua, a las desaparecidas acequias al aire, sus "ba├▒os", y al derribado lavadero de la Balseta. A su lado, los primeros huertos urbanos de la ciudad, cuando eso a├║n se consideraba nost├ílgico "ocio de viejos", un mini parque tem├ítico de lo provinciano. Detr├ís hay un enorme espacio vac├¡o, convertido en plaza, donde deber├¡a estar la chimenea de la antigua f├íbrica textil, pero que fue derribada con alevos├¡a y nocturnidad, cuando esas cosas viejas no se valoraban demasiado. A la derecha, la calle de Joaqu├¡n Sorolla, y al fondo, las traseras de la calle Garc├¡a Lorca. Fuente visual: Revista "Nuestra Zaragoza", Ayuntamiento de Zaragoza.', 1992, 1992, 1992, 'Anos 90', 'SAN JOS├ë', 41.63353700, -0.87923700, '0101000020E610000062DC0DA2B522ECBF29E78BBD17D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27460993726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27460993726.webp', 'https://www.flickr.com/photos/zaragozaantigua/27460993726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22714, 'Vista Miguel Servet 1970', 'Vista a├®rea de la calle de Miguel Servet y su entorno, desde las inmediaciones de la estaci├│n de Utrillas (fuera de plano). En el centro de la imagen, el Matadero. M├ís arriba, el cuartel de San Jos├® y el resto de la ciudad consolidada, con el Pilar. Fuente: www.facebook.com/photo.php?fbid=10208503253957120&set...', 1970, 1970, 1970, 'Anos 70', 'SAN JOS├ë', 41.64356200, -0.86952000, '0101000020E610000033F9669B1BD3EBBF6479573D60D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29670696426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29670696426.webp', 'https://www.flickr.com/photos/zaragozaantigua/29670696426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24396, 'Miguel Servet c.1960', 'Imagen de una maqueta que representa el antiguo colegio de La Salle Montemol├¡n en su esquinera ubicaci├│n entre el camino de las Torres (izquierda), y la calle de Miguel Servet (derecha), en cuyo n├║mero 36 ten├¡a radicada su direcci├│n postal y entrada principal. Tras unos a├▒os de provisional estancia en una casa de las inmediaciones ("casa de Policeto", desde 1909, como Colegio de Nuestra Se├▒ora del Pilar), en 1916 fue inaugurado este centro, con nueva planta proyectada por Francisco Albi├▒ana, autor del bloque central en forma h├¡brida de "T-L", con formas y aires neomud├®jares, casi racionalistas. Ten├¡a inmediata vecindad con la "Fundici├│n de Iranzo" (la construcci├│n que chaflanea el principio del camino de las Torres), y al otro lado de Miguel Servet quedaba la Harinera del Pilar, y el cuartel de Intendencia de San Jos├®. Pose├¡a el colegio dos peque├▒os patios donde la soberan├¡a del baloncesto era notable, a los que luego se a├▒adi├│ el gran patio del fondo, junto a la calle de la Concepci├│n, resultado del encementamiento de una antigua zona de huertos. En 1929 mud├│ su denominaci├│n por la de Colegio La Salle Montemol├¡n. El curso 1971-1972 fue el ├║ltimo en estas instalaciones, y el siguiente de 1972-1973 fue el pionero en las nov├¡simas aulas de la calle Jos├® Galiay, frente a la antigua Granja Agr├¡cola, donde mantuvo en su nombre de forma descontextualizada el "Montemol├¡n" de sus or├¡genes en lugar de actualizarlo por el de "Miraflores" de su nueva ubicaci├│n, al estilo de los Lakers tras dejar Minnesota y r4esidenciarse en Los ├üngeles. El colegio de la imagen fue vendido, derribado, y sobre ├®l fue levantada una de esas renombradas modernidades habitacionales de las que esta ciudad tanto se enorgullece. Fuente visual: "Memoria Escolar 1971-1972", amable aportaci├│n de Juan Carlos Crespo.', 1960, 1960, 1960, 'Anos 60', 'SAN JOS├ë', 41.64714000, -0.87386400, '0101000020E610000016DBA4A2B1F6EBBF7BF7C77BD5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26134908475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26134908475.webp', 'https://www.flickr.com/photos/zaragozaantigua/26134908475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24534, 'Matadero c.1945', 'Imagen capturada en el patio principal del matadero municipal, a espaldas de la monumental puerta de entrada desde la calle de Miguel Servet, cuya sombra se proyecta sobre la fuente del Buen Pastor. Aparcados en los porches, camiones frigor├¡ficos para distribuci├│n de la carne procesada en este veterano establecimiento en servicio desde 1887.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS├ë', 41.64476000, -0.87007600, '0101000020E6100000971AA19FA9D7EBBF6DE2E47E87D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50078126331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50078126331.webp', 'https://www.flickr.com/photos/zaragozaantigua/50078126331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24701, 'Matadero 1878', 'Alzado del proyecto de Ricardo Magdalena para el matadero municipal de Zaragoza, mayo de 1878. Ser├í inaugurado para albergar la Exposici├│n Aragonesa de 1885. Fuente: AMZ.', 1878, 1878, 1878, 'Siglo XIX', 'SAN JOS├ë', 41.64477600, -0.87006000, '0101000020E61000002BD9B11188D7EBBF739F1C0588D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21087475345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21087475345.webp', 'https://www.flickr.com/photos/zaragozaantigua/21087475345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24568, 'La Granja c.1928', 'Imagen capturada en la Granja Agr├¡cola durante la visita de la Comisi├│n Permanente del ayuntamiento de la ciudad, encabezada por su alcalde, Miguel Allu├® Salvador. Junto a ├®l, el ingeniero-director de la Granja, Jos├® Cruz Lapazar├ín Berista├¡n, les muestra el funcionamiento de una trilla mec├ínica. Fuente visual: exposici├│n ÔÇ£La investigaci├│n agroalimentaria en Arag├│n. Sus inicios con Rodr├¡guez AyusoÔÇØ. Centro de Investigaci├│n y Tecnolog├¡a Agroalimentaria de Arag├│n (CITA).', 1928, 1928, 1928, 'Anos 20', 'SAN JOS├ë', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20110116930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20110116930.webp', 'https://www.flickr.com/photos/zaragozaantigua/20110116930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25138, 'Cementera Miraflores 1945', 'Postal publicitaria con el dibujo de las instalaciones de la f├íbrica de Cementos Portland Zaragoza, en Miraflores. El Pilar de las dos torres, al fondo, referencia universalmente las enormes instalaciones de esta planta, que se extienden delimitadas por las l├¡neas de ferrocarril a Utrillas, y la que conecta Madrid con Barcelona. Fuente: Archivo Enrique Baile.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS├ë', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20950434333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20950434333.webp', 'https://www.flickr.com/photos/zaragozaantigua/20950434333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21636, 'Calle de Miguel Servet 1925', 'Reci├®n llegado de los antiguos talleres de Carde y Escoriaza, redenominados Material M├│vil y Construcciones desde principios de los a├▒os veinte, el nov├¡simo coche que inauguraba en los Tranv├¡as de Zaragoza la serie de los "50", revestido de madera para hacer m├ís liviano su peso, y coloreado de amarillo. De fondo, la esquina del antiguo edificio de oficinas y direcci├│n junto al ingreso al cocher├│n de la calle de Miguel Servet, sito en su lado sur e inmediatos a la estaci├│n de Utrillas.', 1925, 1925, 1925, 'Anos 20', 'SAN JOS├ë', 41.63962900, -0.86622400, '0101000020E61000006954E0641BB8EBBF5E49F25CDFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50113666052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50113666052.webp', 'https://www.flickr.com/photos/zaragozaantigua/50113666052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22439, 'Miraflores 1962', 'Imagen de una locomotora a vapor de la MZA, serie 651/680, camino de la estaci├│n de Campo Sepulcro, tras haber pasado por la de Miraflores (al fondo, a la derecha). La imagen se ha capturado desde la altura del puente para tr├ífico rodado que daba continuidad al camino de Cabald├│s. Los campos de esta zona formaban parte de los terrenos de la antigua Granja Agr├¡cola. La estaci├│n de Utrillas queda a la izquierda, fuera de plano. Al fondo, el gran complejo de la cementera de Miraflores, que incluye las chimeneas que emergen de la estaci├│n ferroviaria. Fuente visual: image.slidesharecdn.com/', 1962, 1962, 1962, 'Anos 60', 'SAN JOS├ë', 41.63351300, -0.86909800, '0101000020E6100000B79BE09BA6CFEBBFA14B38F416D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30819877595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30819877595.webp', 'https://www.flickr.com/photos/zaragozaantigua/30819877595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22882, 'Estaci├│n de Utrillas 1985', 'Imagen panor├ímica de la antigua estaci├│n de Utrillas, abandonada desde 1966. Hoy esta toma habr├¡a que hacerla desde la calle Valent├¡n Zabala, donde antes se localizaba la gran curva de acceso a la Estaci├│n en que la v├¡a ├║nica de entrada se multiplicaba hasta en ocho viales para conducir tanto al Dep├│sito de locomotoras (los "Arcos" de la izquierda), a los muelles de descarga de mercanc├¡as, a los andenes para depositar/recoger pasaje en el Edificio Principal (a la derecha), al cocher├│n de vagones, y al mar de v├¡as del fondo de la Estaci├│n. Hacia la derecha, otras tres v├¡as conduc├¡an al descargadero de las carboneras, donde la actual calle Bubierca. En la imagen, en primer├¡simo plano, soberan├¡a de aliagas, espartos, ontinas, sisallos, y alguna que otra aspirante a capitana que verdean, aun en blanco y negro, en el espacio de tr├ínsito de las v├¡as del tren. Encima, magn├¡fico y dominante, el exoexqueleto del Dep├│sito de Locomotoras. De ├®l emerge, axial, la Chimenea MFU con matr├¡cula del a├▒o 1925. A su lado, el cementoso dep├│sito de agua ya s├│lo como ocasional criadero de renacuajos/ranas. Sin soluci├│n de continuidad, los muros y enormes farolas de las cocheras de los autobuses urbanos que sustituyeron en ubicaci├│n y trayectos a los tranv├¡as de la ciudad. Estos muros se retranquearon un bastante-m├ís-para-ac├í, aprovechando que el T├¡ber pasa por Roma, ocupando el lugar de las v├¡as del ferrocarril, de forma que cuando se construy├│ el Colegio P├║blico Tom├ís Alvira hubo que retrasar la medianera unas decenas de metros. Gracias a eso hay una continuidad peatonal con la actual plaza de ├üngel Sanz Briz. Al fondo de la imagen, los bloques del Camino de Cabald├│s, antes de urbanizarse con bloques, y nuevos espacios abiertos, como la Plaza Ferm├¡n Aguayo. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/10799465686/in...', 1985, 1985, 1985, 'Anos 80', 'SAN JOS├ë', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19645417384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19645417384.webp', 'https://www.flickr.com/photos/zaragozaantigua/19645417384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22998, 'David Bowie 1997', 'Actuaci├│n del cantante londinense David Bowie (1947-2016) en el pabell├│n deportivo Pr├¡ncipe Felipe de Zaragoza, el mi├®rcoles 16 de julio de 1997. Fuente: Heraldo de Arag├│n.', 1997, 1997, 1997, 'Anos 90', 'SAN JOS├ë', 41.63532000, -0.86619800, '0101000020E61000001A8A3BDEE4B7EBBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24373261365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24373261365.webp', 'https://www.flickr.com/photos/zaragozaantigua/24373261365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24475, 'GIESA 1945', 'Puerta principal de acceso a la f├íbrica Guiral Industrias El├®ctricas S.A. (GIESA), terminada de construir en 1945 en la calle Miguel Servet.', 1945, 1945, 1945, 'Anos 40', 'SAN JOS├ë', 41.63948300, -0.86488400, '0101000020E610000060ADDA3521ADEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20986429389.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20986429389.webp', 'https://www.flickr.com/photos/zaragozaantigua/20986429389/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24702, 'Miguel Servet 1927', 'Imagen de la colocaci├│n de tendido a├®reo de cable telef├│nico en la parte derecha de la carretera de Zaragoza a Castell├│n, o Miguel Servet. La foto ha sido capturada entre la calle de Tom├ís Higuera, y la de Belchite. A la derecha, los muros de la estaci├│n de Utrillas y los gemelos edificios de viviendas de la plaza de acceso a la estaci├│n. Al fondo a la izquierda, el palacio de Larrinaga. Fuente visual: foto Alfonso, en Fundaci├│n Telef├│nica.', 1927, 1927, 1927, 'Anos 20', 'SAN JOS├ë', 41.64163200, -0.86773800, '0101000020E6100000E7E26F7B82C4EBBF960854FF20D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21104405094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21104405094.webp', 'https://www.flickr.com/photos/zaragozaantigua/21104405094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
