INSERT INTO public.photos VALUES (21598, 'Parque Primo de Rivera 1928', 'Postal. Vista desde el Cabezo de Buenavista del reci├®n redenominado parque Primo de Rivera y su reci├®n construido Rinc├│n de Goya, Fuente: www.ebay.com/', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25302397710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25302397710.webp', 'https://www.flickr.com/photos/zaragozaantigua/25302397710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24979, 'Monumento a Pignatelli 1933', 'Monumento a Pignatelli en los ÔÇ£JardinesÔÇØ del mismo nombre, entre la avenida de Wilson (a la izquierda), y la avenida del Siglo XX/paseo de Cu├®llar (derecha). Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63686900, -0.88504400, '0101000020E61000003BAC70CB4752ECBF096B63EC84D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22875244899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22875244899.webp', 'https://www.flickr.com/photos/zaragozaantigua/22875244899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21820, 'Incendio Tudor 1935', 'Foto: Mar├¡n Chivite. El martes 1 de octubre de 1935 se produjo un incendio en el edificio principal de la f├íbrica de Acumuladores Tudor "La Pilar", aunque continu├│ en funcionamiento en esa ubicaci├│n hasta 1946. En la imagen, labores de extinci├│n desde la avenida de la Rep├║blica (derecha). Tras el bloque incendiado, el paseo de Cu├®llar y el parque Pignatelli, con la c├║pula de la iglesia de San Fernando al fondo. Fuente: Heraldo de Arag├│n.', 1935, 1935, 1935, 'Anos 30', 'UNIVERSIDAD', 41.63940900, -0.88593500, '0101000020E610000061376C5B9459ECBF50E27327D8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31644488321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31644488321.webp', 'https://www.flickr.com/photos/zaragozaantigua/31644488321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22830, 'Plaza de San Francisco 1970', '"Plaza de San Francisco (Monumento a Fernando el Cat├│lico)". ├ôleo sobre lienzo, 73 x 60 cm, Mar├¡a ├üngeles Ca├▒ada, 1970. Al fondo, fachada de los pares del paseo de Fernando el Cat├│lico, desde el n├║mero 32 hacia atr├ís.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64092800, -0.89485900, '0101000020E61000001D007157AFA2ECBF9C8BBFED09D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53637685189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53637685189.webp', 'https://www.flickr.com/photos/zaragozaantigua/53637685189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24541, 'C.┬║ de las Torres 1924', 'Imagen capturada en el vecino solar del taller de canter├¡a de Bayod sito en el arbolado camino de las Torres (a la izquierda, tras la valla) y confrontando con la f├íbrica del acumulador Tudor. En este solar estuvo ubicada una f├íbrica de yeso, y en el momento de realizar la fotograf├¡a se estaban obrando los cimientos de donde habnr├¡a de surgir el notable edificio de Casa Faci, chaflanero con el paseo de Sagasta.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.64011800, -0.88620700, '0101000020E61000008A8F4FC8CE5BECBF5CCAF962EFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52170286347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52170286347.webp', 'https://www.flickr.com/photos/zaragozaantigua/52170286347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23129, 'Avenida Goya 2006', 'Foto: M. Mart├¡nez. Vista de la avenida de Goya, con la Gran V├¡a a la izquierda. En el aparcamiento arbolado del centro de la imagen se inaugurar├í en 2012 la estaci├│n ferroviaria de cercan├¡as Zaragoza-Goya. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'UNIVERSIDAD', 41.64401100, -0.89141800, '0101000020E6100000721AA20A7F86ECBFD3A1D3F36ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31589489240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31589489240.webp', 'https://www.flickr.com/photos/zaragozaantigua/31589489240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24175, 'Puente sobre el Huerva en Goya 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 18/02/1965. "Nuevo puente sobre el Huerva". El soterramiento de las v├¡as del ferrocarril por la Avenida de Goya, supuso la construcci├│n de un nuevo puente sobre el Huerva, sin nombre. En la imagen, obras de construcci├│n del nuevo puente, con vista de los nuevos t├║neles para el ferrocarril. Al fondo, la pasarela peatonal sobre el r├¡o, que desaparecer├í cuando el nuevo puente est├® terminado.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981631606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981631606.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981631606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21599, 'Vista desde la Seo c.1925', 'Postal, Lucien Roisin. Vista de Zaragoza desde la torre de la Seo hacia 1925, con su abigarrado caser├¡o en el entorno del Pilar (a la derecha). Fuente: www.catedu.es', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65556400, -0.87903600, '0101000020E61000008736001B1021ECBFAC376A85E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25499563562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25499563562.webp', 'https://www.flickr.com/photos/zaragozaantigua/25499563562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24945, 'Parque Primo de Rivera c.1974', 'Fuentes en el paseo de San Sebasti├ín del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63486400, -0.89440000, '0101000020E6100000575BB1BFEC9EECBF31B43A3943D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27143364480.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27143364480.webp', 'https://www.flickr.com/photos/zaragozaantigua/27143364480/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25120, 'Colegio mayor Cardenal Xavierre 1943', 'Dibujo del proyecto de Lorenzo Moncl├║s del edificio del Colegio mayor Cardenal Xavierre, ejecutado en 1948 junto al campus universitario de la plaza de San Francisco entre las calles de Pedro Cerbuna y Baltasar Graci├ín. Ni el edificio de su izquierda ni el arco de su derecha existen o existieron nunca. Fuente: Zaragoza 1908-2008. FCC.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64168000, -0.89563200, '0101000020E6100000C808A87004A9ECBFA73FFB9122D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524713978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524713978.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524713978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
