INSERT INTO public.photos VALUES (21780, 'La Lonja 1932', 'La Lonja desde el paseo de la Ribera. A la izquierda, la calle de Don Jaime I. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65588600, -0.87624900, '0101000020E6100000F3E2C4573B0AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22953545510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22953545510.webp', 'https://www.flickr.com/photos/zaragozaantigua/22953545510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22378, 'Vista a├®rea Parque Grande 1964', 'Vista parcial del parque Primo de Rivera de Zaragoza y del antiguo ensanche de Miralbueno, hoy Universidad. Al fondo, el norte de la ciudad. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22290228726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22290228726.webp', 'https://www.flickr.com/photos/zaragozaantigua/22290228726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22450, 'Vista &quot;Casa Grande&quot; 1960', '"Vista panor├ámica d''un bloc d''habitatges a la ciutat de Saragossa." Desde GAZA entendemos que se trata de una a├®rea visual centrada en la Residencia Sanitaria "Jos├® Antonio", en el paseo de Isabel la Cat├│lica. Al fondo, campos de cultivo. Adem├ís, gratis et amore, desde GAZA hemos volteado horizontalmente la imagen original para tratar de orientar la vista de forma adecuada. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63516400, -0.90013200, '0101000020E610000087A8C29FE1CDECBF5CCCCF0D4DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31241373871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31241373871.webp', 'https://www.flickr.com/photos/zaragozaantigua/31241373871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20900, 'Venida de la Virgen a├▒o 40', '"Venida de la Virgen del Pilar a Zaragoza", Maestro de Luesia, c 1490. Sarga pintada al temple que representa la llegada de Mar├¡a a la ciudad, acompa├▒ada de ├íngeles cantores, la madrugada del 2 de enero del a├▒o 40, lunes. Se conserva en la sacrist├¡a de la bas├¡lica del Pilar. A la izquierda de la columna, el ap├│stol Santiago con sus correligionarios. Detr├ís, el r├¡o Ebro y el Arrabal, con sus bosques y campos de cultivo. Fuente: eszaragoza.blogspot.com.es/', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65697100, -0.87824500, '0101000020E610000043041C42951AECBFD0B52FA017D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30696808570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30696808570.webp', 'https://www.flickr.com/photos/zaragozaantigua/30696808570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21658, 'Estaci├│n Campo Sepulcro 1927', 'In├®dita imagen capturada en el acceso a la estaci├│n de Campo Sepulcro con motivo de la llegada a Zaragoza del Infante don Jaime de Borb├│n y Battenberg al objeto de inaugurar, en representaci├│n de su padre Alfonso XIII, la Exposici├│n Regional Av├¡cola ubicada en la Lonja. Su espigada Alteza aparece flanqueada por el Alcalde Allu├® Salvador y el capit├ín general Perales Vallejo, y rodeado por buen n├║mero de no menos altos representantes militares, religiosos y civiles locales. Su apretada agenda de actividades programada para la tarde de ese d├¡a incluy├│ la preceptiva participaci├│n en un Tedeum en el templo del Pilar; la visita en el campamento de Alfonso XIII de los terrenos previstos para acoger la Academia General Militar; la asistencia a la final de la Copa del Rey en el campo del Iberia que disputaron el Arenas Club de Guecho y el Real Uni├│n Club de Ir├║n (que resultar├¡a vencedor por un tanto a cero). Despu├®s inaugur├│ la referida Exposici├│n Av├¡cola y se desplaz├│ a la Casa Consistorial donde firm├│ el Libro de Oro de la Ciudad y fue agasajado con un "lunch". Finalmente, regres├│ a la estaci├│n de Campo Sepulcro donde se subi├│ a un "break" agregado al tren correo de Madrid para hacer el viaje de vuelta a esa villa.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.65234900, -0.89480600, '0101000020E61000006877483140A2ECBF064A0A2C80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53210201584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53210201584.webp', 'https://www.flickr.com/photos/zaragozaantigua/53210201584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21974, 'Campo Sepulcro 1941', 'Entre 1941 y 1943, la estaci├│n de ferrocarril de Campo Sepulcro fue un nudo de comunicaci├│n muy importante para la ordenaci├│n y clasificaci├│n de los voluntarios falangistas que configuraron la denominada "Divisi├│n Azul", encuadrada como 250┬¬ divisi├│n de infanter├¡a de la Wermacht durante la agresi├│n armada del III Reich alem├ín contra la Uni├│n Sovi├®tica. Zaragoza fue lugar de paso de convoyes procedentes de Andaluc├¡a, las dos Castillas, Valencia, e incluso de Catalu├▒a, en su ruta, bien hacia el paso por Hendaya, bien al de Port-Bou. Y lo hizo en las dos direcciones, tanto de salida hacia el frente ruso, como de llegada de los "retornados". Hubo tambi├®n un part├¡cipe contingente zaragozano. En la imagen, nocturno paso por al estaci├│n de ferrocarril de Campo Sepulcro de uno de los primeros convoyes de voluntarios falangistas con destino a Rusia, presumiblemente de voluntarios manchegos en su paso hacia Hendaya. Una breve parada, camino de seguir combatiendo contra el comunismo (ahora directamente en su cubil, pues comulgaban con la consigna "Rusia es culpable"), es aprovechada para reafirmar sus predispuestas convicciones ideol├│gicas. Banderas al viento, c├ínticos cuarteleros, y vivas al caudillo, al duce y al f├╝hrer, alimento espiritual de estos autoproclamados cruzados del fascismo. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1941, 1941, 1941, 'Anos 40', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24441554504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24441554504.webp', 'https://www.flickr.com/photos/zaragozaantigua/24441554504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22132, 'Campo Sepulcro 1956', 'Imagen en altura de un grupo de unidades ferroviarias el├®ctricas 1500v de la serie 433, (denominadas "Ping├╝inos") producidas para la RENFE en la factor├¡a de Material M├│vil y Construcciones. Al fondo, la estaci├│n de Campo Sepulcro, y m├ís al fondo, los grandes bloques de viviendas militares de la manzana entre Anselmo Clav├® y el paseo de Mar├¡a Agust├¡n. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23946424076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23946424076.webp', 'https://www.flickr.com/photos/zaragozaantigua/23946424076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22136, 'C.┬║ de la Romareda 1959', 'Foto capturada en el ingreso principal de las oficinas de VIASA (Veh├¡culos Industriales y Agr├¡colas SA) proyectadas por el arquitecto Jos├® de Yarza Garc├¡a en el antiguo camino de la Romareda, reci├®n redenominado calle Manuel Escoriaza y Fabro (el n┬║ 103) y esquinera con la de Vicente Berdus├ín. Esta factor├¡a hab├¡a sido construida entre 1957-58 como ap├®ndice empresarial de Material M├│vil y Construcciones (Antiguos Talleres de Carde y Escoriaza) para la construcci├│n bajo licencia en Espa├▒a de la norteamericana marca de autom├│vil todoterreno Jeep. Hacia la izquierda, fuera de plano, el inmediato mar de v├¡as de la estaci├│n de ferrocarril Campo Sepulcro. Fuente visual: arch. J. de Yarza', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65370100, -0.89790000, '0101000020E61000004182E2C798BBECBF662E7079ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24298626768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24298626768.webp', 'https://www.flickr.com/photos/zaragozaantigua/24298626768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22168, 'Vista VIASA 1959', 'Vista a├®rea centrada en la factor├¡a VIASA (Veh├¡culos Industriales y Agr├¡colas, S.A.), ap├®ndice empresarial de Material M├│vil y Construcciones, parte de cuyas naves se ven abajo. Por el mismo precio, y a su justo lado, las grandes naves de ALSOVISA (Alfonso Solans Viamonte, S.A.), f├íbrica de camas met├ílicas y somieres, sita en la calle de Blanca de Navarra. A la derecha, mar de v├¡as de la estaci├│n Campo Sepulcro. Al fondo, el r├¡o Ebro. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65370100, -0.89790000, '0101000020E61000004182E2C798BBECBF662E7079ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31212708832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31212708832.webp', 'https://www.flickr.com/photos/zaragozaantigua/31212708832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22169, 'Vista a├®rea Delicias 1959', 'Imagen a├®rea desde el barrio de Las Delicias, con la iglesia de San Valero abajo, y en el centro el gran complejo de Material M├│vil y Construcciones. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65140800, -0.89985300, '0101000020E6100000BEA3C68498CBECBF282D5C5661D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31315606756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31315606756.webp', 'https://www.flickr.com/photos/zaragozaantigua/31315606756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22170, 'Calle Unceta 1956', 'Imagen de la fachada de la Escuela de Formaci├│n Profesional San Valero, cuyos primeros pasos databan de 1952, en el entorno de la vecina parroquia de San Valero (barrio de las Delicias), como escuela de capacitaci├│n profesional para peones y aprendices. En 1954 fue inaugurado el primer taller escuela por el arzobispo Domenech y Valls, y en 1956 su sucesor, el arzobispo Morcillo, inaugur├│ la ampliaci├│n, en esa misma ubicaci├│n. En la imagen, tras el singular grupo ciclista (posiblemente de alumnos y profesores), fachada de la escuela, en el n┬║ 11-13 de la calle de Unceta. A la izquierda, fuera de plano, la calle del Padre Manj├│n (antigua de Marcelino Domingo). A su derecha, las antiguas parcelas de los n├║meros 15, y 17. Al otro lado de la calle, fuera de plano, la parroquia de San Valero, esquinera con la calle de Graus. Fuente visual: www.sanvalero.es/', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65308400, -0.90233600, '0101000020E6100000501C40BFEFDFECBF3BC5AA4198D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31333893032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31333893032.webp', 'https://www.flickr.com/photos/zaragozaantigua/31333893032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22261, 'Talleres Carde y Escoriaza c.1961', 'Vista a├®rea de la zona ocupada por los talleres Carde y Escoriaza, en los terrenos donde se construy├│ luego la urbanizaci├│n Parque Roma. Tras la factor├¡a, se pueden ver las instalaciones de la estaci├│n Campo Sepulcro, y m├ís all├í el cuartel del Cid junto a la plaza de Toros, llegando la visual incluso al r├¡o Ebro.', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781681738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781681738.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781681738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22323, 'Estaci├│n Campo Sepulcro c.1967', 'Imagen capturada desde la altura de los bloques de vivienda militar de la calle Anselmo Clav├®, del acceso desde ese vial a la estaci├│n de ferrocarril de Campo Sepulcro. A la izquierda, el dep├│sito de locomotoras. A la derecha, talleres de la estaci├│n. Al fondo, el edificio central. Detr├ís, el complejo industrial de Carde y Escoriaza. Fuente visual: www.facebook.com/photo.php?fbid=879812342051965&set=p...', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65210400, -0.89413500, '0101000020E6100000CDAFE600C19CECBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15987338746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15987338746.webp', 'https://www.flickr.com/photos/zaragozaantigua/15987338746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22405, 'Campo Sepulcro 1968', 'Imagen del and├®n principal de la estaci├│n de ferrocarril de Campo Sepulcro, cuando ya era denominada extraoficialmente "Estaci├│n de Madrid" para evitar la referencia a la cadaverina que dio pie a la denominaci├│n de ese entorno desde los tiempos de alguno de los Carolo. La esquivez con este aspecto de la tradici├│n y el esp├¡ritu "detodalavida" que impregna la ciudad, se argumentaba por motivos tur├¡sticos, de falta de atractivo del nombre. Cuando unos a├▒os despu├®s la estaci├│n fue remozada integralmente, en el paquete entr├│ tambi├®n un nuevo nomencl├ítor para ella (Portillo), aunque ello supusiera violentar las coordenadas de esta ubicaci├│n, extendi├®ndola hasta donde antes nunca llegara. Pero el turismo mejor├│, y la modernidad se precipit├│ sobre la ciudad como nunca antes. En la imagen, otra de esas escenas de la Espa├▒a que no luc├¡a: maletas de cart├│n y cajas atadas con cuerdas, portadas por personas sin glamour ni estilo. Como nosotros. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24244362520.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24244362520.webp', 'https://www.flickr.com/photos/zaragozaantigua/24244362520/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22467, 'Campo Sepulcro 1968', 'Imagen centrada en una locomotora 4-8-2 que, junto a otras estacionadas, maniobra en el ├írea descubierta del dep├│sito de la estaci├│n Zaragoza-Campo Sepulcro, entre el edificio de la estaci├│n (al fondo), y Anselmo Clav├® (a la derecha, fuera de plano). Fuente visual: foto Bernard Harrison, en www.flickr.com/photos/30937/19479014850/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32903066464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32903066464.webp', 'https://www.flickr.com/photos/zaragozaantigua/32903066464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22473, 'Campo Sepulcro 1968', 'Imagen centrada en dos locomotoras (posiblemente, "Santa Fe") estacionadas en el ├írea cubierta del dep├│sito de la estaci├│n Zaragoza-Campo Sepulcro. Al fondo, los bloques de viviendas para militares de Anselmo Clav├®. Fuente visual: foto Bernard Harrison, en www.flickr.com/photos/30937/19671464931/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33623233581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33623233581.webp', 'https://www.flickr.com/photos/zaragozaantigua/33623233581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22510, 'Campo Sepulcro c.1965', 'Imagen de los talleres de la estaci├│n de ferrocarril de Campo Sepulcro, con varias locomotoras a vapor de la serie 2400 en tareas de mantenimiento y reparaci├│n. Estos talleres estaban radicados junto al dep├│sito de locomotoras, a la altura de la calle de Madre Sacramento. Al fondo, el cuartel de la Polic├¡a Armada de la avenida de Anselmo Clav├®. Cuando la estaci├│n fue remodelada, pocos a├▒os despu├®s, sobre estos talleres se construy├│ el edificio del Centro de clasificaci├│n postal de Correos.', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65125400, -0.89416200, '0101000020E6100000336E6AA0F99CECBFD1B1834A5CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51016543032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51016543032.webp', 'https://www.flickr.com/photos/zaragozaantigua/51016543032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22541, 'Delicias Este 1973', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 24/04/1973. Vista en altura desde uno de los nuevos bloques de viviendas de la Avenida de Madrid, de c├│mo estaban las cosas en esta parte del Barrio de las Delicias, concretamente en las traseras de la Estaci├│n de El Portillo, reci├®n estrenada su remodelaci├│n integral, incluyendo el nombre. Proliferaci├│n de naves industriales, sobre todo de los gigantescos talleres de Carde y Escoriaza, inmediatos a la Estaci├│n, que hoy dan nombre a la larga calle que por all├¡ circula. Abajo, y peque├▒itas, las parcelas de las calles del entorno, como Do├▒a Blanca de Navarra (en medio de la imagen), que desde la Avenida de Madrid conectaba con esta zona. Otras calles: Navas de Tolosa, Tenor Gayarre, Bolivia... Tras el traslado de las naves a pol├¡gonos industriales m├ís lejanos, esa zona se urbaniz├│ y modific├│ mucho.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65194300, -0.89825000, '0101000020E61000005839B4C876BEECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14937650406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14937650406.webp', 'https://www.flickr.com/photos/zaragozaantigua/14937650406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20878, 'Castillo de Miranda s. XII', 'Reconstrucci├│n virtual de Daniel Herrera del estado original del castillo de Miranda, en el barrio de Juslibol de Zaragoza. Fuente: deuslovol.blogspot.com.es/', 1150, 1100, 1199, 'Siglo XIX', NULL, 41.70776800, -0.92423200, '0101000020E61000006155BDFC4E93EDBFE2934E2498DA4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19843375686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19843375686.webp', 'https://www.flickr.com/photos/zaragozaantigua/19843375686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22546, 'Estaci├│n del Portillo 1973', '1973. La estaci├│n de Campo Sepulcro fue ampliada y reformada profundamente por RENFE, y rebautizada como Zaragoza-El Portillo, concentrando todos los servicios que hasta ese momento prestaban las estaciones de Campo Sepulcro, Delicias, y Arrabal. En la imagen, casi resplandece la nueva estaci├│n. Al fondo, naves de Carde y Escoriaza. A la derecha, el acceso a la antigua estaci├│n de Campo Sepulcro fue reaprovechado para acceso al aparcamiento "subterr├íneo". En el centro, donde estuvo el dep├│sito de locomotoras de la antigua estaci├│n, el elevado acceso a la nueva Estaci├│n, con la parada de taxis y el aparcamiento en superficie.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65183100, -0.89409800, '0101000020E61000008368AD68739CECBF6EC2BD326FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978837241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978837241.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978837241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22565, 'Zaragoza-El Portillo 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 22/09/1974. Imagen de la estaci├│n de ferrocarril "Zaragoza-El Portillo", con su rampa de acceso para veh├¡culos y peatones. El edificio hab├¡a sido proyectado por Demetrio Ullastres y Alfredo Mart├¡nez Alonso, y levantado en 1971. Obtuvo el Trofeo Ricardo Magdalena de 1972. Esta rampa estaba construida en el lugar del dep├│sito de locomotoras de vapor de la anterior estaci├│n Campo Sepulcro.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65183100, -0.89409800, '0101000020E61000008368AD68739CECBF6EC2BD326FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15231688809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15231688809.webp', 'https://www.flickr.com/photos/zaragozaantigua/15231688809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22592, 'De Campo Sepulcro, a Portillo 1970', 'En 1967, la Estaci├│n Campo Sepulcro pas├│ a ser la principal estaci├│n ferroviaria de la ciudad. En 1970, RENFE procedi├│ a su ampliaci├│n y reforma, modificando sustancialmente su aspecto, y cambiando su denominaci├│n por la de "Zaragoza-El Portillo", nombre menos "mortuorio" y de m├ís "atractivo tur├¡stico" (┬┐?) Inaugurada en 1973, estuvo activa hasta 2003. En la imagen, estado de las obras de la nueva estaci├│n sobre el espacio de la antigua, a├║n en pie. El antiguo dep├│sito de locomotoras, ya ha sido derribado. Fuente visual: RENFE', 1970, 1970, 1970, 'Anos 70', 'DELICIAS', 41.65174300, -0.89461300, '0101000020E610000043723271ABA0ECBFCF328B506CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16370010694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16370010694.webp', 'https://www.flickr.com/photos/zaragozaantigua/16370010694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22595, 'Estaci├│n Campo Sepulcro-Portillo 1970', 'Vista a├®rea del proceso de transici├│n entre la Estaci├│n de ferrocarril de Campo Sepulcro, y la de "Zaragoza-El Portillo". En marzo de 1970 se derrib├│ el antiguo Dep├│sito de locomotoras "vaporosas", en cuyo solar se levant├│ el plano inclinado de acceso al caj├│n de la nueva estaci├│n. La nueva estaci├│n, cuya traza original es obra de los ingenieros Demetrio Ullastres y Alfredo Mart├¡nez Alonso, fue Premio Ricardo Magdalena 1972. Las obras avanzaban r├ípidamente, y a finales de 1970 este era el estado de las mismas. Mientras, la antigua estaci├│n segu├¡a siendo utilizada (plano parcial de la misma, a la derecha). Tambi├®n estaba en obras el nuevo centro de clasificaci├│n postal "Zaragoza-Portillo", y en el entorno se levantaban nuevos bloques de viviendas. A├║n en pie, a la izquierda, la antigua Casa de Convalecientes, desde 1968 Colegio Polit├®cnico Nuestra Se├▒ora del Pilar. Al aire, sin cubrir, el pedazo de trinchera ferroviaria entre la calle Santander, y avenida de Valencia. Fuente visual: RENFE.', 1970, 1970, 1970, 'Anos 70', 'DELICIAS', 41.65183100, -0.89409800, '0101000020E61000008368AD68739CECBF6EC2BD326FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16810505748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16810505748.webp', 'https://www.flickr.com/photos/zaragozaantigua/16810505748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22610, 'Vicente Berdus├ín 1975', 'Imagen de la r├ípida transici├│n de un espacio industrial, a otro residencial. Al fondo, la Urbanizaci├│n "Parque Roma" avanza desde la nov├¡sima Plaza de Roma, conforme desaparecen las imponentes naves de la antigua f├íbrica de Escoriaza. Estas instalaciones fabriles de tipo pesado, entre 1920 y 1969 denominadas "Material M├│vil y Construcciones", forman parte absolutamente central en la historia de los ferrocarriles peninsulares. Al comienzo de los a├▒os 60 del pasado siglo, ocupaba 100.000 metros cuadrados, y daba trabajo a 1300 personas, aunque un proceso de fusi├│n empresarial posterior supuso abandonar y vender esta zona entre 1970-73, y trasladarse a un nueva ubicaci├│n en la Avenida de Catalu├▒a. La imagen ha sido capturada desde la calle Vicente Berdus├ín.', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65132600, -0.89829300, '0101000020E61000002A3927F6D0BEECBF6A847EA65ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19171127305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19171127305.webp', 'https://www.flickr.com/photos/zaragozaantigua/19171127305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23032, 'Avenida de Madrid 1992', 'La avenida de Madrid, en el punto donde confluye el denso tr├ífico proveniente de la calle de Marcelino Unceta, a la derecha y fuera de plano. Al fondo, vista parcial del paso elevado met├ílico en el entorno de la Aljafer├¡a. En 2003 se termin├│ la reforma de esta v├¡a de 2 km, ensanchando sus aceras y reservando la direcci├│n hacia el centro de la ciudad para los autobuses.', 1992, 1992, 1992, 'Anos 90', 'DELICIAS', 41.65397000, -0.90277700, '0101000020E61000007D9752978CE3ECBF5648F949B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207294182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207294182.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207294182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23166, 'Estaci├│n El Portillo 2006', 'Vista a├®rea del entorno de la estaci├│n El Portillo en 2006, tras su abandono en 2003. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.65209300, -0.89524800, '0101000020E6100000ACE63922DFA5ECBFAB798EC877D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32791228421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32791228421.webp', 'https://www.flickr.com/photos/zaragozaantigua/32791228421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23195, 'Agrupaci├│n Jubilados RENFE 2010', 'Foto: Rusolera, febrero de 2010. Sede de la Agrupaci├│n de Pensionistas y Jubilados de RENFE, en la avenida Jos├® Anselmo Clav├® de Zaragoza. El mismo a├▒o de la foto, este edificio neomud├®jar ser├í derribado. Fuente: zaragozaciudad.net/zaragozafluye/2010/080301-sede-de-la-a...', 2010, 2010, 2010, 'Siglo XXI', 'DELICIAS', 41.65289600, -0.89371300, '0101000020E6100000505260014C99ECBF38D89B1892D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21496097670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21496097670.webp', 'https://www.flickr.com/photos/zaragozaantigua/21496097670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23220, 'Derribo Averly 2016', 'Imagen capturada desde la altura del inmueble del n┬║ 17 de la calle del Trovador durante el derribo de la veterana y referencial fundici├│n Averly que, activa desde 1880 y hasta 2011, fue demolida en 2/3 de su original extensi├│n para dar paso, con el benepl├ícito de los poderes econ├│micos de la ciudad, a una necesaria promoci├│n privada de 120 viviendas de lujo de la constructora Brial cuya ejecuci├│n comenzar├í a principios de 2021, y cuyas llaves se entregar├ín en 2022-2023. Al fondo, entorno de la antigua estaci├│n de Zaragoza-El Portillo.', 2016, 2016, 2016, 'Siglo XXI', 'DELICIAS', 41.65447200, -0.89510600, '0101000020E61000000E828E56B5A4ECBFE8120EBDC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50678763063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50678763063.webp', 'https://www.flickr.com/photos/zaragozaantigua/50678763063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23234, 'Cuartel del Cid 2021', 'El cuartel de Caballer├¡a del Portillo, llamado luego del Cid, fue levantado en 1775 a instancias de Ram├│n Pignatelli, seg├║n proyecto de Pedro Pablo Cam├│n. Se alz├│ en el solar ocupado desde 1766 como ÔÇ£tinglado de artiller├¡aÔÇØ (polvor├¡n y armer├¡a), junto al convento de los Agustinos Descalzos (1602), derruido en los Sitios de 1808-1809 y cuyos terrenos sirvieron para ampliar el cuartel. Entre 1968 y 1976 fue derribado, conservando su tapia recayente al paseo de Mar├¡a Agust├¡n. En 2021 se realizaron prospecciones arqueol├│gicas con miras a construir viviendas en el solar, y aparecieron viviendas isl├ímicas, estructuras medievales y restos del cuartel. Una vez arrasado todo con la autorizaci├│n de la comisi├│n de Patrimonio del Gobierno de Arag├│n, en 2022 se comienza la construcci├│n all├¡ de una urbanizaci├│n de lujo, conservando parte del muro y la puerta trasera del recinto militar. En la foto, vista del yacimiento arqueol├│gico en agosto de 2021, con el Edificio Pignatelli y el de la Maternidad al fondo. A la derecha, fuera de plano, el paseo de Mar├¡a Agust├¡n.', 2021, 2021, 2021, 'Siglo XXI', 'DELICIAS', 41.65422300, -0.89269200, '0101000020E61000009ED32CD0EE90ECBF40A54A94BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51868764065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51868764065.webp', 'https://www.flickr.com/photos/zaragozaantigua/51868764065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23271, 'Campo del Sepulcro 1808', '"Batalla de las Heras, en la cual los franceses, intentando forzar el punto de Buena Vista y penetrar en Zaragoza fueron rechazados gloriosamente por los Aragoneses, y forzados a situarse fuera del tiro de ca├▒├│n de la Ciudad", Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. La batalla de las Eras (una zona agr├¡cola de la periferia de la ciudad), o del Campo del Sepulcro, tuvo lugar el 15 de junio de 1808, donde d├®cadas despu├®s se levantar├¡a la Estaci├│n de Ferrocarril del mismo nombre (Campo Sepulcro). De resultas del combate, los soldados franceses no tuvieron ├®xito en su ataque, y se retiraron. Al fondo, se eleva el castillo de La Aljafer├¡a. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65251400, -0.89476300, '0101000020E61000009677D503E6A1ECBF5017299485D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15266672542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15266672542.webp', 'https://www.flickr.com/photos/zaragozaantigua/15266672542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23316, 'Campo Sepulcro c.1912', 'La apertura de la l├¡nea Zaragoza-Madrid el 25 de mayo de 1863 supuso la inauguraci├│n de la estaci├│n de Campo Sepulcro, recinto provisional que acogi├│ los primeros viajeros de la l├¡nea Madrid-Zaragoza-Alicante (MZA). En 1896 se inaugur├│ la estaci├│n definitiva, proyectada con aires clasicistas por el ingeniero L├│pez de Letona, con su larga fachada de 144 metros de longitud de la que sobresale en planta y altura un gran pabell├│n central, que en la imagen centra la escena, acompa├▒ado de dos pabellones algo m├ís peque├▒os en los extremos hasta los que se dispone una marquesina corrida para proteger de la solanera canicular. La parte met├ílica de su estructura proven├¡a de los cercanos talleres Averly, salvo la armadura de vigas de la cubierta, que era bilba├¡na, y los ladrillos y tejas de los tejares locales. Un acabado final m├ís que digno, por encima de la media de otras estaciones peninsulares y aun europeas. En 1967, tras el cierre de las estaciones de Cari├▒ena, Utrillas y Caminreal pas├│ a ser la principal estaci├│n de la ciudad. En 1973, el ente gestor RENFE procedi├│ a su "ampliaci├│n y reforma", es decir, a su derribo integral, sustituy├®ndola por otra estaci├│n moderna y de nueva planta, y cambiando su denominaci├│n por la de Zaragoza-El Portillo (aunque estaba proyectado que se llamara "de Goya"), hasta que en 2003 fue a su vez sustituida por la actual estaci├│n de Zaragoza-Delicias. En la imagen, vista de la fachada principal de la estaci├│n MZA de Campo Sepulcro y su explanada de ingreso desde el paseo de las Estaciones por donde circulaba el tranv├¡a de la l├¡nea de Madrid, que la conectaba con la plaza de la Constituci├│n.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65216800, -0.89483300, '0101000020E6100000CE35CCD078A2ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781246727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781246727.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781246727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23319, 'Fundici├│n Averly c.1900', 'Mudados desde la calle San Miguel en 1880 a una nueva ubicaci├│n m├ís espaciosa en Campo Sepulcro, junto a la hom├│nima estaci├│n de ferrocarril, Averly inicia una etapa de crecimiento y producci├│n de ra├¡les para tranv├¡as, turbinas hidr├íulicas, engranajes, poleas, cojinetes, elementos de transmisi├│n, ruedas dentadas, material sanitario especializado, maquinaria e instalaciones de moliner├¡a, panader├¡a, extracci├│n de aceites y vinos, generadores y autoclaves de vapor, instalaciones para riegos y material para la agricultura, etc. En la ciudad, y en el terreno de la fundici├│n art├¡stica, reconocemos obras de Averly en la estatua del Justicia (Plaza de Arag├│n), el le├│n del Batallador (Cabezo de Buena Vista), la Fuente de la Samaritana (Plaza del Justicia), la Fuente de las Garzas (Plaza de Utrillas), ornamentos de La Seo y El Pilar, los chapiteles de sus torres, las columnas de los porches del Mercado Central, las estructuras met├ílicas en los palcos del Teatro Principal... En la imagen, salida de obreros de la fundici├│n, porque Averly tambi├®n fue cantera del movimiento obrero organizado en la ciudad. Fuente visual: Archivo Averly.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65443700, -0.89371200, '0101000020E6100000395E81E84999ECBF6C257497C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14787924160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14787924160.webp', 'https://www.flickr.com/photos/zaragozaantigua/14787924160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23320, 'Campo Sepulcro. Proyecto 1896', 'Alzado del proyecto de la estaci├│n ferroviaria "definitiva" de Zaragoza, denominada de Campo Sepulcro.', 1896, 1896, 1896, 'Siglo XIX', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856811727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856811727.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856811727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23321, 'Estaci├│n Campo Sepulcro 1960', 'Antigua estaci├│n de Madrid. 1960. La estrecha calle de la izquierda separa el conjunto de la estaci├│n de la f├íbrica Escoriaza.', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65366200, -0.89650000, '0101000020E6100000E3A59BC420B0ECBFA8514832ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14933958096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14933958096.webp', 'https://www.flickr.com/photos/zaragozaantigua/14933958096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23326, 'Campo Sepulcro c.1967', 'Imagen del edificio principal de la estaci├│n de ferrocarril de Campo Sepulcro o Madrid. Al fondo, a la derecha, los modernos y verticales bloques esquineros entre las calles del Tenor Gayarre, y Manuel Escoriaza y Fabro, e inmediatos a Viasa, y Alsoviasa.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15845267499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15845267499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15845267499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23328, 'Fundici├│n Averly c.1903', 'Dibujo de las instalaciones de la f├íbrica de fundiciones Averly de Zaragoza, en el paseo de Mar├¡a Agust├¡n n┬║ 59. Empresa fundada en 1880. Fuente visual: Gente de orden, Ibercaja, 1997.', 1903, 1903, 1903, 'Anos 1900', 'DELICIAS', 41.65443700, -0.89371200, '0101000020E6100000395E81E84999ECBF6C257497C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20185724960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20185724960.webp', 'https://www.flickr.com/photos/zaragozaantigua/20185724960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23330, 'Campo Sepulcro 1895', 'Fototipia Lucas Escol├í, 1895. Construcci├│n de la definitiva Estaci├│n de Campo Sepulcro, o de los Directos, de la l├¡nea MZA (durante casi 29 a├▒os hubo una provisional estaci├│n, unas decenas de metros m├ís al norte, donde los talleres). Ser├í inaugurada en 1896. La imagen est├í capturada desde el Camino de Herederos, junto a una torre agr├¡cola donde casi 20 a├▒os despu├®s ser├í construida la f├íbrica de chocolates ÔÇ£Casa Or├║sÔÇØ. Fuente visual: www.facebook.com/photo.php?fbid=879415128747780&set=g...', 1895, 1895, 1895, 'Siglo XIX', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20973707464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20973707464.webp', 'https://www.flickr.com/photos/zaragozaantigua/20973707464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23331, 'Campo Sepulcro 1849', '"Plano del Campo del Sepulcro en Zaragoza con el amojonamiento del terreno propio del ramo de guerra, seg├║n las escrituras de venta que obran en el archivo de la Direcci├│n Subinspecci├│n de Ingenieros", Joaqu├¡n Gironza, Zaragoza, 28 de junio de 1849. L├¡mites de la propiedad militar del Campo del Sepulcro de Zaragoza, entre el camino de la Casa Blanca (actual avenida Anselmo Clav├®) y el camino de Ronda (actual paseo de Mar├¡a Agust├¡n). Fuente: AMZ.', 1849, 1849, 1849, 'Siglo XIX', 'DELICIAS', 41.65283200, -0.89287600, '0101000020E6100000F6436CB07092ECBF21E4BCFF8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21036546012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21036546012.webp', 'https://www.flickr.com/photos/zaragozaantigua/21036546012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23332, 'Campo Sepulcro 1961', 'V├¡as de tr├ínsito y convoy estacionado junto a la estaci├│n de ferrocarril de Campo Sepulcro. Al fondo, a la derecha, Anselmo Clav├® y una parcial vista del antiguo edificio de la Casa de Convalecientes, que desde finales de los a├▒os cincuenta estaba ocupado por el Colegio Polit├®cnico Nuestra Se├▒ora del Pilar. Fuente visual: Trevor Rowe, Archivo EuskoTren/Museo Vasco del Ferrocarril.', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23633262179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23633262179.webp', 'https://www.flickr.com/photos/zaragozaantigua/23633262179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23334, 'Averly 1909', 'La fundici├│n de Antonio Averly llevaba desde 1880 instalada en la industrial zona de Campo Sepulcro, inmediata a la estaci├│n de ferrocarril de ese nombre. En 1903, la empresa pas├│ a denominarse "Hijos de A. Averly", y desde 1918, "Averly, S.A." De acuerdo con la teor├¡a microbiana del contagio, las medidas de profilaxis frente a la transmisi├│n de enfermedades infecciosas se convirtieron en los albores del siglo XX en uno de los pilares b├ísicos de la moderna actuaci├│n sanitaria. Y aplicar la desinfecci├│n requiri├│ nuevos equipos y materiales acordes, que en Averly pronto estuvieron prestos a fabricar y ofrecer al mercado. De esta forma, los grandes talleres de fundici├│n y construcci├│n general de m├íquinas Averly, incluyeron en su cat├ílogo, y dentro de la categor├¡a "material sanitario", una extensa relaci├│n de ofertas: estufas fijas y m├│viles de desinfecci├│n, pulverizadores, generadores de vapor-formol, esterilizadores, legiadoras, desinfectadoras, carros de transporte... Estos productos estaban destinados a hospitales, lazaretos, sanatorios, lavaderos, penitenciar├¡as, colegios... y Averly atend├¡a a cualquier solicitud de informaci├│n, o de presupuesto, desde el apartado postal n┬║ 36, y el tel├®fono n┬║ 49. En la imagen, un "generador de vapor formol" de tracci├│n animal construido de Averly, para desinfecci├│n de todo tipo de tejidos (mantas, colchones, ropa...) mediante la inyecci├│n de agua con formol a m├ís de 110 grados cent├¡grados, durante unos 15 minutos. Fuente visual: Revista "El Monitor Sanitario", Madrid.', 1909, 1909, 1909, 'Anos 1900', 'DELICIAS', 41.65435000, -0.89404300, '0101000020E6100000A1F7C610009CECBF9D11A5BDC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28020637115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28020637115.webp', 'https://www.flickr.com/photos/zaragozaantigua/28020637115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23336, 'Campo Sepulcro 1963', 'Imagen de una locomotora a vapor, posiblemente de la serie "1400", pasando frente al and├®n principal de la estaci├│n de ferrocarril de Campo Sepulcro, en direcci├│n sur, hacia Miraflores. Detr├ís de ella, el muro perimetral de las enormes instalaciones de la empresa Carde y Escoriaza y, a la izquierda, fuera de plano, la v├¡a de conexi├│n por donde sal├¡a el material rodante all├¡ fabricado. Fuente visual: es.slideshare.net/', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65167300, -0.89558800, '0101000020E6100000E014562AA8A8ECBFD65757056AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30684647422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30684647422.webp', 'https://www.flickr.com/photos/zaragozaantigua/30684647422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23337, 'Campo Sepulcro 1963', 'Imagen de una locomotora a vapor de la MZA, serie 741/780, construida en el Primer Reich alem├ín durante la primera d├®cada del siglo, tirando de un convoy en direcci├│n a Madrid, delante de las naves y muelles cubiertos localizados en la manzana con forma de quesito entre la calle del Trovador (derecha), y la avenida de Madrid (izquierda). Esta fachada luego ser├¡a completamente reedificada de nueva planta, con altos bloques de edificios. A la derecha de la imagen, fuera de plano, se encontraba la amplia zona de muelles de Campo Sepulcro. Fuente visual: image.slidesharecdn.com/', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65463100, -0.89663900, '0101000020E61000003C2EAA4544B1ECBF51F9D7F2CAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30737601581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30737601581.webp', 'https://www.flickr.com/photos/zaragozaantigua/30737601581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23338, 'Estaci├│n de Madrid 1965', 'Foto: Juli├ín Beguer├¡a Cervero. Acceso a la estaci├│n de Madrid o Campo Sepulcro, desde la avenida de Jos├® Anselmo Clav├® (a la espalda del fot├│grafo). El ni├▒o se llama Javier Treg├│n. A la estaci├│n le quedaban siete a├▒os. Fuente: Heraldo de Arag├│n.', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65234100, -0.89489400, '0101000020E6100000395FECBDF8A2ECBF836BEEE87FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31582125454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31582125454.webp', 'https://www.flickr.com/photos/zaragozaantigua/31582125454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23339, 'Campo Sepulcro c.1900', 'La fundici├│n Averly en su ubicaci├│n de Campo Sepulcro, cercana al ferrocarril de la l├¡nea MZA, en una imagen capturada frente a su entrada principal desde la "traves├¡a" de la carretera de Madrid a Francia, luego redenominada paseo de Mar├¡a Agust├¡n, donde adem├ís estaba ubicada la zona de vivienda fabril, con su correspondiente y ajardinado hotelito, en primer plano. Al fondo, y a la derecha, la zona productiva, con la fundici├│n, taller de maquinaria, y almac├®n de modelos-carpinter├¡a. Fuente visual: "Andal├ín, peri├│dico quincenal aragon├®s".', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65432600, -0.89364600, '0101000020E61000005D70067FBF98ECBF147651F4C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31877248433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31877248433.webp', 'https://www.flickr.com/photos/zaragozaantigua/31877248433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23341, 'Estaci├│n Campo Sepulcro 1908', 'Carroza del rey Alfonso XIII ante la estaci├│n de Campo Sepulcro, durante su visita en 1908. Fuente: Heraldo de Arag├│n.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65216500, -0.89502900, '0101000020E610000037177FDB13A4ECBF444C89247AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32430948433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32430948433.webp', 'https://www.flickr.com/photos/zaragozaantigua/32430948433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23342, 'Estatua del Justicia 1899', 'Estatua del Justicia Juan de Lanuza, para el monumento dise├▒ado por F├®lix Navarro, fundida en Averly. Est├í a la espera de que se coloque en 1904 en la glorieta de Pignatelli, que ser├í entonces redenominada plaza de Arag├│n. Fuente: Revista Nuevo Mundo, 1899.', 1899, 1899, 1899, 'Siglo XIX', 'DELICIAS', 41.65435000, -0.89404300, '0101000020E6100000A1F7C610009CECBF9D11A5BDC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32697415680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32697415680.webp', 'https://www.flickr.com/photos/zaragozaantigua/32697415680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23343, 'Campo Sepulcro 1908', 'Vista del Campo Sepulcro en 1908, con las tropas formadas durante la visita de Alfonso XIII. Al fondo el cuartel de los Trinitarios (antiguo convento) y la gran torre cuadrangular de la facultad de Medicina y Ciencias. A la izquierda, paseo de Mar├¡a Agust├¡n. Abajo, v├¡as del tranv├¡a a la estaci├│n de Cari├▒ena, en la actual avenida de Jos├® Anselmo Clav├®. Fuente visual: revista "Ilustraci├│n militar. Ej├®rcito y Marina".', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65280300, -0.89290000, '0101000020E610000018265305A392ECBF87DD770C8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33203571146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33203571146.webp', 'https://www.flickr.com/photos/zaragozaantigua/33203571146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23344, 'Campo Sepulcro c.1896', 'Imagen de la nueva estaci├│n de los Directos en Campo Sepulcro, o estaci├│n de Madrid, con detalle del inmediato espacio, a la derecha, donde estaba prevista la construcci├│n del dep├│sito de locomotoras a vapor. A la izquierda, tras el mar de v├¡as, algunas de las Torres del camino de Herederos, al norte del barrio de Cari├▒ena. Fuente visual: Gu├¡a de Zaragoza 1902.', 1896, 1896, 1896, 'Siglo XIX', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34458892294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34458892294.webp', 'https://www.flickr.com/photos/zaragozaantigua/34458892294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23346, 'Campo Sepulcro 1966', 'Imagen centrada en el paso por el mar de v├¡as de la estaci├│n Zaragoza-Campo Sepulcro de la moderna locomotora diesel, primera de la serie 352 de las "V├¡rgenes" y denominada "Virgen del Rosario", tirando de una rama del Talgo III en direcci├│n a la condal Barcelona. La vistosa combinaci├│n de los colores rojo y plata en esta composici├│n, dicen que constitu├¡a todo un espect├ículo para la vista. En 2002 esta locomotora fue dada de baja del servicio, y desguazada, y parece ser que la cabina perdura en el Museo del Ferrocarril de Arganda del Rey, porque los museos del ferrocarril, haberlos haylos. A la izquierda, naves del complejo fabril de Material M├│vil y Construcciones. En el centro, la veterana estaci├│n, con un convoy estacionado y tirado, posiblemente, por una locomotora vaporosa de la serie 401/414. A la derecha e inmediata, aunque fuera de plano, el dep├│sito de locomotoras de vapor. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65147300, -0.89538400, '0101000020E6100000C092AB58FCA6ECBF0F9D9E7763D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39801337703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39801337703.webp', 'https://www.flickr.com/photos/zaragozaantigua/39801337703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23348, 'Campo Sepulcro 1968', 'Ferroviaria estampa capturada en la estaci├│n de Zaragoza-Campo Sepulcro, cuyo edificio y and├®n principal queda a la izquierda. Centra la imagen un convoy de pasajeros tirado por una locomotora a vapor Mikado, y encaminado en direcci├│n a Logro├▒o. Hacia el fondo destacan las dos torrecillas de Industrias del Cartonaje S.A., antigua f├íbrica de chocolates Or├║s, y algunos de los modernos bloques levantados en el entorno de la moderna avenida de Goya. A la derecha, naves del complejo fabril de Material M├│vil y Construcciones. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65147300, -0.89538400, '0101000020E6100000C092AB58FCA6ECBF0F9D9E7763D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46962853502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46962853502.webp', 'https://www.flickr.com/photos/zaragozaantigua/46962853502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23349, 'Campo Sepulcro 1910', 'Imagen capturada en el campo de balompi├® habilitado en Campo Sepulcro y centrada en el "primer team" de la nueva sociedad "Zaragoza Foot-Ball Club", constituida a principios de a├▒o y que utlizaba el referido campo para jugar sus partidos. El nombre de "Foot-Ball Club" era habitual entre los equipos pioneros de este deporte en las diversas ciudades donde fueron surgiendo, como el que fue constituido con ese nombre en 1903, que es considerado el primer club local de esta disciplina deportiva en Zaragoza, si bien su vida activa finaliz├│ en 1904. En 1910 surgi├│ una nueva sociedad que incorpor├│ "Zaragoza" al nombre de aquella "Foot-Ball Club", si bien mantuvo su car├ícter "amateur" y, a la postre, ef├¡mero. En 1912 este equipo lleg├│ a inaugurar su propio terreno de juego en el perif├®rico camino de San Jos├®, cedido temporalmente por su propietario, el comerciante Francisco Agelet, si bien termin├│ sus d├¡as jugando en el "campo de los alemanes" de la calle de Bilbao.', 1910, 1910, 1910, 'Anos 10', 'DELICIAS', 41.65116600, -0.89268200, '0101000020E6100000BA4A77D7D990ECBF3222516859D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53461103455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53461103455.webp', 'https://www.flickr.com/photos/zaragozaantigua/53461103455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23350, 'Campo Sepulcro 1967', 'Imagen capturada ante el puente giratorio del dep├│sito de locomotoras sito en la estaci├│n de Zaragoza-Campo Sepulcro, y centrada en un agostino intercambio ferroviario de pareceres, con el fondo de dos vaporosas Renfe 141 o "Mikado" y una Renfe 2701.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65125400, -0.89416200, '0101000020E6100000336E6AA0F99CECBFD1B1834A5CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54226615682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54226615682.webp', 'https://www.flickr.com/photos/zaragozaantigua/54226615682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23694, 'Sanatorio San Jorge 1966', 'En 1920 el arquitecto Miguel ├üngel Navarro dise├▒├│ una vivienda para la familia Monterde en la calle Marcelino Domingo (Padre Manj├│n, tras el 18 de julio de 1936) del Barrio de la Explanada, muy cerca del enlace del ferrocarril de Cari├▒ena con la estaci├│n de Campo Sepulcro. El edificio estaba definido en un estilo neorregionalista que incorporaba elementos del repertorio modernista. M├ís tarde fue bastante modificado y ampliado, seg├║n los distintos usos que se le fueron dando. En la abrile├▒a imagen, el edificio funcionando como "Sanatorio S. Jorge. Obra Sindical 18 de Julio". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65341000, -0.90171500, '0101000020E610000026016A6AD9DAECBF8F705AF0A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217731081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217731081.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217731081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23644, '&quot;Feliz Navidad&quot; 1938', 'En fechas se├▒aladamente entra├▒ables, una oximor├│nica estampa navide├▒a con uno los soldados alemanes de la Luftwaffe encuadrados en la denominada "Legi├│n C├│ndor", durante su destino en el Aer├│dromo de Sanjurjo de la ciudad, cuando funcionaba como base a├®rea de utilizaci├│n conjunta, en este caso hispano-germano-italiana, desde 1937. "Feliz Navidad" ("Frohe Weihnachten"), y algo parecido al trazo de unos cristales de nieve, iluminan y llenan de sentimiento el posado junto a dos, entre otros proyectiles de menor calibre, impactantes artefactos explosivos de bombardeo empleados por la fuerza a├®rea nazi destacada en apoyo de la Espa├▒a nacionalista.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15811716717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15811716717.webp', 'https://www.flickr.com/photos/zaragozaantigua/15811716717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23709, 'Calle de Graus 1932', 'Imagen de la parcela del n┬║ 6 de la calle Graus, en el barrio de las Delicias, donde fueron detenidas cuatro personas por posesi├│n de metralla y componentes qu├¡micos (clorato de potasa, glicerina, azufre, ├ícido sulf├║rico...) susceptibles de ser utilizados para fabricar bombas y explosivos. Los detenidos fueron puestos a disposici├│n judicial. La parcela-polvor├¡n estaba ubicada muy cerca de la calle de Unceta, y casi frente al solar donde dos a├▒os m├ís tarde los escolapios construir├¡an la primera iglesia parroquial de San Valero, que tambi├®n contaba con un local para escuelas, que lleg├│ a albergar a 80 alumnos. Iglesia y escuela estuvieron activas hasta 1939, en que cerraron. Una nueva iglesia parroquial de San Valero se levantar├¡a en los a├▒os 40, y buena parte de su mobiliario proced├¡a de la derribada iglesia de San Andr├®s Ap├│stol. Fuente visual: Foto Mart├¡nez ("Mundo Gr├ífico", Madrid).', 1932, 1932, 1932, 'Anos 30', 'DELICIAS', 41.65257900, -0.90268000, '0101000020E6100000DF1AD82AC1E2ECBF38876BB587D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21440630243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21440630243.webp', 'https://www.flickr.com/photos/zaragozaantigua/21440630243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23717, 'Av. de Madrid 1976', 'Imagen capturada en la avenida de Madrid junto al cine Madrid (izquierda), inaugurado en 1955 con proyecto del arquitecto Eduardo Lagunilla. Este cine fue clausurado unos a├▒os m├ís tarde, en 1984, y el amplio local reconvertido en centro de fomento de la ludopat├¡a. A la derecha, irrepetible imagen de la antigua fachada de los n├║meros pares de la avenida desde el n├║mero 36 hasta la calle del Arzobispo A├▒oa de Busto, cuyo moderno n├║mero 1 (antiguo 44 de la avenida) est├í en pleno proceso de descontextualizada construcci├│n, al uso de la ├®poca. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.65413400, -0.90177800, '0101000020E6100000BE1248895DDBECBFD099B4A9BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27802236399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27802236399.webp', 'https://www.flickr.com/photos/zaragozaantigua/27802236399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21509, 'Cabezo de Buena Vista c.1926', 'Patrimonio Cultural Universidad de Zaragoza. Luis Gand├║ Mercadal. Ca. 1926. Paseo por Cabezo de Buena Vista una fresca ma├▒ana de invierno. En la imagen, M┬¬ Luisa Gand├║ Dorel, hija de Luis Gand├║ Mercadal. Detr├ís de ellas, la ciudad de Zaragoza vista desde este Cabezo. Fuente visual: patrimoniocultural.unizar.es/node/3153', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.63246000, -0.89215300, '0101000020E6100000BCE7C072848CECBF9B030473F4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15649014151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15649014151.webp', 'https://www.flickr.com/photos/zaragozaantigua/15649014151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23729, 'Av. de Madrid 1979', 'Imagen del incuestionable absolutismo del motor en la ├®poca, tramo de la avenida de Madrid justo al lado del despartidero (a la derecha) que mojoneaba el arranque de la avenida de Navarra, y que se manten├¡a como barbecho urban├¡stico usufructuado mientras tanto por comerciales diversos, incluyendo propaganda electoral del Partido del Trabajo de Arag├│n, ilustrada con la imagen de su candidato cabecero a las Elecciones Generales de 1979, el secretario general de la Confederaci├│n de Sindicatos Unitarios de Trabajadores, CSUT , Jer├│nimo Lorente Hern├índez. A la izquierda, imagen del antiguo n┬║ 117 de la avenida, luego sustituido por un moderno bloque hasta cuatro veces m├ís alto. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65439600, -0.90136100, '0101000020E6100000B3791C06F3D7ECBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33191005256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33191005256.webp', 'https://www.flickr.com/photos/zaragozaantigua/33191005256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23731, 'Delicias c.1925', 'Imagen capturada desde la altura de la f├íbrica de Carde y Escoriaza inmediata a la estaci├│n ferroviaria de Campo Sepulcro, orientada hacia el oeste, con una interesante panor├ímica de la barriada de las Delicias. En primer t├®rmino, y tras el ramal del Boquerazo de la acequia de la Romareda, antiguos campos de Tarongi y de la Torre de Domingo. En el centro de la imagen, el referencial remate que culminaba la casa de la familia Monterde en la calle de Marcelino Domingo. Al fondo a la izquierda, la casa de la familia Palomar destaca desde su dominante emplazamiento natural. Fuente visual: Archivo CAF (AHPZ-DARA)', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65305400, -0.90008200, '0101000020E610000016FC36C478CDECBFD042024697D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37768583714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37768583714.webp', 'https://www.flickr.com/photos/zaragozaantigua/37768583714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23733, 'Calle del Padre Manj├│n 1980', 'En 1920 el arquitecto Miguel ├üngel Navarro dise├▒├│ una destacada vivienda para la familia Monterde en la calle Marcelino Domingo (redenominada del Padre Andr├®s Manj├│n, tras el 18 de julio de 1936) del barrio de la Explanada, muy cerca del enlace del ferrocarril de Cari├▒ena con la estaci├│n de Campo Sepulcro. Este edificio estaba definido en un estilo neorregionalista que incorporaba elementos del repertorio modernista. M├ís tarde fue bastante modificado y ampliado, seg├║n los distintos usos que se le fueron dando con el paso del tiempo. En la imagen, el inmueble funcionando como "Cl├¡nica San Jorge de la SS (Seguridad Social)" del Instituto Nacional de la Salud (INSALUD), heredero del previo Instituto Nacional de Previsi├│n. Fuente visual: AMZ', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65341000, -0.90171500, '0101000020E610000026016A6AD9DAECBF8F705AF0A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41283023180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41283023180.webp', 'https://www.flickr.com/photos/zaragozaantigua/41283023180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23922, 'Cuartel de El Cid 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1968. Imagen del interior de los patios del antiguo Cuartel de Caballer├¡a de El Cid, tras el derribo de sus instalaciones. Al fondo, a la izquierda, la Iglesia de El Portillo, y las traseras de algunas viviendas de la plaza. A la derecha, sobresale levemente la torre-c├║pula de la sucursal de una entidad bancaria local. Una buena parte de los solares resultantes siguen a la espera de un destino urbanizado.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65435600, -0.89290700, '0101000020E6100000B7D26BB3B192ECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15030027708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15030027708.webp', 'https://www.flickr.com/photos/zaragozaantigua/15030027708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23932, 'Cuartel del Cid 1968', 'Imagen capturada desde el interior de una de las estancias que se abr├¡an al patio del antiguo Cuartel de Caballer├¡a de El Cid, cuando estaba siendo derribado tras haber sido despojado de sus funciones castrenses, tal y como era tradici├│n desde que fuera construido all├í en los remotos tiempos de la Ilustraci├│n. Al fondo, sobresale levemente la torre-c├║pula de la sucursal de una entidad bancaria local, esquinada entre la plaza del Portillo y General Franco. 47 a├▒os despu├®s, de momento, buena parte del gran solar resultante sigue esperando alguna finalidad. Tampoco hay ning├║n panel informativo arqueol├│gico que avise de lo que esto fuera, o fuese, por si a alguien, de forma accidental, o harto improbable, llegara a interesarle. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65458000, -0.89325100, '0101000020E610000046D1031F8395ECBFCF4E0647C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23820032459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23820032459.webp', 'https://www.flickr.com/photos/zaragozaantigua/23820032459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23936, 'P.┬║ de Mar├¡a Agust├¡n 1965', '"Vista de Zaragoza desde el estudio", ├│leo sobre lienzo, Luis Esteban Ram├│n, ca. 1965, Interesante visual desde el tramo del paseo de Mar├¡a Agust├¡n comprendido entre la calle del General Franco y la de Jos├® Anselmo Clav├®. Abajo, instalaciones del cuartel del Cid. Al fondo, alturas de la ciudad, entre el torre├│n de la plaza del Portillo 2 y la c├║pula de San Ildefonso, tras la plaza de Toros. Fuente visual: zaragozacool.wordpress.com', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65460200, -0.89321800, '0101000020E6100000575A46EA3D95ECBFB6F292FFC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26245745327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26245745327.webp', 'https://www.flickr.com/photos/zaragozaantigua/26245745327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24195, 'Estaci├│n Campo Sepulcro 1933', 'Estaci├│n de ferrocarril Campo Sepulcro, de la compa├▒├¡a MZA. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23217883536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23217883536.webp', 'https://www.flickr.com/photos/zaragozaantigua/23217883536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24201, 'Campo Sepulcro c.1920', 'Imagen de la nueva v├¡a de conexi├│n entre las instalaciones fabriles de los talleres de Carde y Escoriaza (al fondo), y la estaci├│n Campo Sepulcro del ferrocarril MZA. Las puertas han sido abiertas, y una locomotora a vapor (posiblemente una 100 con caldera renovada) enfila la curva de acceso ferroviario tirando de material rodante reci├®n terminado. La maniobra, bajo un sol cenital, es seguida atentamente por operarios, tancredos, y p├║blico en general. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (CAF), AHPZ.', 1920, 1920, 1920, 'Anos 20', 'DELICIAS', 41.65272800, -0.89660900, '0101000020E61000009293895B05B1ECBF7D9752978CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31690153993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31690153993.webp', 'https://www.flickr.com/photos/zaragozaantigua/31690153993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24463, 'Campo Sepulcro 1924', 'Almacenes de Carbones Pina, de Juan P├®rez Herrero, en las instalaciones de la Estaci├│n Ferroviaria de Campo Sepulcro de Zaragoza, con su propio apartadero, en 1924. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20038867901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20038867901.webp', 'https://www.flickr.com/photos/zaragozaantigua/20038867901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24474, 'Talleres Carde y Escoriaza c.1945', 'Pintura del complejo de la f├íbrica de Carde y Escoriaza en su ubicaci├│n junto a la estaci├│n de Campo Sepulcro. Permaneci├│ all├¡ desde los a├▒os 20 hasta los 70, fabricando material pesado, como ferrocarriles y tranv├¡as. Fuente: "150 a├▒os de ferrocarril en Zaragoza", 2011.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20587697371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20587697371.webp', 'https://www.flickr.com/photos/zaragozaantigua/20587697371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24871, 'Estaci├│n de Campo Sepulcro c.1945', 'Imagen capturada en el punto de situado o lugar autorizado de parada de coches de punto a tracci├│n animal en la estaci├│n de Campo Sepulcro o de Madrid, ubicado justo frente al edificio principal de la estaci├│n al que se acced├¡a por la derecha desde la calle de Anselmo Clav├®. En ese momento perduraban unos 25 coches de punto en activo, al precio de 5 pesetas la hora para tres personas o 6 pesetas la hora para cuatro. El ├║ltimo de estos veh├¡culos fue retirado del servicio en 1957.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65259300, -0.89482700, '0101000020E6100000467D923B6CA2ECBF9D4CDC2A88D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54982028592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54982028592.webp', 'https://www.flickr.com/photos/zaragozaantigua/54982028592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25062, 'Dos generales y un Alcalde 1927', 'Ayuntamiento de Zaragoza/Foto A. de la Barrera. "General Primo de Rivera". El Alcalde de la ciudad, Miguel Allu├® Salvador (sentado a la izquierda), recoge en la Estaci├│n Campo Sepulcro, en carruaje oficial, al General y Dictador Miguel Primo de Rivera y Orbaneja, y al general Jos├® Sanjurjo Sacanell. Todos sonr├¡en mucho. Datada y comentada por el proyecto GAZA ("Gran Archivo Zaragoza Antigua"), es un compendio de im├ígenes de la antigua Zaragoza (Espa├▒a), acompa├▒adas de textos creados por Jos├® Mar├¡a Ballest├¡n Miguel y la colaboraci├│n de Antonio Tausiet. adioszaragoza.blogspot.com', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.65216800, -0.89483300, '0101000020E6100000CE35CCD078A2ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938013762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938013762.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938013762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25162, 'Do├▒a Blanca de Navarra c.1948', 'Dibujo con la representaci├│n de las nuevas instalaciones de la f├íbrica de camas met├ílicas y somieres Alfonso Solans Viamonte, en la calle de Navarra, barriada del Cigarral, en las Delicias. Hasta esta ubicaci├│n se vino el negocio desde su emplazamiento original, fundado all├í por 1927 en el arranque del camino de las Fuentes, inmediato a la calle Miguel Servet, cuando Alfonso Solans Viamonte se independiz├│ del negocio camero de su padre Froil├ín Solans Ler├¡n, e inici├│ el suyo propio. En este momento, su hijo Alfonso Solans Serrano estaba haciendo lo propio, e iniciaba su carrera empresarial en un local de la calle Santiago Lapuente. En el dibujo, la representaci├│n de la calle de Navarra, en primer plano, es ciertamente fantasiosa, pues m├ís parece una avenida que el peque├▒o vial con entrada por la avenida de Madrid, y final brusco ante la f├íbrica de Material M├│vil y Construcciones y el camino de la Mosquetera. Al poco tiempo, la empresa fue redenominada ALSOVISA (Alfonso Solans Viamonte, S.A.), y esta calle mud├│ su nombre por el de Do├▒a Blanca de Navarra para evitar confusiones con la nueva y prometedora avenida de Navarra. A la derecha, la calle del Tenor Gayarre, que la separar├í de la planta de VIASA. A la izquierda, y tras el cierre de la f├íbrica y posterior reurbanizaci├│n de la zona a mediados de los a├▒os 70, se abrir├í la prolongaci├│n de la calle Pablo Sarasate. Al fondo, el paso a nivel de las Delicias y v├¡as conducentes al entorno ferroviario de la estaci├│n de Campo Sepulcro. Fuente visual: www.todocoleccion.net/', 1948, 1948, 1948, 'Anos 40', 'DELICIAS', 41.65345300, -0.89919300, '0101000020E61000001D59F96530C6ECBF8E3C1059A4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32107434036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32107434036.webp', 'https://www.flickr.com/photos/zaragozaantigua/32107434036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26029, 'Vista El Portillo ca. 1975', 'Foto: Colecci├│n Carlos Carretero. Vista a├®rea centrada en la estaci├│n de El Portillo. Fuente: www.facebook.com/photo.php?fbid=10211203909242019&set...', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65199500, -0.89483600, '0101000020E61000001212691B7FA2ECBFE813799274D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30450603376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30450603376.webp', 'https://www.flickr.com/photos/zaragozaantigua/30450603376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26036, 'El Portillo 1974', 'Imagen del acceso desde la calle de Jos├® Anselmo Clav├® a la reciente estaci├│n de ferrocarril Zaragoza-El Portillo, donde RENFE concentr├│ todos los servicios que hasta ese momento prestaban las estaciones de Campo Sepulcro, Delicias, y Arrabal. Tras la moderna construcci├│n, atisbos del mar de v├¡as de la estaci├│n, y algunos edificios del entorno de la calle Escoriaza y Fabro, todav├¡a con las naves de la antigua f├íbrica de Material M├│vil (derecha). A su lado, la descomunal urbanizaci├│n Parque Roma progresa adecuadamente. La clara ma├▒ana permite una visual, incluso, del nuevo Hospital Cl├¡nico Universitario, all├í en la calle San Juan Bosco. Fuente visual: www.ebay.es/', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65167300, -0.89466500, '0101000020E6100000E2067C7E18A1ECBFD65757056AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31197955402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31197955402.webp', 'https://www.flickr.com/photos/zaragozaantigua/31197955402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20876, 'El Portillo 1119', 'Seg├║n D. Josef F├®lix de Amada (1796), estaba Sarago├ºa reci├®n conquistada por Alfonso I y Gast├│n de B├®arn, cuando los moros, que son muy traidores, en gran turba y silencio, y aprovechando la oscuridad de la noche y un notable descuido de los cristianos (los guardas y centinelas estaban en brazos de morfeo), se colaron haciendo una brecha en la muralla de tapial frente a la Aljafer├¡a. Pero la virgen sant├¡sima, que velaba por todos los suyos, incluso los descuidados, capitane├│ de repente un volante ej├®rcito de esp├¡ritus celestiales en forma visible, y les repeli├│ con el pavor de las soberanas luces que destellaban, y el sangriento estrago que les caus├│. Tama├▒a ruidera despert├│ finalmente a los guardas, que dieron avisos que s├│lo sirvieron para testificar el milagro producido: el contorno del Portillo estaba lleno de infinitos moros muertos, adem├ís de una peque├▒a imagen de la reina de los ├íngeles que ella misma dej├│ en la brecha de la muralla por donde se colaron los infieles, como prenda de su protecci├│n y amparo. Los at├│nitos lugare├▒os celebraron la victoria, y acordaron levantar un magn├¡fico templo para resguardar la material imagen, con el t├¡tulo de Nuestra Se├▒ora del Portillo. Acordaron adem├ís no reparar la muralla, que con la virgen bastaba. Los moros padecieron tan espantosa matanza, que ya no volvieron a intentarlo. En la xilograf├¡a an├│nima del siglo XVIII, representaci├│n simplificada del milagro: a los pies del muro, unos moros se caen al suelo, derribados por la sobrenatural armada, cuya capitana destellea como sol, y eclipsa la brecha abierta. Fuente visual: Wifredo Rinc├│n Garc├¡a, "La Zaragoza de los Sitios", Colecci├│n Editorial Fundaci├│n Sitios n┬║ 4, 2008.', 1119, 1119, 1119, 'Siglo XIX', 'DELICIAS', 41.65595200, -0.89345400, '0101000020E61000004E5FCFD72C97ECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18987161143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18987161143.webp', 'https://www.flickr.com/photos/zaragozaantigua/18987161143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20909, 'La Aljafer├¡a 1757', 'Miguel Mar├¡n. 1757. "Plano en peque├▒o del Castillo de la Aljafer├¡a de Zaragoza con sus contornos para indicar donde se halla colocado, como assi mismo las tierras dependientes de el y el agua que reciven de las dos Azequias de los Rios Jalon y la Huerba"". El dibujo est├í orientado mirando desde el este, con unas muy interesantes referencias la ubicaci├│n de la puerta del Portillo, la iglesia y convento de San Agust├¡n, la iglesia del Portillo, la huerta del convento de Santa In├®s, adem├ís del cauce de las acequias, campos de cultivo, y molino harinero, y la delimitaci├│n casi catastral de las tierras vinculadas al cuartel de la Aljafer├¡a. Fuente: Servicio Geogr├ífico del Ej├®rcito, Servicio Hist├│rico Militar (Cartoteca, sign. 009/145), Madrid.', 1757, 1757, 1757, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15319052637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15319052637.webp', 'https://www.flickr.com/photos/zaragozaantigua/15319052637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20911, 'La Aljafer├¡a 1772', 'L. Jaime. 1846. "Vista geom├®trica de la fachada pr.al del Castillo de la Aljafer├¡a en Zaragoza". La fachada principal se corresponde con el pa├▒o, o lado, este. La imagen, hoy, estar├¡a dibujada desde la calle de los Diputados. Fuente: "La Aljafer├¡a", Cortes de Arag├│n, 1998.', 1772, 1772, 1772, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15504951702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15504951702.webp', 'https://www.flickr.com/photos/zaragozaantigua/15504951702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22336, 'Jard├¡n de Invierno 1961', 'Cuadro de jota en el Jard├¡n de Invierno del Cabezo de Buenavista de Zaragoza. Postal, 1961.', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63172600, -0.89277800, '0101000020E610000041D3122BA391ECBF3604C765DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19553853706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19553853706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19553853706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20932, 'Aljafer├¡a 1500', 'Dibujo realizado hacia 1875 que ilustra el posible aspecto, desde el noreste, del palacio de la Aljafer├¡a en la ├®poca de los Reyes Cat├│licos, con su original recinto amurallado, la torre del Homenaje culminada en mirador y la iglesia de la parroquia de San Mart├¡n. Fuente visual: www.cortesaragon.es/', 1500, 1500, 1500, 'Siglo XIX', 'DELICIAS', 41.65656600, -0.89697300, '0101000020E6100000E8A38CB800B4ECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25174985037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25174985037.webp', 'https://www.flickr.com/photos/zaragozaantigua/25174985037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20958, 'Puerta del Portillo c.1800', '"Puerta del Portillo", Antonio Callaved, 2012. De origen medieval, fue destruida en los sitios y vuelta a construir, hasta ser derribada en 1868. A la derecha, iglesia del Portillo. Se ubicaba en la actual calle de Conde de Aranda. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1800, 1800, 1800, 'Siglo XIX', 'DELICIAS', 41.65597400, -0.89272400, '0101000020E610000075560BEC3191ECBF5E83BEF4F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15280181625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15280181625.webp', 'https://www.flickr.com/photos/zaragozaantigua/15280181625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21000, 'N.┬¬ S.┬¬ del Portillo 1827', 'Fotograf├¡a realizada sobre 1880 por Anselmo Mar├¡a Coyne del dibujo que representaba el proyecto de rehabilitaci├│n de la tardobarroca iglesia parroquial de Nuestra Se├▒ora del Portillo, realizado en 1827 por el arquitecto Jos├® de Yarza y Mi├▒ana al objeto de reconstruirla tras los da├▒os sufridos durante los asedios franceses de 1808-1809. En este caso, se trata del dibujo de la fachada principal de la iglesia, con el gran p├│rtico en arco de medio punto por el que se ingresa a su interior desde la plaza del Portillo. Esta obra se mantuvo inconclusa hasta la d├®cada de los a├▒os ochenta del pasado siglo XX, cuando el arquitecto Jos├® Manuel P├®rez Latorre reinterpret├│ el proyecto dej├índolo tal y como ahora es visible. Jos├® de Yarza y Mi├▒ana particip├│ tambi├®n en los proyectos de reconstrucci├│n (algunos realizados, otros no) de un buen n├║mero de iglesias, conventos y monasterios afectados por los referidos asedios, como la iglesia y convento de Santa M├│nica, el Real Monasterio de Santa Engracia, el convento de los Capuchinos, el convento de los Trinitarios Descalzos, y la iglesia parroquial de N.┬¬ S.┬¬ de Altab├ís. Fuente visual: Archivo Coyne, en AHPZ', 1827, 1827, 1827, 'Siglo XIX', 'DELICIAS', 41.65586500, -0.89282000, '0101000020E6100000FCDEA63FFB91ECBFA7CB6262F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45008437781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45008437781.webp', 'https://www.flickr.com/photos/zaragozaantigua/45008437781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21048, 'Cuartel Aljafer├¡a 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1874-1877. "Vista del Cuartel de la Aljafer├¡a con soldados." El Regimiento de Galicia, alojado en este "Cuartel", posa en disposici├│n de revista.', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65614400, -0.89646900, '0101000020E610000022179CC1DFAFECBFBABBCE86FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679640338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679640338.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679640338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21064, 'La Aljafer├¡a 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1874-1877. "Vista del Cuartel de la Aljafer├¡a." El Regimiento de Galicia, alojado en este "Cuartel", a├║n no ha salido para posar en posici├│n de revista, delante del antiguo Palacio de la Alegr├¡a. El fot├│grafo aprovecha para realizar una captura de prueba.', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15503036261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15503036261.webp', 'https://www.flickr.com/photos/zaragozaantigua/15503036261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21104, 'Plaza del Portillo 1889', '"Saragosse. Vue g├®nerale". J. L├®vy et Cie. Una d├®cada despu├®s de que J. Laurent et Cie. nos impactara con su fenomenal vista panor├ímica de la ciudad desde las alturas de la iglesia del Portillo, J. Levy et Cie. se suben tambi├®n al mismo punto para realizar una ├║nica captura, no menos interesante. A los pies sigue la circular plaza del Portillo, a la que desembocan las paralelas calles del Portillo y Agustina de Arag├│n. A la izquierda, inmediatos, algunos cambios: el muro de la huertas y convento de Santa In├®s, ya est├ín retranqueados como signo de que el ensanchamiento de la estrecha calle del Portillo va en serio. Su estrechez no hab├¡a sido problema durante siglos: por ejemplo, cuando un monarca entraba por la puerta del Portillo, giraba por Santa In├®s, giraba de nuevo hacia San Pablo, y llegaba directo a la plaza del Mercado. Ahora se argumentaba que era necesario dar amplitud a la calle como acceso directo al Coso, lo que requer├¡a ampliarla, sanearla, y de paso, dar alg├║n pelotazo urban├¡stico. Dicho y hecho, aunque costar├¡a un tiempo. Este ensanchamiento se llevar├¡a una parte de la antigua "Casa de la Galera", el complejo que hace esquina con Santa In├®s, que luego desempe├▒├│ funciones de c├írcel, y que desde 1883 hab├¡a sido reconvertido en escuela de ni├▒os... Los mismos recortes afectaron a muchos edificios de esta calle, hasta el Coso. Esta es la g├®nesis de la posteriormente denominada calle Conde de Aranda. Al fondo, sobre los tejados, la l├¡nea de torres de la ciudad, cambiante seg├║n el ritmo de los derribos. De izquierda a derecha: el Pilar, San Pablo, Santa Isabel, San Salvador y su cimborrio, la Torre Nueva (pre-muerta), San Felipe y Santiago el Menor, las Escuelas P├¡as, San Juan y San Pedro, La Magdalena, el palacio de Morata, San Gil, San Carlos, San Miguel, y San Ildefonso. Cerca de ├®sta, apenas cuatro a├▒os antes a├║n se levantaba la torre del antiguo convento de los M├¡nimos de la Victoria. Fuente visual: Zaragoza en la mirada ajena. Cortes de Arag├│n, 2012', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115472282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115472282.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115472282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21112, 'Aljafer├¡a 1889', '"Saragosse. Caserne de l''Aljaferia". Antiguo palacio, cuando era dependencia cuartelaria del Ministerio de la Guerra. Imagen capturada desde la carretera a Madrid. Sobresalen, al fondo, la torre del homenaje, y los restos desmochados de la torrecilla de la iglesia de San Mart├¡n. Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750553871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750553871.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750553871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21126, 'La Aljafer├¡a 1889', '"Puerta trasera del oratorio isl├ímico de la Aljafer├¡a". Esta puerta se encuentra hoy cegada, frente a la entrada principal del palacio, en el patio de San Mart├¡n. Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65671000, -0.89669400, '0101000020E61000001F9F909DB7B1ECBF637AC2120FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40289731665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40289731665.webp', 'https://www.flickr.com/photos/zaragozaantigua/40289731665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21221, 'Aljafer├¡a 1900', 'En domingo, y desde la Ribera Baja, una excursi├│n a Zaragoza a merendar y tirar unas fotos, que el tiempo acompa├▒a. La merienda, ya ha tendido lugar en los tranquilos y arbolados alrededores del cuartel de la Aljafer├¡a, por la parte de detr├ís, no lejos del amistoso polvor├¡n donde unos a├▒os despu├®s se habilitar├í el "hom├│dromo", o minicampo de maniobras para los efectivos cuartelarios. El posado, perfectamente ordenado de menor a mayor importancia (chavaler├¡a, mujeres, hombre, cura) junto a la v├¡a del ferrocarril de Madrid a Barcelona, no lejos del Camino de Herederos y del Convento de los Carmelitas Descalzos de San Jos├®, apenas a unas decenas de metros. Al fondo, panorama urbano del momento. A la izquierda, la rotunda silueta del castillo-cuartel. Por encima sobresale la torre de Santiago del Pilar, junto a la mole de la Torre del Trovador. A la derecha, c├║pula y torrecillas de la Real Casa de la Misericordia. El humo, de la activa Fundici├│n Averly. Fuente visual: quintodeebro.com/ Familia Florencio Jardiel Dobato', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65670500, -0.89965500, '0101000020E610000027DA5548F9C9ECBF520FD1E80ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915606913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915606913.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915606913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21263, 'El Portillo 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 7, Zaragoza 1908 - Centenario de los Sitios", 1907. "Esta puerta es la que Agustina de Arag├│n defendi├│ heroicamente, en el ataque del 2 de julio, salvando a la ciudad en uno de los momentos de mayor peligro." Vista del emplazamiento de la antigua puerta del Portillo, en la esquina de la iglesia del Portillo con la calle del Conde de Aranda y el paseo de Mar├¡a Agust├¡n actuales. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'DELICIAS', 41.65622400, -0.89352900, '0101000020E6100000F8E12021CA97ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767895975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767895975.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767895975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21664, 'Plaza del Portillo 1930', '"Iglesia de Nuestra Se├▒ora del Portillo".', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65575900, -0.89275700, '0101000020E610000064CDC8207791ECBF628731E9EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14681281839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14681281839.webp', 'https://www.flickr.com/photos/zaragozaantigua/14681281839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21692, 'Plaza del Portillo 1930', '"Plaza del Portillo y monumento a Agustina de Arag├│n". Imagen tomada con la iglesia del Portillo como tel├│n de fondo del monumento. M├ís al fondo, a la derecha, la calle del Conde Aranda, con vista de los muros tras los que estaban los enormes huertos del convento de Santa In├®s.', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060071759.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060071759.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060071759/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21810, 'Plaza del Portillo 1930', 'Imagen capturada, de buena ma├▒ana, en los jardines de la plaza del Portillo. Al fondo, la iglesia decimon├│nica y hom├│nima, y la despejada vista de ese tramo de la antigua calle del Portillo, entonces recayente a los muros de la enorme huerta conventual de Santa In├®s. Como valor a├▒adido, y en primer├¡simo plano, la sombra del fot├│grafo portugu├®s Ant├│nio Passaporte en el ejercicio de su profesi├│n.', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29783242092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29783242092.webp', 'https://www.flickr.com/photos/zaragozaantigua/29783242092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21883, 'La Aljafer├¡a 1931', 'Imagen capturada junto al soterrano cauce de la acequia de la Romareda Baja, o del Boquerazo, en el tramo paralelo a la carretera de Madrid a Francia. Tras los ├írboles y al fondo, explanada de acceso al cuartel de la Aljafer├¡a, cuando era sede de los regimientos de infanter├¡a "Infante" y "Gerona" del Ej├®rcito. Este antiguo palacio presentaba la traza conferida en la reforma que entre 1860-80 lo consolid├│ como dependencia cuartelera, como era tradici├│n desde los albores del siglo XVIII, cuando la Guerra de Sucesi├│n. Sobre el pa├▒o de la fachada principal destacan las marquesinas de los dos accesos. Sobre el tejado emerge la cuadrangular Torre del Trovador, cubierta, y la torrecilla de la iglesia de San Mart├¡n.', 1931, 1931, 1931, 'Anos 30', 'DELICIAS', 41.65598400, -0.89540700, '0101000020E6100000CB80B3942CA7ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49116449481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49116449481.webp', 'https://www.flickr.com/photos/zaragozaantigua/49116449481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21991, 'La Aljafer├¡a 1944', 'Imagen capturada durante una inspecci├│n, o revista, del regimiento de artiller├¡a antia├®rea n┬║ 73, llevada a cabo en la explanada de acceso al cuartel de la Aljafer├¡a, cuya luminosa fachada principal aparece al fondo. El ca├▒├│n objeto de admiraci├│n era uno de los impresionantes 8,8-cm-Flak, posiblemente el modelo 36, que los aliados alemanes hab├¡an introducido en la pen├¡nsula durante la guerra de 1936-39 como ayuda del Reich de los 1000 a├▒os a la Espa├▒a nacionalista. El 4 de junio de 1931, el Palacio de la Aljafer├¡a hab├¡a sido declarado Monumento Nacional de Inter├®s Hist├│rico-Art├¡stico. Fuente visual: www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'DELICIAS', 41.65654200, -0.89635300, '0101000020E6100000D47C957CECAEECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30897108105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30897108105.webp', 'https://www.flickr.com/photos/zaragozaantigua/30897108105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22127, 'P.┬║ de Mar├¡a Agust├¡n 1951', 'Imagen del paseo de Mar├¡a Agust├¡n en su tramo en destacado descenso desde el Portillo, y hasta la Puerta Sancho, abajo. Hacia la izquierda, se abren las calles Teniente Coronel Pueyo, primero, y Aljafer├¡a, despu├®s. Al fondo, donde la pronunciada curva a la derecha, la calle de Santa Luc├¡a lleva a un paso a nivel ferroviario que permite al acceso a la Almozara y la Qu├¡mica. En la despejada calzada, v├¡as del tranv├¡a de la l├¡nea 7 "Ayuntamiento-Puerta Sancho". Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'DELICIAS', 41.65651900, -0.89368000, '0101000020E610000062DBA2CC0699ECBFF01989D008D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159027235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159027235.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159027235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22352, 'La Aljafer├¡a 1966', 'Cuartel del Pr├¡ncipe en el palacio de la Aljafer├¡a. Fuente: "Espa├▒a, qu├® hermosa eres", 1966.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20562363812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20562363812.webp', 'https://www.flickr.com/photos/zaragozaantigua/20562363812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22367, 'Paso a nivel de Delicias 1967', 'Imagen del paso a nivel de Delicias con el paseo de Mar├¡a Agust├¡n al fondo, el 24 de junio de 1967. Confluencia de diversos medios de transporte en la actual plaza de la Ciudadan├¡a. Fuente: Asociaci├│n Paso a Nivel.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21395637735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21395637735.webp', 'https://www.flickr.com/photos/zaragozaantigua/21395637735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22383, 'Calle Boggiero 1962', 'Fielato del Portillo, en la esquina de la calle de Basilio Boggiero (derecha) con el paseo de Mar├¡a Agust├¡n. En la puerta, parte del equipo de la Polic├¡a Sanitaria de Abastos, que controlaba el estado de los productos alimentarios y proced├¡a al cobro de sus tasas. Fuente visual: Bolet├¡n Municipal de Zaragoza.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65694400, -0.89343400, '0101000020E6100000874D64E60297ECBFD7A6B1BD16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22390669160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22390669160.webp', 'https://www.flickr.com/photos/zaragozaantigua/22390669160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22438, 'Paso a nivel Delicias c.1968', 'Continuaci├│n de la imagen anterior, en el entorno del antiguo paso a nivel ferroviario de Delicias. En primer plano, proveniente de la estaci├│n de Campo Sepulcro, traquetea una poderosa locomotora a vapor del tipo 1-5-1, "Santa Fe", pasando junto a la Torre de agujas ferroviarias ubicada en la esquina noreste del paso a nivel. Detr├ís, la estructura del met├ílico puente de se├▒ales ferroviarias, algunos edificios de la avenida de Madrid, y al fondo, el mar de v├¡as de Campo Sepulcro y los grandes bloques de viviendas de la avenida de Anselmo Clav├®. Fuente visual: www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65548900, -0.89832400, '0101000020E6100000EBC726F911BFECBFA2F14410E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30767140540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30767140540.webp', 'https://www.flickr.com/photos/zaragozaantigua/30767140540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22483, 'Av. de Madrid 1968', 'Imagen capturada en el principio de la avenida de Madrid, con el fondo edilicio de la peque├▒a manzana entre la avenida, la calle del Comandante Rodr├¡guez de C├│rdoba, y la calle del Castillo. En el centro de la imagen, el peque├▒o y antiguo inmueble del n┬║ 2 de la calle del Castillo, luego derribado y sustituido por un edificio m├ís moderno y vertical. De fondo, los grandes bloques del ├║ltimo tramo de los n├║meros pares de la calle del General Franco, chaflanero el ├║ltimo con el paseo de Mar├¡a Agust├¡n. A la derecha, vista parcial de las traseras de la iglesia del Portillo. Transita la composici├│n tranviaria M+R n┬║ 108 en servicio en la l├¡nea 5 "Venecia-Delicias", encaminada hacia la plaza de Espa├▒a para ascender luego hasta ese barrio del sur, pasado el Canal Imperial de Arag├│n. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65603400, -0.89423600, '0101000020E6100000C6FCDCD0949DECBF33880FECF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40075841073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40075841073.webp', 'https://www.flickr.com/photos/zaragozaantigua/40075841073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22519, 'Aljafer├¡a 1966', 'Vista a├®rea centrada en el antiguo palacio de la Aljafer├¡a, todav├¡a bajo jurisdicci├│n militar con funciones cuarteleras. En su aspecto destacan las primeras obras de restauraci├│n acometidas bajo la direcci├│n del arquitecto Francisco ├ì├▒iguez Almech. Rodean al cuartel otras instalaciones militares adosadas y extentas, como su antiguo polvor├¡n y el "hom├│dromo". En primer t├®rmino, naves de la f├íbrica de muebles de Loscertales.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65663100, -0.89592200, '0101000020E61000008B8A389D64ABECBF17450F7C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53286721558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53286721558.webp', 'https://www.flickr.com/photos/zaragozaantigua/53286721558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22813, 'P.┬║ de Mar├¡a Agust├¡n 1974', 'In├®dita imagen capturada en la estrat├®gica esquina entre el arranque de la avenida de Madrid y el tramo del paseo de Mar├¡a Agust├¡n que al fondo ofrece su aspecto en ese momento, entre el cuartel del Cid, a la derecha, y las traseras de la iglesia de N.┬¬ S.┬¬ del Portillo. Entre ambos ruinosos entornos se abre la moderna calle que conecta con la plaza del Portillo y que desde 1968 homenajeaba a Jes├║s Muro Sevilla como jefe provincial de Falange Espa├▒ola el 18 de julio de 1936. En primer t├®rmino, frecuentado observatorio o mirador donde algunos de los parroquianos del inmediato Caf├® Madrid (justo a la derecha y fuera de plano), mayormente vinculados con el sector del transporte carretero en cami├│n (ch├│feres, ayudantes, descargadores), "hacen tiempo" entre carga y carga. Algunos de ellos probablemente tendr├ín estacionado el cami├│n en la cercana explanada junto al castillo de la Aljafer├¡a. El inmediato barrio del Castillo, al otro lado de la avenida de Madrid, concentraba un buen n├║mero de despachos de oficina de empresas de transporte.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65585500, -0.89395800, '0101000020E610000014ECBFCE4D9BECBF84F57F0EF3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51561016174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51561016174.webp', 'https://www.flickr.com/photos/zaragozaantigua/51561016174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22864, 'Portillo 1987', 'Desde la torre de la iglesia de N┬¬ S┬¬ del Portillo m├ís cercana a la calle Conde Aranda, un vistazo en altura al sureste urbano de la mano de Luis M├¡nguez, que nos da una buena visual de la inmediata plaza del Portillo, con el estado de las antiguas parcelas del arranque de la calle Pignatelli (izquierda). En l├¡nea recta, varios edificios referenciales de lo que fueran las Eras del Campo del Toro: el Coso de la Misericordia, antes de su cubrimiento, y la antigua Real Casa de la Misericordia, sede de la Diputaci├│n General de Arag├│n desde 1983, en obras de restauraci├│n de su neobizantina iglesia. Al fondo, el edificio Ebrosa, absolutista tope visual. En la calle Madre Rafols, emergen las torres del convento de las Hermanas de la Caridad de Santa Ana. Enfrente, los esquineros y deshabitados edificios para mandos del antiguo cuartel de Sangenis. Por el fondo, y como contrastado tel├│n de fondo, los grandes bloques de la avenida de C├®sar Augusto.', 1987, 1987, 1987, 'Anos 80', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15662110277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15662110277.webp', 'https://www.flickr.com/photos/zaragozaantigua/15662110277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22904, 'Muebles Loscertales 1989', 'Imagen del acceso a la f├íbrica de muebles de alta gama Sim├│n Loscertales Bona, en la calle Aljafer├¡a, donde terminaba la calle Comandante Rodr├¡guez de C├│rdoba (desde 2009, Sebasti├ín Banzo Urrea), tal y como estaba el 20 de febrero de 1989. Hab├¡a cerrado sus puertas en 1985. Fuente: "Memoria de las calles de Zaragoza", Juli├ín Ruiz Mar├¡n, Librer├¡a General, 2003.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65724800, -0.89540900, '0101000020E6100000F96871C630A7ECBF43AED4B320D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21742335371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21742335371.webp', 'https://www.flickr.com/photos/zaragozaantigua/21742335371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22968, 'Restauraci├│n de La Aljafer├¡a 1994', 'Jes├║s Lacueva. La Aljafer├¡a (1994): trabajos de construcci├│n del s├│tano-almac├®n del Patio de las Cortes. El desmoche de la techumbre de enfrente (lado Norte) se practic├│ para colocar la estructura de madera de la sala de comisiones C (despu├®s, sala "Manuel Gim├®nez Abad"); el de la derecha, para ubicar los grupos parlamentarios y la sala "Goya". Fuente: Manuel Ballar├¡n.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65637500, -0.89690300, '0101000020E6100000B0E595EB6DB3ECBFBC74931804D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945038411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945038411.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945038411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22970, 'Paso a nivel Delicias a├▒os 90', 'A finales de los a├▒os 80 del siglo XX, se decidi├│ que el estado de insalubridad y estrechamiento para los peatones en el paso a nivel ferroviario, carretero y peatonal de Delicias era insostenible. As├¡ que se construy├│ lo que se dio en llamar "Mecano", con su bola blanca gigante posmoderna. En 2001 se desmont├│ y se soterraron las v├¡as.', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65527500, -0.89784300, '0101000020E610000030293E3E21BBECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009511522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009511522.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009511522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23002, 'Avenida de Madrid a├▒os 90', 'Vista del paso elevado peatonal sobre la avenida de Madrid. Al fondo, barrio de Las Delicias. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321240142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321240142.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321240142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23004, 'Palacio de la Aljafer├¡a a├▒os 90', 'Vista del Palacio de la Aljafer├¡a, una vez concluida su restauraci├│n. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65598100, -0.89714700, '0101000020E61000005D8B16A06DB5ECBF10E6762FF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422108855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422108855.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422108855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23035, 'Paso Delicias 1990', 'Imagen capturada desde la altura del inmueble del n┬║ 1 de la calle de Juan XXIII con una panor├ímica vista del entorno del reci├®n inaugurado paso elevado de Delicias, que en el centro de la escena fue construido por el Ayuntamiento para permitir a los peatones atravesar el enlace a la autopista de Logro├▒o, las v├¡as del ferrocarril conducentes a la estaci├│n del Portillo, y dar as├¡ continuidad a la avenida de Madrid de la misma forma que el paso a desnivel permit├¡a al tr├ífico rodado. Esta infraestructura cost├│ 450 millones de pesetas y estuvo en construcci├│n desde mayo de 1988 a abril de 1990. Fue inaugurado oficialmente el 27 de abril de este ├║ltimo a├▒o. En primer t├®rmino y a la izquierda, el colegio p├║blico Juan XXIII, y tras la zona ocupada por las v├¡as del ferrocarril y la autopista, vista del lienzo occidental del palacio de la Aljafer├¡a, que sigue en obras, con la traza preservada del decimon├│nico cuartel. A la derecha, la ancha calle de Escoriaza y Fabro y la de S├ídaba, paralela a las v├¡as, y entre ambas, solar en forma de "quesito" que en 1994 ser├¡a urbanizado.', 1990, 1990, 1990, 'Anos 90', 'DELICIAS', 41.65525400, -0.89804600, '0101000020E610000039B709F7CABCECBF5E49F25CDFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50308514688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50308514688.webp', 'https://www.flickr.com/photos/zaragozaantigua/50308514688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23055, 'Paso a nivel Delicias 1994', 'Imagen, que con el tiempo se convertir├¡a en recurrente, centrada en las escaleras mec├ínicas del reciente paso elevado de Delicias estropeadas, en este caso por los da├▒os producidos por modernos luditas urbanos que encuentran sentido a su vida destrozando el mobiliario p├║blico. Como informa el cartel, para estas ocasiones deb├¡a utilizarse la rampa cuyo uso significaba una notable inversi├│n de tiempo. Al fondo y tras la trinchera ferroviaria, inmueble del principio de la calle de Juan XXIII.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65540700, -0.89769200, '0101000020E6100000C72FBC92E4B9ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50446814942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50446814942.webp', 'https://www.flickr.com/photos/zaragozaantigua/50446814942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23068, 'Paso Elevado Delicias 2000', '2000. "Paso a Nivel con estructura met├ílica". Construido a finales de los 80 supuestamente para beneficio de las personas a pie, fue desmontado en 2001, con apenas una d├®cada de vida ├║til, a pesar de lo anunciado por el Bolet├¡n (para)Oficial del Ayuntamiento (Revista "Nuestra Zaragoza", agosto-setiembre 1989): "Su dise├▒o y estructura han sido concebidos para convertirse en un punto de referencia de la arquitectura urbana. Para facilitar la vida de los paseantes el Alcalde ha dado instrucciones de que se modifique ligeramente el proyecto de forma que los peatones puedan acceder al paso mediante escaleras mec├ínicas o rampas m├│viles, puesto que los cinco metros de desnivel pueden ser muy fatigosos para personas mayores o que llevan paquetes". Personas mayores, portaquetes, y paseantes en general quedamos muy agradecidos al (ex) Alcalde Trivi├▒o por sus desvelos, se encuentre donde se encuentre.', 2000, 2000, 2000, 'Siglo XXI', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14785329388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14785329388.webp', 'https://www.flickr.com/photos/zaragozaantigua/14785329388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23133, 'Jacques Chirac 2004', 'Foto: Jos├® Miguel Marco. Jacques Chirac, presidente de la Rep├║blica Francesa entre 1995 y 2007, pasea por la Aljafer├¡a flanqueado por el presidente del Reino de Espa├▒a, Jos├® Luis Rodr├¡guez Zapatero, y el de la Comunidad Aut├│noma de Arag├│n, Marcelino Iglesias. Es el 7 de diciembre de 2004, y se celebra la XVII Cumbre hispano-francesa. Fuente: Heraldo de Arag├│n.', 2004, 2004, 2004, 'Siglo XXI', 'DELICIAS', 41.65661900, -0.89682700, '0101000020E6100000F06E6589CEB2ECBF537765170CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31708731961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31708731961.webp', 'https://www.flickr.com/photos/zaragozaantigua/31708731961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23198, 'Paseo Mar├¡a Agust├¡n 2015', 'Obras de renovaci├│n de tuber├¡as en el paseo de Mar├¡a Agust├¡n, en su confluencia con la avenida de Madrid (al fondo), en octubre de 2015. Destaca en el centro el estado ruinoso del edificio del antiguo Caf├® Madrid (1889-1997), que alberga el restaurante Casa Emilio (1939). Su fachada fue remozada en 2017. Fuente: www.zaragoza.es', 2015, 2015, 2015, 'Siglo XXI', 'DELICIAS', 41.65607700, -0.89380800, '0101000020E6100000C1E61C3C139AECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25699741837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25699741837.webp', 'https://www.flickr.com/photos/zaragozaantigua/25699741837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23213, 'La Aljafer├¡a 2014', 'Foto: Maroiane B. En agosto de 2014 se difundieron varias fotograf├¡as en las que se reivindicaba al grupo armado integrista ISIS en distintos lugares de Espa├▒a, tras autoproclamar un califato con capital en Mosul, Irak, una vez invadida. En 2017, el gobierno iraqu├¡ recuper├│ esa ciudad. Aqu├¡ podemos ver la bandera de tal organizaci├│n, ante el palacio de la Aljafer├¡a de Zaragoza. La instant├ínea est├í tomada en su esquina noreste, junto al foso. Al fondo, bloque de viviendas de la avenida de Madrid esquinero con la plaza de la Ciudadan├¡a. Fuente: Agencia EFE.', 2014, 2014, 2014, 'Siglo XXI', 'DELICIAS', 41.65718000, -0.89630800, '0101000020E6100000D594641D8EAEECBFEACA67791ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36039001464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36039001464.webp', 'https://www.flickr.com/photos/zaragozaantigua/36039001464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23245, 'Saraqusta 1115', '"Sarakosta", dibujo de Jos├® Luis Cano que representa el palacio de la Aljafer├¡a. En el centro, el fil├│sofo Avempace (1080-1139), cuando fue nombrado visir del gobernador almor├ívide Ibn Tifilwit. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1115, 1115, 1115, 'Siglo XIX', 'DELICIAS', 41.65660300, -0.89699900, '0101000020E6100000376E313F37B4ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31811731450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31811731450.webp', 'https://www.flickr.com/photos/zaragozaantigua/31811731450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23247, 'Saraqusta 1067', 'Fant├ística imagen creada por ordenador para la serie "El Cid" que representa supuestamente la Saraqusta de la Taifa gobernada por Al-Muqt├ídir Billah cuando las tropas del rey Sancho II de Castilla comandadas por ''Ruy'' D├¡az de Vivar se aproximan a ella para cobrar "las parias". La imagen presenta una recreaci├│n muy lograda de una ciudad medieval aparentemente musulmana, con sus murallas, alminares variados y c├║pulas de colores, si bien parece poco probable para la Saraqusta de la ├®poca. Las tropas en su aproximaci├│n por el oeste deber├¡an encontrarse primero con la Al-Ja''Fariyya (La Aljafer├¡a), construcci├│n exenta y fuera del per├¡metro amurallado, que aqu├¡ no aparece cuando deber├¡a hacerlo justo a la izquierda de la puerta de la muralla. Adem├ís el ingreso a la ciudad no era tan desolador por tratarse de una zona regada con el agua de varias acequias (Almozara y Romareda). Y las monta├▒as del fondo no se corresponden con el relieve de la Sierra de Alcubierre.', 1067, 1067, 1067, 'Siglo XIX', 'DELICIAS', 41.65624000, -0.89439800, '0101000020E61000002A73F38DE89EECBFDC291DACFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51323388974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51323388974.webp', 'https://www.flickr.com/photos/zaragozaantigua/51323388974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23248, 'La Aljafer├¡a 1118', 'Portada del c├│mic "Misterio en el valle del Viento", primera entrega de "Las aventuras de F├ítima". Con dibujos de Alfonso Pinedo y guion de Carlos Cabrero y Miguel ├üngel Fec├®, la historieta se sit├║a en los momentos en que Alfonso I el Batallador se dispone a tomar Saraqusta. En la ilustraci├│n, los protagonistas aparecen con el palacio de la Aljafer├¡a detr├ís, minarete incluido. Esta obra rinde homenaje con su estilo al de Herg├®, creador de Tint├¡n.', 1118, 1118, 1118, 'Siglo XIX', 'DELICIAS', 41.65663100, -0.89592200, '0101000020E61000008B8A389D64ABECBF17450F7C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52100345769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52100345769.webp', 'https://www.flickr.com/photos/zaragozaantigua/52100345769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23252, 'Aljafer├¡a 1737', 'Crist├│bal Cubero. 1737. "Plano del fuerte de la Aljaferia de Zaragoza, con la Plaza de Armas, delante de la principal puerta". El dibujo est├í orientado mirando desde el este. Fuente: www.mcu.es/', 1737, 1737, 1737, 'Siglo XIX', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16616536792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16616536792.webp', 'https://www.flickr.com/photos/zaragozaantigua/16616536792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22371, 'Vista a├®rea Parque Grande 1964', 'Vista a├®rea del parque Primo de Rivera y el Cabezo Buenavista con el Jard├¡n de Invierno. Al fondo, el Hospital Militar. M├ís al fondo, el Acampo Casellas y Valdespartera, al suroeste de la ciudad. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21695070983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21695070983.webp', 'https://www.flickr.com/photos/zaragozaantigua/21695070983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23262, 'Ctra. de Madrid 1913', 'Imagen capturada junto al arbolado cauce de la acequia de la Romareda Baja, o del Boquerazo, en el tramo paralelo a la carretera de Madrid a Francia, que queda a espaldas del fot├│grafo, delimitado entre la calle del Trovador, hacia la izquierda, y el paseo de Mar├¡a Agust├¡n, hacia la derecha. Al fondo, despejada explanada de acceso al castillo de la Aljafer├¡a, habilitado como dependencia cuartelera del Ej├®rcito. Esta caudalosa acequia hacia la derecha surt├¡a luego la huerta de los conventos de Santa In├®s, de las Carmelitas Descalzas de San Jos├® o Fecetas, y de Santa Luc├¡a, adem├ís de al lavadero de la Sierra de Agua, ya en la calle del Veintinueve de Septiembre, para terminar derivando en la acequia Mayor de la Almozara, un poco antes de su desemboque en el r├¡o Ebro.', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.65598400, -0.89459100, '0101000020E61000004F78094E7DA0ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48576393371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48576393371.webp', 'https://www.flickr.com/photos/zaragozaantigua/48576393371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23265, 'Aljafer├¡a c.1895', 'Imagen centrada en el castillo de la Aljafer├¡a habilitado como cuartel del ramo de la Guerra para acoger al regimiento de infanter├¡a del Infante N┬║ 5 y el regimineto de Gerona N┬║ 22. En primer t├®rmino, curso al aire de la acequia Baja de la Romareda, tambi├®n denominada del "Boquerazo" que, proveniente del camino de la Mosquetera, y tras cruzar soterrada la carretera de Madrid a Francia contin├║a hacia la derecha para cruzar el paseo de Mar├¡a Agust├¡n y dirigirse hacia los conventos de Santa In├®s y de las Fecetas.', 1895, 1895, 1895, 'Siglo XIX', 'DELICIAS', 41.65587900, -0.89551400, '0101000020E61000004D86E3F90CA8ECBF0C91D3D7F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54162313102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54162313102.webp', 'https://www.flickr.com/photos/zaragozaantigua/54162313102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23269, 'La Aljafer├¡a 1808', '"Bater├¡a del Portillo. Donde, al ver sus defensores caer muertos o heridos sin quedar quien sirviese la artiller├¡a, la intr├®pida Agustina Arag├│n, saltando por encima de los cad├íveres arrebat├│ la mecha de manos de un artillero que acababa de expirar; y haciendo fuego con gallarda bizarr├¡a ataj├│ el ├¡mpetu furioso de los enemigos en el ataque del 4 de julio". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Al fondo vemos la Aljafer├¡a, a la derecha de una torre agr├¡cola. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65613800, -0.89280000, '0101000020E610000036CD3B4ED191ECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15244962776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15244962776.webp', 'https://www.flickr.com/photos/zaragozaantigua/15244962776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23438, 'La Aljafer├¡a 1983', 'Excavaci├│n en La Aljafer├¡a para recuperar el foso de Tiburzio Spanochi de finales del siglo XVI. A la izquierda, el recreado pa├▒o oriental palaciego por el que se acced├¡a a la nueva sede de las Cortes de Arag├│n. En primer t├®rmino, camiones aparcados en esta zona con fuerte presencia del sector del transporte interurbano de mercanc├¡as. Al fondo, la industrial Qu├¡mica y el barrio de La Almozara. La foto est├í tomada desde cierta altura en el inmueble del n┬║ 33 de la avenida de Madrid.', 1983, 1983, 1983, 'Anos 80', 'DELICIAS', 41.65626900, -0.89677100, '0101000020E6100000F609A01859B2ECBF7730629F00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871802947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871802947.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871802947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23439, 'Panor├ímica Aljafer├¡a 1973', 'El castillo de la Aljafer├¡a centra esta vista en altura capturada desde el reciente bloque del n┬║ 31 de la avenida de Madrid. Se estaba realizando, seg├║n el proyecto de Francisco ├ì├▒iguez, la reconstrucci├│n de la puerta de acceso, los dos torreones que la flanquean y el resto de cubos del lienzo oriental de la muralla, con el torre├│n de ├íngulo y su enlace con la torre del Homenaje. El proceso de restauraci├│n se prolong├│ durante d├®cadas, desde que ese arquitecto lo emprendiese en 1947 y hasta su muerte en 1982. El Ayuntamiento, propietario del inmueble desde 1978, lo cedi├│ en 1984 a las Cortes de Arag├│n para establecer all├¡ su sede. En la panor├ímica y de izquierda a derecha: el paso a nivel del ferrocarril y la avenida de Madrid, que se├▒alan el acceso hacia el populoso barrio de Las Delicias; el entorno del palacio de la Aljafer├¡a, que conserva varias construcciones de car├ícter militar, e incluye la inevitable explanada como aparcamiento de camiones; las naves de la Industrial Qu├¡mica de Zaragoza y las v├¡as del ferrocarril. Al fondo van creciendo altas edificaciones en el barrio de La Almozara.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65551900, -0.89550300, '0101000020E610000053094FE8F5A7ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875982386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875982386.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875982386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23447, 'La Aljafer├¡a 1593', 'Dibujo de la Aljafer├¡a de Zaragoza, en la parte de Levante. Tiburcio Spanochi, 1593. Archivo General de Simancas, Ministerio de Cultura de Espa├▒a. "Este singular edificio sufri├│ a lo largo de nueve siglos una compleja metamorfosis que lo presenta como un crisol de culturas y hechos hist├│ricos. Los mayores cambios se producen en la Edad Moderna. Se destina a sede y prisi├│n del Tribunal del Santo Oficio. Tras las alteraciones de Arag├│n de 1591, Felipe II propone al ingeniero Tiburcio Spanochi su fortificaci├│n y transformaci├│n en ciudadela. El proyecto se realiza en 1593 rodeando el palacio de un foso con baluartes. La fortaleza se construye de argamasa y ladrillos con cadenas de sillares en las esquinas, siendo las dos puertas, sobre todo la principal de este dibujo, las que concentran la decoraci├│n. Su funci├│n palatina dar├í paso al uso militar que mantuvo hasta mediados del siglo XX."', 1593, 1593, 1593, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061057811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061057811.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061057811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23453, 'La Aljafer├¡a 1998', 'A├®rea vista de la ciudad con el Palacio de la Aljafer├¡a como hito fundamental, visto desde el oeste. Tras la decisi├│n tomada en 1985 de ubicar aqu├¡ a las Cortes de Arag├│n, la imagen del edificio se corresponde con las labores de adecuaci├│n del mismo a funciones y utilidades para las que no estaba pensado, con una compleja cohabitaci├│n de espacios institucionales y muse├¡sticos, que se inclinan siempre en beneficio de los corporativos intereses de quienes est├ín detr├ís del foso. Fuente visual: "La Aljafer├¡a", Cortes de Arag├│n, 1998.', 1998, 1998, 1998, 'Anos 90', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15319745870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15319745870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15319745870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23455, 'La Aljafer├¡a 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junio 1973. Imagen del Castillo de la Aljafer├¡a, cuando se estaba realizando, seg├║n el proyecto de Francisco ├ì├▒iguez, la reconstrucci├│n de la puerta de acceso de la muralla, de los dos torreones que la flanquean y del resto de la muralla del lienzo este, con el torre├│n de ├íngulo y su enlace con la torre del Homenaje. Para la reconstrucci├│n de los torreones cil├¡ndricos, ├ì├▒iguez tuvo en cuenta los alzados de Spanochi de 1593 y los alzados y plantas de Miguel Mar├¡n de 1757. Las obras de intervenci├│n en la Aljafer├¡a, en sus diversas fases, se extendieron desde 1955 hasta 1997.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65671300, -0.89653300, '0101000020E6100000D21C59F965B0ECBFD5EDEC2B0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380138162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380138162.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380138162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23467, 'La Aljafer├¡a 1860', 'Vista de la fachada principal del palacio de la Aljafer├¡a. Detr├ís sobresalen la torre del Trovador y la de la capilla de San Mart├¡n. Fuente: Mariano J├║dez y Ortiz. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey. Libro Primeros tiempos de la fotograf├¡a en Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'DELICIAS', 41.65654200, -0.89635300, '0101000020E6100000D47C957CECAEECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28489798401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28489798401.webp', 'https://www.flickr.com/photos/zaragozaantigua/28489798401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23470, 'La Aljafer├¡a 1593', 'Maqueta elaborada por Ramiro Hern├índez con el aspecto del palacio de La Aljafer├¡a en 1593, tras su fortificaci├│n por orden de Felipe II. Fuente: Heraldo de Arag├│n.', 1593, 1593, 1593, 'Siglo XIX', 'DELICIAS', 41.65660300, -0.89699900, '0101000020E6100000376E313F37B4ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31440509833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31440509833.webp', 'https://www.flickr.com/photos/zaragozaantigua/31440509833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23476, 'La Aljafer├¡a 1986', 'Foto: Juan Gonz├ílez Misis. 10 de mayo de 1986. El pr├¡ncipe Felipe de Borb├│n se afana en la colocaci├│n de la primera piedra de las obras de acondicionamiento del palacio de la Aljafer├¡a como futura sede de las Cortes de Arag├│n. Fuente: Heraldo de Arag├│n.', 1986, 1986, 1986, 'Anos 80', 'DELICIAS', 41.65648500, -0.89700700, '0101000020E6100000ED0E290648B4ECBF44A852B307D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33499313435.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33499313435.webp', 'https://www.flickr.com/photos/zaragozaantigua/33499313435/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23696, 'Carmelitas Descalzos 1923', 'En 1835, los procesos desamortizadores desamortizaron a los PP. Carmelitas Descalzos del Convento de San Jos├®, en el que llevaban casi desde 1594. Volvieron en febrero de 1897, a la casa-asilo para sacerdotes que el Arzobispo les prest├│ en el barrio de Delicias. All├¡ estuvieron hasta enero de 1946, en que se trasladaron a la nueva parroquia de la calle San Juan de la Cruz. Este edificio fue luego ocupado por el colegio de las Hijas de San Jos├® y la escuela de San Valero hasta su derribo en los a├▒os 80. En la imagen, la Casa-Asilo prestada para convento carmelita, sita en las inmediaciones del cuartel de la Aljafer├¡a, entre la carretera de Madrid y las v├¡as del ferrocarril, junto al Barrio de la Explanada. Su fachada mira hacia la Aljafer├¡a.', 1923, 1923, 1923, 'Anos 20', 'DELICIAS', 41.65538200, -0.90006300, '0101000020E610000065DEAAEB50CDECBF8C31B08EE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15519093557.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15519093557.webp', 'https://www.flickr.com/photos/zaragozaantigua/15519093557/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23697, 'Paso a nivel Delicias 1915', 'Archivo Municipal. Francisco G├│rriz (Donaci├│n Palacio Fuenclara). 1915. "Retrato de grupo de ni├▒os". Imagen capturada en el paso a nivel de Delicias, antes de que fuera ensanchado. El tranv├¡a circulaba junto a la acera de enfrente. Poco tr├ífico rodado, y sol.', 1915, 1915, 1915, 'Anos 10', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15583773786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15583773786.webp', 'https://www.flickr.com/photos/zaragozaantigua/15583773786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23699, 'Juan XXIII 1984', 'Imagen de la calle Juan XXIII capturada desde la entrada por la Avenida de Madrid, con visual (a la izquierda) de la casa-asilo para sacerdotes que el Arzobispo prest├│ en el barrio de Delicias a los PP. Carmelitas Descalzos y que fue su base de operaciones desde febrero de 1897 hasta enero de 1944, en que se trasladaron a la nueva parroquia de la calle San Juan de la Cruz. A finales de los a├▒os 80 del pasado siglo, el edificio fue piqueteado, y en su lugar se construyeron las nuevas instalaciones del IES "El Portillo", que se vino aqu├¡ desde las antiguas instalaciones del Colegio de Maristas de San Vicente de Pa├║l. De esta forma, el IES queda justo enfrente del Colegio P├║blico Juan XXIII. Fuente visual: "Zaragoza, sus calles y su historia", HA, 1984.', 1984, 1984, 1984, 'Anos 80', 'DELICIAS', 41.65538200, -0.90006300, '0101000020E610000065DEAAEB50CDECBF8C31B08EE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16030415709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16030415709.webp', 'https://www.flickr.com/photos/zaragozaantigua/16030415709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23713, 'Paso a nivel Delicias 1913', '"Nuevo paso a nivel recientemente inaugurado en el Castillo de la Aljafer├¡a, de gran inter├®s para la l├¡nea de Zaragoza-Navarra". En 1911, al objeto de reducir la peligrosidad del cruce transversal, y a nivel, de la carretera de Madrid y la l├¡nea de ferrocarril de Alsasua, el Ayuntamiento impuls├│ la construcci├│n de un paso subterr├íneo "mediante una trinchera suficiente para el paso de carros sin entorpecimiento y obst├ículos". Fue inaugurado en 1912. En la imagen, capturada desde la carretera de Madrid, con el cuartel de La Aljafer├¡a a la izquierda, vista de la trinchera del primer paso a nivel de las Delicias. Un buen n├║meros de "tancredos", y entre ellos no faltan escolares del entorno, comprueban la firmeza del paso. Por abajo, peatones hacia Delicias. Al fondo, el ├írea del Portillo. Fuente: Foto Mar├¡n, diario "La Cr├│nica".', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25477385870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25477385870.webp', 'https://www.flickr.com/photos/zaragozaantigua/25477385870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23735, 'Paso a nivel Delicias 1912', 'Imagen de las obras de construcci├│n del nuevo paso a nivel ferroviario de la l├¡nea de Madrid-Zaragoza (p.k. 340,436), sobre el paso inferior de la carretera de Madrid a Francia. En 1911, y al objeto de reducir la creciente peligrosidad del cruce a nivel de la carretera y la l├¡nea de ferrocarril, el Ayuntamiento impuls├│ la construcci├│n de este paso subterr├íneo en forma de "trinchera suficiente para el paso de carros sin entorpecimiento y obst├ículos". En este excepcional caso, la trinchera o zanja no era para uso ferroviario. La imagen ha sido capturada desde la carretera de Madrid, con el cuartel de La Aljafer├¡a a la izquierda y fuera de plano, y algunos inmuebles recayentes a la carretera, a la derecha. Al fondo, ascendente rampa hacia el ├írea del Portillo. Desde su privilegiada posici├│n en la parte superior, los "tancredos" de turno observan el progreso de las obras.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65526600, -0.89796000, '0101000020E610000095B7239C16BCECBF22179CC1DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48876001528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48876001528.webp', 'https://www.flickr.com/photos/zaragozaantigua/48876001528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23736, 'Ctra. de Madrid c.1893', 'Interesante y poco frecuente imagen capturada desde la Casa-Asilo de Sacerdotes propiedad del Arzobispado sita en el camino de Herederos paralelo a la v├¡a del ferrocarril de Madrid. En primer t├®rmino, el paso a nivel ferroviario de las l├¡nea de Madrid que, en su camino hacia la estaci├│n de los directos, se cruza con la carretera de Madrid a Francia. A la derecha, el barrio de la Explanada, que culmina al fondo en la gran estructura del Hospicio Provincial y la c├║pula de San Ildefonso. Hacia la izquierda, la iglesia del Portillo, de la que casi emergen la torre de San Pablo Ap├│stol y la recrecida torre de Santiago del templo del Pilar. Algo m├ís hacia la derecha y al fondo, la torre y cimborrio de la Seo, y la Torre Nueva demediada y en inexorable proceso de derribo. Adem├ís pueden verse la torre de Santa Mar├¡a Magdalena, San Gil Abad, etc. En 1896 esta Casa-Asilo ser├¡a cedida a la Orden de los Carmelitas, que la habilitar├¡an como provisional convento durante varias d├®cadas.', 1893, 1893, 1893, 'Siglo XIX', 'DELICIAS', 41.65530200, -0.89832500, '0101000020E610000002BC051214BFECBF6F8099EFE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49050784196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49050784196.webp', 'https://www.flickr.com/photos/zaragozaantigua/49050784196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23739, 'Paso de Delicias 1923', 'Imagen del paso a nivel ferroviario de Delicias desde la avenida de Madrid. A la izquierda, inmuebles de los n├║meros 49-55, donde destaca el aserradero de maderas de Gim├®nez y Hern├índez. A la derecha, operarios laborando en la torre de agujas y la fachada del convento de los carmelitas descalzos de san Jos├®. Al fondo, el barrio de las Delicias. En primer t├®rmino, terroso aspecto de la avenida con la v├¡a ├║nica de la l├¡nea Delicias del tranv├¡a, que en 1927 ser├¡a desdoblada.', 1923, 1923, 1923, 'Anos 20', 'DELICIAS', 41.65532600, -0.89777800, '0101000020E61000006A2FA2ED98BAECBFF81BEDB8E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51284102729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51284102729.webp', 'https://www.flickr.com/photos/zaragozaantigua/51284102729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23917, 'Vista desde El Portillo c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1874-1877. "Vista general desde el Portillo". Panor├ímica perge├▒ada para la ocasi├│n, en una composici├│n in├®dita, democr├ítica, cient├¡fica y popular, generada en los laboratorios del', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65588700, -0.89301400, '0101000020E610000038D89B189293ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14832053848.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14832053848.webp', 'https://www.flickr.com/photos/zaragozaantigua/14832053848/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23926, 'Plaza del Portillo 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Marzo 1966. Imagen de la celebraci├│n de la Fiesta de la Guardia Municipal en la plaza del Portillo. Detr├ís de la Polic├¡a Montada de Saldud├í, la iglesia del Portillo (con su recuerdo al "Ausente"), y las viviendas a ella anexas, en lo que hoy es calle Monse├▒or ├ôscar Ata├║lfo Romero, y aleda├▒os.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15716569715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15716569715.webp', 'https://www.flickr.com/photos/zaragozaantigua/15716569715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23927, 'Agustina de Arag├│n 1808', 'Litograf├¡a de P├®rez, 1873. Ilustraci├│n sobre la c├®lebre reusina Agustina Zaragoza (1786-1857), que seg├║n la leyenda, prendi├│ fuego a un ca├▒├│n a los 22 a├▒os en la puerta del Portillo de Zaragoza, ante el ataque franc├®s durante los sitios. Fuente: Los Ni├▒os, revista de educaci├│n y recreo, octubre de 1873.', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65606200, -0.89276300, '0101000020E6100000EC8502B68391ECBFFD12F1D6F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20040832241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20040832241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20040832241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23930, 'Calle Jes├║s Muro 1968', '"Discurso durante la inauguraci├│n de la calle Jes├║s Muro." La apertura de un nuevo vial entre la plaza del Portillo y el paseo de Mar├¡a Agust├¡n dio pie a que el Ayuntamiento decidiera ponerle el nombre del recientemente fallecido Jes├║s Muro Sevilla, singularizando en el correspondiente azulejo su responsabilidad como jefe de la Falange zaragozana el 18 de julio de 1936. En la imagen, nocturna captura del acto oficial de inauguraci├│n de la nueva calle, con presencia de miembros de la corporaci├│n municipal, con el alcalde Ces├íreo Alierta al frente, y "camisas viejas" (+ ├│ -) de la Falange local. A los micr├│fonos, Radio Zaragoza. Al fondo, entre las tinieblas, restos del Cuartel del Cid (izquierda), y la c├║pula y torres del Hogar Pignatelli. Esta calle ser├í redenominada "Marie Curie" en el a├▒o 2009.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65489500, -0.89331300, '0101000020E6100000C8EE02250596ECBF2FA86F99D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22480873808.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22480873808.webp', 'https://www.flickr.com/photos/zaragozaantigua/22480873808/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23931, 'Plaza del Portillo 1968', 'Imagen capturada durante la celebraci├│n oficial del celestial patronazgo ejercido por Nuestra Se├▒ora del Portillo sobre la Guardia Municipal de la ciudad, como tradicionalmente ven├¡a haci├®ndose desde los a├▒os 40 (de ese mismo siglo XX). El lugar son las inmediaciones a la iglesia del Portillo, que queda a la derecha de la imagen. Como fondo esc├®nico, el antiguo Cuartel de Caballer├¡a del Cid, desmilitarizado tras la primera fase de la "Operaci├│n Cuarteles", que ya ha sido limpiamente seccionado para posibilitar la apertura de un nuevo vial entre la plaza del Portillo y el paseo de Mar├¡a Agust├¡n (al fondo), vial al que el Ayuntamiento decidi├│ ponerle el nombre del recientemente fallecido Jes├║s Muro Sevilla, jefe de la Falange zaragozana el 18 de julio de 1936. En el suelo, entre adoquines, perdura el tendido viario de la desmantelada l├¡nea tranviaria de Madrid. A la derecha, el edificio del n┬║ 5 de la plaza del Portillo. Fuente visual: Gerardo Sancho Ramo (Archivo P├║blico Municipal)', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65499200, -0.89245500, '0101000020E610000090DAC4C9FD8EECBF219221C7D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23359946661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23359946661.webp', 'https://www.flickr.com/photos/zaragozaantigua/23359946661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23941, 'Plaza del Portillo 1892', 'Imagen capturada desde la altura de la iglesia del Portillo, y centrada en el entorno de esa arbolada plaza. Tras ella, el antiguo coso de la Misericordia, y a su derecha, la Casa Inclusa, y el cuartel de caballer├¡a del Cid. A la izquierda, la calle de Pignatelli y el cuartel de Ingenieros de Sangenis. De fondo, el impresionante Hospicio Provincial, con su neobizantina c├║pula. Hemos volteado horizontalmente la original imagen, y as├¡ se ven m├ís las cosas en su sitio. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30802095414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30802095414.webp', 'https://www.flickr.com/photos/zaragozaantigua/30802095414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23942, 'Portillo 1808', '"La hero├¡na de Zaragoza". ├ôleo sobre lienzo, Marcos Hir├íldez Acosta, 1871. Representaci├│n del momento en que Agustina de Arag├│n prende la mecha de un ca├▒├│n contra el ej├®rcito franc├®s, en los Sitios de Zaragoza. Al fondo a la derecha, la entrada a la ciudad por la puerta del Portillo, anexa a la iglesia hom├│nima, fuera de cuadro. Fuente: web.dpz.es/arscatalogi.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65614900, -0.89383200, '0101000020E6100000E2C80391459AECBFCC26C0B0FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32103983833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32103983833.webp', 'https://www.flickr.com/photos/zaragozaantigua/32103983833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23944, 'El Portillo 1808', '"La defensa de Zaragoza"; ├│leo sobre lienzo, David Wilkie, 1828. Agustina de Arag├│n comparece ante su m├¡tico ca├▒├│n, presta a dispararlo hacia las afueras de Zaragoza contra el ej├®rcito franc├®s. Tras ella, el Portillo propiamente dicho. Fuente: WIkimedia Commons.', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65622400, -0.89352900, '0101000020E6100000F8E12021CA97ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40384270754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40384270754.webp', 'https://www.flickr.com/photos/zaragozaantigua/40384270754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23973, 'Pl. del Portillo c.1962', 'Archivo Municipal de Zaragoza. Archivo fotogr├ífico Editorial Arribas (EDIVIS). A├▒os 60. "Plaza de Toros." Un primer Coso Taurino fue mandado construir por Ram├│n Pignatelli para conseguir ingresos con que mantener la Casa de la Misericordia. Inaugurado en 1764, era en madera, luego ladrillo, y en 1895, en piedra. La gran reforma de 1916, dirigida por Martinez de Ubago y Miguel Angel Navarro, le dio el aspecto actual. En la imagen, vista panor├ímica de la plaza del Portillo, la plaza de toros, el Cuartel del Cid, La Casa de la Misericordia, la Maternidad e Inclusa de la DPZ, y las casas de militares del Paseo de M┬¬ Agust├¡n.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65537000, -0.89228600, '0101000020E61000008DB7955E9B8DECBFC763062AE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181301378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181301378.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181301378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24171, 'Paso elevado Delicias 1989', 'Construcci├│n del paso elevado sobre las v├¡as del tren y la avenida de Madrid. Fuente: Nuestra Zaragoza, agosto 1989.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65510500, -0.89781300, '0101000020E6100000868E1D54E2BAECBF19390B7BDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14844870208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14844870208.webp', 'https://www.flickr.com/photos/zaragozaantigua/14844870208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24174, 'Aljafer├¡a: v├¡as al aire 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 02/05/1974. Vista desde la calle Juan XXIII de un Talgo circulando en direcci├│n a la Estaci├│n del Portillo (hacia la derecha). Detr├ís sobresale uno de los cuadrangulares torreones de la Aljafer├¡a, el que da a la Avenida de Madrid. M├ís al fondo, a la derecha, sobresalen las dos torrecillas de la iglesia de la Real Casa de la Misericordia. La se├▒ora pasando por las v├¡as, yendo a visitar a su prima del Barrio de la Qu├¡mica.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65640100, -0.90016000, '0101000020E6100000035B25581CCEECBFE607AEF204D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907637952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907637952.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907637952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24176, 'Paso a nivel Delicias c.1966', '"Paso a desnivel". Colecci├│n Paco Boisset Locomotora a vapor tirando de un convoy en el paso a nivel de Las Delicias, viviendo de la estaci├│n Campo Sepulcro (al fondo). Por debajo pasa la avenida de Madrid.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15007240298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15007240298.webp', 'https://www.flickr.com/photos/zaragozaantigua/15007240298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24185, 'Paso a desnivel Delicias 2001', 'Demolici├│n del paso a desnivel en la avenida de Madrid de Zaragoza, en 2001. Fue levantado en 1989. Hoy ocupa su lugar la Rotonda de la Ciudadan├¡a. Fuente: www.elperiodicodearagon.com/', 2001, 2001, 2001, 'Siglo XXI', 'DELICIAS', 41.65510500, -0.89781300, '0101000020E6100000868E1D54E2BAECBF19390B7BDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19854244565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19854244565.webp', 'https://www.flickr.com/photos/zaragozaantigua/19854244565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24190, 'Paso inferior Delicias 1989', 'Uno de los dos tramos peatonales del paso a nivel bajo la v├¡a f├®rrea y la autopista, en el acceso al barrio de las Delicias de Zaragoza, el 6 de marzo de 1989. Son sus ├║ltimos momentos: ese mismo a├▒o se construir├í un paso elevado. Fuente: "Memoria de las calles de Zaragoza", Juli├ín Ruiz Mar├¡n, Librer├¡a General, 1998.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21052272374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21052272374.webp', 'https://www.flickr.com/photos/zaragozaantigua/21052272374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24203, 'T├║nel de cercan├¡as 2007', 'Foto: ├ülvaro Calvo. Obras de cubrimiento del t├║nel ferroviario de cercan├¡as bajo la desmantelada plaza de la Ciudadan├¡a (abajo), en septiembre de 2007. Unir├í la estaci├│n Delicias con la futura del Portillo (a la espalda). Hacia el fondo, la futura avenida Ciudad de Soria, Esta obra tambi├®n incluy├│ un t├║nel carretero "de salida r├ípida de la ciudad", que tras ser construido no fue puesto en servicio. A la izquierda, edificios en la calle Juan XIII. Fuente: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', 'DELICIAS', 41.65573700, -0.89867300, '0101000020E6100000EC8A19E1EDC1ECBF7AE3A430EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32359189121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32359189121.webp', 'https://www.flickr.com/photos/zaragozaantigua/32359189121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24204, 'Vista Delicias 1997', 'Vista a├®rea centrada en el paso elevado de Las Delicias, que salv├│ entre 1989 y 2001 el tr├ínsito de la avenida de Madrid sobre las v├¡as del ferrocarril y la autopista. Abajo, instalaciones de la estaci├│n del Portillo y de Averly. Al fondo a la derecha, el meandro de Ranillas. Fuente: Colecci├│n particular.', 1997, 1997, 1997, 'Anos 90', 'DELICIAS', 41.65528300, -0.89803700, '0101000020E61000006C223317B8BCECBFF84F3750E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32645266985.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32645266985.webp', 'https://www.flickr.com/photos/zaragozaantigua/32645266985/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24361, 'Torre de San Mart├¡n 1964', 'Fototeca Universidad de Sevilla. Antonio Palau. Agosto de 1964. "Aljafer├¡a: torre". Muy interesante imagen de la torre de la iglesia de San Mart├¡n enclavada en el interior del Cuartel de la Aljafer├¡a. Construida en formas y modas tardo-barrocas, casi neocl├ísicas, sobre un previo alminar modificado tras la conquista cristiana de 1118 (el cuerpo inferior de la imagen). La torre fue desmochada durante los conflictos b├®licos de los a├▒os 1808-1809, y luego restaurada. Lleg├│ en el estado que muestra la imagen hasta que la intervenci├│n y restauraci├│n del Palacio, en la segunda mitad del siglo XX, elimin├│ los a├▒adidos barrocos, dejando despejado el previo alminar. La imagen ha sido tomada desde una ventana del patio de San Mart├¡n, el principal acceso al interior del Palacio. Fuente visual: fototeca.us.es/imagen.jsp?id=25891&tipo=v&elto=16...', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65677400, -0.89664700, '0101000020E6100000F2CEA10C55B1ECBF7A6EA12B11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15013872864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15013872864.webp', 'https://www.flickr.com/photos/zaragozaantigua/15013872864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24407, 'Capilla de San Mart├¡n a├▒os 30', 'Acuarela de Ambrosio Ruste que representa la puerta de entrada a la capilla de San mart├¡n, en el patio de acceso de la Aljafer├¡a. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'DELICIAS', 41.65675800, -0.89664300, '0101000020E610000097FE25A94CB1ECBF75B169A510D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629262823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629262823.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629262823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24417, 'Aljafer├¡a 1890', 'Imagen del mihrab, con orientaci├│n sureste, de la mezquita poligonal ubicada en al Qasr al-Ja''fariyya (palacio de Ab├╗ Ja''far o Aljafer├¡a), del siglo XI, en su estado como dependencia cuartelera a finales del siglo XIX. Fuente visual: "Detalle del interior de la mezquita - Palacio de la Aljafer├¡a", fototipia de Joarizti y Mariezcurrena, en ÔÇ£Zaragoza Art├¡stica, Monumental e Hist├│ricaÔÇØ, Anselmo y Pedro Gasc├│n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'DELICIAS', 41.65666700, -0.89676800, '0101000020E6100000B22D03CE52B2ECBF64AE0CAA0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34305565736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34305565736.webp', 'https://www.flickr.com/photos/zaragozaantigua/34305565736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24509, 'Jabones Nicol├ís c.1955', 'Vista de la entrada de la antigua f├íbrica de Jabones Nicol├ís, poco despu├®s de que este mismo espacio fuese ocupado por la f├íbrica de muebles de alta gama Sim├│n Loscertales Bona, en la calle Aljafer├¡a, donde terminaba la calle Comandante Rodr├¡guez de C├│rdoba (desde 2009, Sebasti├ín Banzo Urrea).', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65708700, -0.89476500, '0101000020E6100000C45F9335EAA1ECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32061267736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32061267736.webp', 'https://www.flickr.com/photos/zaragozaantigua/32061267736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24519, 'Calle del Trovador 1945', 'Posado de trabajadores de la f├íbrica de gaseosas Anastasio Jim├®nez, comercializadora de gaseosas y sifones Tasio, ante la entrada de la factor├¡a, en el n├║mero 11 de la calle del Trovador. Tras el carruaje de la derecha, acceso cerrado a lo que luego ser├í la prolongaci├│n de la calle de Jer├│nimo Borao (hasta mediados los sesenta, callej├│n), que parte del paseo de Mar├¡a Agust├¡n. Perdura el inmueble. El de la derecha, no. Fuente visual: Asociaci├│n Paso a nivel.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65509900, -0.89538500, '0101000020E6100000D7868A71FEA6ECBF3752B648DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38319990051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38319990051.webp', 'https://www.flickr.com/photos/zaragozaantigua/38319990051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24548, 'Calle de la Aljafer├¡a c.1969', 'Imagen capturada en la secci├│n de maquinistas de la f├íbrica de muebles de alta gama de Sim├│n Loscertales Bona en la calle de la Aljafer├¡a, all├¡ ubicada desde 1960 y hasta 1985.', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.65708700, -0.89476500, '0101000020E6100000C45F9335EAA1ECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54471969052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54471969052.webp', 'https://www.flickr.com/photos/zaragozaantigua/54471969052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24555, 'La Aljafer├¡a 1848', '"Aljafer├¡a de Zaragoza", xilograf├¡a de Ildefonso Cibera para la Historia general de Espa├▒a, Madrid, 1848. Se pueden ver la torre de la capilla de San Mart├¡n, el tejado a dos vertientes de la cubierta torre del Homenaje, y la contraescarpa del foso, del remozado recinto en los finales del XVIII, como cuartel del ej├®rcito. Fuente visual: ├ülbum gr├ífico de Zaragoza, 1985.', 1848, 1848, 1848, 'Siglo XIX', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19499093442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19499093442.webp', 'https://www.flickr.com/photos/zaragozaantigua/19499093442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24556, 'Av. de Madrid 1979', 'Imagen de uno de los edificios promovidos por el emprendedor ├üngel Colmenero Criado, en este caso, por medio de la empresa "PROCANSA" (Promotora Inmobiliaria C├íntabro Pirenaica S. A.), en la Avenida de Madrid 7, una promoci├│n de 117 viviendas, con un "Gran Pasaje Comercial", "Oficinas", y "Tres plantas de Garajes". Las condiciones de compra se anunciaban inmejorables, con "M├¡nimas entradas", y "Resto, grandes facilidades". No era para menos, ya que este emprendedor ten├¡a la costumbre de hacer m├ís alturas de las legalmente autorizadas, y venderlas como si nada. El a├▒o de la imagen, precisamente, fue procesado por reiteradas irregularidades en las promociones que impulsaba, como en el sonado caso del "Edificio Venus" del Paseo General Mola 62, y otros m├ís, en San Juan de la Pe├▒a, Paseo de las Damas, y este de la Avenida de Madrid. Un par de a├▒os antes, durante la ├║ltima corporaci├│n franquista, este emprendedor interpuso una querella al Colegio de Arquitectos para defender su honor de las denuncias de que constru├¡a m├ís alturas de las autorizadas. Mientras tanto, el Ayuntamiento hac├¡a como que paralizaba las obras, pero en la pr├íctica estas continuaban. En 1979, la primera corporaci├│n de la recuperada democracia municipal derrib├│ una obra ilegal promovida por este emprendedor en la calle Jer├│nimo Borau, precisamente en las traseras del complejo que estaba construyendo en la Avenida de Madrid. Este era el aspecto de la obra de la Avenida de Madrid. Algunas pintadas aluden al personaje referido. En 1982 esta promoci├│n estar├¡a finalizada. A su izquierda, los veteranos edificios del n┬║ 3-5, donde Casa Emilio. Imagen obtenida desde la calle Comandante Rodr├¡guez de C├│rdoba, desde 2009 denominada Sebasti├ín Banzo Urrea, primer alcalde constitucional de Zaragoza durante la Segunda Rep├║blica. Fuente visual: Gerardo Sancho Ramo, Archivo P├║blico Municipal.', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65569500, -0.89457000, '0101000020E61000007172BF4351A0ECBF4B9352D0EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19996019222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19996019222.webp', 'https://www.flickr.com/photos/zaragozaantigua/19996019222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24558, 'Vista a├®rea Aljafer├¡a 1986', 'Vista a├®rea del entorno de la Aljafer├¡a.', 1986, 1986, 1986, 'Anos 80', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22129312348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22129312348.webp', 'https://www.flickr.com/photos/zaragozaantigua/22129312348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24559, 'La Aljafer├¡a 1983', 'Antiguo palacio de la Aljafer├¡a durante las obras de restauraci├│n iniciadas en 1947 por Francisco ├ì├▒iguez. Al fondo, a la izquierda, la avenida de Madrid. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1983, 1983, 1983, 'Anos 80', 'DELICIAS', 41.65665500, -0.89592400, '0101000020E6100000B972F6CE68ABECBFA0E062450DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22725003887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22725003887.webp', 'https://www.flickr.com/photos/zaragozaantigua/22725003887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24560, 'La Aljafer├¡a 1627', 'Plano de la Aljafer├¡a de Zaragoza, con indicaci├│n del lugar que ocupaba la sede de la Inquisici├│n, 1627. Este plano fue datado por Pedro I. Sobradiel en 2009. Incluye, superpuestos, unos papeles con las fachadas del patio de San Mart├¡n, lugar que ocupaba la Inquisici├│n tras la fortificaci├│n del edificio en 1593, habiendo sido anteriormente todo el edificio propiedad de ese tribunal. Fuente: servicios3.aragon.es/bva/i18n/catalogo_imagenes/grupo.cmd...', 1627, 1627, 1627, 'Siglo XIX', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23808862353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23808862353.webp', 'https://www.flickr.com/photos/zaragozaantigua/23808862353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24561, 'La Aljafer├¡a 1708', '"Plano del castillo de la Inquisici├│n, cerca de Zaragoza, capital del reino de Arag├│n en Espa├▒a, en el estado en que estaba en 1708", por el ingeniero franc├®s Claude Mass├®. Se trata de uno de los varios proyectos te├│ricos de fortificaci├│n del castillo de la Aljafer├¡a durante la guerra de Sucesi├│n espa├▒ola. Fuente visual: Pedro I. Sobradiel, El castillo de la Aljafer├¡a: 1600-1800. de medieval a ilustrado, IEIOP, Zaragoza, 2009.', 1708, 1708, 1708, 'Siglo XIX', 'DELICIAS', 41.65656600, -0.89697300, '0101000020E6100000E8A38CB800B4ECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24118516037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24118516037.webp', 'https://www.flickr.com/photos/zaragozaantigua/24118516037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24562, 'La Aljafer├¡a 1592', '"Traza del castillo que se ha de hacer en la Aljafer├¡a de Zaragoza", Tiburcio Spanochi, 1592. En 1592, Felipe II proyect├│ varias obras de fortificaci├│n de la ciudad de Zaragoza, a ra├¡z de los altercados sucedidos desde 1591. De todas ellas, s├│lo se realiz├│ la transformaci├│n del Palacio de la Aljafer├¡a en castillo fortificado. En el plano, la Aljafer├¡a, el r├¡o Ebro, la Puerta Sancho, la Puerta del Portillo y la iglesia del Portillo. Fuente: Archivo General de Simancas.', 1592, 1592, 1592, 'Siglo XIX', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24352922561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24352922561.webp', 'https://www.flickr.com/photos/zaragozaantigua/24352922561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26070, 'Ferias 1963', 'Vista a├®rea capturada sobrevolando el recinto de la 23 Feria Nacional de Muestras, rodeado en esta ocasi├│n de las atracciones del ferial instalado con motivo de las Fiestas del Pilar. Hacia el fondo, la plaza del Emperador Carlos V y el final del paseo de Fernando el Cat├│lico, justo donde se prolonga como paseo de Isabel la Cat├│lica.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63770500, -0.90032000, '0101000020E61000003AE97DE36BCFECBF72BF4351A0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50831255853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50831255853.webp', 'https://www.flickr.com/photos/zaragozaantigua/50831255853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24564, 'Mot├¡n de Zaragoza 1591', 'ÔÇ£Las alteraciones de Arag├│n. Mot├¡n de Zaragoza, 1591ÔÇØ. Grabado del siglo XIX coloreado posteriormente. En 1591 se produjeron ciertas algaradas en las calles de Zaragoza, que la historiograf├¡a dio en ubicar en diversos entornos urbanos. Uno de estos pretendidos motines habr├¡a tenido lugar en la Aljafer├¡a, donde fue trasladado Antonio P├®rez provisionalmente; la ilustraci├│n quiz├ís pretende reflejar ese entorno, sin demasiado acierto. Fuente visual: www.alamy.es', 1591, 1591, 1591, 'Siglo XIX', 'DELICIAS', 41.65671000, -0.89669400, '0101000020E61000001F9F909DB7B1ECBF637AC2120FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41057293392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41057293392.webp', 'https://www.flickr.com/photos/zaragozaantigua/41057293392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24877, 'Plaza del Portillo 1910', 'AHPZ. Archivo Coyne. 1910. Chavales posando en las traseras del "Monumento a Agustina de Arag├│n y la hero├¡nas de los Sitios", inaugurado recientemente en la Plaza del Portillo. Al fondo, el Coso de la Misericordia, que unos pocos a├▒os despu├®s ser├í mudejarizado con la reforma de Navarro y Mart├¡nez de Ubago.', 1910, 1910, 1910, 'Anos 10', 'DELICIAS', 41.65552700, -0.89237600, '0101000020E61000008B87F71C588EECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14834430038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14834430038.webp', 'https://www.flickr.com/photos/zaragozaantigua/14834430038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24923, 'Plaza del Portillo 1908', 'Foto: Freudenthal. Inauguraci├│n del monumento a Agustina de Arag├│n en la plaza del Portillo, por parte de Alfonso XIII y Victoria Eugenia, el 29 de octubre de 1908. Al fondo, iglesia del Portillo. Fuente: La ilustraci├│n espa├▒ola y americana, a trav├®s de www.facebook.com/photo.php?fbid=1205203256182307&set=...', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65565200, -0.89243700, '0101000020E6100000F7B0170AD88EECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33245875235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33245875235.webp', 'https://www.flickr.com/photos/zaragozaantigua/33245875235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24926, 'Plaza del Portillo 1908', 'El escultor Mariano Benlliure, inspeccionando su monumento a Agustina de Arag├│n en la plaza del Portillo, en octubre de 1908. Ser├í inaugurado por los reyes el 29 del mismo mes. Fuente: Foto Moya. Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65565200, -0.89243700, '0101000020E6100000F7B0170AD88EECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41188191021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41188191021.webp', 'https://www.flickr.com/photos/zaragozaantigua/41188191021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25098, 'Victoria Eugenia 1908', 'Foto: Go├▒i. La reina Victoria Eugenia y su marido Alfonso XIII inauguran el monumento a Agustina de Arag├│n en la plaza del Portillo, el 29 de octubre de 1908. Fuente: Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65569200, -0.89243500, '0101000020E6100000C9C859D8D38EECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40292986515.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40292986515.webp', 'https://www.flickr.com/photos/zaragozaantigua/40292986515/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25103, 'Calle del Portillo 1908', 'Imagen capturada desde la altura del inmueble del n┬║ 33 del paseo de Mar├¡a Agust├¡n y centrada en el cortejo del rey Alfonso XIII que, acompa├▒ado del alcalde y de los infantes Fernando y Luis Alfonso y proveniente del coso de la Misericordia, se dirige al recinto de la Exposici├│n Hispano-Francesa para visitarlo. A la izquierda, los muros perimetrales de la gran huerta del convento de Santa In├®s. A la derecha, la iglesia de Nuestra Se├▒ora del Portillo. Al fondo y en el centro, inmueble de la antigua Casa de la Galera esquinera entre la calle de Santa In├®s y la calle del Portillo. Al fondo y a la izquierda, vista parcial de la torre de San Pablo Ap├│stol, y la torre de la Seo algo m├ís a la derecha. En primer t├®rmino y sobre el firme, tendido de la l├¡nea de Madrid del tranv├¡a, curvea hacia la derecha y la estaci├│n de Campo sepulcro o del Mediod├¡a. Esta fue la primera de las dos veces que el jefe del Estado acudi├│ a Zaragoza este a├▒o. As├¡, el d├¡a 14 de junio, acudi├│ para asistir a diversas celebraciones memorialistas en las que inaugur├│ l├ípidas dedicadas a Jos├® Palafox en la hom├│nima calle; al T├¡o Jorge o Jorge Ibort en la hom├│nima calle del Arrabal; a Basilio Boggiero, Santiago Sas y el bar├│n de Warsage en el puente de Piedra; a Antonio de Torres en la calle de Don Jaime I; a la condesa de Bureta en la calle de la Torre Nueva; a Pedro Mar├¡a Ric en la Audiencia Provincial; finalmente, el Monumento al Reducto del Pilar no pudo ser inaugurado porque no estaba terminado. Por la tarde, el Rey fue a la plaza de toros a ver al torero Lagartijo torear miuras. En el tercer toro y aprovechando que el Lagartijo recibi├│ un varetazo, el Rey abandon├│ la plaza para, como muestra la imagen, encaminarse hacia el recinto de la exposici├│n Hispano-Francesa.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65617600, -0.89360400, '0101000020E6100000A164726A6798ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50629504571.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50629504571.webp', 'https://www.flickr.com/photos/zaragozaantigua/50629504571/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25855, 'Calle del Conde de Aranda c.1994', 'Desde el inmueble del n┬║ 126 de la calle del Conde Aranda recayente a la plaza del Portillo, un vistazo en altura al tramo final de esa calle centrado en el denso tr├ífico direccionado hacia el estrat├®gico cruce con el paseo de Mar├¡a Agust├¡n y el arranque de la avenida de Madrid. Al fondo, solar en obra donde estuviera el antiguo n┬║ 83 de este paseo y el n┬║ 2 de la calle del Castillo, donde poco despu├®s se levantar├¡a el actual y chaflanero n┬║ 2 de esa calle.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65618400, -0.89330400, '0101000020E6100000FB592C45F295ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50497334301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50497334301.webp', 'https://www.flickr.com/photos/zaragozaantigua/50497334301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25897, 'Paseo Mar├¡a Agust├¡n c.1955', 'Cuesta del tramo del paseo Mar├¡a Agust├¡n entre la Puerta de Sancho y el Portillo (al fondo). Distintos medios de transporte, entre ellos un tranv├¡a de la l├¡nea 7 "Ayuntamiento-Portillo". Fuente: www.facebook.com/photo.php?fbid=1574816756079888&set=...', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65718000, -0.89336300, '0101000020E6100000399B8E006E96ECBFEACA67791ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15225868337.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15225868337.webp', 'https://www.flickr.com/photos/zaragozaantigua/15225868337/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25935, 'La Ajafer├¡a c.1956', 'Imagen capturada desde la altura del antiguo inmueble del n┬║ 21 de la avenida de Madrid, casi esquinero con el arranque de la calle del Trovador, y centrada en el cuartel de La Aljafer├¡a con el que confrontaba. En primer t├®rmino, remolque de una composici├│n tranviaria de la serie 100 en servicio en la l├¡nea 5 Torrero-Delicias encaminada hacia este barrio. Tras ella, jardines con que se hab├¡an hermoseado los terraplenes de acceso al cuartel, del que emergen la mole de la torre del Trovador, y la torrecilla de la iglesia de San Mart├¡n. A la derecha, instalaciones fabriles de la Industrial Qu├¡mica de Zaragoza.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65595200, -0.89602900, '0101000020E61000000C90680245ACECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49495637613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49495637613.webp', 'https://www.flickr.com/photos/zaragozaantigua/49495637613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22529, 'Cabezo de Buena Vista 1972', 'La serie de tranv├¡as "80" entr├│ en servicio en 1933, aunque hasta 1937 quedaron en cocheras. Con un remolque jardinera, comenz├│ ese a├▒o en la l├¡nea 11 "Parque", y en 1947 es asignado a la L├¡nea 5 "Torrero-Delicias", luego "Venecia-Delicias". En noviembre de 1971 esta L├¡nea fue suprimida. Fue adquirido por el Ayuntamiento para instalarlo en el Cabezo de Buena Vista como Biblioteca Infantil, como recoge la imagen. En 1980 fue definitivamente desguazado. Fuente visual: www.flickr.com/photos/jhm0284/5812535645/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63226000, -0.89374900, '0101000020E610000083A5BA809799ECBFD4484BE5EDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14705380058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14705380058.webp', 'https://www.flickr.com/photos/zaragozaantigua/14705380058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21485, 'Estaci├│n de Cari├▒ena 1926', '1926. La necesidad de contar con un ferrocarril por el que transportar la producci├│n vitivin├¡cola de Cari├▒ena para su exportaci├│n a Francia, fue el principal motor de la creaci├│n del ferrocarril de Cari├▒ena a Zaragoza. Fue inaugurado el 10 de agosto de 1887, con un servicio regular de trenes consistente en dos convoyes mixtos diarios de ida y vuelta, que perdurar├¡an hasta 1933, a├▒o en que esta l├¡nea fue clausurada y subsumida en la de Caminreal. Pese a su cercan├¡a a Campo Sepulcro, la conexi├│n entre ambas estaciones era complicada, por la notable diferencia de altura entre una y otra. Hubo que trazar un amplio ramal de enlace entre el "Barrio de la Romareda" (actual calle Vicente Berdus├ín y Escoriaza y Fabro) y el "Barrio de La Explanada" (a la izquierda de la carretera de Madrid), hasta llegar a un muelle intercambiador cerca del Paso a Nivel de Delicias. En la imagen, estaci├│n de Cari├▒ena en Zaragoza, con un convoy mixto (plataformas para mercanc├¡as+vagones de viajeros) tirado por la locomotora a vapor n┬║ 2, denominada "Pilar". Al fondo, el ampliado edificio central de la estaci├│n, derribado a principios de los a├▒os 50.', 1926, 1926, 1926, 'Anos 20', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14998663245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14998663245.webp', 'https://www.flickr.com/photos/zaragozaantigua/14998663245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21865, 'Calle del Moncayo 1933', 'Imagen capturada en la calle del Moncayo, una de las m├ís representativas del muy industrial barrio de Cari├▒ena o de la Romareda, frente a la estaci├│n de Campo Sepulcro, Mediod├¡a, Madrid, o MZA. A la izquierda, el emboque a la calle del Sol y una de las reconocibles torres gemelas de la f├íbrica de chocolate de Or├║s. A ambos lados de la arbolada calle, hotelitos e industrias varias. Al fondo, el arranque de la calle del Moncayo desde la avenida de Romareda, paralela al tendido ferroviario que hacia la derecha lleva a Barcelona, pasando junto a la cercana y reci├®n clausurada estaci├│n de tren de Cari├▒ena. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65006200, -0.89600600, '0101000020E610000001A260C614ACECBFA92F4B3B35D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36400788246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36400788246.webp', 'https://www.flickr.com/photos/zaragozaantigua/36400788246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22301, 'Campo Sepulcro 1967', 'Archivo Municipal. Gerardo Sancho Ramo. Noviembre 1967. Imagen del mar de v├¡as de la estaci├│n de tren Campo Sepulcro, a puento de pasar un convoy tirado por una nueva locomotora diesel. A la derecha, las vaporosas en su dep├│sito, con un futuro bastante incierto.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65008400, -0.89472000, '0101000020E6100000C47762D68BA1ECBF91D3D7F335D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15559127050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15559127050.webp', 'https://www.flickr.com/photos/zaragozaantigua/15559127050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22786, 'Calle de Santander 1976', 'Imagen capturada en el arranque de la calle de Santander desde la de Escoriaza y Fabro. A la derecha, donde estuviera ubicada la antigua estaci├│n del ferrocarril de v├¡a estrecha de Cari├▒ena-Zaragoza, la manzana delimitada por las calles de Asturias y de Cari├▒ena, con los bloques finalizados de los n├║meros 4 y 6, y el resto en construcci├│n, o en tr├ínsito hacia el derribo, como el chafl├ín de primer plano a la derecha. Al fondo, la moderna plaza de Roma. La ancha calzada para circulaci├│n motorizada determina el espacio resultante y algunos veh├¡culos, incluso, ocupan la acera aparcados temporalmente en la acera de la izquierda. A la derecha, una soleada cabina telef├│nica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38497478261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38497478261.webp', 'https://www.flickr.com/photos/zaragozaantigua/38497478261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22843, 'Calle Anselmo Clav├® 1989', 'Demolici├│n completa de un edificio de viviendas de 6 plantas, de estructura mixta hormig├│n y madera, en el chafl├ín de la calle Anselmo Clav├® con la calle Madre Sacramento.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65077300, -0.89351800, '0101000020E6100000FE648C0FB397ECBF560F98874CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15108149056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15108149056.webp', 'https://www.flickr.com/photos/zaragozaantigua/15108149056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22984, 'El Portillo a├▒os 90', 'Vista a├®rea de la zona de Zaragoza alrededor de la estaci├│n del Portillo. Fuente: viajesferroviarios.blogspot.com.es/2015/01/la-revolucion-...', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65077600, -0.89416200, '0101000020E6100000336E6AA0F99CECBFC782C2A04CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19259886222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19259886222.webp', 'https://www.flickr.com/photos/zaragozaantigua/19259886222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23155, 'Calle Asturias 2009', 'Foto: Juan Carlos Arcos. Construcci├│n de la Escuela Infantil Municipal El And├®n, en la calle de San Pedro Arbu├®s 4. La imagen muestra la fachada recayente a la calle de Asturias. Este equipamiento p├║blico del barrio de Las Delicias fue inaugurado en 2010. Fuente: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'DELICIAS', 41.65019300, -0.89565600, '0101000020E6100000EAEA8EC536A9ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32352330903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32352330903.webp', 'https://www.flickr.com/photos/zaragozaantigua/32352330903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23184, 'El Portillo c.2000', 'El tren diurno "R├¡o Arag├│n" Madrid-Jaca parte desde la estaci├│n de Zaragoza-El Portillo tras el preceptivo cambio de la locomotora el├®ctrica que lo traccion├│ hasta aqu├¡ por la diesel 319.3 de la imagen, debido a la ausencia de catenaria desde Tardienta. Este servicio convencional desapareci├│ en diciembre de 2003 como otros tantos como consecuencia de la entrada en servicio la Alta Velocidad Espa├▒ola. Esta locomotora fue vendida a la Rep├║blica Argentina en 2009.', 2000, 2000, 2000, 'Siglo XXI', 'DELICIAS', 41.65083700, -0.89426900, '0101000020E6100000B4739A05DA9DECBF6D0377A04ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51046375371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51046375371.webp', 'https://www.flickr.com/photos/zaragozaantigua/51046375371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23318, 'Vista Campo Sepulcro c.1967', 'Panorama de las instalaciones de la Estaci├│n de ferrocarril de Campo Sepulcro. Los edificios centrales de la Estaci├│n quedan empeque├▒ecidos ante el impresionante Dep├│sito de Locomotoras. Adem├ís, talleres, aguadas, almacenes, viviendas... A la izquierda, el enorme complejo industrial de Carde y Escoriaza. Un poco m├ís al fondo, el Paso a Nivel de Delicias. A la derecha, al fondo, la chimenea de Averly. La imagen ha sido tomada desde la azotea del n┬║ 27 de la calle Alselmo Clav├® (la sombra que se proyecta), por aquel entonces el ├║nico edificio de gran altura en toda esa parte de la calle.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65050000, -0.89364700, '0101000020E61000007364E597C198ECBF2506819543D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14787761130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14787761130.webp', 'https://www.flickr.com/photos/zaragozaantigua/14787761130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23970, 'Jard├¡n de Invierno 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1966. Imagen de una simp├ítica reuni├│n-encuentro de la Delegaci├│n Nacional del Frente de Juventudes (organizaci├│n juvenil del franquismo) en el Parque Primo de Rivera, en el precioso Jard├¡n de Invierno.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63172600, -0.89277800, '0101000020E610000041D3122BA391ECBF3604C765DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097672174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097672174.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097672174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23322, 'Estaci├│n de Cari├▒ena c.1900', 'Principios Siglo XX. Colecci├│n Gerardo Alca├▒iz. La Estaci├│n de Cari├▒ena se inaugur├│ en 1887, muy cerca de la de Campo Sepulcro. En la imagen, al fondo, las traseras del edificio de la Estaci├│n, cuyos andenes quedaban recayentes hacia el otro lado. En la v├¡a, el tranv├¡a M-3, habilitado para transporte de mercanc├¡as, desde esta Estaci├│n, por la red tranviaria de la ciudad. La Estaci├│n de Cari├▒ena se ubicaba en lo que ahora es comienzo de la calle Santander. Fue clausurada en 1933, y desmantelado el tendido. El edificio de la estaci├│n ser├¡a derribado a principios de los a├▒os 50.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14955731386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14955731386.webp', 'https://www.flickr.com/photos/zaragozaantigua/14955731386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23323, 'Campo Sepulcro 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1966. Imagen tomada desde la pasarela peatonal sobre el mar de v├¡as de la Estaci├│n de Campo Sepulcro, encauzado hacia la Avenida Goya. Al fondo, a la izquierda, el edificio central de la Estaci├│n. A la izquierda, el dep├│sito de locomotoras. Escoriaza y Fabro queda a la izquierda, donde la f├íbrica Or├║s; Anselmo Clav├®, a la derecha.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64917000, -0.89409800, '0101000020E61000008368AD68739CECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15237567832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15237567832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15237567832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23325, 'Campo Sepulcro 1912', 'Despedida de tropas coloniales en la Estaci├│n Campo Sepulcro, con direcci├│n al norte de ├üfrica, a pelear en la Guerra del Rif.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65103300, -0.89411400, '0101000020E6100000EFA99CF6949CECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15458669657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15458669657.webp', 'https://www.flickr.com/photos/zaragozaantigua/15458669657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23329, 'Campo Sepulcro c.1965', 'Locomotora de vapor Compound De Glehn fabricada en Alemania en 1902, en servicio para la MZA, capturada un poco antes de llegar a la estaci├│n de Campo Sepulcro. Al fondo, Talleres Mercier, en la avenida de Jos├® Anselmo Clav├®. Fuente visual: Foto J.B. Snell, en image.slidesharecdn.com/', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65103300, -0.89411400, '0101000020E6100000EFA99CF6949CECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20524912229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20524912229.webp', 'https://www.flickr.com/photos/zaragozaantigua/20524912229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23333, 'Estaci├│n de Cari├▒ena 1887', '"Tren oficial de la inauguraci├│n" de la nueva estaci├│n del ferrocarril de Zaragoza a Cari├▒ena, el 10 de agosto de 1887. Al fondo, el edificio central de la Estaci├│n, en el entorno de Campo del Sepulcro, en una zona luego denominada "barrio de Cari├▒ena". Esta l├¡nea fue clausurada y desmantelada en 1933 al entrar en servicio la nueva l├¡nea Zaragoza- Teruel-Valencia.', 1887, 1887, 1887, 'Siglo XIX', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25190810155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25190810155.webp', 'https://www.flickr.com/photos/zaragozaantigua/25190810155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23335, 'Campo Sepulcro 1961', 'Imagen capturada desde el pretil del mar de v├¡as ferroviarias, que hacia la izquierda se ensanchaba progresivamente hasta llegar a la estaci├│n Campo Sepulcro. Al otro lado de la zanja, Anselmo Clav├®, y al fondo, el antiguo edificio de la Casa de Convalecientes, que desde finales de los a├▒os cincuenta estaba ocupado por el Colegio Polit├®cnico Nuestra Se├▒ora del Pilar. Fuente visual: Archivo Municipal de Zaragoza', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.64917000, -0.89409800, '0101000020E61000008368AD68739CECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30091576485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30091576485.webp', 'https://www.flickr.com/photos/zaragozaantigua/30091576485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23340, 'Campo Sepulcro 1967', 'Imagen capturada en el mar de v├¡as de la antigua estaci├│n de Campo Sepulcro, centrada en dos locomotoras vaporosas all├¡ estacionadas, la primera, de la serie 240-4000, y la segunda, de la serie 241-4000 (ambas, numeraci├│n RENFE). Al fondo, la avenida Anselmo Clav├®, y el reconocible edificio chaflanero con la calle Madre Sacramento, frente al cuartel de la Polic├¡a Armada. A la izquierda, remates de las viviendas militares recayentes a la calle General Mayand├¡a y el paseo de M┬¬ Agust├¡n. Fuente visual: foto Graham T.V. Stacey, en www.spanishrailway.com/', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65009400, -0.89398900, '0101000020E6100000D57ABFD18E9BECBFB5A9BA4736D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31956847385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31956847385.webp', 'https://www.flickr.com/photos/zaragozaantigua/31956847385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23345, 'Campo Sepulcro 1911', 'Imagen capturada desde el mar de v├¡as de la estaci├│n de Campo Sepulcro de la zanja, o trinchera, y v├¡a ├║nica del ferrocarril MZA en direcci├│n a Barcelona, as├¡ como de los nuevos pasos elevados tendidos sobre ella, siendo el de primer plano el que conduc├¡a hacia la derecha al ingreso principal a la estaci├│n de ferrocarril de Cari├▒ena, y los siguientes en el entorno del cruce de la carretera de Zaragoza a Valencia por Teruel. Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'DELICIAS', 41.64889100, -0.89394600, '0101000020E6100000037B4CA4349BECBF99D53BDC0ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39010644140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39010644140.webp', 'https://www.flickr.com/photos/zaragozaantigua/39010644140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24172, 'Pasarela Avenida de Goya 1966', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Abril 1966. Desde la Estaci├│n de Campo Sepulcro y hasta el Paseo de Teruel, donde terminaba la Avenida de Goya, la trinchera del ferrocarril en direcci├│n a Barcelona segu├¡a al aire, sin cubrir. Una pasarela met├ílica salvaba esa contingencia. Hacia la derecha, sucesivamente se abren reconocibles las calles de Santander, Tarragona-Burgos, Paseo de Teruel, y S. Antonio Mar├¡a Claret. En ese punto la Avenida de Goya comienza una peraltada curva hacia la izquierda, en la que se perfila el Coraz├│n de Mar├¡a (parroquia cat├│lica). El lado izquierdo de la Avenida estaba menos urbanizado, y hoy s├│lo perdura el reciente edificio de 10 plantas que chaflanea la calle C├ínovas. Justo a la derecha, en primer t├®rmino, donde arranca la calle Santander, desde 1887 y hasta 1933 estuvo activa la Estaci├│n de tren de v├¡a estrecha de Cari├▒ena. Abandonada la l├¡nea ese a├▒o, con la entrada en funcionamiento de la l├¡nea de Caminreal, su recorrido por la ciudad fue pronto urbanizado, y el edificio de la estaci├│n piqueteado en 1940. La paralela calle Cari├▒ena recuerda su existencia. En la actualidad, en este punto comienza el espacio de la Glorieta de los Zagr├¡es, confluencia de Anselmo Clav├®, Escoriaza y Fabro, y Goya.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64883300, -0.89395800, '0101000020E610000014ECBFCE4D9BECBF65C8B1F50CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849306291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849306291.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849306291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24255, 'Calle de Pamplona 1937', 'Familiar imagen de Gustavo Freudenthal Neuhaus, fot├│grafo retirado y exc├│nsul del Imperio Alem├ín y de la Rep├║blica de Alemania, junto a su nieta Mar├¡a Rosario ("Charito") Freudenthal Royo posando con dos perrillos en los jardines de su "hotelito" sito en la calle de Pamplona n┬║ 5 (actual de Joaqu├¡n Or├║s), barrio de La Romareda.', 1937, 1937, 1937, 'Anos 30', 'DELICIAS', 41.65055700, -0.89585700, '0101000020E6100000C5909C4CDCAAECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51780064118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51780064118.webp', 'https://www.flickr.com/photos/zaragozaantigua/51780064118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25871, 'Calle Tarragona 2013', 'Entrada al local del n├║mero 14 de la calle de Tarragona, que fuera ocupado por el cine Salamanca, cuyo voladizo se conserva. Al fondo, la calle de Salamanca.', 2013, 2013, 2013, 'Siglo XXI', 'DELICIAS', 41.64835300, -0.89569900, '0101000020E6100000BCEA01F390A9ECBFBAA1293BFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388763531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388763531.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388763531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26061, 'Barrio de Cari├▒ena c.1925', 'Imagen capturada desde la altura de las antiguas naves de carpinter├¡a y general de montaje de los Talleres de Carde y Escoriaza, con una interesante vista panor├ímica del que fuera original Barrio de Cari├▒ena o de la Romareda. En primer t├®rmino, naves de los talleres de herrer├¡a y montaje, y oficinas de la referida empresa, denominada Material M├│vil y Construcciones desde 1920. Detr├ís, el singular barrio de Cari├▒ena, con las traseras de las viviendas unifamiliares vertebradas por el cruce de las calles de San Pedro y de Pamplona, y el murete perimetral del mar de v├¡as la estaci├│n de ferrocarril de Campo Sepulcro. A la derecha, torrecillas de la que fuera f├íbrica de chocolares de Or├║s, y algo m├ís hacia la derecha, fachada principal de la interesante Casa de Convalecientes. Las chimeneas del centro de la imagen corresponden con el gran complejo fabril de Talleres Mercier. Al fondo, poderoso torre├│n cuadrangular de la Facultad de Medicina y Ciencias; hacia la izquierda, rotunda presencia del convento-colegio de las madres Adoratrices Esclavas del Sant├¡simo y de la Caridad, en la calle de Hern├ín Cort├®s esquinero con la calle de la Venerable Madre Sacramento. Cierran la panor├ímica, m├ís a la izquierda, las emergentes torrecillas de la iglesia parroquial de Santa Engracia.', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65034000, -0.89605000, '0101000020E6100000EA95B20C71ACECBFECA353573ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48997388177.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48997388177.webp', 'https://www.flickr.com/photos/zaragozaantigua/48997388177/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22149, 'Av. de Navarra 1958', 'Imagen capturada en la antigua carretera de Logro├▒o, redenominada avenida de Navarra, y centrada en la tranviaria unidad n┬║ 160 dirigi├®ndose al final de la l├¡nea 16 &quot;Portazgo de San Lamberto&quot;, cuyo tendido estaba trazado en el lado de los impares de la avenida. Este &quot;Topolino&quot; ser├¡a desguazado en 1972. El disperso entorno edilicio de la ├®poca posiblemente sea el de las inmediaciones a la calle del Arzobispo Soldevila (a la derecha, fuera de plano). Fuente visual: Jos├® Mar├¡a Valero Su├írez, Centenario del tranv├¡a el├®ctrico. Zaragoza, 1902-2002.', 1958, 1958, 1958, 'Anos 50', 'DELICIAS', 41.65502400, -0.90353800, '0101000020E6100000162F1686C8E9ECBF2C0C91D3D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27481278687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27481278687.webp', 'https://www.flickr.com/photos/zaragozaantigua/27481278687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22152, 'Av. de Navarra 1959', 'Vista a├®rea de la avenida de Navarra y su entorno. Al fondo, el r├¡o Ebro y el barrio de La Almozara. En el centro, la Estaci├│n de Caminreal y las naves de Transportes Ochoa. A la derecha, el Cuartel de Ferrocarriles y el Mercado de Pescados. Abajo, el Castillo Palomar. Fuente visual: Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65734400, -0.91386200, '0101000020E610000030D461855B3EEDBF651C23D923D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28323489712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28323489712.webp', 'https://www.flickr.com/photos/zaragozaantigua/28323489712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22160, 'Avenida de Navarra 1959', 'Vista a├®rea de la avenida de Navarra y su entorno, con el edificio circular del Mercado de Pescados en el centro. A la derecha, estaci├│n de Caminreal. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65598800, -0.90651300, '0101000020E61000005DC30C8D2702EDBFC3482F6AF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30549378343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30549378343.webp', 'https://www.flickr.com/photos/zaragozaantigua/30549378343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22233, 'Avenida de Madrid c.1955', 'Imagen capturada en el arranque de la calle de Ram├│n de Campoamor, esquina con la avenida de Madrid, y centrada en la composici├│n tranviaria formada por el coche n┬║ 65 (antiguo n┬║ 72 transformado) y el remolque n┬║ 89, en servicio en la l├¡nea 5. Torrero-Delicias, a punto de girar hacia nuestra izquierda para curvear la calle de Campoamor e incorporarse luego nuevamente a la avenida de Madrid, donde la plaza de Huesca, para retomar el trayecto de esta l├¡nea de vuelta hasta Torrero. A la derecha de la imagen, la composici├│n coche n┬║ 82 + remolque n┬║ 78 (posiblemente), en servicio en la misma l├¡nea, encaminados hacia Torrero. Tras ellos, el inmueble del n┬║ 165 de la avenida de Madrid, inmediato al arranque de la calle de Las Delicias, y gran solar donde pocos a├▒os despu├®s se construir├¡a el inmueble del n┬║ 161-163 de la avenida, esquinero con la calle de Don Pedro de Luna.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65312200, -0.90600700, '0101000020E61000006A4E5E6402FEECBF29266F8099D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50173250413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50173250413.webp', 'https://www.flickr.com/photos/zaragozaantigua/50173250413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22324, 'Avenida de Madrid 1969', 'Imagen de la composici├│n motor-remolque 109+109 de la l├¡nea 5 del tranv├¡a "Venecia-Delicias" en la Avenida de Madrid, a punto de llegar a la plaza de Huesca (hasta 1962, plaza de Rocasolano). A la derecha, se abre la calle de N┬¬ S┬¬ de Bonaria. A la izquierda, un poco m├ís adelante, la calle D. Pedro de Luna. Los edificios que aparecen en la imagen han sufrido una curiosa inversi├│n: los m├ís altos, hoy son como miniaturas, comparados con los gigantes que han surgido sobre las ruinas de las parcelas que parecen m├ís desvalidas. Esta l├¡nea tranviaria, dos a├▒os despu├®s, ser├¡a clausurada. Fuente visual: Archivo Municipal. Gerardo Sancho. 1969', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.65337800, -0.90512700, '0101000020E61000003E40F7E5CCF6ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16089084439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16089084439.webp', 'https://www.flickr.com/photos/zaragozaantigua/16089084439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22459, 'Los S├¡rex 1968', 'Participantes en un partido de f├║tbol amistoso celebrado en 1968 en el campo de f├║tbol de la estaci├│n de Caminreal, en Las Delicias (al fondo). Los equipos enfrentados estaban formados por un combinado de hosteler├¡a y por empleados del Gran Hotel. Entre los fotografiados posan los componentes del grupo musical Los S├¡rex. Como madrina de la ceremonia, en el centro, Elba Montalvo, cantante del grupo cubano Los Rivero. Algunos de los que aparecen en la imagen son destacados hosteleros de Zaragoza. Fuente: Heraldo de Arag├│n.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65713200, -0.90927300, '0101000020E61000008A58C4B0C318EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31909037883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31909037883.webp', 'https://www.flickr.com/photos/zaragozaantigua/31909037883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22507, 'Colonia Tudor 1962', 'Imagen de la Colonia Tudor finalmente realizada en empinado terreno entre la avenida de Navarra y el castillo Palomar, que queda detr├ís. El proyecto original, de 1942, era mucho m├ís ambicioso y constaba de viviendas de varios tipos para capataces y empleados y para obreros, aunque no fue llevado a cabo. Este proyecto s├¡ desarrollado veinte a├▒os despu├®s constaba de los cinco bloques que aparecen en la fotograf├¡a. En los a├▒os noventa estas viviendas fueron derribadas y la zona reurbanizada.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65582300, -0.91480400, '0101000020E6100000DEFFC7091346EDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50874022983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50874022983.webp', 'https://www.flickr.com/photos/zaragozaantigua/50874022983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22520, 'Colonia Tudor 1962', 'Imagen de la Colonia Tudor ubicada en empinado terreno entre la avenida de Navarra y el castillo Palomar, que queda justo detr├ís. El proyecto original, de 1942, era mucho m├ís ambicioso y constaba de viviendas de varios tipos para capataces, empleados y obreros de esta empresa, aunque no fue llevado a cabo. El proyecto finalmente desarrollado veinte a├▒os despu├®s constaba de s├│lo cinco bloques. Treinta a├▒os despu├®s esta colonia fue derribada y la zona reurbanizada.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65582300, -0.91480400, '0101000020E6100000DEFFC7091346EDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54139500585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54139500585.webp', 'https://www.flickr.com/photos/zaragozaantigua/54139500585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22615, 'Av. de Madrid 1976', 'Imagen de los antiguos edificios que esquinaban la Avenida de Madrid con la calle Delicias, luego derribados para levantar otros m├ís higi├®nicos, modernos y altos. A la izquierda extrema, el n┬║ 4 de la calle Delicias (1969). A partir de ah├¡, y hasta el bloque del n┬║ 173 de la Av. de Madrid (1970), a la derecha extrema, todos los edificios han desaparecido, llev├índose con ellos sus bajos comerciales, como la panader├¡a "ARPAN" (Delicias n┬║ 2), la "Ferreter├¡a Marqueta", y "Modas Yoana" (Av. Madrid n┬║ 167), unos G├®neros de Punto, y otro despacho de "Pan y Reposter├¡a" (Av. Madrid n┬║ 169), y una oficina de la Caja de Ahorros (Av. Madrid n┬║ 171). S├│lo sobrevive, modernizada, la agencia de la caja-banco, que se ha expandido, como el universo, y ocupa casi todo el espacio de los locales. Qu├® cosas. Fuente: Archivo P├║blico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.65294600, -0.90614600, '0101000020E6100000C3D66CE525FFECBFEA060ABC93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19202659722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19202659722.webp', 'https://www.flickr.com/photos/zaragozaantigua/19202659722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22650, 'Calle Don Pedro de Luna c.1975', 'Calle de Don Pedro de Luna, en el barrio de Las Delicias de Zaragoza, vista desde la avenida de Madrid. Fuente: www.facebook.com/photo.php?fbid=853713991317894&set=g...', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65322600, -0.90548100, '0101000020E6100000B0C7444AB3F9ECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21086358078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21086358078.webp', 'https://www.flickr.com/photos/zaragozaantigua/21086358078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22672, 'Calle del Requet├® Navarro 1979', 'Calle del Requet├® Navarro, desde 1979 de Rioja, en una vista de su arranque desde la avenida de Madrid. Centra la imagen el edificio de la Casa del Barrio, antigua f├íbrica de galletas que en los a├▒os 50 fuera Pat├¡n Baile, en el n┬║ 219-219 dupdo. de la avenida, luego derribado. Detr├ís, la calle de Croacia, moderno vial que marcaba tendencia respecto a la traza viaria por venir. A la izquierda, edificio de la Compa├▒├¡a Telef├│nica construido en 1972.', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65221500, -0.91038500, '0101000020E6100000529B38B9DF21EDBFF67AF7C77BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24173708189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24173708189.webp', 'https://www.flickr.com/photos/zaragozaantigua/24173708189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22716, 'Avenida de Madrid, 1974', 'En 1902 fueron abiertas la "Escuelas Nacionales del Castillo", como primer colegio de ni├▒as y ni├▒os del que habr├¡a de ser barrio de Delicias, en la entonces carretera de Madrid a Francia, luego avenida de Delicias. En 1935 los escolares fueron reubicados en los nuevos centros construidos durante la Segunda Rep├║blica, y el edificio fue reutilizado como estafeta de correos. A partir de 1939 recuper├│ sus funciones como colegio, y en 1945 fue redenominado "Escuela Nacional Emilio Moreno Calvete", hasta mediados los a├▒os 70. En la d├®cada de los 90, en un nuevo edificio sobre el solar del antiguo derribado fue inaugurado el actual "CEIP Emilio Moreno Calvete". En la imagen, captura del antiguo edificio colegial, sito en el n┬║ 145 de la avenida de Madrid. A su derecha, inmediato, quedaba el antiguo Cine Espa├▒a, luego Delicias. Fuente visual: Foto Pilar Borobio, incluida en la exposici├│n "Escuelas y escolares en Delicias, 1900-2000", Centro C├¡vico Esquinas del Psiqui├ítrico.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65346100, -0.90415000, '0101000020E610000074B515FBCBEEECBF111B2C9CA4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29931566602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29931566602.webp', 'https://www.flickr.com/photos/zaragozaantigua/29931566602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22821, 'Monsalud 1974', 'In├®dita imagen capturada desde la altura de uno de los modernos bloques de viviendas de la calle "E" (desde 1978 calle de Ram├│n J. Sender) del pol├¡gono 40 Monsalud y centrada en las reci├®n inauguradas instalaciones de ├ügreda Autom├│vil en esta perif├®rica zona entre la V├¡a de la Hispanidad y la avenida de Navarra. Centra la escena el gran garaje-aparcamiento para un centenar de autobuses, adem├ís de un concesionario para exposici├│n y venta de veh├¡culos Mercedes Benz y DKW. Fue dise├▒ado por el arquitecto Jos├® Beltr├ín Navarro, y a la inauguraci├│n con bendici├│n previa asistieron Mois├®s Calvo Pardo, presidente-gerente de la empresa, y Mariano Horno Liria, alcalde. Al fondo y a la izquierda, bloques en construcci├│n en el entorno de la calle "G" del pol├¡gono (actual n┬║ 3 de la calle de Biarritz), y al otro lado de la avenida de Navarra las instalaciones de la Tudor.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65665700, -0.91886000, '0101000020E61000002C4833164D67EDBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51633883347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51633883347.webp', 'https://www.flickr.com/photos/zaragozaantigua/51633883347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22831, 'V├¡a Universitas 1985', 'La ciudad va creciendo y devorando su pasado. En el cruce de la avenida Madrid con v├¡a Universitas (edificio de Telef├│nica en primer plano a la izquierda) a├║n quedaban algunas casas con corral. Pero ya no.', 1985, 1985, 1985, 'Anos 80', 'DELICIAS', 41.65199200, -0.91013700, '0101000020E61000004A253CA1D71FEDBF77A04E7974D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701998757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701998757.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701998757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22834, 'Cuartel Las Delicias c.1987', 'Acuartelamiento ferroviario Las Delicias, en la avenida de Navarra. Ocupado por la Compa├▒├¡a de Ferrocarriles, fue derribado en 2004.', 1987, 1987, 1987, 'Anos 80', 'DELICIAS', 41.65564900, -0.90749600, '0101000020E6100000AF06280D350AEDBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754547999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754547999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754547999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23056, 'Calle del Capit├ín Pina 1994', 'Imagen capturada en el tramo del paseo de Calanda delimitado por las transversales calles de Graus y de Bolivia, y centrado en el cartel anunciador de la construcci├│n de un garaje subterr├íneo que conservar├¡a la denominaci├│n franquista de este vial (calle del Capit├ín Pina, antes calle Pinos) cuyo ancho aspecto era resultado del previo derribo de las parcelas occidentales de esta calle. Este proyecto de ensanchamiento ya hab├¡a sido perfilado (entre la avenida de Madrid y la calle de Domingo Ram) en un Plan Especial aprobado en 1973 que no tuvo desarrollo posterior. De resultas de esta intervenci├│n, el paseo se extiende actualmente desde la avenida de Navarra y hasta la calle de la Duquesa de Villahermosa.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65156700, -0.90362500, '0101000020E6100000D122DBF97EEAECBF9013268C66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449704672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449704672.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449704672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23140, 'Barrio del AVE 2006', 'Avance del proyecto de urbanizaci├│n del nuevo barrio del AVE, presentado en mayo de 2006 y dise├▒ado por el arquitecto Eduardo Leira. Seg├║n ├®l, el paseo de la Estaci├│n ser├¡a "el nuevo paseo de la Independencia". La plaza de la Estaci├│n (luego denominada de El Peri├│dico de Arag├│n) ser├¡a como "el Rockefeller Center de Nueva York". El presidente de Arag├│n, Marcelino Iglesias, consider├│ que era "el mayor impulso nunca dado a esta ciudad". De las nuevas edificaciones, mostradas en color marr├│n, la ├║nica realizada en 2017 es el Centro de Especialidades Inocencio Jim├®nez del Servicio Aragon├®s de Salud, en la avenida de Navarra 78, inaugurado en febrero de 2015. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.66025800, -0.91682600, '0101000020E61000007DEBC37AA356EDBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31830351741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31830351741.webp', 'https://www.flickr.com/photos/zaragozaantigua/31830351741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23189, 'Plaza de Huesca 2010', 'Foto Pedro Zapater Delgado, 2010. Surtidor de gas├│leo en estado de abandono, situado en la plaza de Huesca de Zaragoza hasta su retirada en 2014. Fue instalado en 1960 y dej├│ de prestar servicio dos d├®cadas despu├®s. Fuente: www.heraldo.es/noticias/zaragoza/un_surtidor_olvidado_las...', 2010, 2010, 2010, 'Siglo XXI', 'DELICIAS', 41.65315300, -0.90630800, '0101000020E6100000274D83A27900EDBF64247B849AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19244621146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19244621146.webp', 'https://www.flickr.com/photos/zaragozaantigua/19244621146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23436, 'Castillo de Palomar 1960', 'Finca con casa de campo en forma de castillo, estaba situada en la actual finca del Parque del Castillo Palomar en el barrio de Delicias y estuvo en propiedad privada y en pie hasta la d├®cada de los a├▒os 60, aunque sus ruinas y cimientos se pudieron contemplar hasta que toda aquella zona y ya siendo propiedad municipal se convirti├│ en parque. Fuente : eszaragoza.blogspot.com.es/', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700702280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700702280.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700702280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23443, 'Castillo de Palomar c.1955', '"Colegio Rosa Arj├│. Clase de Gimnasia en el Castillo Palomar". Este Colegio P├║blico estaba en la calle San Antonio Abad, y para ir al patio recorr├¡an medio kil├│metro hasta llegar al entorno del "Castillo Palomar", una finca de la familia Palomar en la que se hab├¡an regalado una casa con apariencia de castillo, en una propiedad que llegaba desde la Avenida de Navarra hasta la Carretera de los Enlaces. Imagen de ni├▒as jugando, con el Castillo Palomar de fondo, tras los pinos. En la actualidad aqu├¡ hay un parque p├║blico de algo m├ís de 55 Ha. de extensi├│n, y todo un nuevo barrio: Monsalud.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945922706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945922706.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945922706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23469, 'Castillo de Palomar c.1929', 'Imagen de la que fuera original casa de Narciso Palomar y Cebri├ín y de Rafaela Mend├¡vil y F├║rida construida entre 1882 y 1920 en el alto de Monsalud dominando una enorme finca que en el momento de realizar esta fotograf├¡a era propiedad de Eustoquia Caballero y Castillejo. A pesar de que Narciso Palomar falleci├│ en 1885 y no vio terminada la gran casa, ├®sta conservar├¡a su nombre desde entonces, llegando esa denominaci├│n hasta nuestros d├¡as. La captura ha sido realizada desde el sur de la enorme propiedad, junto al ascendente camino hasta la gran casa construida en bizarras formas historicistas y mud├®jares sobre un alto que se elevaba casi cien metros respecto de su entorno, visible por ello desde mucha distancia, tal que los antiguos castillos medievales. Al fondo sobresalen los montes de Juslibol por encima de los muros perimetrales del recinto. Fuente visual: Colecci├│n Jos├® Luis Cintora.', 1929, 1929, 1929, 'Anos 20', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30997518928.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30997518928.webp', 'https://www.flickr.com/photos/zaragozaantigua/30997518928/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23477, 'Castillo de Palomar 1943', 'Imagen capturada en el entorno del Castillo Palomar, en la periferia del barrio de Delicias-Terminillo, frente a la estaci├│n de ferrocarril de Caminreal, a la cota 223.5. La fachada principal de ingreso al castillo hace de tel├│n de fondo a un invernal posado donde destaca un sargento, luciendo el caracter├¡stico capote castrense de la ├®poca. Fuente visual: www.todocoleccion.net/', 1943, 1943, 1943, 'Anos 40', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33602265582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33602265582.webp', 'https://www.flickr.com/photos/zaragozaantigua/33602265582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23695, 'Cooperativa de San Antonio 1914', 'La primera cooperativa de casas baratas de Zaragoza fue la "Cooperativa de San Antonio" (abril 1913), para la que el arquitecto Teodoro R├¡os proyect├│ 40 viviendas unifamiliares en las inmediaciones de la carretera de Navarra. Estas casas se destinaban a obreros y empleados de poco sueldo, que pagar├¡an mensualidades hasta convertirse en propietarios de la casa. En 1917 se hizo una ampliaci├│n que llegar├¡a hasta la carretera de Madrid por la calle del Arzobispo (luego, Arzobispo Soldevila). En la imagen, vial central en torno al que se ordenaban las Casas Baratas. Cada dos ventanas, una casa (piso superior, dos habitaciones; piso inferior, patio, "water-closset", comedor, cocina, cuarto amplio). Al fondo, la carretera de Navarra, o de Logro├▒o. Fuente visual: www.facebook.com/photo.php?fbid=855742017781758&set=g... Fuente textual: Mar├¡a Pilar Biel Ib├í├▒ez, Zaragoza y la industrializaci├│n: la arquitectura industrial en la capital aragonesa entre 1875-1936, IFC, 2004', 1914, 1914, 1914, 'Anos 10', 'DELICIAS', 41.65466900, -0.90383500, '0101000020E6100000795DBF6037ECECBF3E5A9C31CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380674223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380674223.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380674223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23701, 'Calle de Antonio Fleta 1964', 'De todas las abundantes acequias que como una red se extend├¡an por Zaragoza, esta imagen nos lleva al barrio de Delicias, al cruce de la calle Antonio Fleta (antes, de Miguel Fleta), con la de N┬¬ S┬¬ de Bonaria (por donde circula el cami├│n), desde la que una acequia bajaba por toda la calle San Antonio Abad, la cruzaba medio al aire, y luego se bifuncaba, yendo un riego hasta la plaza de Huesca, y otra segu├¡a en paralelo a la antigua carretera de Madrid durante un buen tramo. Esta imagen de las acequias al aire era recurrente en la Zaragoza de la periferia. Fotograf├¡a datada gracias a la amable aportaci├│n de Fernando Benito. Fuente visual: Archivo Municipal, Gerardo Sancho Ramo, 1964.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65400400, -0.90515900, '0101000020E610000016C3D50110F7ECBF02BA2F67B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18194641035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18194641035.webp', 'https://www.flickr.com/photos/zaragozaantigua/18194641035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23703, 'Plaza de Huesca 1980', 'La antigua plaza de Gregorio Rocasolano contaba desde 1960 con un surtidor de gas├│leo que aparece en la foto. Fue desmontado en 2014. Fuente: Zaragoza barrio a barrio, 1981.', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65315300, -0.90630800, '0101000020E6100000274D83A27900EDBF64247B849AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18649882333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18649882333.webp', 'https://www.flickr.com/photos/zaragozaantigua/18649882333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23706, 'Calle de Graus 1978', 'Aspecto de la cuesta de la calle de Graus del barrio de Las Delicias, con la calle de Don Pedro de Luna a la espalda y la del Doctor P├®rez Serrano al fondo. A la derecha, bares desaparecidos, como El Pinar, c├®lebre por sus patatas bravas. Fuente: www.rafaelcastillejo.com', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.65189400, -0.90481700, '0101000020E6100000B4ACFBC742F4ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21109557458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21109557458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21109557458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23716, 'Calle de Ram├│n de Campoamor c.1962', 'Vista de la calle de Ram├│n de Campoamor desde la avenida de Madrid, con un tranv├¡a de la l├¡nea 5 "Venecia-Delicias". El edificio de la derecha perdura en 2016; no as├¡ el puesto de venta de cupones. Fuente visual: foto Christian Schnabel, en historiastren.blogspot.com', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65297600, -0.90697300, '0101000020E61000003A5CAB3DEC05EDBF5589B2B794D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27584992994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27584992994.webp', 'https://www.flickr.com/photos/zaragozaantigua/27584992994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23720, 'Av. de Madrid 1964', 'Imagen de la avenida de Madrid, a la altura de la reciente calle denominada Garcilaso de la Vega (izquierda), cuando dos unidades de la serie 40 (n┬║ 44, y n┬║ 47) en servicio en la l├¡nea 14 (Oliver), se est├ín cruzando en el desv├¡o de mitad de trayecto, entre la plaza de Huesca (antigua de Rocasolano, al fondo de la imagen), y el Enlace de Carreteras. Era curiosa la denominaci├│n de esta l├¡nea, porque durante casi veinte a├▒os dio servicio al barrio de Oliver, sin llegar a entrar en ├®l. Estas dos unidades tranviarias fueron retiradas de la circulaci├│n y desguazadas al poco tiempo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65151300, -0.91285100, '0101000020E610000061DEE34C1336EDBF9DF529C764D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31500011746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31500011746.webp', 'https://www.flickr.com/photos/zaragozaantigua/31500011746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23725, 'Avenida Madrid 1978', 'Foto: Pilar Borobio. Aspecto de la avenida de Madrid en 1978, antes de que llegara hasta ella la V├¡a Univ├®rsitas (derecha, sin construir). Varios autobuses urbanos la recorren. Fuente: Heraldo de Arag├│n.', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.65199200, -0.91013700, '0101000020E61000004A253CA1D71FEDBF77A04E7974D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32269486632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32269486632.webp', 'https://www.flickr.com/photos/zaragozaantigua/32269486632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23730, 'Estaci├│n Delicias 1963', 'Panor├ímica que comienza en una vista parcial de la estaci├│n Delicias o de Caminreal, para mostrar luego el campo de f├║tbol de la Renfe, un d├¡a de partido. Fuente: www.facebook.com/photo.php?fbid=10207332728345162&set...', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65713200, -0.90873600, '0101000020E6100000D65416855D14EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33746173495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33746173495.webp', 'https://www.flickr.com/photos/zaragozaantigua/33746173495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23732, 'Av. de Navarra 1980', 'Imagen centrada parcialmente en la gran explanada de acceso (que inclu├¡a ├írboles) a la original estaci├│n del ferrocarril Central de Arag├│n o Caminreal, luego Zaragoza-Delicias. Los andenes y v├¡as quedaban en las traseras del referencial edificio dise├▒ado por el arquitecto Luis Guti├®rrez Soto. Justo a la derecha, fuera de plano, se localizaba el Campo de Deportes Renfe "Delicias" para pr├íctica del balompi├®. Fuente visual: AMZ.', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65713200, -0.90927300, '0101000020E61000008A58C4B0C318EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38492538825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38492538825.webp', 'https://www.flickr.com/photos/zaragozaantigua/38492538825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23734, 'Hostal y garaje Oroel c.1962', 'Imagen capturada desde cierta altura en la avenida de Navarra y centrada en el moderno hostal y garaje Oroel, ubicados en el n┬║ 50 de la avenida, cuando los accesos, la acera y la calzada a├║n no hab├¡an sido urbanizadas convenientemente. A la izquierda, vista parcial del moderno Mercado de Pescados. A la derecha, el vecino y tambi├®n nov├¡simo inmueble edilicio del n┬║ 40 de la avenida. Fuente visual: www.delcampe.net', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65546900, -0.90589000, '0101000020E610000005C078060DFDECBF5A457F68E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45638708542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45638708542.webp', 'https://www.flickr.com/photos/zaragozaantigua/45638708542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23959, 'Cine Delicias 1974', 'Cine Delicias, construido en 1945 con proyecto de Teodoro R├¡os Balaguer en la avenida de Madrid n┬║ 147, en el solar del hom├│nimo cine proyectado en 1923 por Francisco Albi├▒ana, que entre 1925 y 1944 fuera Cinema Espa├▒a. En la imagen, marquesina del cine, clausurado en 1973. A la izquierda, la Escuela Nacional Emilio Moreno Calvete, y a la derecha, la "F├íbrica de alambres y puntas de Par├¡s de Arribas Hermanos", esquinera con la calle de Sangenis.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65322600, -0.90489500, '0101000020E6100000A20BEA5BE6F4ECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907444173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907444173.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907444173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24029, 'Mercado de Pescados 1960', 'Quiso la causalidad que el 18 de julio de ese a├▒o fuera inaugurado el nuevo Mercado de Pescados de la ciudad, con dise├▒o del arquitecto municipal Marcelo Carqu├® Aniesa, y ubicado en la avenida de Navarra, antigua de Caminreal. La imagen captura un emotivo momento de la inici├ítica ceremonia, cuando el plenario de autoridades civiles y militares est├í a punto de recibir el confesional, y tradicionalista, hisopazo. En primera l├¡nea de impacto, Antonio Zubiri Vidal, presidente de la DPZ; Jos├® Manuel Pardo de Santayana, recio gobernador civil; Luis G├│mez Laguna, alcalde; y Jos├® Lacalle Larraga, jefe de la regi├│n a├®rea pirenaica. M├ís resguardados, Juan Cabrera Felipe, rector de la Universidad; Gumersindo Claramunt Pastor, presidente del Banco Zaragozano, y alg├║n teniente de alcalde que otro, como Luis Ari├▒o Malo. Las gafas de sol eran ese d├¡a una necesidad, no una falta de respeto, por supuesto. Unos a├▒os despu├®s, los exteriores de este moderno mercado aparecer├¡an en la pel├¡cula "Culpable para un delito", como escenario del nocturno deambular por un ficticio y portuario barrio chino. El mercado estuvo activo, como tal, hasta los a├▒os 80, en que fue convertido en Centro C├¡vico del barrio de las Delicias. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65555100, -0.90662900, '0101000020E6100000AB5D13D21A03EDBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25351324512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25351324512.webp', 'https://www.flickr.com/photos/zaragozaantigua/25351324512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24793, 'Reloj de sol 2009', 'Foto: Jos├® El├¡as. Trabajos de instalaci├│n en Vadorrey del gnomon del mayor reloj solar del mundo, junto al parque de Oriente, el 30 de octubre de 2009. Se trata de una estructura de acero inoxidable de 46 metros, dise├▒ada por Juan Antonio Ros. El proyecto inclu├¡a el acondicionamiento del entorno, con fuentes, jardines y otras estructuras asociadas. En 2011 se coloc├│ la segmentaci├│n horaria en el pavimento y en 2015 se a├▒adi├│ una esfera met├ílica interpretativa. En 2017 se sigue a la espera de que la obra se complete, configurando la llamada plaza del Tiempo. En la imagen, al fondo, el barrio de la Jota, tras la calle del Marqu├®s de la Cadena. Fuente: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'LAS FUENTES', 41.65420100, -0.86046500, '0101000020E6100000D4484BE5ED88EBBF5801BEDBBCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32441676234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32441676234.webp', 'https://www.flickr.com/photos/zaragozaantigua/32441676234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24034, 'Calle de Arag├│n c.1942', 'Imagen capturada ante el antiguo n┬║ 1 de la calle de Arag├│n, que desde 1937 hab├¡a sido habilitado como provisional iglesia parroquial del barrio de las Delicias, dada la paralizaci├│n de las obras de la iglesia de San Valero en la calle de Unceta. Las instalaciones de la imagen, casi esquineras con la avenida de Madrid (hacia la izquierda, fuera de plano), contaban con dependencias parroquiales en espacial cohabitaci├│n con el grupo de la Juventud Cat├│lica Obrera del barrio, creado en 1934. Esta situaci├│n se prolong├│ hasta que a principios del a├▒o 1947 fue inaugurada formalmente la nueva iglesia parroquial de San Valero, y unos a├▒os antes, esta calle de Arag├│n hab├¡a sido ya redenominada de Don Alonso de Arag├│n. Ninguno de los inmuebles de la imagen perdura. Fuente visual: La Cr├│nica de Zaragoza: Delicias-La Almozara.', 1942, 1942, 1942, 'Anos 40', 'DELICIAS', 41.65400600, -0.90330200, '0101000020E6100000202A8D98D9E7ECBFA3B1F677B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27230000798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27230000798.webp', 'https://www.flickr.com/photos/zaragozaantigua/27230000798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24169, 'Estaci├│n de Caminreal 1933', 'El 2 de abril de 1933 se inaugur├│ el tramo ferroviario conocido como "El Caminreal" comunicando Teruel y Valencia con Zaragoza y enlazando a su vez con la l├¡nea internacional de Canfranc, reci├®n inaugurada en 1928. El dise├▒o y la ejecuci├│n de la estaci├│n de Ferrocarril Zaragoza-Delicias fue llevada a cabo por el arquitecto Luis Guti├®rrez Soto, siendo inaugurada en 1932. La estaci├│n de ferrocarril Zaragoza-Delicias constituye el ejemplo m├ís importante de las diversas estaciones construidas en la l├¡nea Zaragoza-Caminreal. Fuente visual: Archivo Asociaci├│n Amigos del Ferrocarril.', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65753900, -0.90946100, '0101000020E61000003D997FF44D1AEDBF1A6CEA3C2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781164919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781164919.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781164919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24192, 'Estaci├│n Caminreal 1933', 'Imagen de la celebrada llegada, desde Valencia, de los primeros viajeros de la l├¡nea de ferrocarril Caminreal-Zaragoza, en la primavera de 1933. Al fondo, la nueva Estaci├│n terminal de l├¡nea, entre Almozara y Delicias. Delante de ella, la gran &quot;explanada de la Estaci├│n&quot;, y la &quot;Entrada&quot; a la misma desde la carretera de Logro├▒o a Zaragoza. La engalanada y festiva comitiva se dirige hacia la ciudad, que queda a la derecha. En las carrozas, las &quot;se├▒oritas Miss Valencia, Miss Arag├│n, Miss Huesca, la Fallera Mayor de Valencia, y la Matrona de la Rep├║blica&quot; camino de la Diputaci├│n Provincial, a un sentido acto de confraternizaci├│n entre el pueblo valenciano y el aragon├®s. Fuente visual: Fot. Aldea, &quot;Mundo Gr├ífico&quot; (Madrid).', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65671300, -0.90989100, '0101000020E61000007097FDBAD31DEDBFD5EDEC2B0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21725304758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21725304758.webp', 'https://www.flickr.com/photos/zaragozaantigua/21725304758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24193, 'Estaci├│n Delicias 1934', 'En abril de 1933 se inaugur├│ el tramo ferroviario conocido como "El Caminreal" comunicando Teruel y Valencia con Zaragoza, y enlazando a su vez por el norte con la l├¡nea internacional de Canfranc, inaugurada en 1928. En la imagen, la estaci├│n terminal del "Ferrocarril Central de Arag├│n", nombre comercial de la Compa├▒├¡a que gestionaba la l├¡nea, capturada desde la enorme explanada por la que se acced├¡a a ella desde la carretera de Logro├▒o.', 1934, 1934, 1934, 'Anos 30', 'DELICIAS', 41.65753900, -0.90946100, '0101000020E61000003D997FF44D1AEDBF1A6CEA3C2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21905448916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21905448916.webp', 'https://www.flickr.com/photos/zaragozaantigua/21905448916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24856, 'Avenida de Madrid 1973', 'Imagen de la avenida de Madrid, a la altura de la calle Ram├│n de Campoamor (izquierda) y Delicias (derecha), en las inmediaciones de la plaza de Huesca, capturada cuando un grupo de operarios procede al levantamiento de las v├¡as del tranv├¡a tendidas en la avenida, sin tr├ínsito desde su erradicaci├│n de servicios previa. En 1969 ya fue suprimida la l├¡nea 14, Oliver, y a finales de 1971, en cumplimiento de la "terminator" hoja de ruta prevista, le toc├│ a la l├¡nea 5, Venecia-Delicias. La prevista sustituci├│n por autobuses urbanos con motor de explosi├│n (que en alg├║n caso ya comenz├│ en "vida activa" de algunas l├¡neas de tranv├¡a) queda reflejado en la imagen con una unidad de la l├¡nea 21, Plaza del Pilar-Oliver, en direcci├│n a Oliver. Por su parte, la l├¡nea 5 del tranv├¡a fue sustituida por la l├¡nea 31 de bus, Venecia-Delicias, y la 32, Cu├®llar-Delicias, sin aportar novedades en el trazado de la ruta. Grandes e indudables avances de la movilidad moderna, "ad maiorem vehiculi gloriam". Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65312400, -0.90608100, '0101000020E6100000FDDCD0949DFEECBFC91D369199D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31392485172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31392485172.webp', 'https://www.flickr.com/photos/zaragozaantigua/31392485172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24858, 'Pl. de Huesca 1974', 'Foto: Pilar Borobio. Vista de la plaza de Huesca, con la avenida de Madrid a la espalda y la calle de Leonardo Torres Quevedo al fondo. Un autob├║s urbano de la l├¡nea 24 recoge a los pasajeros. Fuente: Heraldo de Arag├│n.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65319100, -0.90662000, '0101000020E6100000DEC83CF20703EDBF51853FC39BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32042343840.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32042343840.webp', 'https://www.flickr.com/photos/zaragozaantigua/32042343840/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25932, 'Calle de Ram├│n Campoamor 1955', 'Imagen capturada desde la avenida de Madrid y centrada en el desemboque desde la calle de Ram├│n Campoamor de la composici├│n 112+102 (motor+remolque) en servicio en la tranviaria l├¡nea 5 "Venecia-Delicias". Aqu├¡ se encontraba la terminal en el barrio de Delicias de esta l├¡nea, en el entorno de la plaza de Rocasolano. Esta unidad motora de la serie de los "100" estuvo en servicio hasta la clausura de la l├¡nea en 1971, siendo transferida luego a la l├¡nea 1 "Bajo Arag├│n", y desguazada en 1975 cuando esta fue tambi├®n clausurada. Como tel├│n edilicio, y de izquierda a derecha, los antiguos inmuebles del n┬║ 84 de la avenida de Madrid y los n├║meros 26, 24 y 22 de la calle de Ram├│n Campoamor, todos ellos desaparecidos. A la derecha, m├¡nima visual del esquinero n┬║ 82 de la avenida de Madrid, que perdura como afortunada excepci├│n a la norma. Fuente visual: foto Jordi Ib├í├▒ez, en Los tranv├¡as de Zaragoza, Javier Pe├▒a Gonzalvo, Jos├® Mar├¡a Valero Su├írez, Zaragoza: DPZ, 1985.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65297600, -0.90697300, '0101000020E61000003A5CAB3DEC05EDBF5589B2B794D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41455524114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41455524114.webp', 'https://www.flickr.com/photos/zaragozaantigua/41455524114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26004, 'La Bombarda 1991', 'Foto: Archivo Taumar (Irene Taul├®s y Rafael Margal├®). Vista a├®rea parcial del barrio de La Bombarda, con solares a├║n sin edificar en primer t├®rmino, y la confluencia de la calle Ramiro I de Arag├│n con la avenida de Navarra (arriba a la izquierda). Arriba a la derecha, el barrio de Monsalud, tras el IES F├®lix de Azara. Fuente: www.facebook.com/photo.php?fbid=1687671944789838&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.65701600, -0.91586800, '0101000020E6100000637E6E68CA4EEDBF7079AC1919D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220301008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220301008.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220301008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26006, 'La Bombarda 1994', 'Foto: Archivo Taumar (Irene Taul├®s y Rafael Margal├®). Vista a├®rea del barrio de La Bombarda, entre la avenida de Navarra (arriba) y la V├¡a Hispanidad (abajo). Fuente: www.facebook.com/photo.php?fbid=1687674321456267&set=...', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65816300, -0.91965500, '0101000020E6100000CB4A9352D06DEDBFF83768AF3ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22220881998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22220881998.webp', 'https://www.flickr.com/photos/zaragozaantigua/22220881998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26007, 'Calle de Juli├ín Sanz Ib├í├▒ez 1994', 'Foto: Archivo Taumar (Irene Taul├®s y Rafael Margal├®). Vista a├®rea del entorno de la calle de Juli├ín Sanz Ib├í├▒ez, que atraviesa la imagen de arriba abajo. A su derecha, la avenida de Madrid. Fuente: www.facebook.com/photo.php?fbid=1687671941456505&set=...', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65177800, -0.91659000, '0101000020E610000086E63A8DB454EDBF4B2025766DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22221560139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22221560139.webp', 'https://www.flickr.com/photos/zaragozaantigua/22221560139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22617, 'Calle de Gal├ín Bergua 1976', 'Urbanizaci├│n de Las Delicias entre Los Enlaces y el Hospital Psiqui├ítrico. Centra la imagen el pol├®mico bloque de Construcciones Cinca S.A., levantado sin licencia de obra y contraviniendo ordenanzas municipales, luego legalizado a la carta. Al fondo, bloque sobre solar de la f├íbrica de Criado y Lorenzo. Tras ├®l, la avenida de Madrid, y a su izquierda, esqueleto del bloque en construcci├│n junto a Los Enlaces. En primer t├®rmino, temporal paisaje lunar.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64832000, -0.91562000, '0101000020E61000005B087250C24CEDBFDEAB5626FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19310103081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19310103081.webp', 'https://www.flickr.com/photos/zaragozaantigua/19310103081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22747, 'Calle del Escultor Palao 1976', 'Imagen de la calle Escultor Palao en el "Pol├¡gono 22", cuando era un sorprendente vial a tiempo parcial, pues parece ser que la empresa constructora "Criado y Lorenzo, SA" cerraba los portones al final de cada jornada, y los peatones y caminantes deb├¡an buscar entonces otra ruta. Cosas de la Zaragoza de la ├®poca. Lo mismo suced├¡a en las inmediatas Roger de Flor, y Gal├ín Bergua. Tras la valla abierta con el s├¡mbolo "prohibido el paso", la calle Gal├ín Bergua. Al fondo, antiguos bloques inmediatos a la desaparecida f├íbrica de Criado y Lorenzo, luego derribados y sustituidos por otros m├ís nuevos. Detr├ís de ellos, a la derecha, emerge en obras el moderno bloque del n┬║ 96 de la V├¡a Hispanidad. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64859500, -0.91534000, '0101000020E61000007C0F971C774AEDBFB0AC342905D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32402673544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32402673544.webp', 'https://www.flickr.com/photos/zaragozaantigua/32402673544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22769, 'Calle de Ram├│n Salanova 1976', 'Imagen capturada desde la montaraz y agreste zona donde se trazar├¡a luego la prolongaci├│n de Duquesa Villahermosa, con interesante visual del estado de las cosas en la zona suroeste del "Manicomio". A la izquierda, vista parcial de dos de los trillizos bloques de la nov├¡sima calle de Ram├│n Salanova. En el centro de la imagen, descampados varios para tr├ínsito peatonal, y aparcamiento, que se extienden hasta el muro perimetral del enorme espacio verde del Hospital Psiqui├ítrico de Nuestra Se├▒ora del Pilar, del que emergen algunos de sus pabellones. Al fondo, estructuras de los nuevos bloques en construcci├│n entre la calle de Barcelona, y la de Daroca. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64558000, -0.91245400, '0101000020E61000001D5723BBD232EDBFD1798D5DA2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33445685111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33445685111.webp', 'https://www.flickr.com/photos/zaragozaantigua/33445685111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22946, 'N.┬¬ S.┬¬ del Salz 1981', 'Campo del Club de F├║tbol Atl├®tico Delicias, denominado de Nuestra Se├▒ora de Guadalupe, y localizado entre las calles del Escultor Palao, de Nuestra Se├▒ora del Salz (tel├│n de fondo edilicio de la imagen), de Terrer y de Demetrio Gal├ín Bergua. Este campo de tierra del barrio de Las Delicias estuvo activo hasta que en 1983 el planeamiento urban├¡stico ubic├│ en este emplazamiento el Colegio P├║blico Ciudad de Zaragoza y el hom├│nimo Pabell├│n Deportivo Municipal. Fuente visual: Antonio Calvo Pedr├│s, AMZ.', 1981, 1981, 1981, 'Anos 80', 'DELICIAS', 41.64850400, -0.91474000, '0101000020E61000002FFA0AD28C45EDBFA0A9D72D02D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38486173246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38486173246.webp', 'https://www.flickr.com/photos/zaragozaantigua/38486173246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23698, 'Calle de Terrer 1977', 'Escena nival capturada desde el bloque de la calle de Barcelona, tramo actualmente denominado calle de la Villa de Andorra, esquinero con la calle de Sig├╝├®s, y centrada en los inmuebles de los n├║meros 2-4 de la calle de Terrer, en cuyos bajos y desde 1972 destaca el Centro Comercial Delicias, mercado de proximidad que perdura. Ante ├®l pasa un autob├║s urbano de la l├¡nea 31. Torrero-Delicias. En el solar de primer t├®rmino, ocupado por camiones, ser├í construido luego el Centro de Salud Universitas. A la izquierda, la calle de Nuestra Se├▒ora del Salz, donde destaca el Campo de Nuestra Se├▒ora de Guadalupe para la pr├íctica futbol├¡stica, hasta que en 1983 el planeamiento urban├¡stico de la zona dedic├│ estos terrenos para el Colegio P├║blico Ciudad de Zaragoza y el hom├│nimo Pabell├│n Deportivo Municipal. M├ís all├í, bloques de la calle de Demetrio Gal├ín Bergua.', 1977, 1977, 1977, 'Anos 70', 'DELICIAS', 41.64736600, -0.91368600, '0101000020E61000008E041A6CEA3CEDBF6B459BE3DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15808433362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15808433362.webp', 'https://www.flickr.com/photos/zaragozaantigua/15808433362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23727, 'Gal├ín Bergua 1978', 'Irrepetible imagen centrada en el montaraz barbecho urban├¡stico de la calle Demetrio Gal├ín Bergua, en el tramo delimitado por las calles de Fray Juan Regla (tras los bloques del fondo), y la del Escultor Palao. Las parcelas de la derecha, recayentes a la calle de N┬¬ S┬¬ del Salz, incluyendo el enternecedor acceso a las parcelitas del n┬║ 10 A, B, C, D, y E de esa calle, perduran de forma prodigiosa. La terrosa pista de primer plano, por la que caminan algunos vecinos se convertir├í, al tiempo, en la acera de acceso a los modernos bloques de los n├║meros 11-21 de Gal├ín Bergua. Fuente visual: Banco de Im├ígenes/Asociaci├│n de Vecinos Barrio de San Jos├®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.64933200, -0.91571500, '0101000020E6100000CB9C2E8B894DEDBF861F9C4F1DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32348482514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32348482514.webp', 'https://www.flickr.com/photos/zaragozaantigua/32348482514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21226, 'Caballos en el Ebro 1905', '"Partida de la balsa", fotograf├¡a del teniente Eladio Pascual, 1905. Imagen perteneciente al reportaje "Pr├ícticas de paso de r├¡os realizadas por el Regimiento Lanceros del Rey, 1┬║ de Caballer├¡a". En este caso, se trata de pasar de una orilla a otra del Ebro, mediante una balsa construida con sacas rellenas de paja. Los caballos atravesaron el r├¡o a nado. Al fondo parece vislumbrarse la silueta del Pilar. La zona donde se realizan las maniobras es, probablemente, aguas abajo, entre las desembocaduras de los r├¡os G├íllego y Huerva, que tambi├®n fueron objeto de pr├ícticas militares en este mismo conjunto de ejercicios. Fuente: Revista La ilustraci├│n Espa├▒ola y Americana, 15-9-1905. hemerotecadigital.bne.es/', 1905, 1905, 1905, 'Anos 1900', 'LAS FUENTES', 41.65237400, -0.86017500, '0101000020E610000011C7BAB88D86EBBF5F61C1FD80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18465102323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18465102323.webp', 'https://www.flickr.com/photos/zaragozaantigua/18465102323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23741, 'Calle de N.┬¬ S.┬¬ del Salz 1976', 'Imagen capturada a la altura del n├║mero 41 de la calle de N.┬¬ S.┬¬ del Salz y centrada en una singular pintada que proclama "┬íViva el alcalde!" y aparece firmada por la no menos singular facci├│n ultraderechista "Alianza anticomunista/anticapitalista", como forma de respaldar al regidor Miguel Merino Pineda en el denominado "conflicto de las vallas", cuando durante la urbanizaci├│n del Pol├¡gono 22 (terrenos de la antigua f├íbrica de Criado y Lorenzo) la empresa constructora "CYLSA" (Criado y Lorenzo, SA) cerraba los portones de obra al final de cada jornada que permit├¡an el paso por el recinto vallado de unos 50.000 metros cuadrados, cortando as├¡ los pasos usados por los peatones que deb├¡an buscar otra ruta dando enorme rodeo. En primer t├®rmino, un SEAT 124, y al fondo la esquina con la calle del Escultor Palao.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64857600, -0.91450400, '0101000020E610000038F581E49D43EDBF397CD28904D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54252959002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54252959002.webp', 'https://www.flickr.com/photos/zaragozaantigua/54252959002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25980, 'Delicias 1968', 'Desde las once alturas del n┬║ 9 de la calle de Demetrio Gal├ín Bergua, panor├ímica del barrio de Las Delicias. En primer t├®rmino, la calle de Nuestra Se├▒ora del Salz, con detalle del n┬║ 16, en contrucci├│n, y del singular acceso a las fincas A, B, C y D del n┬║ 8, y las A, B, C, D, y E del n┬║ 10. Detr├ís, la calle de Mos├®n Andr├®s Vicente, cruzada de izquierda a derecha por las calles de Fray Luis Regla, de Antonio Bravo, de Eloy Mart├¡nez, y del Escultor Palao. A├▒os despu├®s, algunos inmuebles de esta calle ser├¡an sustituidos por bloques m├ís altos, como en el caso de los n├║meros 12-14, 18, y 20. A la derecha, traseras de los bloques de la plaza, actual calle, de la Ciudadela, que eclipsan a los norte├▒os pabellones de Dronda, y de Santa Ana, del Hospital Psiqui├ítrico Nuestra Se├▒ora del Pilar. Al fondo, la perspectiva permite ver las cuatro torres del Pilar, con la c├║pula mayor en medio. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64736100, -0.91414300, '0101000020E610000027C11BD2A840EDBF59DAA9B9DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15236729062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15236729062.webp', 'https://www.flickr.com/photos/zaragozaantigua/15236729062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21534, 'Barrio de la Romareda 1927', 'Panor├ímica del barrio de la Romareda. Este conjunto conform├│, con otros similares adyacentes, el actual barrio de Las Delicias. Se situ├│ en traseras de la Estaci├│n de Campo Sepulcro, en la parte comprendida entre las actuales avenidas de Valencia y Madrid. Tomaba su nombre de la acequia alta de la Romareda. Fuente visual de la imagen: M┬¬ Pilar Biel Ib├í├▒ez, Zaragoza y la industrializaci├│n: la arquitectura industrial 1875-1936, IFC, 2004.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19472107288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19472107288.webp', 'https://www.flickr.com/photos/zaragozaantigua/19472107288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21714, 'Ciudad Jard├¡n 1936', 'Emplazamiento de Casas Baratas que se proyecta construir en la zona de ensanche de Miralbueno, secci├│n 6┬¬. Zaragoza, mayo de 1936. Fuente: AMZ.', 1936, 1936, 1936, 'Anos 30', 'DELICIAS', 41.64617800, -0.90247800, '0101000020E6100000ED80EB8A19E1ECBF85B2F0F5B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18934629413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18934629413.webp', 'https://www.flickr.com/photos/zaragozaantigua/18934629413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21716, 'Ciudad jard├¡n 1934', '"Plano Emplazamiento de 500 casas baratas que se proyectan en la Zona de Ensanche de Miralbueno [Ciudad Jard├¡n]", septiembre de 1934. Fuente: AMZ.', 1934, 1934, 1934, 'Anos 30', 'DELICIAS', 41.64617800, -0.90247800, '0101000020E6100000ED80EB8A19E1ECBF85B2F0F5B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19554355432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19554355432.webp', 'https://www.flickr.com/photos/zaragozaantigua/19554355432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21912, 'Campo Sepulcro 1939', 'Imagen capturada en el gran complejo fabril de la empresa Material M├│vil y Construcciones sita al oeste de la estaci├│n de ferrocarril de Campo Sepulcro y centrada en la ceremonia de la "Fiesta de la exaltaci├│n del Trabajo" instituida por el Fuero del Trabajo y que se deb├¡a celebrar obligatoriamente el 18 de julio coincidiendo con el aniversario del "Glorioso Alzamiento Nacional". Esta fiesta respond├¡a al "nuevo" concepto del trabajo como "fiesta de la hermandad y de la unidad de los productores incorporada en la alegr├¡a un├ínime de la Patria al festejar el 18 de julio". De esa forma, los "productores" ten├¡an que celebrar ese d├¡a "en agrupaci├│n ordenada", reunidos en sus respectivas empresas y dispuestos "conforme a la jerarqu├¡a natural de la producci├│n" en lugar presidido por la Bandera Nacional, las del "Movimiento" y el retrato del "Caudillo" en sitio de honor, y si fuera posible, con m├║sica de los respectivos himnos. Cerraban la fiesta los gritos reglamentarios de "ESPA├æA, UNA; ESPA├æA, GRANDE; ESPA├æA, LIBRE; ┬íARRIBA ESPA├æA!" En la imagen, vista en altura del momento en que los "productores", dispuestos en el gran pasillo central flanqueado por las naves y talleres de esta empresa, saludan con el reglamentario brazo en alto a la ense├▒a nacional que preside el acto. Al fondo, traseras de la larga calle de Roche y campos de cultivo que flanquean la carretera de Zaragoza a Valencia hasta los pabellones del cuartel de Palafox.', 1939, 1939, 1939, 'Anos 30', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52156383140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52156383140.webp', 'https://www.flickr.com/photos/zaragozaantigua/52156383140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22181, 'Calle Escosura 1959', 'Imagen a├®rea sobrevolando el antiguo entorno, en primer t├®rmino, de las calles Escosura, Tarragona y ├üvila, para obtener una buena perspectiva del complejo fabril de Material M├│vil y Construcciones, junto a la estaci├│n de Campo Sepulcro y el barrio de Cari├▒ena, a la derecha. A la izquierda, indefinido enlace con el barrio de Delicias. Al fondo, la Aljafer├¡a y la Almozara. Fuente visual: fondo fotogr├ífico TAF Helic├│pteros SA , en Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.64892300, -0.89843100, '0101000020E61000006CCD565EF2BFECBFA54FABE80FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31895640275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31895640275.webp', 'https://www.flickr.com/photos/zaragozaantigua/31895640275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22249, 'Barrio de la Romareda 1956', 'Imagen capturada desde la altura de las nuevas naves seriadas de los talleres de Material M├│vil y Construcciones, S.A. en terrenos inmediatos al antiguo barrio de la Romareda, que a la izquierda se presenta arbolado y vertebrado por las calles del Moncayo y la antigua de Gasc├│n, actual de Escoriaza. Al fondo, inmuebles de la calles de Salamanca, Tarragona, ├üvila y Escosura.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65070900, -0.89667300, '0101000020E6100000429946938BB1ECBF3F1BB96E4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52321858824.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52321858824.webp', 'https://www.flickr.com/photos/zaragozaantigua/52321858824/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21544, 'Reformatorio Buen Pastor 1921', 'Dibujo de Regino Borobio del Reformatorio del Buen Pastor de Zaragoza, 1921. La Torre Ramona se acondicion├│ para reformatorio en 1917 y dej├│ de funcionar como tal en 1955. Tras funcionar como colegio de monjas, el edificio sigue en pie en la calle de Mar├¡a de Arag├│n del barrio de Las Fuentes en 2015. Fuente: Eloy Fern├índez Clemente, "Gente de orden", Ibercaja, 1995.', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64094400, -0.86212600, '0101000020E61000006000E1438996EBBFA148F7730AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20124614286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20124614286.webp', 'https://www.flickr.com/photos/zaragozaantigua/20124614286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22252, 'Campo Sepulcro 1953', 'Imagen capturada en el interior de una de las naves de la factor├¡a de Material M├│vil y Construcciones sita en el barrio de Cari├▒ena o de la Romareda, junto a la estaci├│n de Campo Sepulcro. La escena se centra en uno de los dos chasis del microcoche "Pulga" aqu├¡ carrozado, una versi├│n m├ís moderna del original proyecto mallorqu├¡n patentado en 1950 y desarrollado en Ontinent (Valencia). Los microcoches o coches diminutos, algunos de ellos sustentados sobre tres ruedas como este "Pulga", conocieron un singular desarrollo en la Espa├▒a de la larga posguerra (a├▒os 50 y 60), siendo este modelo "Pulga" uno de los pioneros, si bien su producci├│n fue muy modesta. Tras el veh├¡culo de primer t├®rmino, uno de los vagones ferroviarios fabricados en esta f├íbrica.', 1953, 1953, 1953, 'Anos 50', 'DELICIAS', 41.65061300, -0.89723100, '0101000020E6100000D3A23EC91DB6ECBF1DAD6A4947D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54723497577.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54723497577.webp', 'https://www.flickr.com/photos/zaragozaantigua/54723497577/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22262, 'Troleb├║s 1966', '1966. El Troleb├║s 51 de la L├¡nea "Ciudad Jard├¡n" haciendo la curva que desde Franco y L├│pez le permite seguir por Duquesa de Villahermosa para llegar a su destino en la Ciudad Jard├¡n, dar la vuelta en la calle Pedro de Luna, y coger San Juan Bosco para retornar a la Terminal de la Plaza de Santa Engracia. En primer t├®rmino, un taxi caracter├¡stico de la ├®poca en Zaragoza. A la izquierda, el Colegio de las "Josefinas" (Hijas de San Jos├®). Al fondo, las naves del inmenso pol├¡gono de Carde y Escoriaza, que llegaban hasta lo que luego, ya urbanizada, ser├í la Plaza de Roma', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64828000, -0.90216600, '0101000020E61000003605323B8BDEECBF5053CBD6FAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14788184428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14788184428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14788184428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22335, 'Calle Santander 1969', 'Pintura de Eduardo Laborda titulada "La calle Santander de Zaragoza". Posiblemente se trate del nuevo bloque de viviendas del n┬║ 32, esquina con la calle Jos├® Pascasio Escoriaza, tan chocante con el hasta entonces m├ís humano en escala entorno de la antigua estaci├│n de ferrocarril de Campo Sepulcro, con sus parcelas, huertos traseros... Al fondo, tal vez los bloques de las viviendas militares de Anselmo Clav├®, frente a la estaci├│n. Fuente visual: "Eduardo Laborda. Simbolismo barroco", Cajal├│n, 2006.', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64916200, -0.89666200, '0101000020E6100000471CB28174B1ECBF29E78BBD17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19537993041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19537993041.webp', 'https://www.flickr.com/photos/zaragozaantigua/19537993041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22564, 'Plaza de Roma 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 08/09/1974. Los sucesivos proyectos de "Casas Baratas" y de ordenaci├│n urban├¡stica del crecimiento de la ciudad por el oeste dejaron pocas realidades en la zona del original barrio de la Romareda, o de Cari├▒ena, salvo la aislada intervenci├│n de la "Ciudad Jard├¡n". Hab├¡a demasiados intereses especulativos en su contra y, adem├ís, la omnipotente presencia del enorme complejo fabril de Escoriaza, en las traseras de Campo Sepulcro, condicionaba cualquier actuaci├│n. Cuando esta f├íbrica se deslocaliz├│ a otra ubicaci├│n, se abrieron nuevas calles, y la urbanizaci├│n de la zona (grandes bloques de viviendas) avanz├│ r├ípidamente al albur del desarrollismo sesentero. As├¡, la plaza de Roma y la estrat├®gica Urbanizaci├│n Parque Roma vieron la luz en fecha tan reciente como 1972, en un entorno irreconocible para quien recordara el paso del antiguo ferrocarril de Cari├▒ena justo aqu├¡. En la imagen, la plaza de Roma vista en altura, con la calle Vicente Berdus├ín a la derecha, luego la calle Italia, y el arranque, a la izquierda, de Duquesa Villahermosa.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.64948200, -0.89899000, '0101000020E610000014CB2DAD86C4ECBF9BABE63922D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15231545788.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15231545788.webp', 'https://www.flickr.com/photos/zaragozaantigua/15231545788/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22585, 'Calle Delicias c.1973', 'Vista de la calle Delicias de Zaragoza desde su embocadura en la calle Duquesa Villahermosa. A la izquierda, colegio p├║blico Andr├®s Manj├│n. Fuente: www.facebook.com/photo.php?fbid=1680995642145619&set=...', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64792500, -0.90372300, '0101000020E61000008693347F4CEBECBF62A1D634EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15647214881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15647214881.webp', 'https://www.flickr.com/photos/zaragozaantigua/15647214881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22599, 'D. Pedro de Luna 1975', 'El denominado "D├¡a del Ahorro", celebrado a bombo y platillo como si de un ejercicio de participaci├│n democr├ítica en la econom├¡a se tratara, era sin embargo algo m├ís pedestre, y menos revolucionario: un puro ejercicio de captaci├│n del ahorro de los pobres por parte de las entidades gestoras del dinero ajeno que, a cambio, "regalaban" libros sobre recuerdos regionalistas entra├▒ables y amables, algunos sesudos libros de historia para decorar estanter├¡as, frescas colonias de garraf├│n, et cetera. De esta forma, y otras m├ís, la entidad de ahorro que aparece en la imagen consigui├│ cuatriplicar sus recursos ajenos en pocos a├▒os, convirti├®ndose en la tercera de las Cajas Confederadas espa├▒olas. Otro asunto muy distinto era en qu├® invert├¡a luego esos dineros, siquiera si lo hac├¡a en la "regi├│n aragonesa" (y Rioja, por supuesto), y con qu├® resultados. En la imagen, una de las filas, o "colas" que se organizaban a la entrada de estas entidades de ahorro en esos d├¡as tan se├▒alados, de "fiesta del ahorro". La clase social de quienes forman la cola es esa que est├í acostumbrada a hacer cola siempre, incluso para dar su dinero a un inter├®s rid├¡culo, o a cambio de un libro de cocina. Estamos en la que fuera calle de Jos├® Arias, luego denominada D. Pedro de Luna, casi en la esquina con el antiguo Camino de la Mosquetera y la acequia de la Romareda, luego Duquesa Villahermosa. La agencia de la entonces caja, hoy banco, sigue en el mismo sitio. Lo que ha desaparecido es el edificio de ladrillo de su izquierda. Fuente: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.64822400, -0.90329200, '0101000020E61000003CA1D79FC4E7ECBFBC3D0801F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18582357213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18582357213.webp', 'https://www.flickr.com/photos/zaragozaantigua/18582357213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22742, 'Calle de Vicente Berdus├ín 1973', 'A lomos de un mulo, un avezado jinete (el detalle del modelo de calzado que gasta lo delata) cruza con resoluci├│n por el final de la calle de Vicente Berdus├ín y se encamina hacia la calle de la Duquesa de Villahermosa. De fondo, portal de ingreso al moderno bloque esquinero del n┬║ 24 de Vicente Berdus├ín, actual n┬║ 46. A la izquierda, local reservado para instalar una sucursal de la Caja de Ahorros de la Inmaculada. A la derecha, local comercial donde a├▒os despu├®s se constituir├í la Ferreter├¡a Arias. A espaldas del fot├│grafo, el antiguo y gran complejo industrial de Material M├│vil y Construcciones, ya redenominada Construcciones y Auxiliar de Ferrocarriles, y en proceso de reubicaci├│n en unas nuevas instalaciones en la avenida de Catalu├▒a.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.64983700, -0.89894600, '0101000020E61000002CD7DB662AC4ECBF895DDBDB2DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31800517187.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31800517187.webp', 'https://www.flickr.com/photos/zaragozaantigua/31800517187/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22751, 'Calle de Escosura 1976', 'Imagen del calificado como "├║ltimo ├írbol de Escosura", que tambi├®n fue finalmente arrancado durante las obras de vialidad y aguas que tras varios meses renovaron el abastecimiento y saneamiento de esta antigua calle, antes denominada de Roche. El ├írbol estaba ubicado a la altura del n┬║ 38-B, en la imagen flanqueado por dos parcelas luego sustituidas por modernos edificios. Hacia la derecha, direcci├│n avenida de Valencia. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64798500, -0.89842000, '0101000020E61000007250C24CDBBFECBF37A6272CF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32611850383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32611850383.webp', 'https://www.flickr.com/photos/zaragozaantigua/32611850383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23041, 'Calle de Vicente Berdus├ín 1994', 'Imagen capturada durante la urbanizaci├│n de la calle de Vicente Berdus├ín y el tramo de la calle de Escoriaza y Fabro comprendido entre esta calle y la avenida de Madrid. En primer t├®rmino, veh├¡culos aparcados sobre los solares de antiguas parcelas derribadas entre las calles de Rom├ín Izuzquiza y de Fuendetodos, donde a finales de esta d├®cada se construir├¡a el actual inmueble del n┬║ 30 de la calle de Vivente Berdus├ín. Hacia el fondo y a la izquierda, bloques de viviendas del camino de la Mosquetera y de las calles de Hilari├│n Eslava. Navas de Tolosa y Do├▒a Blanca de Navarra. Al fondo, bloques de la calle de Fuenterrab├¡a. A la derecha, bloques de la urbanizaci├│n Parque Roma. La urbanizaci├│n de esta zona inclu├¡a la renovaci├│n del servicio de alcantarillado para resolver las cr├│nicas deficiencias de evacuaci├│n de aguas pluviales que se acumulaban en el paso a desnivel de la avenida de Madrid.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65087700, -0.89879700, '0101000020E6100000EFC517EDF1C2ECBFFB5B02F04FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50380195132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50380195132.webp', 'https://www.flickr.com/photos/zaragozaantigua/50380195132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23122, 'V├¡a Univ├®rsitas 2006', 'Foto: Mar├¡a Torres-Solanot. Construcci├│n del Centro C├¡vico Esquinas del Psiqui├ítrico, en la V├¡a Univ├®rsitas 30-32. En 2003 fueron adjudicadas las obras de este entorno por parte del Gobierno de Arag├│n al grupo Bruesa. Los equipamientos municipales incluidos fueron un pabell├│n polideportivo, un teatro y este centro, inaugurado en 2010. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.64679300, -0.90780100, '0101000020E6100000C7D5C8AEB40CEDBF1024EF1CCAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31130296583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31130296583.webp', 'https://www.flickr.com/photos/zaragozaantigua/31130296583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23317, 'Plaza de Roma 1968', '1968. Familia Rold├ín. "Gravera (Plaza Roma) vista desde la C/ Italia". La urbanizaci├│n del pol├¡gono industrial de Carde y Escoriaza en las traseras de la Estaci├│n Campo Sepulcro iba a suponer que la ciudad tuviera una "Plaza de Roma" modelada como eje entre Duquesa Villahermosa, y las nuevas calles de Santander y Vicente Berdus├ín, adem├ís de propiciar el crecimiento de altos y modernos bloques residenciales. En la imagen, familiar posado a la entrada de la calle Desiderio Escosura, desde lo que m├ís tarde ser├í la Plaza de Roma, con el enorme bloque de entrada a la calle en plena construcci├│n. Al fondo, el no menos impresionante Edificio Torresol. A la izquierda, ins├│lita vista de las calles Tarragona y ├üvila. Antes, restos piqueteados de las naves de Carde y Escoriaza, utilizados como parque infantil de juego, como pasaba en todos los barrios de la periferia de la ciudad, sin que aparentemente ninguna madre entrara en coma.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.64898500, -0.89908700, '0101000020E6100000B247A81952C5ECBF1B4CC3F011D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14783752810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14783752810.webp', 'https://www.flickr.com/photos/zaragozaantigua/14783752810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23693, 'Hospital Psiqui├ítrico 1964', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 4/7/1964. Instalaciones del Hospital Psiqui├ítrico Nuestra Se├▒ora del Pilar de Zaragoza (manicomio). Al fondo, la capilla que a├║n se levanta en el parque. En primer plano, busto con arbusto de D. Manuel Dronda, pr├│cer local fallecido el 1 de diciembre de 1899, que hab├¡a dedicado tiempo y fortuna a la mejora del manicomio, comprando terrenos y mandando construir pabellones. La DPZ acord├│ que a su cad├íver se le hiciera una mascarilla funeraria (por el escultor Palao) para un busto fundido en metal que honrara su memoria en lugar principal del establecimiento.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.64685600, -0.91068400, '0101000020E6100000E2B19FC55224EDBF569C6A2DCCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15024451200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15024451200.webp', 'https://www.flickr.com/photos/zaragozaantigua/15024451200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23702, 'San Sime├│n, o los Gigantes en el manicomio 1925', 'Se estiman en unos 400 los tipos de trastornos mentales que acompa├▒an al ser humano en su tr├ínsito por este valle de l├ígrimas. Entre los m├ís comunes se encuentran los trastornos afectivos (depresiones y distimias), de ansiedad (fobias, angustias, obsesivos compulsivos, somatizaci├│n ...), adicciones (inn├║meras), trastornos psic├│ticos (esquizofrenia, bipolaridad ...), y aquellos asociados a la tercera edad (demencias, trastornos del sue├▒o ...) A pesar de sus enormes complejidades, la "locura", como simplificaci├│n extrema del asunto, es interpretada culturalmente como un defecto, un estigma: loco es quien ha perdido la raz├│n. Desde que en la edad media se pretend├¡a sanar al loco mediante la "extracci├│n de la piedra de la locura", o cirug├¡a mayor, han sido varias las estrategias de las pol├¡ticas p├║blicas a la hora de afrontar este tema, aunque la m├ís generalizada ha sido la asociada con el estigma que le acompa├▒a: poner al loco fuera de circulaci├│n como medida de saneamiento social, y recluirlo en un hospital, junto a los pobres. Hasta que en 1914 se desarrolla la enfermer├¡a mental de car├ícter laico, y en los a├▒os 20 se crea la Escuela Nacional de Sanidad y la Escuela de Psiquiatr├¡a, los tratamientos consist├¡an en un internado donde se velaba por la salud corporal, la alimentaci├│n y la educaci├│n en la doctrina cristiana. En Zaragoza, la DPZ acord├│ construir seg├║n estos preceptos, en 1873, un Manicomio Modelo en la Granja de N┬¬. S┬¬. del Pilar, en el Terminillo. Hasta entonces, los asilados estaban ingresados en el Hospital de Gracia. Una vez terminados, los nuevos pabellones ten├¡an capacidad para 600 enfermos, con casi 4 hect├íreas de buena huerta alrededor. En 1912 este Manicomio pas├│ a depender del Estado. En la imagen, el Rey y la Reina encabezan la tradicional comparsa de Gigantes en los jardines y pabellones del Manicomio, para fiestear a los internos. ├ëstos observan atentamente a los inanimados artefactos despojados de sus titiriteros, mientras que uno de ellos pref', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.64690100, -0.91150000, '0101000020E61000005EBA490C022BEDBFF65FE7A6CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18484244615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18484244615.webp', 'https://www.flickr.com/photos/zaragozaantigua/18484244615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23704, 'Calle Delicias 1925', 'Fuente: M┬¬ Pilar Biel Ib├í├▒ez, Zaragoza y la industrializaci├│n: la arquitectura industrial 1875-1936, IFC, 2004.', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65027300, -0.90474300, '0101000020E6100000211E8997A7F3ECBF643C4A253CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19039560603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19039560603.webp', 'https://www.flickr.com/photos/zaragozaantigua/19039560603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23705, 'Calle Sangen├¡s 1924', 'Acceso de los Talleres Chalmeta en 1924. Fundados en 1919, produc├¡an envases met├ílicos, art├¡culos de hojalater├¡a y estampaciones sobre metales. Estaban situados en la calle de Antonio Sangen├¡s 40 del barrio de las Delicias. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65013000, -0.90335800, '0101000020E6100000198F52094FE8ECBF0113B87537D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19845170688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19845170688.webp', 'https://www.flickr.com/photos/zaragozaantigua/19845170688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23707, 'Isabel de Borb├│n 1913', 'Visita de la infanta Isabel de Borb├│n, "la Chata", hija de la reina Isabel II, al Manicomio de Zaragoza en julio de 1913. Le acompa├▒an el prior del Manicomio de Nuestra Se├▒ora del Pilar, la superiora y el m├®dico director, dr. Gimeno Riera. Fuente: Fotograf├¡a de Aurelio Grasa publicada en el libro "Aurelio Grasa 1893-1972", Galer├¡a Costa, 3, 1976. P├ígina 37. Form├│ parte de la exposici├│n conmemorativa celebrada en dicha galer├¡a en 1978. Tambi├®n fue publicada en la p├ígina 53 del cat├ílogo "Aurelio Grasa reportero gr├ífico 1910-1917", RSFZ, Galer├¡a Costa,3. Zaragoza 2003. Fotografia publicada en Heraldo de Arag├│n el 23 de julio de 1913, en ABC el 25 de julio de 1913. El peri├│dico ABC conserva una copia de esa fotograf├¡a de Aurelio Grasa que el mismo envi├│ para su publicaci├│n. www.aureliograsa.es', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64716400, -0.91050300, '0101000020E6100000CD1DFD2FD722EDBF03931B45D6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21280020406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21280020406.webp', 'https://www.flickr.com/photos/zaragozaantigua/21280020406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23710, 'Calle Delicias a├▒os 80', 'Foto: V├¡ctor M. Soriano. Vista de la calle Delicias de Zaragoza, a la altura del n├║mero 34. A la izquierda, calle B├®lgica. Al fondo, avenida de Madrid. En 1990, se remodel├│ y convirti├│ en peatonal. Fuente visual: www.facebook.com/photo.php?fbid=1082365388459063&set=...', 1980, 1980, 1989, 'Anos 80', 'DELICIAS', 41.65100400, -0.90513900, '0101000020E61000004FB16A10E6F6ECBF58C85C1954D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357529120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357529120.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357529120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23711, 'Calle de Garc├¡a S├ínchez 1976', 'Parada terminal que enlazaba las l├¡neas 22 y 24 del autob├║s urbano entre Las Fuentes y Las Delicias, en la calle de Jos├® Garc├¡a S├ínchez. Al fondo, el colegio de las Hijas de San Jos├®, Al fondo, el colegio de las Hijas de San Jos├®, chaflanero entre Duquesa Villahermosa y Marcelino de Unceta. La huelga que anuncia el cartel dur├│ del 8 al 11 de octubre, cuando se lleg├│ a un principio de acuerdo. Por si acaso, el domingo 10 salieron autobuses conducidos por personal del Parque M├│vil de los ministerios civiles, y microbuses por ch├│feres del Ej├®rcito de Tierra.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64841800, -0.90014800, '0101000020E6100000F2E9B12D03CEECBFA1116C5CFFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24006878943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24006878943.webp', 'https://www.flickr.com/photos/zaragozaantigua/24006878943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23737, 'Manicomio 1913', 'Visita de la infanta Isabel de Borb├│n, "la Chata", hija de la reina Isabel II, al Manicomio de Nuestra Se├▒ora del Pilar en el Terminillo, en julio de 1913. Le acompa├▒an el prior de los Hermanos de San Juan de Dios y la superiora de las Hermanas de la Caridad de Santa Ana, sor Amalia Porcano, adem├ís del espigado subdirector m├®dico, doctor Joaqu├¡n Gimeno Riera. A la derecha y en segundo plano, el arzobispo Juan Soldevila, siempre interesado en todo lo relacionado con el Terminillo. A la izquierda, uno de los lacayos del coche de caballos en que se desplazaba la infanta por la ciudad en su estancia.', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.64731800, -0.90945100, '0101000020E61000005A10CAFB381AEDBF5A0EF450DBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50783415323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50783415323.webp', 'https://www.flickr.com/photos/zaragozaantigua/50783415323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23740, 'Barrio de Roche 1927', 'Imagen capturada en el barrio de Roche, resultante de la parcelaci├│n a principios de los a├▒os 20 del campo de Juan Roche sito en una perif├®rica ubicaci├│n entre la carretera de Valencia, la estaci├│n de Cari├▒ena y los talleres de Material M├│vil y Construcciones (hacia el fondo). La de la imagen se trataba probablemente de la parcela ya construida y con el numeral 13 de este barrio particular de una sola calle. Tras el 18 de julio de 1936 la calle ser├¡a redenominada de Desiderio Escosura. Actualmente esta localizaci├│n se corresponder├¡a con el punto donde la calle del Obispo Taj├│n cruza la de Escosura.', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.64769500, -0.89843200, '0101000020E610000083C13577F4BFECBF306475ABE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52324354983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52324354983.webp', 'https://www.flickr.com/photos/zaragozaantigua/52324354983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24030, 'Calle Duquesa Villahermosa 2003', 'Foto: Beatriz Benedicto. Entorno conocido como "Esquinas del Psiqui├ítrico", con la calle de la Duquesa de Villahermosa en el centro, atraves├índolo de izquierda a derecha. All├¡ est├ín situadas las ferias del barrio de las Delicias. Entre 2007 y 2011, el entorno se urbanizar├í con equipamientos p├║blicos y viviendas. Al fondo a la derecha, V├¡a Universitas. Fuente: www.facebook.com/photo.php?fbid=532016703802554&set=g...', 2003, 2003, 2003, 'Siglo XXI', 'DELICIAS', 41.64665700, -0.90708000, '0101000020E6100000BB61DBA2CC06EDBF5F5D15A8C5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26208873619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26208873619.webp', 'https://www.flickr.com/photos/zaragozaantigua/26208873619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24217, 'Campo Sepulcro 1949', 'Imagen capturada en la factor├¡a de Material M├│vil y Construcciones sita junto a la estaci├│n de Campo Sepulcro y centrada en la armadura interior de uno de los diez automotores basados en el modelo Renault ABJ-4 encargados por RENFE, que una vez finalizados recibir├¡an la denominaci├│n de ABJ-7 dentro de la serie RENFE 9313-9332. Al fondo, vista parcial del barrio de Cari├▒ena o de la Romareda con algunos de los singulares "hotelitos" vertebrados en torno a la calle del Moncayo. A la izquierda despunta una de las torrecillas de la antigua f├íbrica de chocolates Or├║s entonces ocupada por la sociedad Industrias del Cartonaje S.A.', 1949, 1949, 1949, 'Anos 40', 'DELICIAS', 41.64993900, -0.89733800, '0101000020E610000054A86E2EFEB6ECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54726346345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54726346345.webp', 'https://www.flickr.com/photos/zaragozaantigua/54726346345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25916, 'Duquesa Villahermosa 1969', 'Imagen de la unidad n┬║ 74 (un BUT de dos pisos) de la l├¡nea de trolebuses "Ciudad Jard├¡n", avanzando por la calle Duquesa Villahermosa hacia el emboque con la calle Pedro L├│pez de Luna, donde iniciar el retorno hacia la plaza de Santa Engracia. La imagen ha sido capturada, casualmente, en la esquina de la calle Don Pedro de Luna. Al fondo, a la izquierda, el gran bloque esquinero con la calle Luis Franco y L├│pez. A la derecha, arbolado de la "Ciudad Jard├¡n" y, emergente, gr├║a de obra, posiblemente del nuevo bloque del n┬║ 30 de la calle de Luis Franco y L├│pez. Fuente visual: desequilibros.blogspot.com.es/', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.64802500, -0.90309800, '0101000020E610000000A8E2C62DE6ECBFC5FEB27BF2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30512970254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30512970254.webp', 'https://www.flickr.com/photos/zaragozaantigua/30512970254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25967, 'Huerta del Manicomio 1971', 'En 1873 la DPZ acord├│ construir un Manicomio Modelo en la Granja de Ntra. Sra. del Pilar, en el Terminillo. Las obras comenzaron en 1878, pero muchos asilados continuaban ingresados en el antiguo Hospital de Gracia. En 1912 el Manicomio pas├│ a depender del Estado. Una vez terminados, los pabellones ten├¡an capacidad para 600 enfermos, y hasta 4 hect├íreas de buena huerta. El Plan Larrodera (1968) recalific├│ parte de las zonas verdes para ladrillo, pero la presi├│n ejercida durante a├▒os de movilizaciones, encabezada por las Asociaciones de cabezas de Familia del barrio, consiguieron modificar el Plan, y terreno para el desdoblamiento de V├¡a Universitas y Duquesa Villahermosa, y para crear un nuevo Parque. En la imagen, parte de las huertas del Manicomio, la m├ís cercana a Duquesa Villahermosa y al Grupo de Viviendas "Severino Aznar" (derecha). En el centro, el Colegio P├║blico "Jos├® Mar├¡a Mir". A su izquierda, el bloque de viviendas de la calle Santa Rita de Casia, en la actualidad vecino al CDM "Duquesa Villahermosa". Con la prolongaci├│n de Duquesa de Villahermosa y el paso de la V├¡a Universitas, esta zona ha vivido una aut├®ntica mutaci├│n. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1971, 1971, 1971, 'Anos 70', 'DELICIAS', 41.64673200, -0.90666100, '0101000020E610000083E0F1ED5D03EDBF6AA33A1DC8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794570428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794570428.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794570428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25973, 'Ciudad Jard├¡n c.1945', 'AHPZ. Estudio Coyne. A├▒os 40. "Ciudad jard├¡n." Imagen tomada desde cierta altura en la calle Duquesa de Villahermosa, esquina calle Delicias. La que se abre a la izquierda (Lorenzo Calvo de Rozas) es una de las calles interiores de la barriada. Al fondo, la ciudad. Construida entre 1936-39, seg├║n proyecto de Miguel ├üngel Navarro. Ideadas dentro de la filosof├¡a de construcci├│n de "Casas Baratas", el franquismo reorient├│ su adjudicaci├│n, en positivo, hacia gentes leales al nuevo r├®gimen, y en negativo hacia quienes no.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.64781500, -0.90343200, '0101000020E6100000AC1DC539EAE8ECBFDB6D179AEBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15114921416.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15114921416.webp', 'https://www.flickr.com/photos/zaragozaantigua/15114921416/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25999, 'La Bozada 1991', 'Foto: Archivo Taumar (Irene Taul├®s y Rafael Margal├®). Vista a├®rea del barrio de la Bozada, con el IES Jer├│nimo Zurita a la derecha, el parque Avempace en el centro y la V├»a Univ├®rsitas arriba. En la esquina superior derecha, el Hospital Cl├¡nico. Fuente: www.facebook.com/photo.php?fbid=1687674314789601&set=...', 1991, 1991, 1991, 'Anos 90', 'DELICIAS', 41.64414800, -0.90849800, '0101000020E6100000B267CF656A12EDBF54E4107173D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21785689684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21785689684.webp', 'https://www.flickr.com/photos/zaragozaantigua/21785689684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21567, 'Calle de Alfonso I c.1920', 'En 1918, Celestino Salinero Ena ampli├│ y reform├│ los originales "Grandes talleres de confecci├│n La Casa Blanca" (Alfonso I, 22). La ampliaci├│n incorpor├│ la planta calle del n┬║ 24 de la finca, chaflanero con la calle Miguel Molino. La reforma le confiri├│ una nueva fachada de conjunto, con el caracter├¡stico color blanco como se├▒a de identidad, y unos interiores tambi├®n redecorados. En la imagen, la nueva fachada comercial. A la izquierda, la calle Miguel Molino. Fuente visual: aportaci├│n de Mariano Lacruz P├®rez de una reproducci├│n fotogr├ífica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Mar├¡a Jos├® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23243939405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23243939405.webp', 'https://www.flickr.com/photos/zaragozaantigua/23243939405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21568, '&quot;La Casa Blanca&quot; c.1920', 'Imagen de los "Grandes talleres de confecci├│n La Casa Blanca" (Alfonso I, 22-24), de Celestino Salinero Ena, tras la reforma y ampliaci├│n de 1918, con un curioso y considerable trampantojo en forma de dibujo que integra toda la primera planta de la finca en el comercio (la parte real era la del fondo, recayente a la calle de Goya, adem├ís de toda la planta calle). El chafl├ín de primer plano de la imagen, el real (planta calle) y el dibujado (primera planta), en el arranque de la calle Miguel Molino. En la parte superior, cartel indicativo del Hotel de El├¡as Cequiel establecido en este inmueble del n┬║ 24 de la calle de Alfonso I y del n┬║ 2 de la calle de Miguel Molino. Fuente visual: aportaci├│n de Mariano Lacruz P├®rez de una reproducci├│n fotogr├ífica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Mar├¡a Jos├® Salinero (nieta de Celestino Salinero).', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23246383025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23246383025.webp', 'https://www.flickr.com/photos/zaragozaantigua/23246383025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21671, 'Calle de Alfonso I a├▒os 30', 'A├▒os 30 del siglo XX. Colecci├│n V├¡ctor Bar├│n. Fila de mujeres para comprar en "Las nuevas seder├¡as". El portal de vecinos entre esa tienda y el Bazar es el n├║mero 26 de la calle, donde vive Dolores Serrat, consejera de Educaci├│n del Gobierno de Arag├│n entre 2011 y 2015 y miembro del Partido Popular. El dato es vox p├│puli porque las manifestaciones ciudadanas recorr├¡an obligadas otros itinerarios para no molestarla; adem├ís de que all├¡ mismo el profesor Antonio Aramayona se colocaba a protestar diariamente desde junio de 2013 por la pol├¡tica de Educaci├│n de la DGA.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65505700, -0.88009600, '0101000020E6100000B0E42A16BF29ECBF080264E8D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14760231379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14760231379.webp', 'https://www.flickr.com/photos/zaragozaantigua/14760231379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21881, 'Calle de Alfonso I 1931', 'Imagen capturada en la calle de Alfonso I en el punto donde desde la izquierda desemboca la calle de la Manifestaci├│n, y donde hacia la derecha comienza la calle de Espoz y Mina. Hacia el fondo, manzanas finales del tramo hasta la plaza del Pilar, que al fondo presenta su antigua y despejada fachada, m├ís visible por la realizaci├│n de la foto en ├®poca invernal, como ilustran los ├írboles de la plaza. Entre los bajos comerciales entoldados a la izquierda, la tienda de tejidos de Pascual Blasco D''Harcourt. En la umbr├¡a derecha, guanter├¡a La Catalana.', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST├ôRICO', 41.65545500, -0.87982800, '0101000020E6100000E25CC30C8D27ECBFF67F0EF3E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47569597722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47569597722.webp', 'https://www.flickr.com/photos/zaragozaantigua/47569597722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21987, 'Calle de Alfonso I 1949', 'Acuarela incluida en la serie "Rincones de Espa├▒a", publicada en 1953 por los laboratorios Roche de Madrid, que reproduce la calle de Alfonso I, con el Pilar al fondo. Fuente: www.delcampe.net', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65517900, -0.88009900, '0101000020E6100000F4C0C760C529ECBF5303CDE7DCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30241943843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30241943843.webp', 'https://www.flickr.com/photos/zaragozaantigua/30241943843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22392, 'Calle Olmo 1965', 'Calle del Olmo. Al fondo, la calle del Temple. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750235347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750235347.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750235347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23287, 'Calle de Alfonso I 1909', 'Imagen de la calle Alfonso I enfocando en direcci├│n hacia el Coso Alto. La calle de la izquierda es la de Espoz y Mina. La de la derecha, Manifestaci├│n. Al fondo, fachada del palacio del marqu├®s de Campo Franco, que pocos a├▒os despu├®s ser├í piqueteado para dar paso al edificio del Banco de Arag├│n, obra de Manuel del Busto (1913). Fuente: Instituto Amatller de Arte Hisp├ínico (Arxiu Mas).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65555100, -0.87971000, '0101000020E610000066DAFE959526ECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15700543099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15700543099.webp', 'https://www.flickr.com/photos/zaragozaantigua/15700543099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23291, 'Calle de Alfonso I 1908', 'Vista de la calle de Alfonso I, desde el cruce con las calles Contamina (izquierda), y Goya (derecha). Antes de la instalaci├│n del local comercial "La Casa Blanca".', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20364430090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20364430090.webp', 'https://www.flickr.com/photos/zaragozaantigua/20364430090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23295, 'Calle Manifestaci├│n c.1895', 'Luminosa imagen finisecular capturada desde el primer piso del 82 de la calle Manifestaci├│n (actual 40), hacia el punto de cruce entre esta calle, y la de Alfonso I, por donde transita hacia la plaza del Pilar una humana procesionaria. En los bajos del 89-91 (actual 35), el "Comercio de Valero Palomar". Al otro lado de la calle Alfonso I, arranca hacia la izquierda el callej├│n de la Leche, y hacia la derecha los primeros edificios impares de la calle Espoz y Mina, que no es que parezca estrecharse: es que lo hace. En los a├▒os 20 del siglo XX, la Leche ser├í redenominada "Fray Juan Cebri├ín". Fuente: donaci├│n de Luis G├│mez Laguna, Archivo P├║blico Municipal.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65545300, -0.87984000, '0101000020E6100000F2CD3637A627ECBF558847E2E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622105418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622105418.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622105418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23299, 'Calle de Alfonso I c.1910', 'En 1908, el ayerbense Celestino Salinero Ena visit├│ la ciudad de Par├¡s, y qued├│ impresionado por el comercio denominado "La Maison Blanche", especializado en la venta de ropa "blanca". A la vuelta, mientras Zaragoza celebraba el Centenario I de los "Sitios", Celestino se embarc├│ en la aventura de reproducir en la ciudad lo visto en Par├¡s. As├¡, en la calle Alfonso I n┬║ 22 (local y primera planta), junto a la entrada de la calle Goya, fund├│ "La Casa Blanca", unos innovadores y exitosos "grandes" talleres de confecci├│n y venta directa de g├®neros de punto, juegos de cama, cubierta, toallas, manteler├¡as... De la ciudad de la luz se trajo, tambi├®n, la francesa idea de iluminar el comercio con l├ímparas de gas, siendo pionero en Zaragoza. En la imagen, Celestino Salinero Ena posando ante su empresa vital. Fuente visual: aportaci├│n de Mariano Lacruz P├®rez de una reproducci├│n fotogr├ífica realizada por Mariano Lacruz Berdejo sobre una imagen original cedida por Mar├¡a Jos├® Salinero (nieta de Celestino Salinero).', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65471900, -0.88031000, '0101000020E6100000B3EF8AE07F2BECBFF0880AD5CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23242807685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23242807685.webp', 'https://www.flickr.com/photos/zaragozaantigua/23242807685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23315, 'Calle de Alfonso I 1908', 'Imagen capturada en la calle de Alfonso I durante la visita del rey Alfonso XIII el d├¡a 15 de junio de ese a├▒o a diversos eventos relacionados con el primer centenario del asedio franc├®s de 1808. En este caso se trata de la "procesi├│n c├¡vico-religiosa" que acompa├▒aba los f├®retros de las hero├¡nas Casta ├ülvarez, Manuela Sancho y Agustina Zaragoza desde el templo del Pilar y hasta la iglesia del Portillo, donde fueron inhumadas. La instant├ínea, realizada a la altura del n┬║ 28 de la calle, junto al emboque a la calle de Espoz y Mina donde destaca al fondo el dep├│sito de transparentes de "La Veneciana", recoge el paso del cortejo en torno al rey Alfonso XIII flanqueado por los infantes Luis Alfonso y Luis Fernando, precedido por el marqu├®s de Viana y seguido por los ministros del gobierno (Gracia y Justicia y Guerra), adem├ís de varios otros marqueses, generales y condes. Las cr├│nicas informan que antes de la procesi├│n las nubes descargaron una fuerte tormenta que con naturalidad convirti├│ las terrosas calles del recorrido, como es el caso de la de Alfonso I, en simp├íticos barrizales.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65540700, -0.87993600, '0101000020E61000007A56D28A6F28ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52079851856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52079851856.webp', 'https://www.flickr.com/photos/zaragozaantigua/52079851856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24245, 'Calle de Alfonso I 1947', 'Imagen capturada en la calle Alfonso I, a la altura del n┬║ 28, frente al callej├│n de las Once Esquinas, donde ten├¡a su estudio el "pintor-fot├│grafo" navarro ├üngel Hilario Garc├¡a de Jal├│n, cuya denominaci├│n art├¡stica era la que figura en el cartel anunciador: Jal├│n ├üngel. Aparcado tranquilamente en la calle, un Peugeot 202, y delante, posado de tres elegantes se├▒oras. Fuente visual: www.todocoleccion.net/', 1947, 1947, 1947, 'Anos 40', 'CASCO HIST├ôRICO', 41.65523200, -0.87996700, '0101000020E61000003BE5D18DB028ECBF76A565A4DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30638539700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30638539700.webp', 'https://www.flickr.com/photos/zaragozaantigua/30638539700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24400, 'San Cayetano 1899', 'Desde las alturas del antiguo palacio de Guara, en la calle de la Montera, un vistazo en direcci├│n noroeste muestra los tejados del barrio de San Felipe, y la c├║pula y torrecillas de la iglesia de Santa Isabel de Portugal, o de San Cayetano, denominaci├│n que en la ├®poca de la imagen (y parece ser que todav├¡a) era considerada "vulgar" o as├¡ llamada por el "vulgo", si bien era esa la hist├│rica denominaci├│n de la casa, convento e iglesia de los padres cl├®rigos regulares de la providencia, o religiosos teatinos, sus regentes. Fuente visual: Francisco G├│rriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65553400, -0.88188900, '0101000020E6100000F777B6476F38ECBF42B5C189E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28406008944.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28406008944.webp', 'https://www.flickr.com/photos/zaragozaantigua/28406008944/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24479, 'Imprenta Berdejo Casa├▒al 1925', 'Taller de la "Imprenta de Arte Berdejo Casa├▒al", en su ubicaci├│n de la calle Loscos 7 (antigua Jazm├¡n). La captura se ha realizado con motivo de la tirada en prensa del n├║mero 1 de la revista "Arag├│n", ├│rgano de expresi├│n del "Sindicato de Iniciativa y Propaganda de Arag├│n" (SIPA). En el colectivo posado, junto al personal del taller, el secretario del SIPA, Eduardo Cativiela y P├®rez, que sostiene un ejemplar de la revista. y junto a ├®l, Eduardo Berdejo Casa├▒al, editor de la revista, y propietario de la imprenta. Fuente: Foto Larraz, amablemente proporcionada por Mariano Lacruz P├®rez.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65556900, -0.88063200, '0101000020E61000004DF4F928232EECBFBEA25BAFE9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528904220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528904220.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528904220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25070, 'Camarada Fleta 1936', '├üngel Jal├│n (├üngel Hilario Garc├¡a de Jal├│n Hueto), Diputaci├│n de Zaragoza, agosto 1936. Retrato de Miguel Burro Fleta. Imagen del tenor Fleta habilitado con el uniforme de la Falange Espa├▒ola de las JONS (Juntas de Ofensiva Nacional-Sindicalista), capturado de tal traza en el Estudio fotogr├ífico de ├üngel Jal├│n (Alfonso I, 28) cuando ya no hab├¡a rojos en la costa. Falleci├│ apenas dos a├▒os despu├®s, y en su homenaje, la nueva, leal y digital corporaci├│n municipal cambi├│ de nombre a la calle Fletas, por "Avenida del Tenor Fleta". Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2851', 1936, 1936, 1936, 'Anos 30', 'CASCO HIST├ôRICO', 41.65497800, -0.88015400, '0101000020E6100000D731AEB8382AECBFBCCCB051D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15696653438.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15696653438.webp', 'https://www.flickr.com/photos/zaragozaantigua/15696653438/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25895, 'Calle del Olmo, c. 1968', 'Pintura centrada en el cruce de las calles del Olmo, desde donde el autor ha capturado la escena, y del Temple, donde al fondo destaca la portalada de acceso al n├║mero 14 de esa calle, una vivienda posiblemente del siglo XVII construida sobre el solar de una parte del gran complejo mon├ístico de la Orden del Temple que ocup├│ toda esa manzana.y que da nombre a esa calle. A la derecha, vista parcial del antiguo inmueble del n┬║ 11 de la calle del Temple, posteriormente derribado junto con sus vecinas de los n├║meros 13 y 15 y que a finales de los a├▒os 80 del pasado siglo XX su solar conform├│ un singular espacio poblado de bancos de sentarse y arbolitos, un antecedente al desarrollo, veinte a├▒os despu├®s, del proyecto "Estonoesunsolar" y que desde principios de este siglo XXI fue objeto de un desarrollo edilicio que conform├│ el moderno inmueble del actual n┬║ 18 de la calle del Olmo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65553500, -0.88191000, '0101000020E6100000D47D00529B38ECBF12312592E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53205391874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53205391874.webp', 'https://www.flickr.com/photos/zaragozaantigua/53205391874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20887, 'Fundaci├│n de Caesaraugusta', 'Emilio Gil Murillo, "Origen y fundaci├│n de Zaragoza ", 1896. Ayuntamiento de Zaragoza. La imagen representa idealizado el rito romano de fundaci├│n de la ciudad, en el 14 antes de la Era. Antes de iniciarlo, el augur consult├│ los auspicios para asegurarse, mediante signos visibles, de que los dioses no se opon├¡an al establecimiento de la ciudad en el lugar escogido. Los dioses no dijeron ni p├¡o. Entonces, revestido con una toga dispuesta a la antigua usanza, cogi├│ las estevas de un arado de bronce, tirado por una ternera y un toro, y traz├│ un surco alrededor de la futura urbe, siguiendo la misma l├¡nea a lo largo de la cual habr├¡a de levantarse el muro delimitador. En el transcurso de la ceremonia, se procuraba que toda la tierra levantada por la reja cayese al interior del recinto. Tras ├®l, los asistentes recog├¡an los terrones que a veces saltaban fuera del per├¡metro y los volv├¡an a echar donde el rito establec├¡a. Al llegar al sitio previsto para las 4 puertas principales, se levantaba el arado con el fin de dejar un espacio libre de toda consagraci├│n. Cuando el oficiante alcanz├│ el punto de partida, la ciudad qued├│ virtualmente fundada.', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65210400, -0.87346600, '0101000020E6100000BB5F05F86EF3EBBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14753929599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14753929599.webp', 'https://www.flickr.com/photos/zaragozaantigua/14753929599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20892, 'Domus Calle Hero├¡smo siglo I', 'En 1991 se document├│, en el solar de la calle Hero├¡smo 5 y 7 con A├▒├│n (en la imagen, a la derecha) de Zaragoza, una domus romana del siglo I, extramuros de la colonia. Fuente: Zaragoza. Prehistoria y arqueolog├¡a, Ayuntamiento de Zaragoza, 1991.', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65117300, -0.87349900, '0101000020E6100000AAD6C22CB4F3EBBFE48409A359D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18564315843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18564315843.webp', 'https://www.flickr.com/photos/zaragozaantigua/18564315843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20893, '├ünforas ca. 20', 'Campo de ├ínforas romano, enterradas hacia el a├▒o 20 despu├®s de la Era, como drenaje o c├ímara de aire para evitar humedades en las casas procedentes de las crecidas del r├¡o Ebro. En mayo de 2003 se descubri├│ este conjunto de casi un millar de ├ínforas puestas hacia abajo, en el solar de la plaza de las Tener├¡as 9 de Zaragoza. Fuente visual: www.facebook.com/photo.php?fbid=1234779646549079&set=...', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65292800, -0.87130000, '0101000020E61000005227A089B0E1EBBF44520B2593D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19386927608.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19386927608.webp', 'https://www.flickr.com/photos/zaragozaantigua/19386927608/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20896, 'Plaza Asso 1991', 'Tareas de recuperaci├│n de un tramo de cloaca romana, descubierta en 1990 en la plaza Asso de Zaragoza. Al fondo, la calle Mart├¡n Carrillo y la torre de la iglesia de la Magdalena. Fuente: Zaragoza. Prehistoria y arqueolog├¡a, Ayuntamiento de Zaragoza, 1991.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65308900, -0.87399300, '0101000020E61000008CDAFD2AC0F7EBBF4D309C6B98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23648332264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23648332264.webp', 'https://www.flickr.com/photos/zaragozaantigua/23648332264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20898, 'Plaza Magdalena 1990', 'En 1990 se hall├│ un tramo de losas de la calzada romana del Decumano M├íximo, que sirvi├│ para confirmar que la calle Mayor se hallaba sobre ├®ste. En la foto, el comienzo de la calle Mayor, a la altura de la plaza de la Magdalena, con la iglesia hom├│nima arriba a la izquierda. Fuente: Las cloacas de Cesaraugusta, IFC, 2013.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194356511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194356511.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194356511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20922, 'Colegio del Padre Eterno 1778', 'Plano del terreno de las Escuelas P├║blicas y del Colegio del Padre Eterno, Joseph Arberuela, Zaragoza, 19 de diciembre de 1778. El colegio del Padre Eterno, de los jesuitas, alberg├│ desde 1788 las primeras instalaciones del Seminario Conciliar de San Valero y San Braulio. Se encontraba en el actual Coso 127, esquina con la calle de San Lorenzo. Fuente: Archivo General de Simancas, Ministerio de Cultura de Espa├▒a.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20225243629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20225243629.webp', 'https://www.flickr.com/photos/zaragozaantigua/20225243629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20941, 'Convento de San Agust├¡n 1563', 'El convento de San Agust├¡n tal y como aparece en la vista de Zaragoza realizada en 1663 por el dibujante Anton van der Wyngaerde/Antonio de las Vi├▒as.', 1563, 1563, 1563, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65140000, -0.87079400, '0101000020E61000005FB2F1608BDDEBBFA54E401361D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54387299485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54387299485.webp', 'https://www.flickr.com/photos/zaragozaantigua/54387299485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20956, 'Coso Bajo 1808', '"Ruinas del Seminario vistas por la noche: cuando los patriotas, que no pod├¡an asistir a la defensa de las puertas, a la luz de sus linternas y de los incendios, causados por las bombas, buscaban entre los escombros a los muertos para darles sepultura". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. El conjunto de edificios del Seminario Mayor de Zaragoza se extend├¡a por el Coso Bajo en direcci├│n al Ebro, m├ís all├í de la calle de San Jorge. En la acera de la gran mole semiderruida, m├ís al fondo, se ve la entrada a la plaza de la Magdalena. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65158800, -0.87402800, '0101000020E6100000A839799109F8EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15267099411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15267099411.webp', 'https://www.flickr.com/photos/zaragozaantigua/15267099411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20967, 'Universidad 1814', '"La Academia de Zaragoza al regreso de Fernando VII". Medalla realizada por Antonio Mart├¡nez y acu├▒ada por la Universidad de Zaragoza cuando se reanudaron las clases tras la retirada de los franceses en 1814. En 1913 se termin├│ una reforma que modific├│ su aspecto, a cargo de Ricardo Magdalena. Al fondo a la derecha, personificaci├│n del r├¡o Ebro. Fuente: Museo del Prado.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65222400, -0.87323600, '0101000020E61000004D13B69F8CF1EBBF49D576137CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18985824170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18985824170.webp', 'https://www.flickr.com/photos/zaragozaantigua/18985824170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22670, 'Feria de Muestras 1976', 'Imagen en altura de la Feria de Muestras, y su caracter├¡stico mirador acristalado, desde un punto de vista contrario a la inmensa mayor├¡a de las capturas realizadas de la zona: hacia el noreste, mirando hacia la ciudad. Este peque├▒o detalle permite observar el agujero, a la derecha, donde antes estuvieron los talleres de la Editorial Luis Vives, y ahora se estaba gestando la macizada y compacta manzana de bloques habitacionales que la iba a sustituir. Eso permite, excepcionalmente, visual directa de la calle Luis Vives y el desemboque a ella de Andr├®s Piquer, Teresa de Jes├║s, y Mariano Superv├¡a, con el Grupo "Francisco Caballero" y restos supervivientes de antiguos hotelitos de la zona del Ensanche de Miralbueno, al poco derribados y sustituidos por cosas m├ís modernas y apropiadas. Fuente visual: Gerardo Sancho Ramo (Archivo P├║blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63744800, -0.89883900, '0101000020E6100000ABD1AB014AC3ECBF477364E597D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23539505284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23539505284.webp', 'https://www.flickr.com/photos/zaragozaantigua/23539505284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21009, 'Arco de Valencia 1867', 'Imagen del antiguo arco de Valencia poco antes de su derribo realizado entre el 20 de enero y el 15 de febrero de ese a├▒o, al objeto de despejar las casas de los n├║meros 71, 73, 75 y 77 del Coso (a la derecha) que afeaban el ingreso a la Universidad Literaria, y parte de la casa del n┬║ 96 de la calle Mayor (a la izquierda). El derribo del arco se hizo hilada a hilada de piedra, y el de las casas piso a piso, sin permitirse "derribos en grandes masas". Tal vez por ello llamaron la atenci├│n buen n├║mero de piedras que luc├¡an caracteres latinos, algunas de las cuales sobrevivieron al reaprovechamiento de los materiales del derribo, que aunque se realiz├│ dentro de los l├¡mites de tiempo establecidos, dej├│ durante varios meses un "rastro" de grandes piedras "y no menores excabaciones" o cisternas ante la despejada fachada de la Universidad Literaria. La captura de esta fotograf├¡a se ha realizado desde el arranque de la vecina calle de Palomar. En primer t├®rmino, tramo del Coso que hasta ese momento era denominado "plaza de la Magdalena", caracterizado por las botigas comerciales y puestos ambulantes all├¡ establecidos. Al fondo, tras el arco, vista de la barroca portada de la iglesia parroquial de Santa Mar├¡a Magdalena, cuya torre despunta a la izquierda. Tras el derribo del arco y las casas, una nueva plaza de la Magdalena surgi├│ entonces en su actual ubicaci├│n.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65210700, -0.87336500, '0101000020E6100000C2120F289BF2EBBF103FFF3D78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092142102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092142102.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092142102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21010, 'Puerta de Valencia 1867', 'Puerta de Valencia vista desde la puerta de la iglesia de la Magdalena, justo antes de ser demolida ese a├▒o, para dar a la plaza de la Magdalena algo m├ís de desahogo y dejar al descubierto el frontispicio de la Universidad. Al fondo, el Coso bajo y la calle de Palomar. Fuente visual: Santos ├ülvarez y Serra, en AMZ.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093846679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093846679.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093846679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21097, 'Paraninfo de la Universidad 1880', 'Sesi├│n inaugural del Congreso Filox├®rico celebrado en 1880 en el paraninfo de la Universidad de Zaragoza en la plaza de la Magdalena. No confundir con el actual edificio sito en la plaza de Para├¡so, construido posteriormente. La plaga vitivin├¡cola de la filoxera fue detectada en Francia en 1865. Las 952.000 Ha de vi├▒edo que ten├¡a en cultivo la provincia de Zaragoza quedaron reducidas, tras la plaga, a 12.275. El congreso cuya inauguraci├│n reproduce el croquis se celebr├│ para intentar frenar la cat├ístrofe agr├¡cola que se preve├¡a. El dibujo, de Bernardo Rico y Ortega, basado en un croquis apuntado por "D. Lascun", posiblemente Dionisio Lasu├®n. Fuente visual: "La Ilustraci├│n Espa├▒ola y Americana".', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65221400, -0.87327900, '0101000020E61000001F1329CDE6F1EBBF26FF93BF7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856449014.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856449014.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856449014/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21111, 'Pl. de la Magdalena 1889', '"Saragosse. ├ëglise de la Magdeleine". Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22736718751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22736718751.webp', 'https://www.flickr.com/photos/zaragozaantigua/22736718751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21135, 'Plaza de la Magdalena c.1880', 'Luminosa imagen capturada desde la altura del inmueble del n┬║ 188 del Coso Bajo y centrada en la plaza de la Magdalena, donde destaca la torre y la puerta de ingreso a la iglesia parroquial de Santa Mar├¡a Magdalena. A la izquierda, desemboque de la calle Mayor en la plaza con vista de las ├║ltimas casas del lado de los pares tras la calle de Pelegrin. A la derecha, esquina del final de la calle de Mart├¡n Carrillo con el arranque de la calle de la Universidad, donde destaca la antigua Casa Tejada, en cuyos bajos se abre la puerta de un comercio de ultramarinos donde tambi├®n se despachaba carb├│n de haya. A continuaci├│n, leve vista de la fachada de la Universidad Literaria. Como el cielo de la fotograf├¡a ha sido "editado" en origen, ha desaparecido la vista de la inacabada torre de Santiago y de la c├║pula central del templo del Pilar, que deber├¡an despuntar sobre Casa Tejada, as├¡ como la torre de la Seo. Hemos volteado horizontalmente la fotograf├¡a tal y como aparece en el AHPZ, para darle sentido y sensibilidad.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65224000, -0.87350900, '0101000020E61000008D5F7825C9F3EBBF4F92AE997CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52230624372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52230624372.webp', 'https://www.flickr.com/photos/zaragozaantigua/52230624372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21145, 'Cuartel de Caballos Sementales 1899', '├ülbum del Ministerio de la Guerra. Ministerio de Defensa de Espa├▒a. 1899. Por Real orden de 17 de agosto de 1885 se cre├│ en Zaragoza una secci├│n de sementales al objeto de la mejora de la caba├▒a de Arag├│n, con 85 sementales percherones y bolo├▒eses. El 22 de marzo de 1905 se crea el Quinto Dep├│sito de Caballos Sementales. Su ubicaci├│n, terrenos municipales de la Calle del Asalto. All├¡ estuvieron hasta el 18 de julio de 1989. En la imagen, carruaje con tres sementales ante la puerta del Dep├│sito. Detr├ís del muro, al fondo, la calle Asalto y su confluencia con Alonso V.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65126900, -0.86970100, '0101000020E6100000478D093197D4EBBF06F357C85CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14991847139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14991847139.webp', 'https://www.flickr.com/photos/zaragozaantigua/14991847139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21157, 'Calle de la Universidad 1898', 'Instituto Universitario Provincial de Zaragoza, 1898. En 1847 se separaron las docencias de los institutos y las universidades, cre├índose este centro en el edificio de la Universidad Literaria de La Magdalena. Su entrada estaba en la calle Universidad. En 1933 fue trasladado al edificio del suprimido Colegio del Salvador, y se le dio el nombre de "Instituto Nacional de Segunda Ense├▒anza Goya". Despu├®s del 18 de julio de 1936, fue trasladado a la Escuela de Artes, primero, y luego regres├│ a la Magdalena. Cuando se inaugur├│ el edificio del nuevo Instituto "Goya" junto al Huerva y la avenida Goya, se traslad├│ all├¡ definitivamente en 1959. Fuente visual: www.facebook.com/photo.php?fbid=10204723386338133&set...', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65304800, -0.87297400, '0101000020E61000000744882B67EFEBBFEE5BAD1397D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19510424782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19510424782.webp', 'https://www.flickr.com/photos/zaragozaantigua/19510424782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21162, 'Calle Mayor 1893', '"Fragmento de la torre e iglesia de Santa Magdalena". Este dibujo, basado en una fotograf├¡a, captura en altura la torre y parcialmente la iglesia con la calle Mayor a sus pies, estrecha como originalmente era. Por una de esas casualidades ocasionales, el dibujante se ha centrado en la f├íbrica de la torre tal y como fue trabajada por los alarifes medievales que la levantaron, y ha prescindido del remate barroco a├▒adido posteriormente. Fuente: "La Ilustraci├│n Ib├®rica", Barcelona.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20497312783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20497312783.webp', 'https://www.flickr.com/photos/zaragozaantigua/20497312783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21205, 'Cuartel de San Agust├¡n 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 8, Zaragoza 1908 - Centenario de los Sitios", 1907. "El convento de San Agust├¡n, donde hoy se encuentran las Factor├¡as militares, h├íllase situado en las afueras, en un punto muy apetecido por los franceses cuando intentaron entrar en Zaragoza por la plaza de la Magdalena; durante el segundo sitio, el uno de febrero, se apoderaron de ├®l las tropas de Napole├│n." Puerta de entrada al cuartel de San Agust├¡n, antes convento. Lo que parece un guardia espera sentado tranquilo. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65071100, -0.87039700, '0101000020E61000001B2B31CF4ADAEBBFE012807F4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750296987.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750296987.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750296987/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21246, 'Pl. de la Magdalena 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 27, Zaragoza 1908 - Centenario de los Sitios", 1907. "Uno de los edificios m├ís antiguos de Zaragoza; muy castigado por hallarse detr├ís de la puerta de Valencia, frente a la cual los franceses colocaron el 7 de febrero de 1809, un ca├▒├│n de a 24, con el que abrieron una gran brecha. En sus cisternas fueron sepultadas numerosas v├¡ctimas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150686613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150686613.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150686613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21247, 'Ruinas del Hospitalito 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 29, Zaragoza 1908 - Centenario de los Sitios", 1907. "Efecto de las bombas enemigas en la capilla de este ben├®fico establecimiento conocido con el nombre de Hospitalito de la Magdalena. Despu├®s de la explosi├│n del almac├®n de la p├│lvora (27junio), en el Hospitalito fueron custodiados los enseres de las casas arruinadas, y en su cementerio enterr├íronse las v├¡ctimas." El Hospitalito u "Hospitalico de Nuestra Se├▒ora de la Misericordia u Hospital de Ni├▒os y Ni├▒as Hu├®rfanos de la ciudad de Zaragoza" fue fundado en 1543 y arruinado en 1808. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65172600, -0.87326300, '0101000020E6100000B3D1393FC5F1EBBFF8F9EFC16BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20150826383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20150826383.webp', 'https://www.flickr.com/photos/zaragozaantigua/20150826383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21256, 'Calle Hero├¡smo 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 22, Zaragoza 1908 - Centenario de los Sitios", 1907. "En esta calle, que viene a salir al Coso en las inmediaciones de la plaza de la Magdalena, ri├▒├®ronse luchas formidables, cuerpo a cuerpo, entre sitiadores y sitiados. Min├íronse las casas, que fueron asaltadas una a una, y reconquistadas igualmente a cuenta de sangre y vidas." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65085200, -0.87403600, '0101000020E61000005EDA70581AF8EBBFA2444B1E4FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20582520218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20582520218.webp', 'https://www.flickr.com/photos/zaragozaantigua/20582520218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21261, 'Calle de las Tener├¡as 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 39, Zaragoza 1908 - Centenario de los Sitios", 1907. "Llamado as├¡ por haberse destinado alguna de sus casas a la fabricaci├│n de curtidos. En su lugar hall├íbase antes emplazada la puerta del Sol. A este arrabal pertenec├¡a el llamado corral de Marigaita desde donde se dominaba gran parte de la ribera del Ebro, por lo cual se construyeron all├¡ muy importantes bater├¡as que ri├▒eron fieras luchas." Vista de la actual calle de Alonso V en su confluencia con la plaza de las Tener├¡as. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65316900, -0.87164300, '0101000020E6100000CA3159DC7FE4EBBF69E1B20A9BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20763354052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20763354052.webp', 'https://www.flickr.com/photos/zaragozaantigua/20763354052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21262, 'Calle del Pozo 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 2, Zaragoza 1908 - Centenario de los Sitios", 1907. "Por el buen punto de vista que ofrec├¡a esta casa, cuya entrada est├í por la calle de Palomar, las balas enemigas hicieron blanco en ella frecuentemente. Durante el segundo sitio los franceses intentaron penetrar en Zaragoza por este punto pero, sin pasar de la plaza de la Magdalena, siempre fueron en├®rgicamente rechazados." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65125200, -0.87232000, '0101000020E6100000EEB1F4A10BEAEBBF30BABC395CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767321535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767321535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767321535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21380, 'Coso Bajo c.1910', 'Anselmo Mar├¡a Coyne, Diputaci├│n de Zaragoza, ca. 1910 Imagen de tremenda carretada de aguateros en el Coso Bajo, a la altura de la plaza de la Magdalena. A la izquierda, la Universidad Literaria de la Magdalena, antes de su reforma por Ricardo Magdalena. Fuente: web.dpz.es/arscatalogi.es/foto.asp?index=2818', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15854328636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15854328636.webp', 'https://www.flickr.com/photos/zaragozaantigua/15854328636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21421, 'Plaza de las Tener├¡as 1911', 'Danzantes en la plaza de las Tener├¡as, durante las fiestas de la Virgen del Carmen. Al fondo, acceso a la plazuela de la Reboler├¡a.', 1911, 1911, 1911, 'Anos 10', 'CASCO HIST├ôRICO', 41.65312700, -0.87155900, '0101000020E6100000541A31B3CFE3EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31581924166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31581924166.webp', 'https://www.flickr.com/photos/zaragozaantigua/31581924166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21427, 'Instituto a├▒os 10', 'Grupo de profesores (con birrete) y dem├ís personal del Instituto General y T├®cnico de Zaragoza (antes Instituto Universitario Provincial), en el patio de su sede en el edificio de la Universidad Literaria, con entrada por la calle Universidad. En esa ├®poca fueron alumnos Ram├│n J. Sender y Mar├¡a Moliner. El archivo del que procede la imagen se halla hoy en la sede del Instituto Goya, heredero de aqu├®l desde 1959. Fuente: Archivo IES Goya de Zaragoza.', 1910, 1910, 1919, 'Anos 10', 'CASCO HIST├ôRICO', 41.65265400, -0.87290000, '0101000020E610000074B515FBCBEEEBBF42CD902A8AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32973656955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32973656955.webp', 'https://www.flickr.com/photos/zaragozaantigua/32973656955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21642, 'Coso Bajo, c.1926', 'Imagen capturada desde la altura del n┬║ 182 del tramo bajo del Coso y centrada un carro a la puerta de la tienda de comestibles de Esteban Mart├¡nez. A la derecha y al fondo, entrada a la plaza de la Magdalena y vista al ingreso principal a la Universidad Literaria de Zaragoza. En primer t├®rmino, tendido tranviario de la l├¡nea Magdalena-Mercado, antes Circunvalaci├│n.', 1926, 1926, 1926, 'Anos 20', 'CASCO HIST├ôRICO', 41.65197600, -0.87340200, '0101000020E61000000C5A48C0E8F2EBBF71E316F373D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51126969715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51126969715.webp', 'https://www.flickr.com/photos/zaragozaantigua/51126969715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21707, 'Casa Gav├¡n 1930', 'Foto Palacio. 1930. Imagen de la antigua "Casa Gav├¡n", esquinada entre la calle Palafox (derecha), y la calle Pedro Li├▒├ín (a la izquierda). Salvada de las obras de apertura de San Vicente de Pa├║l, por estar un poco alejada del epicentro del nuevo vial, varias d├®cadas despu├®s ser├¡a piqueteada para construir encima una indescriptible edificaci├│n de Telef├│nica. Fuente visual: "Arag├│n : revista gr├ífica de cultura aragonesa" (A├▒o VI, N┬║ 63, dic. 1930).', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65360900, -0.87406300, '0101000020E6100000C498F4F752F8EBBF86AFAF75A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16012092932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16012092932.webp', 'https://www.flickr.com/photos/zaragozaantigua/16012092932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21790, 'Coso Bajo c.1934', 'Vista a├®rea del Coso bajo y sus alrededores. Arriba a la izquierda, el gran edificio de la Universidad de la Magdalena. A la derecha, el intrincado laberinto de la calle del Sepulcro, Pallaruelo, del Lobo, Monserrate, Conde de Alperche, Chantre... Fuente visual: www.facebook.com/photo.php?fbid=575487972606230&set=g...', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24147192773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24147192773.webp', 'https://www.flickr.com/photos/zaragozaantigua/24147192773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21952, 'Calle Universidad 1949', 'Imagen de la calle Universidad capturada desde el tramo entre las calles Torrellas y Palafox, que es la primera calle que se abre a la izquierda. Al fondo, la calle Don Teobaldo, con leve vista del Convento de las Canonesas del Sto. Sepulcro. Inmediata, a la derecha, la calle Trinidad. La imagen se ha tomado justo al lado de los muros de la antigua Universidad Literaria de la Magdalena. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65322600, -0.87285500, '0101000020E610000075CDE49B6DEEEBBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19171108130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19171108130.webp', 'https://www.flickr.com/photos/zaragozaantigua/19171108130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21990, '&quot;CEFA&quot; Plaza de Asso, 1946', 'Imagen del interior de los originales talleres de Celulosa Fabril "CEFA", empresa fundada por Eduardo Blanchard Castillo en 1946, en el n┬║ 1 de la plaza de Asso, entre las calles del ├ôrgano, y Torrellas. All├¡ se acomet├¡a la fabricaci├│n de c├ípsulas de celulosa para tapones de botellas, y pronto comenzar├¡a la producci├│n de gelatinas, sacarinas y jabones, y en 1952, el desarrollo de la inyecci├│n de termopl├ísticos, que hizo de los juguetes una de las grandes se├▒as de identidad de la empresa. A mediados de esa d├®cada, este espacio se hab├¡a quedado muy peque├▒o, lo que deriv├│ en su traslado a una nueva y mucho mayor planta, en la calle de Miguel Servet. Fuente visual: "CEFA: una mirada al futuro 1946-2016", en Archivo Jos├® Mar├¡a Ballest├¡n Miguel.', 1946, 1946, 1946, 'Anos 40', 'CASCO HIST├ôRICO', 41.65294000, -0.87378700, '0101000020E61000003F70952710F6EBBF0820B58993D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30749184261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30749184261.webp', 'https://www.flickr.com/photos/zaragozaantigua/30749184261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22021, 'Calle de Jos├® Palafox c.1940', 'Imagen del ├║ltimo tramo de la calle de Jos├® Palafox, donde destaca a la derecha, en el n┬║ 29, el Laboratorio Qu├¡mico Municipal construido en 1914 con proyecto de Jos├® de Yarza Echenique. Frente a ├®l, los antiguos inmuebles de los n├║meros 28 y 30. Hacia el fondo, la calle se estrecha de forma notable hasta el cruce con la de Gav├¡n. La imagen est├í realizada desde la esquina con la calle de la Universidad, a espaldas de la hom├│nima e hist├│rica instituci├│n educativa, con un tancredo en primer t├®rmino ejerciendo de tal.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65324200, -0.87286500, '0101000020E610000058569A9482EEEBBFD32F116F9DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49898657137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49898657137.webp', 'https://www.flickr.com/photos/zaragozaantigua/49898657137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22036, 'Calle del ├ôrgano c.1940', 'Grabado de Salvador Mart├¡nez Blasco con una vista de la calle del ├ôrgano y la iglesia de la Magdalena. A la derecha, casona de los Lanes de Villanueva, esquinera con la calle de Mart├¡n Carrillo y derribada a principios de los a├▒os 40. Su piedra armera con el escudo perdura en el Museo de Zaragoza.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54413600082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54413600082.webp', 'https://www.flickr.com/photos/zaragozaantigua/54413600082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22110, 'Calle Mayor 1951', 'Imagen del ├║ltimo tramo de la calle Mayor, paralelo a la iglesia parroquial de la Magdalena, casi ya en la plaza del mismo nombre. En el lateral del templo luce soleado, a├║n, el antiguo bajorrelieve en forma de capilla, o figurado altar, dedicada a San Crist├│bal de Licia, que adem├ís le daba nombre al arquitrabado "arco" bajo el que embocaba, justo enfrente, la calle de San Crist├│bal, entre la "Farmacia" de la imagen (edificio luego derribado), y el abalconado n┬║ 60 de la calle Mayor (sobrevive). Esta tipolog├¡a de "arcos" era pr├íctica com├║n como forma de ganar espacio extra habitacional en zonas densamente edificadas de la ciudad antigua, dejando la altura suficiente para que pudiera transitar por debajo, sin problemas, una persona a lomos de caballer├¡a. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22004534908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22004534908.webp', 'https://www.flickr.com/photos/zaragozaantigua/22004534908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22141, 'Calle de Gav├¡n 1951', 'Imagen de la calle de Gav├¡n, que fuera antiguo callizo de Domingo Vero, capturada en el tramo entre la plaza de Asso, y la calle de Palafox, al fondo destaca el esquinero y superviviente palacio del siglo XVI de los Gurrea de Castro. Fuente visual: Juan Mora Insa, Archivo Municipal de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65362100, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBF4A7D59DAA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25052731130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25052731130.webp', 'https://www.flickr.com/photos/zaragozaantigua/25052731130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21644, 'Fray Luis Amig├│ 1921', 'Imagen capturada en la casa-reformatorio del Buen Pastor establecida desde 1917 en Torre-Ramona, con un posado de la comunidad de religiosos Terciaros capuchinos de N┬¬ S┬¬ de la Soledad encargada de administrar esta instituci├│n. Entre los posantes destaca la figura de Fray Luis Amig├│ (nacido como Jos├® Mar├¡a Amig├│ Ferrer), el segundo sentado desde la izquierda, fundador de la congregaci├│n en 1889 y obispo desde 1907, durante una visita a sus hermanos. Una derivada de su apellido hizo que popularmente se conociera a esta congregaci├│n como "amigonianos".', 1921, 1921, 1921, 'Anos 20', 'LAS FUENTES', 41.64205800, -0.86345600, '0101000020E6100000861E317A6EA1EBBF4D11E0F42ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51246815274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51246815274.webp', 'https://www.flickr.com/photos/zaragozaantigua/51246815274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22900, 'Felipe Gonz├ílez 1983', 'Foto: EFE. Felipe Gonz├ílez, presidente del gobierno espa├▒ol entre 1982 y 1996, inaugura la 17┬¬ edici├│n de la FIMA (Feria Internacional de Maquinaria Agr├¡cola) en la Feria de Muestras de Zaragoza. A la izquierda, Jos├® Luis Mart├¡nez Candial, entonces presidente de la C├ímara de Comercio e Industria de Zaragoza y despu├®s de Ibercaja. Fuente: Ayuntamiento de Valladolid.', 1983, 1983, 1983, 'Anos 80', 'UNIVERSIDAD', 41.63759000, -0.89959300, '0101000020E6100000A5BC564277C9ECBFDA20938C9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21246408275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21246408275.webp', 'https://www.flickr.com/photos/zaragozaantigua/21246408275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22177, 'Calle del Asalto 1951', 'Despejada imagen de la parte final de la calle de Asalto capturada desde el principio de la calle de Monreal, con el irregular tramo donde desembocan en ella, por la derecha, las calle de la Reboler├¡a, y la de Alonso V. A la izquierda, olmos (posiblemente) junto a la acequia que prove├¡a de agua a los talleres y f├íbricas textiles ubicadas en esta zona, recuerdo de cuando siglos atr├ís esta era la "reboler├¡a" de la ciudad, donde se trataban y curt├¡an pieles; de esta acequia se derivaba, poco despu├®s. un riego que todav├¡a era denominado "de los Curtidores". A continuaci├│n de los ├írboles, el ingreso al cuartel de Remonta y de Sementales del Ej├®rcito y, al fondo, la antigua y gran torre de Juan Faustino Bruil y Olliarburu, luego de Monserrat, y que en 1965 ser├¡a parque Bruil. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65197000, -0.86989200, '0101000020E61000003FAA61BF27D6EBBF8FFCC1C073D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31583846812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31583846812.webp', 'https://www.flickr.com/photos/zaragozaantigua/31583846812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22251, 'Calle de San Crist├│bal 1953', 'Pintura de la calle y el arco de San Crist├│bal, por Antonio Mar├¡a Almaz├ín, 1953. Al fondo, el inicio de la calle Mayor.', 1953, 1953, 1953, 'Anos 50', 'CASCO HIST├ôRICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54414106768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54414106768.webp', 'https://www.flickr.com/photos/zaragozaantigua/54414106768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22279, 'Universidad de la Magdalena 1968', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 05/09/1968. Derribo de la antigua Universidad de la Magdalena. Imagen tomada desde la Plaza de la Magdalena. A la derecha, el Coso Bajo. "Hay que rendirse a la evidencia, no se pod├¡a evitar la demolici├│n de un edificio como ├®ste: un caser├│n inmenso que no admit├¡a reformas satisfactorias y que, al desaparecer, dar├í paso a modernos y eficaces edificios que albergar├ín centros y dependencias de Ense├▒anza Media y Primaria, construidos de acuerdo con las m├ís modernas directrices pedag├│gicas. Y el futuro gran edificio tendr├í desde luego una fachada de estilo mud├®jar, que har├í juego con la inmediata iglesia de la Magdalena, cuya graciosa torre ha sido devuelta al m├ís brillante momento de su pr├¡stino g├│tico-mud├®jar; con lo que la plaza que se abre ante ella puede convertirse en uno de los rincones m├ís evocadores y bellos de Zaragoza". ÔÇö Ram├│n Salanova (ABC, 21.09.1968)', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65241600, -0.87349300, '0101000020E6100000211E8997A7F3EBBF8EB1135E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14990204666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14990204666.webp', 'https://www.flickr.com/photos/zaragozaantigua/14990204666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22386, 'Calle ├ôrgano 1968', 'Calle del ├ôrgano. A la izquierda, iglesia de la Magdalena. Al fondo, calle Mayor. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65261600, -0.87412200, '0101000020E610000001DA56B3CEF8EBBF556CCCEB88D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22529747333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22529747333.webp', 'https://www.flickr.com/photos/zaragozaantigua/22529747333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22387, 'Calle Mart├¡n Carrillo 1968', 'Calle de Mart├¡n Carrillo. A la derecha, la iglesia de la Magdalena. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65251900, -0.87375700, '0101000020E610000095D5743DD1F5EBBF62821ABE85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22530671053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22530671053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22530671053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22390, 'Pl. de la Magdalena 1968', 'Plaza de la Magdalena desde la calle Mart├¡n Carrillo. A la derecha, la calle Mayor. Al fondo, el Coso Bajo. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65227100, -0.87348900, '0101000020E6100000C64D0D349FF3EBBF8A90BA9D7DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22733787348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22733787348.webp', 'https://www.flickr.com/photos/zaragozaantigua/22733787348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22395, 'Calle Mart├¡n Carrillo 1968', 'Casa Tejada, en la esquina de la calle Mart├¡n Carrillo con la de la Universidad (derecha), vista desde la plaza de la Magdalena. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65245500, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF4C8E3BA583D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22831783030.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22831783030.webp', 'https://www.flickr.com/photos/zaragozaantigua/22831783030/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22396, 'Calle Don Teobaldo 1968', 'Esquina de la calle de Don Teobaldo frente al Monasterio de la Resurrecci├│n, tambi├®n llamado Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65362600, -0.87258700, '0101000020E6100000A6457D923BECEBBF5CE84A04AAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22832693050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22832693050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22832693050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22408, 'Universidad Magdalena 1968', 'Imagen capturada desde la plaza de la Magdalena durante el derribo de la antigua Universidad Literaria all├¡ ubicada. Considerada mayoritariamente un "caser├│n inmenso que no admit├¡a reformas satisfactorias", estrangulaba adem├ís el vital tr├ífico rodado del Coso Bajo, pues cuando fue construida no se tuvo la previsi├│n de pensar en ├®l. En primer plano, montoneras de piedras y cascotes de ladrillos producto del derribo. Al frente, la "Capilla de Cerbuna", sede de la Biblioteca universitaria, mantenida en pie y declarada Monumento Hist├│rico-Art├¡stico (Decreto de 13 de marzo de 1969), aunque cuatro a├▒os despu├®s se hundir├í como resultado de no haber realizado ninguna obra de consolidaci├│n y/o protecci├│n efectiva del edificio que, aislado de las construcciones que le arropaban, termin├│ cay├®ndose "solo". A la derecha, el Coso Bajo. Sic transit gloria Urbis. Fuente visual: Joaqu├¡n Gil Marraco (Cat├ílogo Exposici├│n grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaci├│n de Jos├® Luis Cintora.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65249500, -0.87271600, '0101000020E61000001C45D61A4AEDEBBFDAE6C6F484D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24558378586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24558378586.webp', 'https://www.flickr.com/photos/zaragozaantigua/24558378586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22613, 'Capilla de Cerbuna 1973', 'Foto Monge, 1973. El domingo 6 de mayo de 1973, por la tarde, se hundi├│ la Capilla Pedro Cerbuna de la antigua Universidad de Zaragoza. Era el ├║nico vestigio que quedaba en pie. Este monumento Hist├│rico Art├¡stico dej├│ sus escombros sobre el patio del colegio anexo (Colegio nacional Nuestra Se├▒ora de La Magdalena), hoy instituto. En la imagen, tomada desde el Coso Bajo, la torre de la Magdalena a la izquierda. Fuente: Diario Amanecer, 8 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19190968590.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19190968590.webp', 'https://www.flickr.com/photos/zaragozaantigua/19190968590/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22614, 'Capilla de Cerbuna 1973', 'Foto Monge, 1973. El domingo 6 de mayo de 1973, por la tarde, se hundi├│ la Capilla Pedro Cerbuna de la antigua Universidad de Zaragoza. Era el ├║nico vestigio que quedaba en pie. Este monumento Hist├│rico Art├¡stico dej├│ sus escombros sobre el patio del colegio anexo (Colegio nacional Nuestra Se├▒ora de la Magdalena), hoy instituto. La imagen est├í tomada desde el Coso Bajo. Fuente: Diario Amanecer, 8 de mayo de 1973.', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19191178720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19191178720.webp', 'https://www.flickr.com/photos/zaragozaantigua/19191178720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22673, 'Capilla Cerbuna 1973', 'Imagen de la antigua Capilla Pedro Cerbuna de la Universidad de Zaragoza, tras su derrumbe por dejaci├│n institucional, como reflejo de la abrumadoramente mayoritaria opini├│n de que eran meras viejas piedras que no pegaban con la moderna ciudad del momento. La imagen est├í capturada desde el Coso Bajo, ya desahogado de las apreturas que los muros de la vieja Universidad le supon├¡an, pues originaban unas estrecheces a la "circulaci├│n", que clamaban al cielo. Al poco tiempo, todo fue terminado de derribar, y todos, tan contentos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65249500, -0.87271600, '0101000020E61000001C45D61A4AEDEBBFDAE6C6F484D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24191131276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24191131276.webp', 'https://www.flickr.com/photos/zaragozaantigua/24191131276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22713, 'Calle de Olleta 1979', 'Imagen capturada en la calle de Jusepillo de Olleta y centrada en el tramo de los pares entre las calles de Alcober y de Luz├ín, donde destacaba el antiguo n├║mero 12, un inmueble de tres alturas representativo de la arquitectura tradicional en esta zona de la ciudad. A la derecha, vista parcial del antiguo n┬║ 10. A├▒os m├ís tarde, casi todos los edificios de este lado de la calle ser├¡an derribados, y sobre ellos se construir├¡an modernos inmuebles, algunos ya en la segunda d├®cada del siglo XXI. A la izquierda, el bajo y esquinero n┬║ 10 de la calle de Luz├ín, que perdura rehabilitado, y despu├®s el n┬║ 15 de la calle de Olleta, derribado luego. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65227400, -0.87181300, '0101000020E6100000E4486760E4E5EBBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29281975518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29281975518.webp', 'https://www.flickr.com/photos/zaragozaantigua/29281975518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22781, 'Pl. de Asso 1979', 'Imagen capturada en la plaza de Ignacio Jord├ín de Asso y centrada en la antigua casa del siglo XVI que desde el siglo XVII era de la familia La Balsa, en el siglo XVIII de los La Balsa-Campi (marquesado del Palacio) para terminar recayendo en los Asso. La importancia de este edificio, aun en un entorno donde se ubicaban otras significadas casas de infanzones y nobles, determin├│ la sucesiva denominaci├│n de este recoleto espacio urbano: plaza de La Balsa, de Campi, y de Asso. De esta casa, tras varias modificaciones e intervenciones (la m├ís reciente a├║n en curso) perdura, grosso modo, la traza de la fachada principal. A la izquierda, acceso a la calle de Gav├¡n y a la derecha, a la calle de Torrellas. Fuente visual: AMZ.', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65317200, -0.87391600, '0101000020E6100000B56FEEAF1EF7EBBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37748363585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37748363585.webp', 'https://www.flickr.com/photos/zaragozaantigua/37748363585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22852, 'Torre de La Magdalena c.1987', 'Vista desde el edificio de la calle Pelegr├¡n 3 de la torre mud├®jar de la iglesia de Santa Mar├¡a Magdalena de Zaragoza. Al fondo, el Pilar.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259848878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259848878.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259848878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22862, 'Barrio de la Magdalena 1987', 'Luis M├¡nguez. 1987. Desde la torre de la iglesia de la Magdalena, una mirada hacia el suroeste, siguiendo la calle de las Cortes├¡as, que tras llegar a San Lorenzo, se denomina de los Estudios, hasta llegar a San Jorge y toparse con la Iglesia del Real Seminario de San Carlos Borromeo, que fue la Sinagoga mayor hasta que los jesuitas le echaron el ojo. Luego, tras cruzar el Coso, la calle Espartero conduce hasta la plaza de San Miguel, donde la antigua puerta del Duque de la Victoria, se cruza el Huerva por el puente de San Jos├®, y la bruma ya no nos deja ver mucho m├ís, aunque al fondo sobresale la Plana de Zaragoza. A la izquierda, en primer├¡simo plano, una rara visual a├®rea de la plazuela de la calle San Crist├│bal, con coche aparcado, por supuesto.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15658335797.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15658335797.webp', 'https://www.flickr.com/photos/zaragozaantigua/15658335797/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22874, 'Calle Mayor 1987', 'Luis M├¡nguez. 1987. Desde la torre de la iglesia de la Magdalena, un vistazo siguiendo el decumano m├íximo en direcci├│n oeste, o calle Mayor hacia la avenida de C├®sar Augusto, donde la puerta de Toledo recordaba el cierre del per├¡metro amurallado de la ciudad romana. Sobre un panorama de tejados y cubiertas, en primer plano, el cruce con la trinchera de San Vicente de Pa├║l, cuya apertura en los primeros a├▒os 30 del s. XX transform├│ profundamente esta parte del Casco Hist├│rico. En l├¡nea recta, m├ís o menos, la visual llega hasta la curva del r├¡o donde se levanta el puente de la Almozara. Hacia la derecha, agrupados, los remates del Torre├│n de la Zuda, y el cimborrio y la torrecilla de San Juan de los Panetes. Hacia la izquierda, el blanco remate bulboso del chafl├ín con Don Jaime I, de Francisco Albi├▒ana. Luego, la c├║pula y torres de Santa Isabel-San Cayetano. Casi al fondo, la mole habitacional de la plaza de Santo Domingo, junto a la torre de San Pablo. La mole est├í bastante m├ís lejos, pero su tama├▒o parece acercarla. A la izquierda m├ís extrema, la reciente torre "nueva" derecha de la iglesia de Santiago.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65246600, -0.87406100, '0101000020E610000096B036C64EF8EBBF3FE0810184D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15843975905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15843975905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15843975905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21233, 'Calle de Alfonso I 1908', 'Vista desde cierta altura de la calle de Alfonso I.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65309800, -0.88208100, '0101000020E61000000589EDEE013AECBFA08A1BB798D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19415078758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19415078758.webp', 'https://www.flickr.com/photos/zaragozaantigua/19415078758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22947, 'Calle de Alonso V 1987', 'Imagen capturada en la calle de Alonso V y centrada en uno de los antiguos torreones del recinto defensivo medieval en ladrillo de la ciudad all├¡ ubicados, que desde principios del siglo XVII hab├¡an sido adaptados para vivienda, al igual que los compases entre torreones. El de la imagen se corresponde con el cuarto torre├│n desde la puerta de la Portaza (luego del Sol, a la derecha, fuera de plano) y ya cercano al gran complejo del convento de San Agust├¡n. La vivienda all├¡ habilitada ten├¡a adjudicado el n├║mero 44 (luego 26) de la calle Alonso V, con traseras a la calle de las Arcadas. Una intervenci├│n municipal posterior supuso la restauraci├│n y rehabilitaci├│n (previo derribo de las viviendas adosadas de finales del siglo XIX) de este y otros dos torreones, adem├ís de algunos inmediatos lienzos del tramo de muralla. Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65207400, -0.87101900, '0101000020E61000005C3AE63C63DFEBBF34492C2977D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38603459816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38603459816.webp', 'https://www.flickr.com/photos/zaragozaantigua/38603459816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22955, 'Calle de Alonso V 1987', 'Imagen capturada en la calle de Alonso V y centrada en uno de los antiguos torreones del recinto defensivo medieval en ladrillo de la ciudad, que desde el siglo XVII hab├¡an sido adaptados para vivienda, al igual que en los compases entre los torreones se adosaron peque├▒as viviendas recayentes tanto a esta como a la trasera calle de las Arcadas. El de la imagen se corresponde con el cuarto torre├│n desde la puerta de la Portaza, luego del Sol, que quedaba a la derecha, fuera de plano. La vivienda all├¡ habilitada ten├¡a adjudicado el n├║mero 26 (antiguo 44) de la calle de Alonso V. A la derecha, el adosado inmueble del n┬║ 24 (antiguo 42), y a la izquierda restos del antiguo inmueble del n┬║ 46, ya cercano al gran complejo del convento de San Agust├¡n. Al fondo y a la izquierda, solana sobre las traseras del inmueble del n┬║ 13 de la calle de Barrioverde. En el momento de tomar esta fotograf├¡a se estaba procediendo a urbanizar la calle. Una intervenci├│n municipal posterior supuso la restauraci├│n y rehabilitaci├│n (previo derribo de las viviendas adosadas de finales del siglo XIX) de este y otros dos torreones, adem├ís de algunos inmediatos lienzos del tramo de muralla medieval.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65205600, -0.87085900, '0101000020E610000026AC8DB113DEEBBF8E942D9276D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48104213632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48104213632.webp', 'https://www.flickr.com/photos/zaragozaantigua/48104213632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22959, 'Calle de Mart├¡n Carrillo c.1981', 'Imagen capturada en el despejado entorno de calle de Mart├¡n Carrillo con el casi irreconocible aspecto de esta zona del barrio de la Magdalena tras los derribos de algunas de las antiguas casonas que tradicionalmente la caracterizaban, como la Casa de Tejada, que se levantaba en el inmediato solar de primer t├®rmino, y que a principios de los a├▒os 90 del pasado siglo XX ver├¡a construirse aqu├¡ unos apreciables inmuebles seriados que desde la plaza de Asso llegan hasta las calles de Torrellas y de la Universidad. A la izquierda, leve vista del renegrido muro de la iglesia parroquial de Santa Mar├¡a Magdalena y del inmueble esquinero con la calle del ├ôrgano, tambi├®n construido sobre otra solariega casona de cuyo nombre no quiero acordarme. En el centro y hacia el fondo, irrepetible vista del inmueble del n┬║ 21 de la calle de Don Juan de Arag├│n, recayente a la plazoleta que se abre en la confluencia con la calle de Pedro Li├▒├ín, visible temporalmente tras el derribo de la antigua casa que desde all├¡ llegaba hasta la plaza de Ignacio Jord├ín Asso, y desde 1983 sustituida por el actual inmueble del n┬║ 2-4 de la calle de Pedro Li├▒├ín. Al fondo se destaca la torre de la Seo y el remate de la torre de Santa Leonor del templo del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52123834300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52123834300.webp', 'https://www.flickr.com/photos/zaragozaantigua/52123834300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23022, 'Plaza de Asso 1997', 'Imagen capturada en la plaza de Ignacio Jord├ín de Asso y centrada en el antiguo inmueble del n┬║ 28 (antes n┬║ 36) de la calle de Juan de Arag├│n, una casona t├¡pica del siglo XVII de un modelo seriado bastante com├║n en el antiguo barrio de La Seo, y que aqu├¡ se muestra en muy precaria situaci├│n. Aparece flanqueada por modernos edificios de viviendas (a la derecha, el sesentero n┬║ 4 de la vecina calle de Torrej├│n; a la izquierda, el tardochentero n┬║ 1 de la plaza de Asso). A├▒os despu├®s esta casa fue derribada, perdurando todav├¡a el solar dejado. Esta imagen fue posible por el derribo, en los a├▒os setenta, de la antigua gran casa del n┬║ 1 de la plaza de Asso que confrontaba con ella, y cuyo solar sirvi├│ para ampliar notablemente la antigua y recoleta plaza.', 1997, 1997, 1997, 'Anos 90', 'CASCO HIST├ôRICO', 41.65298600, -0.87418500, '0101000020E61000009AEB34D252F9EBBF785F950B95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49352382846.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49352382846.webp', 'https://www.flickr.com/photos/zaragozaantigua/49352382846/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23074, 'Vista Sureste 2009', 'Foto Javier Pe├▒a, diciembre 2009. Vista de Zaragoza hacia el Sureste, desde la torre de la Seo. La imagen la preside la torre de La Magdalena. Fuente: www.facebook.com/photo.php?fbid=1012283675454144&set=...', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15304358694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15304358694.webp', 'https://www.flickr.com/photos/zaragozaantigua/15304358694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23120, 'Coso Bajo 2006', 'Vista del veterano solar esquinero del Coso Bajo (n├║mero 164) con la calle del Doctor Palomar (izquierda). Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65182800, -0.87327500, '0101000020E6100000C442AD69DEF1EBBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31106504104.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31106504104.webp', 'https://www.flickr.com/photos/zaragozaantigua/31106504104/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23236, 'Casa Edad de Hierro', 'Vista general de una casa en la I Edad de Hierro (750-500 antes de nuestra Era), en la actual calle Palafox n┬║ 26. Fuente visual: Historia de cuatro ciudades, 2001.', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65339000, -0.87333800, '0101000020E61000005C548B8862F2EBBF48C49448A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14969299326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14969299326.webp', 'https://www.flickr.com/photos/zaragozaantigua/14969299326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23471, 'Calle del ├ôrgano c.1935', 'Imagen de la puerta de acceso al antiguo n┬║ 3 de la calle del ├ôrgano, sobre la que destaca el dieciochesco blas├│n de la familia de los Sanez (sic) de Villa Nueva (Lanes de Villanueva). Esta casona, esquinera con la calle de Carrillo (a la derecha, fuera de plano), y frente a las traseras de la iglesia parroquial de la Magdalena, fue luego derribada al principio de los a├▒os 40, y levantado sobre su solar un edificio de nueva planta. La piedra armera con el escudo perdura en el Museo de Zaragoza. Fuente visual: Archivo Jos├® Galiay, AHPZ.', 1935, 1935, 1935, 'Anos 30', 'CASCO HIST├ôRICO', 41.65273900, -0.87398000, '0101000020E61000006475ABE7A4F7EBBF70E998F38CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31458861225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31458861225.webp', 'https://www.flickr.com/photos/zaragozaantigua/31458861225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23534, 'Universidad Magdalena 1932', 'Fotograf├¡a Mart├¡n Chivite. Heraldo de Arag├│n. 10-05-1932. El Debate parlamentario sobre el Estatuto de Catalu├▒a pronto se extendi├│ a un agrio debate paralelo en los peri├│dicos, especialmente entre la prensa m├ís reaccionaria. En la calle, los elementos de la derecha m├ís extrema, provocaron graves sucesos, como este de Zaragoza que salt├│ a la prensa estatal. En la Plaza de la Magdalena, entonces sede del Rectorado y las Facultades de Derecho y de Filosof├¡a y Letras de la Universidad, estudiantes contrarios al debate del Estatuto, desempedraron adoquines del firme, los introdujeron al interior de la Universidad, y se hicieron fuertes dentro. Avisados los Guardias de Asalto, fueron exhortaron a que depusieran su actitud, a lo que respondieron lanzando adoquines, uno de los cuales impact├│ sobre un Teniente, caus├índole heridas graves. Adem├ís, en los altercados que siguieron, con intercambio de disparos de bala incluido, resultaron heridos un par de estudiantes, y un Cabo. La Guardia de Asalto entr├│ en el recinto, detuvo a 60 estudiantes, y cesaron los disturbios. Al lugar acudieron el Gobernador, el presidente de la Audiencia Territorial, y un juez instructor. La Junta de Gobierno de la Universidad lament├│ lo sucedido, censur├│ el proceder de los causantes de los des├│rdenes, aplic├│ el Reglamento de disciplina escolar a los escolares menores de edad implicados, y abri├│ un expediente para depurar responsabilidades. Adem├ís, la Universidad fue clausurada dos d├¡as. Fuente: ABC Madrid. En la imagen, publicada en prensa despu├®s de los hechos, algunos de los estudiantes detenidos en el momento de abandonar el edificio de la Universidad de la Magdalena. Adoquines implicados, en el suelo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65208000, -0.87328900, '0101000020E6100000029CDEC5FBF1EBBF1630815B77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666083288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666083288.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666083288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23535, 'La Magdalena 1930', '"Iglesia de Santa Mar├¡a Magdalena".', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65230400, -0.87365400, '0101000020E61000006FA0C03BF9F4EBBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688755579.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688755579.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688755579/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23536, 'Plaza de la Magdalena 1930', '"La Universidad" (Plaza de la Magdalena).', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65222400, -0.87323600, '0101000020E61000004D13B69F8CF1EBBF49D576137CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688776958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688776958.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688776958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23537, 'Puerta de la Universidad c.1965', 'Puerta de la Universidad de Zaragoza en la plaza de la Magdalena.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65211300, -0.87332200, '0101000020E6100000F1129CFA40F2EBBFF225547078D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728749260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728749260.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728749260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23538, 'Pl. de la Magdalena 1677', 'Entrada de Carlos II en Zaragoza. Dibujo, 1910. El 1 de mayo de 1677 el rey Carlos II jur├│ los Fueros de Arag├│n en la Seo de Zaragoza, y el 14 daban comienzo, en presencia del monarca, las Cortes del Reino. Las Cortes se celebraron finalmente en Zaragoza, y no en Calatayud, como estaba previsto inicialmente. El rey permaneci├│ en la capital aragonesa hasta el 2 de junio. Fuente: reinadodecarlosii.blogspot.com.es/2012/03/las-relaciones-...', 1677, 1677, 1677, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15033442500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15033442500.webp', 'https://www.flickr.com/photos/zaragozaantigua/15033442500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23541, 'Puerta del Sol 1749', '"Puerta del Sol", Antonio Callaved, 2011. Esta puerta cerraba la ciudad al final del actual Coso Bajo, junto a las Tener├¡as. Fue construida en 1749 y derribada en el siglo XIX. La piedra con un sol tallado que la coronaba se conserva en el Museo de Zaragoza. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1749, 1749, 1749, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092631837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092631837.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092631837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23542, 'Incendio discoteca Flying 1990', 'Foto Eduardo Bayona/El Peri├│dico de Arag├│n. La madrugada del domingo 14 de enero de 1990 se produjo un incendio en la discoteca Flying, sita en la esquina de la calle Trinidad con Don Teobaldo. Murieron 43 personas. En la imagen podemos ver varios de los cad├íveres depositados en el exterior de la sala, en la calle Trinidad.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65333800, -0.87267200, '0101000020E6100000335184D4EDECEBBFF59D5F94A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161776125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161776125.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161776125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23544, 'Pl. de San Agust├¡n 1964', 'Celebracioes festivas en la plaza de San Agust├¡n en 1964. Fuente: www.facebook.com/photo.php?fbid=385217108301791&set=o...', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST├ôRICO', 41.65090800, -0.87080100, '0101000020E6100000FF5E0A0F9ADDEBBF365A0EF450D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15738315929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15738315929.webp', 'https://www.flickr.com/photos/zaragozaantigua/15738315929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23545, 'Calle de la Universidad 1954', 'Chiquiller├¡a jugando entre claroscuros en la calle de la Universidad. Una canci├│n infantil parece escucharse entre risas: Al corro de la patata, comeremos ensalada, como comen los se├▒ores, naranjitas y limones... Al fondo, la plaza de la Magdalena, y a la izquierda e inmediata, la calle de la Trinidad. Este entorno, luego desaparecido, s├│lo perdura ya en la memoria, como sucede con el que fuera trenque de la muralla de piedra, la plaza del Estudio, y los colegios de San Vicente Ferrer, de la Trinidad y de San Juan Bautista de los Navarros. Y por supuesto el edificio de la vieja Universidad, entre las puertas de Valencia y del Sol. En la solana de la imagen, entrada del viejo Instituto Goya, denominaci├│n desde 1933 del anterior Instituto de Segunda Ense├▒anza de la Magdalena. Fuente visual: Foto Pomar├│n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65329800, -0.87267200, '0101000020E6100000335184D4EDECEBBF6745D4449FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16166489434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16166489434.webp', 'https://www.flickr.com/photos/zaragozaantigua/16166489434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23546, 'Las Tener├¡as 1591', 'F. Mota es el nombre con el que firmaba sus trabajos el pintor Fernando Fern├índez Mota, ilustrador de publicaciones entre finales del XIX y principios del XX. En este caso, se trata de otro interesante ejercicio de reinvenci├│n hist├│rica propio del nacionalismo rom├íntico decimon├│nico, aqu├¡ centrado en los extra├▒os sucesos y alteraciones del verano de 1591. Esta imagen es muestra de los desvar├¡os que dichas alteraciones produjeron en el imaginario rom├íntico-conservador. Tomando una reciente fotograf├¡a del franc├®s Jean Laurent de un pedazo del lienzo de las murallas medievales de las Tener├¡as, este pintor ceut├¡ F. Mota agrega unos desorientados soldados que parecen sacados de una expedici├│n del extreme├▒o Pizarro al otro lado del charco, y construye una representaci├│n considerada "pintura hist├│rica". Que los soldados est├ín desorientados, es literal: viniendo desde Utebo (como dicen las cr├│nicas hist├│ricas), en lugar de entrar por la puerta de Sancho, la del Portillo, o incluso la de Baltax, esta tropa habr├¡a dado la vuelta a la ciudad, hasta buscar el ingreso por la Portaza. Mientras tanto, la ciudad, al fondo, esperando pacientemente a ser "conquistada". Fuente visual: ÔÇ£Entrada de las tropas castellanas en ZaragozaÔÇØ, Fernando Fern├índez Mota, 1919.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65335400, -0.87184100, '0101000020E610000061FBC9181FE6EBBFFB5A971AA1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17666352789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17666352789.webp', 'https://www.flickr.com/photos/zaragozaantigua/17666352789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23547, 'Coso Bajo 1959', 'Imagen del punto donde la antigua calle de San Lorenzo desemboca en el Coso. El edificio central, esquinero entre ambas calles, con el a├▒adido del peque├▒o de su derecha, varias d├®cadas despu├®s ser├í reinventado en nueva planta. Los dem├ís edificios, perduran. Fuente visual: "Arag├│n. Cuatro ensayos", 1960, Banco de Arag├│n.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65171100, -0.87362700, '0101000020E610000009E23C9CC0F4EBBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18797925412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18797925412.webp', 'https://www.flickr.com/photos/zaragozaantigua/18797925412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22167, 'Vista a├®rea Las Fuentes 1955', 'Vista a├®rea del n├║cleo inaugural del barrio de Las Fuentes: las viviendas para tranviarios llamadas Grupo Vizconde de Escoriaza, levantadas en 1953, y la primera fase del grupo de viviendas "Jos├® Antonio Gir├│n", de 1955. En 1957, el tranv├¡a ampliar├í sus servicios hasta aqu├¡, con la inauguraci├│n de su l├¡nea 17 "Las Fuentes". Al fondo, el r├¡o Ebro y la ciudad consolidada. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1955, 1955, 1955, 'Anos 50', 'LAS FUENTES', 41.64833000, -0.85835400, '0101000020E61000004D81CCCEA277EBBF0282397AFCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30989909240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30989909240.webp', 'https://www.flickr.com/photos/zaragozaantigua/30989909240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23548, 'Pl. de la Magdalena 1591', '"Mot├¡n en Zaragoza en defensa de los Fueros". Ilustraci├│n de Fernando Fern├índez Mota, 1910 La fantas├¡a recreacionista asociada a la instrumentalizaci├│n pol├¡tica del pasado hist├│rico, en ocasiones genera escenarios delirantes como el presente, en el que el autor de la ilustraci├│n sit├║a una acci├│n de 1591 en un entorno imposible en el barrio de la Magdalena de esa ├®poca: la Puerta de Valencia se ha evaporado, siendo que fue derribada casi tres siglos despu├®s (1867), y la puerta de acceso a la iglesia parroquial de la Magdalena es recolocada tal y como quedar├í tras su orientaci├│n de 1730 (hasta entonces, por la calle Mayor), e incluso aparece la portada neocl├ísica que le ser├í a├▒adida m├ís tarde, en 1758. Si este es el escenario de la Magdalena de 1591, c├│mo ser├ín los sucesos que en ella acontecen. Fuente: Historia de Espa├▒a, Miguel Segu├¡, 1910.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18965139881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18965139881.webp', 'https://www.flickr.com/photos/zaragozaantigua/18965139881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23549, 'Pedro Santisteve 1990', 'Pedro Santisteve (Zaragoza, 1958), abogado penalista y alcalde de Zaragoza desde 2015, sustituyendo a Juan Alberto Belloch (2003-2015). En la imagen, en el bar La V├¡a L├íctea (Doctor Palomar 25) en 1990. Fuente: Asociaci├│n Cultural y Recreativa Barrio Verde de Zaragoza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65113200, -0.87187600, '0101000020E61000007D5A457F68E6EBBF85B01A4B58D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19065572706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19065572706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19065572706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23550, 'Calle Mayor 1847', 'Dibujo de Jos├® G├│mez Piquer de 1997, recreando el rinc├│n de la calle Mayor n┬║ 59 (a la izquierda, fuera de la imagen) donde fue instalada la Escuela Profesional de Veterinaria de Zaragoza en 1847, y hasta 1853. En las inmediaciones, en la esquina de la calle de Torrej├│n con Mayor, hoy sede del PCE en Arag├│n, tuvo su sede el Colegio de Nuestra Se├▒ora del Torrej├│n, colegio mayor universitario seglar fundado en 1602 y clausurado a mediados del siglo XIX. El dibujo supone la torre de la iglesia de La Magdalena sin su recrecimiento barroco, que s├¡ estaba en la fecha que se intenta reflejar. Fuente: Cr├│nica de 150 a├▒os de estudios veterinarios en Arag├│n. IFC, 2000.', 1847, 1847, 1847, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115291828.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115291828.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115291828/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23551, 'Coso Bajo 1984', 'Foto Arturo Burgos, 1984. Calle del Coso Bajo de Zaragoza en 1984, con visual de sus n├║meros pares en el tramo comprendido entre las plazas de La Magdalena y las Tener├¡as. Fuente: Zaragoza, sus calles y su historia, 1984.', 1984, 1984, 1984, 'Anos 80', 'CASCO HIST├ôRICO', 41.65240800, -0.87278000, '0101000020E6100000CB4A9352D0EDEBBF0BD3F71A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19428864662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19428864662.webp', 'https://www.flickr.com/photos/zaragozaantigua/19428864662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23553, 'Plaza de la Magdalena 1960', 'Imagen del funeral, el 19 de octubre de 1960, de Carmelo Zald├¡var, jefe de administraci├│n del Ayuntamiento de Zaragoza. La comitiva se dirige, desde la calle Mayor, a la puerta de la iglesia de la Magdalena. En el lateral del templo se observa la capilla exterior adosada dedicada a San Crist├│bal, como el arco que ten├¡a enfrente en la calle del mismo nombre. AL fondo de la calle, el mercado de San Vicente de Pa├║l, recayente a la v├¡a del mismo nombre. Fuente: AMZ.', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65236800, -0.87371300, '0101000020E6100000ACE122F774F5EBBF7D7A6CCB80D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20466773353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20466773353.webp', 'https://www.flickr.com/photos/zaragozaantigua/20466773353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23554, 'Calle del ├ôrgano 1989', 'La calle del ├ôrgano el 17 de febrero de 1989, en las traseras de la iglesia de La Magdalena, que debe su nombre al recept├ículo de ese instrumento, que forma un pasadizo o arco sobre la v├¡a. En primer plano, el pil├│n de piedra ya desaparecido, como casi todos los de su entorno. La imagen est├í tomada desde la calle Mayor, con la de Mart├¡n Carrillo al fondo. Fuente: "Memoria de las calles de Zaragoza", Juli├ín Ruiz Mar├¡n, Librer├¡a General, 2002.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65244800, -0.87403700, '0101000020E610000074CE4F711CF8EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21053815984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21053815984.webp', 'https://www.flickr.com/photos/zaragozaantigua/21053815984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23557, 'Calle de Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agust├¡n y termina en la de las Arcadas. La imagen est├í capturada justo antes de que la calle Barrioverde cruce la calle Olleta, ascendente y adoquinada de izquierda a derecha. Al fondo, a la izquierda, se deriva la calle de Luz├ín. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65219900, -0.87368200, '0101000020E6100000EB5223F433F5EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22728082717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22728082717.webp', 'https://www.flickr.com/photos/zaragozaantigua/22728082717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23560, 'Calle San Crist├│bal 1965', 'Ins├│lita imagen, posiblemente de la antigua plazuela de Juan del Corral, como ensanche de la calleja de San Crist├│bal de la Magdalena, que conectaba la calle de San Lorenzo, al fondo, con la calle Mayor, en este caso bajo un arquitrabado arco nominado tambi├®n "de San Crist├│bal". De ser as├¡, esta plazuela tendr├¡a relaci├│n con el lugar donde estuvo la casa solariega de esta familia infanzona de caballeros hidalgos, apellidados del Corral, o Xim├®nez del Corral, que se establecieron en la ciudad en el siglo XVII. Unos a├▒os despu├®s de esta captura fotogr├ífica, el entorno edificatorio fue bastante transformado, aunque la plazuela mantiene su planta de "quesito" (m├ís o menos). Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65212200, -0.87414100, '0101000020E6100000B1F7E28BF6F8EBBF4580D3BB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22758258227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22758258227.webp', 'https://www.flickr.com/photos/zaragozaantigua/22758258227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23561, 'Calle Olleta 1967', 'Calle de Jusepillo de Olleta en 1967. Comienza en la de San Agust├¡n y termina en la de las Arcadas. Hoy radicalmente transformada. La imagen est├í capturada, precisamente, donde la calle Olleta desembocaba en la calle de las Arcadas, cuyo antiguo (y desaparecido) azulejo n├║mero 21, bajo el de la aseguradora de incendios, referencia el lugar. Los tendedores con cuerda, y una prenda a secar, se├▒ales de moradores. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65219900, -0.87187900, '0101000020E6100000C136E2C96EE6EBBFF1BDBF417BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22826932950.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22826932950.webp', 'https://www.flickr.com/photos/zaragozaantigua/22826932950/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23565, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en el tramo de los antiguos y dispares n├║meros impares entre la calle de San Lorenzo (izquierda) y la plaza de la Magdalena (a la derecha, fuera de plano). Este tramo ser├¡a profundamente remodelado a├▒os despu├®s. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65182500, -0.87363700, '0101000020E6100000EC6AF294D5F4EBBF8CDB68006FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24834862868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24834862868.webp', 'https://www.flickr.com/photos/zaragozaantigua/24834862868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23566, 'Plaza de la Magdalena 1960', 'Imagen, desde cierta altura, de la sesentera plaza de la Magdalena durante el funeral de Carmelo Zald├¡var, jefe de administraci├│n del Ayuntamiento. A la izquierda, la calle Mayor. En el centro, la iglesia parroquial de Santa Mar├¡a Magdalena, funcional, y con el remate barroco de la torre. A la derecha, el edificio de la antigua Universidad Literaria (hasta 1958 sede del Instituto Goya), y el que fuera colegio de San Juan Bautista. Por encima, despuntan dos torres pilaristas. Fuente visual: Archivo Municipal de Zaragoza.', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65223900, -0.87360700, '0101000020E610000042D0D1AA96F4EBBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25499727161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25499727161.webp', 'https://www.flickr.com/photos/zaragozaantigua/25499727161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23568, 'Pl. de San Agust├¡n 1991', 'Imagen parcial de la plaza de San Agust├¡n capturada desde el final de la calle Viola, con vista del espacio donde desembocan las calles de San Agust├¡n y de las Arcadas. A la derecha, parte del antiguo convento y cuartel de San Agust├¡n que luego ser├¡a reformada para acoger la biblioteca municipal Mar├¡a Moliner. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65116000, -0.87126600, '0101000020E61000004DBC033C69E1EBBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28318398369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28318398369.webp', 'https://www.flickr.com/photos/zaragozaantigua/28318398369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23569, 'Calle Mart├¡n Carrillo a├▒os 30', 'Acuarela de Ambrosio Ruste representando la calle de Mart├¡n Carrillo, con la iglesia de la Magdalena a la derecha y la plaza hom├│nima al fondo. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65255000, -0.87373700, '0101000020E6100000CEC3094CA7F5EBBF9D8026C286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31595527374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31595527374.webp', 'https://www.flickr.com/photos/zaragozaantigua/31595527374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23573, 'Pl. Magdalena 1931', 'Foto: Miguel Mar├¡n Chivite. "Animado aspecto de las puertas del colegio electoral instalado en la Universidad, durante la ma├▒ana del domingo" 12 de abril de 1931, d├¡a de las elecciones municipales, cuyo resultado determin├│ la llegada de la Segunda Rep├║blica dos d├¡as despu├®s. Fuente: Heraldo de Arag├│n.', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST├ôRICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31898187726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31898187726.webp', 'https://www.flickr.com/photos/zaragozaantigua/31898187726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23574, 'Plaza de la Universidad c.1929', 'Imagen de la monumental escalera de la antigua Universidad Literaria de la Magdalena. Esta fue una de las destacadas piezas que Ricardo Magdalena dio nuevo empaque en la gran reforma acometida entre 1907-1912. De 1925 es el elemento que centraliza la imagen, una l├ípida que fue inaugurada durante la Dictadura de Primo de Rivera, con presencia del rey Alfonso XIII, en homenaje a los estudiantes valencianos muertos en los asedios de Zaragoza en 1808-1809. Cuando en 1967 este lugar fue derribado, la l├ípida fue demediada y reinstalada sin atributos identificativos en un ins├│lito establecimiento de la ciudad. Oficialmente se la dio por desaparecida, de forma que la l├ípida que hoy se encuentra en el actual Paraninfo de la plaza de Para├¡so es una reproducci├│n de la l├ípida que, sobre el mismo asunto, fue inaugurada en 1924 en la Universidad de Valencia. Parece enrevesado, aunque tal vez s├│lo sea que Zaragoza tiene complejas sinuosidades que fluyen en el mar de fondo de su acontecer hist├│rico, bajo una enga├▒osa apariencia de simplicidad. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65283500, -0.87293900, '0101000020E6100000EBE40CC51DEFEBBF9357E71890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32214302646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32214302646.webp', 'https://www.flickr.com/photos/zaragozaantigua/32214302646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23576, 'Coso Bajo 1814', '"Entrada triunfal de Fernando VII en Zaragoza". ├ôleo sobre lienzo, Miguel Parra Abril, 1818. La escena representa la visita de Fernando VII a Zaragoza, el 6 de abril de 1814. La comitiva estaba formada tambi├®n por su hermano Carlos Mar├¡a Isidro, el duque de San Carlos y Jos├® Palafox. Entraron por el puente de Piedra, siguieron por las Tener├¡as, pasaron por la plaza de la Magdalena y subieron por el Coso hasta llegar al palacio de S├ístago. El rey estuvo en Zaragoza hasta el 11 de abril. El escenario escogido para el cuadro es el tramo del Coso Bajo con las simb├│licas ruinas del seminario, tomando como modelo el grabado de G├ílvez y Brambila de 1814 "Ruinas del Seminario". Se trata del edifico que se ve al fondo, entre las calles de San Jorge y San Lorenzo. Fuente visual: Palacio Real de Madrid.', 1814, 1814, 1814, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65158800, -0.87421900, '0101000020E61000009F56D11F9AF9EBBFA73B4F3C67D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32856669552.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32856669552.webp', 'https://www.flickr.com/photos/zaragozaantigua/32856669552/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23578, 'Universidad Literaria c.1929', 'Imagen capturada en el descansillo de la monumental escalera de la Universidad Literaria de la Magdalena, una de las destacadas piezas que Ricardo Magdalena hab├¡a reformado en 1907-1912 d├índole este imponente aspecto. En la planta baja, acceso desde el vest├¡bulo recayente a la plaza de la Magdalena y ventanas a la galer├¡a del patio de luces. Toda esta zona qued├│ convertida en un campo de cascotes cuando el edificio fue derribado a finales de la prodigiosa d├®cada de los a├▒os sesenta, que terminaron depositados en uno de los abundantes vertederos de escombros que jalonaban la periferia de una ciudad ensimismada en la modernidad y progreso. Fuente visual: foto Juan Mora Insa, en elblogdezaragoza.blogspot.com.es/', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65218900, -0.87338300, '0101000020E61000005C3CBCE7C0F2EBBFCDE7DCED7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34922119006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34922119006.webp', 'https://www.flickr.com/photos/zaragozaantigua/34922119006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23580, 'Calle del R├¡o 1986', 'Imagen capturada desde el solar de los antiguos talleres y almacenes municipales de la Reboler├¡a y centrada en los edificios de vivienda de los antiguos n├║meros 16, 18, 29 y 22 de la calle del R├¡o. A la derecha, ingreso al callej├│n del R├¡o. A la izquierda, esquinero y moderno bloque del n┬║ 18 de la calle Monreal. A├▒os despu├®s, estos inmuebles ser├¡an derribados y sustituidos por el moderno bloque del n┬║ 18 de la calle del R├¡o. Justo enfrente ser├¡a construido otro nuevo bloque correspondiente a los actuales n┬║ 7, 9 y 11 de la misma calle, junto al CEIP (Colegio P├║blico de Educaci├│n Infantil y Primaria) y al Pabell├│n Deportivo Municipal Tener├¡as. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65343700, -0.87010700, '0101000020E610000058A9A0A2EAD7EBBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37743144235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37743144235.webp', 'https://www.flickr.com/photos/zaragozaantigua/37743144235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23581, 'Iglesia Magdalena c.1966', 'Vista de la iglesia de Santa Mar├¡a Magdalena cuando comienzan a desmocharle la torre para devolverle el probable aspecto original, eliminando su remate barroco.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65253300, -0.87391700, '0101000020E6100000CC63CDC820F7EBBFC7478B3386D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38037597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38037597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/38037597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23582, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los solares y antiguos edificios correspondientes a los n├║meros 170, 172 y 174 del Coso, y el n├║mero 5 del arranque de la calle de San Agust├¡n (a la derecha). Desde finales de la d├®cada siguiente estos inmuebles ser├¡an derribados y sobre sus solares se levantar├¡an las actuales viviendas que all├¡ se ubican. Al fondo, a la derecha, el n┬║ 2 de la calle de Jusepillo Olleta. Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65204200, -0.87292900, '0101000020E6100000075C57CC08EFEBBF29CFBC1C76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38580739381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38580739381.webp', 'https://www.flickr.com/photos/zaragozaantigua/38580739381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23583, 'Coso Bajo 1986', 'Imagen capturada en el Coso Bajo y centrada en los antiguos edificios (de finales del siglo XIX) correspondientes a los n├║meros 174 (parcial), 176, 178 y 180, esquinero con el arranque de la calle de Alcober, de la que se muestran las fachadas de los n├║meros 1, 3 y 5. De todos ellos perdura el n├║mero 180. El resto fueron luego derribados, bien para dar paso a modernas construcciones habitacionales (actual n├║mero 174), bien para "esponjar" esta zona ubicada entra las plazas de la Magdalena, Tener├¡as, y San Agust├¡n mediante un solar habilitado para uso p├║blico (esquina Alcober-Coso). Fuente visual: AMZ.', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65241900, -0.87253200, '0101000020E6100000C3D4963AC8EBEBBFFF243E7782D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38639236771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38639236771.webp', 'https://www.flickr.com/photos/zaragozaantigua/38639236771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23584, 'Convento de San Agust├¡n 1809', 'Imagen del costumbrista ├│leo sobre lienzo &quot;Heroica defensa de la torre de San Agust├¡n en Zaragoza en la Guerra de la Independencia&quot; pintado por C├®sar ├ülvarez Dumont en 1884, posiblemente basado en el Episodio Nacional de Benito P├®rez Gald├│s, &quot;Zaragoza&quot;. Los ver├¡dicos hechos referidos sucedieron durante el segundo asedio de la ciudad por las tropas francesas, en febrero de 1809. El ├│leo centra la atenci├│n en el interior de la torre del convento de San Agust├¡n y unos peleones paisanos dispuestos en colorista y triangular composici├│n que culmina en la campana de la torre. A la izquierda, una gran bota de vino y varios grafitis patri├│ticos en la pared, entre los que destacan &quot;gabacho&quot;, despectiva denominaci├│n del franc├®s desde el siglo XVII y &quot;Pepe Botella&quot;, capciosa referencia al rey Jos├® I Bonaparte. Fuente visual: www.museodelprado.es', 1809, 1809, 1809, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65090300, -0.87077200, '0101000020E61000006BB8C83D5DDDEBBF24EF1CCA50D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39937575692.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39937575692.webp', 'https://www.flickr.com/photos/zaragozaantigua/39937575692/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23585, 'Calle de San Crist├│bal c.1965', 'Imagen capturada en la antigua calle de San Crist├│bal con una interesante vista parcial de la torre de la iglesia parroquial de la Magdalena emergiendo entre antiguas viviendas de la calle Mayor, construidas en el siglo XVI y muy reformadas en el XIX. El remate de la torre segu├¡a siendo el tradicional desde ├®poca barroca. Fuente visual: foto Palacio, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65225800, -0.87401200, '0101000020E61000003CF88903E8F7EBBFF646AD307DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40580927171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40580927171.webp', 'https://www.flickr.com/photos/zaragozaantigua/40580927171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23586, 'Calle de Jos├® Palafox 1991', 'Imagen centrada en el solar conformado tras el derribo del n┬║ 31 de la calle de Jos├® Palafox (tramo antiguamente denominado de San Vicente) y el n┬║ 15 de la calle Universidad (antigua de la Trinidad), tras una transitoria y colorista remodelaci├│n hasta que se llevara a cabo el correspondiente desarrollo urban├¡stico. Este solar lindaba, a la izquierda, con el antiguo Laboratorio Qu├¡mico Municipal construido en 1914 seg├║n proyecto del arquitecto municipal Jos├® de Yarza Echenique. A la derecha, los n├║meros 16 y 14 de la calle de Don Teobaldo, construidos en la d├®cada de los a├▒os treinta, y fachada del convento de las Canonesas Regulares del Santo Sepulcro. Pocos a├▒os despu├®s, sobre este solar ser├¡a construido el actual n┬║ 18 de la calle de Don Teobaldo. Fuente visual: AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65328400, -0.87295000, '0101000020E6100000E561A1D634EFEBBF028063CF9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42332210674.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42332210674.webp', 'https://www.flickr.com/photos/zaragozaantigua/42332210674/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23587, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los n├║meros 6-12 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la reboler├¡a, al otro lado de la entonces calle de las Tener├¡as. El estrechisimo inmueble del n┬║ 8, a la derecha del ├írbol de la escena, se correspond├¡a con uno de los antiguos torreones que desde finales del siglo XVII hab├¡a sido reconvertido en vivienda. Tras estos edificios circulaba la calle de las Arcadas, en el tramo donde a la izquierda desembocaba la calle de Jusepillo de Olleta. En el momento de tomar esta fotograf├¡a se estaba procediendo a urbanizar la calle de Alonso V. Una intervenci├│n municipal posterior supuso la restauraci├│n y rehabilitaci├│n, previo derribo de las viviendas adosadas, de este y otros dos torreones, adem├ís de algunos inmediatos lienzos del tramo de muralla medieval. En este caso la rehabilitaci├│n del oculto torre├│n tuvo que ser forzosamente muy creativa.', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65252900, -0.87143800, '0101000020E610000095BBCFF1D1E2EBBF8658FD1186D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48108411727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48108411727.webp', 'https://www.flickr.com/photos/zaragozaantigua/48108411727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23588, 'Calle de Alonso V 1986', 'Imagen capturada en la calle de Alonso V y centrada en el tramo de los inmuebles de los n├║meros 10-16 (de derecha a izquierda), adosados desde finales del siglo XIX sobre la muralla medieval de ladrillo que delimitaba la ciudad en esta zona, dejando extramuros a la reboler├¡a, al otro lado de la entonces calle de las Tener├¡as. El inmueble del n┬║ 16, a la izquierda, se hab├¡a construido previo derribo del tercero de los antiguos cubos de la muralla, desde la antigua puerta de la Portaza, luego del Sol. Tras estos edificios circulaba la calle de las Arcadas y el desemboque en la misma de la calle de Jusepillo de Olleta. En el momento de tomar esta fotograf├¡a se estaba procediendo a urbanizar la calle de Alonso V. Una intervenci├│n municipal posterior supuso la restauraci├│n creativa, previo derribo de las viviendas adosadas, de este tramo de la muralla medieval, y se apunt├│ la preexistencia del referido y desaparecido cubo de la muralla con una reconstrucci├│n parcial.', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65244800, -0.87127800, '0101000020E61000005E2D776682E1EBBF992B836A83D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48114400817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48114400817.webp', 'https://www.flickr.com/photos/zaragozaantigua/48114400817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23590, 'Calle de Mart├¡n Carrillo 1991', 'Imagen capturada desde cierta altura en el inmueble del n┬║ 5 de la calle del ├ôrgano, y centrada los modernos edificios residenciales que a la izquierda se extienden en esta manzana desde la calle de Torrellas, la plaza de Asso (n┬║ 6) la calle de Mart├¡n Carrillo (n┬║ 3, 5 y 7) y hasta la calle de la Universidad. Fueron proyectados por los arquitectos Te├│filo Mart├¡n S├íenz y Luis Fern├índez Ram├¡rez sobre los solares de antiguas casonas en esta parte del barrio de la Magdalena, incluyendo la fotog├®nica Casa Tejada. En primer t├®rmino, aspecto de la calle de Mart├¡n Carrillo tras la urbanizaci├│n integral de esta zona, dot├índola de nuevo mobiliario urbano, arbolado, iluminaci├│n e incluyendo itinerarios peatonales. A la izquierda, las referidas viviendas residenciales a├║n sin ocupar, y con los bajos comerciales tapiados de obra y a├║n vacantes. A la derecha, lienzo norte├▒o de la iglesia parroquial de Santa Mar├¡a Magdalena. Al fondo y a la izquierda, el IES Pedro de Luna, recayente a la plaza de la Magdalena y construido donde estuviera la hom├│nima universidad. Tras el Coso Bajo, vista parcial del solar tras derribo del n┬║ 164, esquinero con la calle de Alejandro Palomar y construido algunos a├▒os despu├®s.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65269700, -0.87387400, '0101000020E6100000FA635A9BC6F6EBBF429946938BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50262950396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50262950396.webp', 'https://www.flickr.com/photos/zaragozaantigua/50262950396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23591, 'Discoteca Flying 1990', 'Terrible matinal del domingo 14 de enero de 1990 tras el incendio en la discoteca Flying sita en la esquina de la calle de Don Teobaldo, desde donde se ha capturado esta imagen, con la de la Trinidad, que por la derecha y hacia el fondo desciende hasta el Coso Bajo. En primer t├®rmino, ingreso al local siniestrado en el que murieron 43 personas, con rastros en la fachada de las t├│xicas emanaciones causantes de la cat├ístrofe.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65330600, -0.87259700, '0101000020E610000089CE328B50ECEBBFEA23F0879FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50307864071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50307864071.webp', 'https://www.flickr.com/photos/zaragozaantigua/50307864071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23593, 'Calle de San Lorenzo 1991', 'Imagen del tramo final de la calle de San Lorenzo, con su tradicional peque├▒o comercio (como "Casa Paco. Novelas-Revistas", a la izquierda) y "aceras" liliputienses, capturada desde el desemboque en el Coso Bajo. Inmediato y a la derecha, vista parcial del gran solar resultante del derribo de los antiguos inmuebles de los n├║meros 53 y 55 de esta calle y de los n├║meros 135 y 137 del Coso, refundidos poco tiempo despu├®s en el moderno inmueble del n┬║ 137 del Coso. Hacia el fondo y a la izquierda, Arranque de la calle de los Pelegr├¡n y vista del esquinero inmueble del n┬║ 51 de la calle de San Lorenzo, que a finales de la d├®cada ser├í derribado y sustituido por el actual n┬║ 1 de los Pelegr├¡n.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65178300, -0.87377700, '0101000020E61000005CE7DF2EFBF5EBBF5D8B16A06DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50439910588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50439910588.webp', 'https://www.flickr.com/photos/zaragozaantigua/50439910588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23594, 'Calle de A├▒├│n 1991', 'Imagen capturada en la calle de Pedro Garc├®s A├▒├│n durante la construcci├│n, a la derecha, de las 45 viviendas municipales de alquiler levantadas sobre el gran solar dejado tras el derribo de los antiguos inmuebles de los n├║meros 5-7, 9 y 11-13 de esta calle, adem├ís del n┬║ 5-7 de la calle del Hero├¡smo. El ingreso a las viviendas desde donde se ha realizado la imagen estaba proyectado mediante un gran espacio interior porticado que recibir├¡a el nombre de plaza de A├▒├│n. Esta gran manzana delimitada entre las calles del Hero├¡smo, Cant├¡n y Gamboa, la Torre y A├▒├│n result├│ ser rica en restos arqueol├│gicos que a├▒os m├ís tarde, con motivo de nuevas excavaciones en esta ├║ltima calle, donde estuvieran los derribados inmuebles n┬║ 21 y 23, revelar├¡an las estructuras arquitect├│nicas de varias destacadas "domus" romanas de la dinast├¡a Julio-Claudia, abandonadas a finales del siglo I de nuestra era, donde se encontraron los restos del mejor conjunto de bienes muebles y decoraciones dom├®sticas de la colonia Caesaraugusta. Al fondo de la imagen, arranque de la calle de A├▒├│n desde la del Hero├¡smo.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65070100, -0.87352000, '0101000020E610000087DC0C37E0F3EBBFBC3C9D2B4AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494632363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494632363.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494632363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23595, 'La Magdalena, 1865', 'Iglesia de Santa Mar├¡a Magdalena recreada con el supuesto aspecto que ten├¡a antes de la gran reforma barroca que en 1727-30 reorient├│ su entrada principal, pasando de la calle Mayor a la antigua cabecera del templo, en la plaza de la Magdalena, y recreci├│ la original torre con un remate que aqu├¡ aparece en color m├ís atenuado y que perdur├│ hasta que fue eliminado en la rehabilitaci├│n de 1970. El punto de vista est├í tomado desde la plaza de la Magdalena, quedando a la izquierda la calle Mayor, y a la derecha la calle de Mart├¡n Carrillo. A espaldas quedaba la Puerta de Valencia.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65235200, -0.87378800, '0101000020E61000005664744012F6EBBF77BD344580D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50880882348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50880882348.webp', 'https://www.flickr.com/photos/zaragozaantigua/50880882348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24020, 'Calle Monreal 2002', 'En marzo de 2002 se celebr├│ en Zaragoza una "reuni├│n informal" de Ministros de Defensa de la Uni├│n Europea. El Foro Zaragoza 2002, formado por cerca de 40 asociaciones, convoc├│ un acto antimilitarista ante la puerta de la f├íbrica de armas Instalaza, en la calle Monreal 27. Esta empresa, fundada en 1943, "es una compa├▒ia de vanguardia que aplica las ├║ltimas tecnolog├¡as en el dise├▒o, desarrollo y fabricaci├│n de equipos y material para ofrecer soluciones eficaces". Sus productos "equipan a las fuerzas armadas de pa├¡ses de todo el mundo, con resultados muy satisfactorios y con un m├íximo nivel de operatividad y eficacia". Fuente: Agencia EFE.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65244700, -0.86942200, '0101000020E61000007F880D164ED2EBBFC9AF1F6283D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24629717866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24629717866.webp', 'https://www.flickr.com/photos/zaragozaantigua/24629717866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24220, 'Pl. de la Magdalena 1872', 'Dibujo: Pradilla; grabado: Severini. 1872. "Zaragoza. Fiestas del Pilar. Cabalgata hist├│rica de don Jaime el Conquistador." Grabado con la recreaci├│n hist├│rica de la entrada del rey Jaime I el Conquistador en la ciudad de Valencia el 28 de septiembre de 1238. Esta cabalgata fue incluida en el programa de las Fiestas del Pilar, y en la imagen se adentra en el Coso Bajo proveniente de la calle Mayor. Al fondo, la plaza de la Magdalena. Unos a├▒os antes se hab├¡a dado el nombre de Don Jaime I a uno de los principales viales de la ciudad. Fuente: "La Ilustraci├│n Espa├▒ola y Americana", Madrid, A├▒o XVI, n┬║ XLII, 08-11-1872.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65201200, -0.87320400, '0101000020E61000007590D78349F1EBBFBE4C142175D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15283479654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15283479654.webp', 'https://www.flickr.com/photos/zaragozaantigua/15283479654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24414, 'Tener├¡as 1942', 'Imagen de la capilla habilitada en el cuartel del Grupo de Autom├│viles del 5┬║ Cuerpo de Ej├®rcito, ubicado desde 1937 en la confluencia de la calle del Asalto, la plaza de las Tener├¡as, y la ribera del Ebro. Una buena muestra de la abrumadora memoria hist├│rica de la guerra de 1936-39, el perenne homenaje a los muertos durante la Cruzada, y la ├¡ntima relaci├│n entre fuerzas armadas, e iglesia cat├│lica. Fuente: Archivo Coyne. AHPZ', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST├ôRICO', 41.65370900, -0.87120100, '0101000020E610000087C267EBE0E0EBBFE90C8CBCACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32796858004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32796858004.webp', 'https://www.flickr.com/photos/zaragozaantigua/32796858004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24879, 'Muralla medieval c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1872-1879. Titulado "Torre├│n del Trovador", se trata de una de las torres de la muralla medieval de r├®jola, en la actual calle de Alonso V.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65237600, -0.87120600, '0101000020E6100000F986C267EBE0EBBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843226426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843226426.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843226426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24911, 'Muralla medieval 2013', 'Foto: Rusolera, abril de 2013. El 6 de abril de 2013 se derrumb├│ parte del lienzo de la muralla medieval de Zaragoza, entre la calle de Alonso V y la de las Arcadas. Unos 25 metros, que fueron repuestos meses despu├®s. Fuente: zaragozaciudad.net/zaragozafluye/2014/091801-muralla-medi...', 2013, 2013, 2013, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65259200, -0.87125700, '0101000020E610000080272D5C56E1EBBFCCD0782288D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21494516160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21494516160.webp', 'https://www.flickr.com/photos/zaragozaantigua/21494516160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25964, 'Colegio San Agust├¡n 1994', 'Tras el desalojo del 23 de diciembre de 1993 de la Casa de la Paz, en el paseo de Sagasta 52, el colectivo de okupas de Zaragoza busc├│ un nuevo alojamiento en el abandonado colegio de San Agust├¡n, en el n├║mero 5 de la calle hom├│nima, a principios de 1994, como ilustra la foto. Fueron desalojados en una semana. En mayo de 1996 volvieron a intentarlo.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST├ôRICO', 41.65153900, -0.87181600, '0101000020E6100000292504ABEAE5EBBFC68844A165D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52492136001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52492136001.webp', 'https://www.flickr.com/photos/zaragozaantigua/52492136001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20960, 'La Lonja 1858', '"Town Hall Zaragoza". J.B. Waring (dib.) y T.H. Macquoid (lit.), 1858. Colecci├│n Pascual de Quinto. Vista de la Lonja de Mercaderes de Zaragoza (Juan de Sari├▒ena, 1551), desde la plaza de La Seo. A la izquierda del edificio queda la calle del Pilar; a la derecha, la Casa de la Ciudad (antiguo Ayuntamiento), en la ribera del r├¡o Ebro; y donde pasa el jinete es la actual calle de Don Jaime I. Fuente: commons.wikimedia.org/wiki/File:Zaragoza_-_La_Lonja.webp', 1858, 1858, 1858, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65566000, -0.87642500, '0101000020E610000096B20C71AC0BECBFCEA5B8AAECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15498200202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15498200202.webp', 'https://www.flickr.com/photos/zaragozaantigua/15498200202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21030, 'Puerta del ├üngel 1860', '"Entrada de SS. MM. en Zaragoza por la puerta del ├üngel el d├¡a 7 de octubre de 1860". Dibujo con la vista desde el interior de la ciudad de la nueva Puerta del ├üngel, construida en el lugar de la anterior con motivo de la visita de la reina Isabel II, el rey consorte Francisco de As├¡s de Borb├│n, y los infantes y el heredero al trono, futuro Alfonso XII. A la izquierda, las "casas consistoriales" del viejo ayuntamiento. A la derecha, el edificio del arzobispado en la plaza de la Seo. La puerta estar├í en pie s├│lo ocho a├▒os. Su exagerada ornamentaci├│n superior, de materiales ef├¡meros, todav├¡a mucho menos. Fuente visual: AMZ', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24331023153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24331023153.webp', 'https://www.flickr.com/photos/zaragozaantigua/24331023153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21091, 'La Lonja c.1877', 'Imagen capturada en el interior de la nave-sal├│n de la renacentista Lonja de Mercaderes con una vista transversal orientada hacia el muro oriental y la puerta de ingreso desde la calle de la Lonja. A la izquierda y fuera de plano quedaban las dos puertas que la comunicaban con la anexa Casa Ayuntamiento. Destaca la b├│veda de crucer├¡a estrellada, las columnas denominadas "aragonesas" por la inserci├│n de un anillo en su fuste a un tercio de la altura, y la portada ornamentada en relieve y en yeso con el escudo imperial flanqueado por leones. Esta fotograf├¡a resulta excepcional ya que posiblemente incluye en ella el posado del fot├│grafo franc├®s Jean Laurent, de blanco y sentado a la izquierda, y su equipo de colaboradores.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52453284748.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52453284748.webp', 'https://www.flickr.com/photos/zaragozaantigua/52453284748/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21113, 'Lonja-Ayuntamiento c.1880', 'Al principio de la antigua calle de la Cuchiller├¡a, otra imagen de la Lonja en tiempos en que era utilizada como espacio para actos p├║blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no pod├¡an evadirse pagando), y algunas representaciones teatrales. A su derecha, inmediato, la Casa Consistorial en su ubicaci├│n de siglos y siglos, con el edificio levantado unas d├®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden d├│rico. Fuente visual: Anselmo Mar├¡a Coyne, Estudio Coyne (DARA_AHPZ)', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65591300, -0.87633500, '0101000020E610000097E2AAB2EF0AECBFB8020AF5F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23310046131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23310046131.webp', 'https://www.flickr.com/photos/zaragozaantigua/23310046131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21115, 'Calle de la Lonja 1889', 'Fachada principal del renacentista edificio de la Lonja, en una imagen capturada desde la plaza de la Seo. A su izquierda, la calle del Pilar, apenas un callej├│n antes del derribo de las parcelas de los n├║meros 36 a 44 accesorio, y la n┬║ 7 de la calle de Don Jaime I. A su derecha, las Casas de la ciudad, o ayuntamiento, y el ingreso desde el puente de Piedra. A pesar de que desde mediados del siglo XIX se acometi├│ la realineaci├│n y la unificaci├│n de los varios nombres que, de toda la vida, ten├¡an los diferentes tramos de la calle Don Jaime I (Nueva de San Gil, Baja de San Pedro, Virgen del Rosario, Cuchiller├¡a), este todav├¡a era denominada "calle de la Lonja", y m├ís tarde "Fernando el Cat├│lico". Mientras el se├▒or Max Jungh├ñndel preparaba la c├ímara para realizar esta imagen, un heterog├®neo grupo de paisanos se ha estacionado en medio, hasta que salga el pajarito. La baja intensidad del tr├ífico rodado facilit├│ un limpio y despejado resultado.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25573691181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25573691181.webp', 'https://www.flickr.com/photos/zaragozaantigua/25573691181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21219, 'Puente de Piedra c.1900', 'Imagen capturada desde cierta altura del puente de Piedra y el Arrabal. Fuente visual: fototipia Lucas Escol├í, en www.memoriademadrid.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65646200, -0.87669800, '0101000020E6100000D6FECEF6E80DECBF8B8862F206D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672942110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672942110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672942110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21232, 'Ribera del Ebro c.1900', 'Imagen capturada desde la ribera del Ebro, junto la "Posada del Rey", espacio de confluencia y descanso de carros, carretas, diligencias, adem├ís de las gentes asociadas a estos medios de negocio y transporte. A la izquierda, la verja que delimitaba el palacio de los marqueses de Ayerbe. A la derecha, el puente de Piedra que cruza el Ebro. Al fondo, la iglesia parroquial de Altab├ís, el convento de Santa Isabel, y un macizo torre├│n del cuartel de San L├ízaro. Fuente visual: Colecci├│n Antonio Arguas Perdiguer, en "El libro de oro de Arag├│n", EPA, 1997.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65625600, -0.87693200, '0101000020E6100000A01B9AB2D30FECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19376659492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19376659492.webp', 'https://www.flickr.com/photos/zaragozaantigua/19376659492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21287, 'Se├▒oritas 1903', 'Foto: Algora. "Grupo de las se├▒oritas que tomaron parte en el concurso de corte organizado por do├▒a Pilar del Valle y celebrado como final de las fiestas de la patrona de Zaragoza en la Lonja local de dicha poblaci├│n". Fuente: Diario ABC, 30-10-1903.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65582800, -0.87663100, '0101000020E6100000E31C75745C0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26075864338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26075864338.webp', 'https://www.flickr.com/photos/zaragozaantigua/26075864338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21360, 'Plaza de La Seo 1900', 'Fotograf├¡a capturada en la plaza de La Seo que contin├║a lo representado en la imagen anterior, donde transita el cortejo municipal salido del hom├│nimo templo durante la celebraci├│n, posiblemente, de la festividad del patr├│n de la ciudad. Aqu├¡ el cortejo est├í dejando la plaza y cruza la calle de la Lonja, luego de Fernando el Cat├│lico. Al fondo, fachada de la Casa-Lonja a esta calle. A la derecha e inmediata, esquina del Seminario Conciliar, y hacia el fondo, vista parcial de la Casa Consistorial.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54788549083.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54788549083.webp', 'https://www.flickr.com/photos/zaragozaantigua/54788549083/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21372, 'La Lonja y el Pilar 1918', 'Una mirada hacia el Oeste desde la torre de La Seo, capturando la calle Don Jaime I y la del Pilar (con las manzanas de viviendas en su entorno), La Lonja, El Pilar y la arbolada plaza de su nombre. Al fondo, tras la cl├¡nica del Doctor Palomar y el antiguo palacio de Aytona, la torre y c├║pula de San Juan de los Panetes, y el Torre├│n de la Zuda. Sobre el Ebro, el puente del Ferrocarril. En la margen izquierda, grandes arboledas, un verdadero bosque de ribera. Fuente: Zaragoza 1908-2008. FCC.', 1918, 1918, 1918, 'Anos 10', 'CASCO HIST├ôRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15524839000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15524839000.webp', 'https://www.flickr.com/photos/zaragozaantigua/15524839000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21373, 'La Seo c.1910', 'Fototeca del Patrimonio Art├¡stico. Archivo Conde de Polentinos. Aurelio de Colmenares y Orgaz. 1892-1930. "Zaragoza II. [Plaza del Pilar y Catedral de San Salvador o la Seo]". Tras voltear horizontalmente la imagen de la Fototeca, muestra correctamente una vista de la plaza de La Seo y la Lonja, desde la calle del Pilar.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65556000, -0.87685800, '0101000020E61000000D8D2782380FECBF6B48DC63E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15608802721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15608802721.webp', 'https://www.flickr.com/photos/zaragozaantigua/15608802721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21451, 'Calle de Don Jaime I c.1918', 'La esquina suroriental de la Lonja marca, a la izquierda, el final de la calle del Pilar en su desemboque en la de don Jaime I, en una imagen realizada desde la inmediata plaza de La Seo, y antes de ser adoquinada esta calle, cuando todav├¡a manten├¡a el tradicional firme de tierra. Desde el puente de Piedra irrumpe por la derecha un tranv├¡a de la l├¡nea del G├íllego, posiblemente el n┬║ 32, encaminado hacia la terminal en la plaza de la Constituci├│n.', 1918, 1918, 1918, 'Anos 10', 'CASCO HIST├ôRICO', 41.65564700, -0.87652400, '0101000020E61000006117450F7C0CECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50784003357.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50784003357.webp', 'https://www.flickr.com/photos/zaragozaantigua/50784003357/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21478, 'La Lonja desde la Seo 1922', 'AHPZ. Archivo Fotogr├ífico Julio Requejo. Junio 1922. "La lonja desde la torre de L''Aseo [La Seo]."', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65559100, -0.87643300, '0101000020E61000004C530438BD0BECBFA646E867EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914596106.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914596106.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914596106/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21587, 'Calle Fernando el Cat├│lico c.1923', 'Puesto de venta ambulante en la calle de Fernando el Cat├│lico, con el fondo del seminario metropolitano. Al fondo, el paseo del Ebro.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST├ôRICO', 41.65581400, -0.87622500, '0101000020E6100000D200DE02090AECBF252191B6F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24787073652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24787073652.webp', 'https://www.flickr.com/photos/zaragozaantigua/24787073652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21595, 'Calle Don Jaime c.1920', 'Calle de Don Jaime I, en su confluencia con la del Pilar (al fondo a la izquierda). Tras el caballero de primer plano, la Lonja. A la izquierda, comercio de recuerdos neoclasicista. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24878756026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24878756026.webp', 'https://www.flickr.com/photos/zaragozaantigua/24878756026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21649, 'Calle del Pilar 1923', 'In├®dita imagen capturada en la calle del Pilar, esquina con la plaza de la Seo y la calle de Fernando el Cat├│lico, que hacia el fondo y a la derecha conduce al paseo del Ebro y el puente de Piedra. En primer t├®rmino, una vendedora ambulante de frutas y verduras, entre las que destacan granadas de temporada. Frente a ella, el "brasero" o solanera de la Lonja, donde se arrima hasta una pareja de urbanos junto a otro puesto ambulante.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST├ôRICO', 41.65555100, -0.87670600, '0101000020E61000008C9FC6BDF90DECBF18EE5C18E9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51371172171.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51371172171.webp', 'https://www.flickr.com/photos/zaragozaantigua/51371172171/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21659, 'Plaza de La Seo, c.1920', 'Imagen tomada en la plaza de La Seo, donde destaca su isleta de verdor centrada en la Fuente de la Samaritana y la ingrata presencia de su denostado mingitorio. Hacia el fondo y tras la calle de Fernando el Cat├│lico, ensanche de la calle del Pilar.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65547900, -0.87635200, '0101000020E61000001A187959130BECBF7E1B62BCE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53605982143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53605982143.webp', 'https://www.flickr.com/photos/zaragozaantigua/53605982143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21740, 'Lonja 1933', 'Imagen de conjunto de la antigua Lonja y Casa de la Moneda de la ciudad, capturada en cierta altura desde el Seminario Diocesano. En primer plano, las traseras del edificio convertidas en despejada zona de jardines y disfrute ciudadano, tras derribo de las antiguas Casas de la Ciudad. A la izquierda, la calle Fernando el Cat├│lico que conduce a la plaza de la Seo. A la derecha, la que fuera Posada del Rey, junto al palacio de los marqueses de Ayerbe, y el Pilar. Fuente visual: "Revista Espa├▒ola de Turismo".', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65588600, -0.87624900, '0101000020E6100000F3E2C4573B0AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21776602559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21776602559.webp', 'https://www.flickr.com/photos/zaragozaantigua/21776602559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21765, 'Plaza La Seo 1932', 'Plaza de la Seo desde la calle del Pilar. A la izquierda, la Lonja. Al fondo, el Arco del Arzobispo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65559800, -0.87660000, '0101000020E6100000228E75711B0DECBF58A9A0A2EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22621963413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22621963413.webp', 'https://www.flickr.com/photos/zaragozaantigua/22621963413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21767, 'Jardines de La Lonja 1932', 'Jardines de la Lonja junto al paseo de la Ribera. Al fondo, el palacio de los marqueses de Ayerbe y el Pilar. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22622365053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22622365053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22622365053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21884, 'La Lonja 1938', 'Imagen capturada en los jardines traseros de la Lonja, donde los posados con palomas se hab├¡an convertido en una antropol├│gica tradici├│n. En este caso, el objetivo se centra, entre bancas palomas, en uno de los aviadores alemanes de la Legi├│n C├│ndor radicados en la ciudad y con servicio en el grupo de bombardeo K/88 establecido en el aer├│dromo Sanjurjo. Por el paseo del Ebro, al fondo, coincide concurrido tr├ífico de caballer├¡a, carro, y veh├¡culo a motor. A la derecha, quiosco de los jardines.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST├ôRICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49596274877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49596274877.webp', 'https://www.flickr.com/photos/zaragozaantigua/49596274877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21897, 'Calle del Pilar c.1934', 'Imagen capturada en la calle del Pilar con el objetivo dirigido hacia la plaza de La Seo, donde destaca a la izquierda el arco del Arzobispo. Unos guardias de asalto caminan junto a la Lonja en direcci├│n a la plaza del Pilar. A la derecha, el singular establecimiento "El Pilar", multitienda de objetos art├¡sticos de recuerdo, objetos de escritorio y ornamentos religiosos.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65572700, -0.87686700, '0101000020E6100000D921FE614B0FECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50945685863.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50945685863.webp', 'https://www.flickr.com/photos/zaragozaantigua/50945685863/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21925, 'Ribera del Pilar c.1940', 'AHPZ-Archivo Fotogr├ífico Jos├® Galiay, (SF). El Pilar desde la ribera del Ebro.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65629600, -0.87643300, '0101000020E61000004C530438BD0BECBF703FE08101D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700887978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700887978.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700887978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22202, 'Xim├®nez de Emb├║n 1958', 'Imagen de la calle de Tom├ís Xim├®nez de Emb├║n capturada desde la ampliada plaza del Pilar. A la izquierda, el edificio en construcci├│n de la nueva Casa Consistorial. A la derecha, la Lonja. Al fondo, el paseo del Ebro, y el fondo esc├®nico de la margen izquierda. Fuente visual: archivo Heraldo de Arag├│n, en "Padre Ebro. El r├¡o Ebro y el siglo XX".', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST├ôRICO', 41.65590600, -0.87700600, '0101000020E610000032AA0CE36E10ECBF06A051BAF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33823491101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33823491101.webp', 'https://www.flickr.com/photos/zaragozaantigua/33823491101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22219, 'Plaza del Pilar 1954', 'Imagen capturada desde la torre de la Seo, posiblemente a la altura de su segundo cuerpo en ladrillo, con una buena perspectiva de la nueva plaza de las Catedrales como sumatorio de las antiguas plazas del Pilar y de Huesca, para convertirse en escenario de multitudinarias ceremonias de reafirmaci├│n del r├®gimen franquista y su ├¡ntima vinculaci├│n con la iglesia cat├│lica. En primer t├®rmino, breve visual de la arbolada plaza de La Seo y de la calle de Don Jaime I. A la derecha, Lonja y andamios de obra de la nueva Casa Consistorial, cuyo avanzado desarrollo en la fachada recayente a la plaza se deb├¡a al Congreso Mariano de este a├▒o, para dar una imagen esc├®nica de falso acabado ante los miles de congresistas venidos de fuera de la ciudad. Del templo del Pilar, detr├ís, despuntan las obras de las dos nuevas torres ribere├▒as, patrocinadas econ├│micamente por Francisco Urzaiz y Leonor Sala, cuando ambas todav├¡a ascend├¡an en sinton├¡a, luego rota por el mayor desarrollo de la torre noroeste en su finalizaci├│n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65552700, -0.87688900, '0101000020E6100000CE1B2785790FECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48300029697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48300029697.webp', 'https://www.flickr.com/photos/zaragozaantigua/48300029697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22236, 'Plaza del Pilar 1954', 'Imagen capturada desde la altura del inmueble chaflanero entre la plaza de La Seo y la calle de Don Jaime I, con una vista centrada en la plaza del Pilar. Por la derecha y sobre el firme se destaca la alargada sombra de la torre de la Seo. Tras ella, la Lonja y la nueva Casa Consistorial haciendo las funciones de una "aldea Potemkim": la fachada recayente a la plaza ha sido terminada a marchas forzadas para el Congreso Mariano celebrado en este entorno, mientras el resto segu├¡a en obras. A su lado, el templo del Pilar con las torres de la ribera en construcci├│n. Al fondo, resplandece al sol el reci├®n terminado "Altar de la Patria" o "Monumento a los h├®roes y m├írtires de Zaragoza. Ca├¡dos en la Cruzada de Liberaci├│n 1936-1939".', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50682145953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50682145953.webp', 'https://www.flickr.com/photos/zaragozaantigua/50682145953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22267, 'Cine Pax 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/diciembre 1968. Los 60 arrancaban en la ciudad con la apertura de varios Cines (no "salas" de cine, Cines), porque en Espa├▒a la televisi├│n a├║n no amenazaba con matar a la estrella de la radio, y del cine. As├¡, en 1961 abrieron sus puertas el "Dux" y el "Roxy", dos cines "de barrio", en San Jos├® y Montemol├¡n, respectivamente. En 1963 vio la luz el "Pax", en la Plaza de la Seo n┬║ 6, con capacidad de 600 personas, y orientado hacia un tipo de cine entre lo familiar, y lo tolerado-para-todos-los-p├║blicos. Ser├í clausurado en 1984, junto con otros 15 cines de la ciudad (entre ellos, todos los cines de barrio). En la imagen, animada fila para el "Pax" cuando proyectaba el norteamericano filme "Rosie!", al que la peculiar espa├▒olizaci├│n del t├¡tulo le hab├¡a a├▒adido la coletilla "Una se├▒ora riqu├¡sima", una comedia donde aparec├¡a la angelical Sandra Dee, la misma que una d├®cada despu├®s ser├¡a parodiada con ca├║stica gracia en "Grease".', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65551900, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850753965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850753965.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850753965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22285, 'Riada de 1961', 'Foto Heraldo de Arag├│n, 1961. La riada del Ebro a su paso por el puente de Piedra de Zaragoza en enero de 1961, la mayor del siglo XX. Fuente: www.heraldo.es/noticias/especiales/2014/07/11/grandes_ria...', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST├ôRICO', 41.65625900, -0.87638600, '0101000020E61000001F8315A75A0BECBF535A7F4B00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15161139382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15161139382.webp', 'https://www.flickr.com/photos/zaragozaantigua/15161139382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22647, 'La Lonja 1970', 'Celebraci├│n del concurso Maja Internacional en el palacio de la Lonja de Zaragoza, el 11 de mayo de 1970. Este certamen tuvo su sede en la ciudad en diez ocasiones, entre 1966 y 1975. En 1970 result├│ ganadora la representante de Chile, Mar├¡a Isabel P├®rez (quinta por la izquierda). Fuente: www.chileancharm.com/', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20928761109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20928761109.webp', 'https://www.flickr.com/photos/zaragozaantigua/20928761109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23173, 'Antonio L├│pez 2009', 'Imagen del pintor manchego Antonio L├│pez Garc├¡a en la plaza del Pilar, durante una aparici├│n p├║blica en la que se ofreci├│ al Cabildo del Pilar para pintar una b├│veda del templo, y esculpir un bulto redondo relacionado. A la izquierda del pintor, el cenotafio de Goya que antes estuviera en el Rinc├│n de Goya del Parque de Buenavista. Tras retrasos y contingencias varias, el 11 de enero de 2016, pocos d├¡as despu├®s del cumplea├▒os 80 de este pintor, fue presentado, mediante una proyecci├│n sobre la c├║pula objeto de la intervenci├│n, el boceto con la imagen del rostro de una mujer que simbolizaba a la Virgen Mar├¡a. El car├ícter hiperrealista de la pintura propuesta, en l├¡nea con el reconocido estilo del autor, y la ausencia de los tradicionales s├¡mbolos y atributos marianos, llevaron al Cabildo a descartar el proyecto por no adecuado, o lejano de la oficial iconodul├¡a mariana. Fuente visual: foto Jos├® Miguel Marco, en www.tribunadelamoraleja.com/', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33274996414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33274996414.webp', 'https://www.flickr.com/photos/zaragozaantigua/33274996414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23797, 'Vista a├®rea 1990', 'Se aprecian las obras en la plaza del Pilar, el templete levantado frente a la Delegaci├│n del Gobierno, los andamios de la restauraci├│n de la Lonja, las ruinas del Foro romano en la plaza de La Seo, el Monumento a los Ca├¡dos sin terminar de desmantelar...', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65571800, -0.87649800, '0101000020E6100000124DA088450CECBF03B34291EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14885512645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14885512645.webp', 'https://www.flickr.com/photos/zaragozaantigua/14885512645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23805, 'Traseras Lonja 1927', 'Imagen desde cierta altura de las traseras de La Lonja, cuando presentaban una feraz zona verde, con visual de las traseras de los edificios de la calle del Pilar, y el Pilar, al fondo. En el jard├¡n del palacio del Marqu├®s de Ayerbe, imagen del quiosco realizado con materiales reciclados del derribado palacio o casa de Torrellas (s. XV). Fuente: Instituto Amatller de Arte Hisp├ínico (Arxiu Mas).', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST├ôRICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15284977933.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15284977933.webp', 'https://www.flickr.com/photos/zaragozaantigua/15284977933/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23856, 'El Pilar desde la Seo 1930', 'Vista de la calle y el templo del Pilar desde la Seo, con su torre a la izquierda. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65554500, -0.87701600, '0101000020E61000001633C2DB8310ECBF350708E6E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27369756636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27369756636.webp', 'https://www.flickr.com/photos/zaragozaantigua/27369756636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23862, 'Plaza del Pilar 1966', 'Tot├®mica puesta en escena del acto de fe de "ver la tele", en aparatos de 20/24 pulgadas, en la plaza del Pilar, de noche, y en invierno. En el interior de la inmediata Lonja, a la derecha, estaba teniendo lugar una representaci├│n de jotas, y los aparatos televisores retransmit├¡an a quienes no hab├¡an podido entrar a verlo en directo, cortes├¡a de una local empresa especializada en la venta de electrodom├®sticos. En la imagen, las traseras del monumento a Francisco de Goya, como tel├│n de fondo al espect├ículo, de cuando "ver la tele" era un privilegiado entretenimiento. Fuente: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65554200, -0.87691100, '0101000020E6100000C21550A8A70FECBFC493DDCCE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30074102022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30074102022.webp', 'https://www.flickr.com/photos/zaragozaantigua/30074102022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23867, 'El Pilar 1906', 'Vista del Pilar desde el paseo del Ebro, con el palacio de Ayerbe a la izquierda, y la torre sureste andamiada por estar a punto de ser terminada.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65647100, -0.87648200, '0101000020E6100000A60BB1FA230CECBFDFE2E13D07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30640584910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30640584910.webp', 'https://www.flickr.com/photos/zaragozaantigua/30640584910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23873, 'Procesi├│n Lonja 1940', 'La Virgen del Pilar es llevada en procesi├│n ante la Lonja, durante los actos del XIX centenario de su viaje a Zaragoza, exactamente el a├▒o 40. Destaca la presencia de representantes civiles. Al fondo, la manzana de casas que en pocos a├▒os ser├í derribada para construir el nuevo ayuntamiento. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65562800, -0.87691200, '0101000020E6100000D9092FC1A90FECBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30880033041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30880033041.webp', 'https://www.flickr.com/photos/zaragozaantigua/30880033041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23876, 'Paseo del Ebro 1940', 'Imagen capturada en los jardines y zona de esparcimiento entre la antigua Lonja y el paseo del Ebro. A la izquierda, las traseras de los edificios recayentes a la calle del Pilar, como la antigua posada de los Reyes, y el palacio de Ayerbe, con su reciclado cenador que al fondo despunta del jard├¡n vallado. Fuente visual: Ferr├ín Forns Navarro, Ajuntament de Girona.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30979688124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30979688124.webp', 'https://www.flickr.com/photos/zaragozaantigua/30979688124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23883, 'Palacio de Ayerbe a├▒os 30', 'Acuarela de Ambrosio Ruste que muestra la Posada de los Reyes y el Palacio de Ayerbe, en el paseo de la Ribera. Estos edificios se encontraban entre la Lonja y el Pilar. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65640500, -0.87693400, '0101000020E6100000CD0358E4D70FECBF27F73B1405D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31629399793.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31629399793.webp', 'https://www.flickr.com/photos/zaragozaantigua/31629399793/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23902, 'Plaza del Pilar 1967', 'Imagen capturada desde la altura del inmueble del n┬║ 1 de la plaza de La Seo, esquinero con la calle de Don Jaime I. con una vista de la plaza del Pilar que alcanza hasta San Juan de los Panetes, al fondo. En primer t├®rmino, el moderno Monumento a Goya. La ocupaci├│n de la plaza como espacio de aparcamiento de veh├¡culos progresa adecuadamente.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49328681616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49328681616.webp', 'https://www.flickr.com/photos/zaragozaantigua/49328681616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23904, 'Paseo del Ebro c.1930', 'Imagen capturada desde la altura del Seminario Conciliar en el arranque de la calle de Don Jaime I y orientada hacia el noroeste, siguiendo la perspectiva del paseo del Ebro. En primer t├®rmino, caseta del peso p├║blico de la Puerta del ├üngel y los Jardines de la Lonja, las traseras de los inmuebles del tramo de los impares de la calle del Pilar, con el hom├│nimo templo de tel├│n de fondo edilicio. A la derecha, cauce del r├¡o Ebro y arboleda de Macanaz,', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65612000, -0.87648100, '0101000020E61000008F17D2E1210CECBF32207BBDFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50150605706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50150605706.webp', 'https://www.flickr.com/photos/zaragozaantigua/50150605706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23908, 'Paseo del Ebro c.1908', 'Despejada y luminosa imagen capturada en el paseo del Ebro a la altura del fielato de consumos de la Puerta del ├üngel, con una interesante panor├ímica de la antigua fachada urbana del inmediato tramo ribere├▒o, desde la posada de los Reyes, junto a cuya solanera se concentran varios carros y caballer├¡as, las traseras y jardines de la gran casa de los Ayerbe, las casas de los Infantes y el templo del Pilar. A la derecha, poste del tendido el├®ctrico de la l├¡nea de Circunvalaci├│n.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65641700, -0.87668500, '0101000020E6100000AF997CB3CD0DECBFEBC4E57805D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51719140471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51719140471.webp', 'https://www.flickr.com/photos/zaragozaantigua/51719140471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23909, 'Plaza del Pilar 1966', 'Nocturna e invernal imagen capturada en la plaza del Pilar y en el entorno al monumento a Francisco de Goya, centrada en el montaje realizado por el establecimiento "Radio La Corona" consistente en la instalaci├│n de algo m├ís de treinta televisores "Vanguard" para ofrecer la retransmisi├│n de la ceremonia de homenaje al equipo cultural-deportivo que presidido por el fot├│grafo Guillermo Fat├ís Ojuel representaba a Zaragoza en el concurso de TVE "La uni├│n hace la fuerza" y en el que result├│ ganador. Tambi├®n fueron homenajeados los componentes del equipo finalista, de La Coru├▒a. Adem├ís los ganadores se llevaron 999.999 pesetas, y 333.333 los finalistas. Mientras en la Lonja ten├¡a lugar la gran ceremonia de homenaje con presencia de las autoridades locales y del jefe de programas de TVE, se├▒or Adolfo Su├írez Gonz├ílez, siendo presentada y animada por los conductores del programa televisivo se├▒ores Mario Beut y Antol├¡n Garc├¡a, estos televisores sirvieron al doble prop├│sito de ofrecer las im├ígenes retransmitidas en directo a quienes no pudieron ingresar al interior de la Lonja, y de servir de publicidad para la firma comercial que los instal├│. Al fondo y a la izquierda del abarrotado entorno al monumento a Goya, cartel luminoso del Cine Pax en la plaza de La Seo.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65548700, -0.87681400, '0101000020E61000002499D53BDC0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52464858820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52464858820.webp', 'https://www.flickr.com/photos/zaragozaantigua/52464858820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23965, 'Requet├® navarro 1936', 'AHPZ. Archivo Coyne. Manuel Coyne. 1936. Tras el 18 de julio, voluntarios carlistas navarros, o requet├®s (denominaci├│n de los soldados carlistas durante la Primera Guerra Carlista, 1833-1840), secundaron las fuerzas nacionalistas que se levantaron en armas contra la Rep├║blica democr├ítica. "Pacificada" Navarra, se plantaron como fuerza de choque armada en los frentes abiertos, como Zaragoza. En la imagen, el ÔÇ£Tercio de Do├▒a Mar├¡a de las NievesÔÇØ de requet├®s navarros, tras cruzar el puente de Piedra, llega al entorno de la Seo. A la izquierda, la Lonja y la calle del Pilar. Al fondo, el cuartel de San L├ízaro.', 1936, 1936, 1936, 'Anos 30', 'CASCO HIST├ôRICO', 41.65571100, -0.87630900, '0101000020E61000004818062CB90AECBF50508A56EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020622255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020622255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020622255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23971, 'Majas Internacionales 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/05/1975. "Majas Internacionales." En coherencia con la declaraci├│n por parte de la ONU de 1975 como "A├▒o Internacional de la Mujer", en Zaragoza se celebra la org├ínica elecci├│n de la "Maja Internacional". En la imagen, las aspirantes al t├¡tulo, tras una recepci├│n oficial en el Ayuntamiento a cargo del Alcalde, Mariano Horno Liria, hacen un simp├ítico posado-homenaje ante el monumento a Francisco Goya en la Plaza del Pilar, pero Goya no cabe en la foto. Al fondo, a la izquierda, cartel del Cine Pax. A la derecha, encima de la Estatua de la Libertad humanizada, visual de la plaza de La Seo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST├ôRICO', 41.65548700, -0.87679200, '0101000020E6100000309FAC18AE0EECBF01FA7DFFE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15111823609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15111823609.webp', 'https://www.flickr.com/photos/zaragozaantigua/15111823609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23979, 'Mu├▒ecos timbaleros 1905', 'Fotograbado "La Luz". 1905. "Los timbaleros del Ayuntamiento". Esta tarjeta postal reproduce el fotomontaje de unos mu├▒ecos vestidos con el uniforme de Timbaleros del Ayuntamiento, delante de una imagen de la fachada del entonces edificio del Ayuntamiento de la ciudad, situado en las traseras de La Lonja. A├▒os despu├®s el Ayuntamiento ser├¡a trasladado a la calle de la Democracia. Fuente: "La tarjeta postal ilustrada", Francisco Pal├í Laguna.', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65603200, -0.87641600, '0101000020E6100000C91D3691990BECBF939048DBF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15299563115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15299563115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15299563115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23980, 'Pablo Serrano 1975', 'Pablo Serrano Aguilar durante el montaje de la Exposici├│n antol├│gica organizada por la Comisi├│n de Cultura del Ayuntamiento en el Palacio de la Lonja (marzo-abril de 1975), con el posado del autor junto a Interpretaci├│n de La Piedad, una de las obras expuestas. En septiembre de ese a├▒o, y en protesta por los fusilamientos ejecutados por el r├®gimen franquista a finales de ese mes, retir├│ su obra de la exposici├│n Telecom 75 (Ginebra, Suiza).', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST├ôRICO', 41.65584700, -0.87662100, '0101000020E6100000FF93BF7B470DECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15302777212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15302777212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15302777212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24071, 'La Lonja 1966', 'Imagen de la danesa Jeannette Christjansen (centro) tras su proclamaci├│n como Maja Internacional 1966 en la Lonja, acompa├▒ada de sus cuatro Damas de Honor: de izquierda a derecha, la irlandesa Muriel O''Hanlon, la belga Rossette Menegain, la francesa Liliane Burnier, y la espa├▒ola Silvia Veiga. En el posado van vestidas a la manera tradicionalista de maja espa├▒ola, y Jeannette luce capote de brega firmado para la ocasi├│n por el popular matador de toros Manuel Ben├¡tez "El Cordob├®s". El jurado del certamen estuvo compuesto por ilustres damas locales, esposas de las autoridades provinciales, y varios "cr├¡ticos de bellezas femeninas" como el modisto Pedro Rodr├¡guez, el director del No-Do, Manuel Augusto Garc├¡a Vi├▒olas (se rod├│ un reportaje para este noticiario), Pedro Chicote, y Antonio Mingote. Fuente visual: revista Blanco y Negro (Madrid), en hemeroteca.abc.es/', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34333147690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34333147690.webp', 'https://www.flickr.com/photos/zaragozaantigua/34333147690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24081, 'Calle Don Jaime 1904', 'Foto: Lete. En el marco de las fiestas de octubre, se celebr├│ una recepci├│n municipal a "los representantes de la Coronilla de Arag├│n". La imagen capta el momento en que estos llegan "con su famosa senyera" hasta las casas del Ayuntamiento, al fondo. A la izquierda, fachada este de la Lonja. Fuente: Diario ABC, 27-10-1904.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65574000, -0.87634200, '0101000020E6100000368FC360FE0AECBFEB56CF49EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39256330224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39256330224.webp', 'https://www.flickr.com/photos/zaragozaantigua/39256330224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21354, 'Plaza de la Constituci├│n 1900', 'Invernal escena capturada en la plaza de la Constituci├│n centrada en el emboque a la calle de los M├írtires, flanqueada por los inmuebles de los n├║meros 35-39 del Coso a la izquierda y los n├║meros 41-45 a la derecha. En la solana de los bajos de estos edificios destaca la nutrida presencia de varias decenas de paisanos en lo que era denominado castiza y clasistamente "brasero de los pobres", uno de los varios existentes en la ciudad. A la derecha y en la calzada inmediata puede verse un coche cerrado tipo C, posiblemente de los construidos en Liverpool por Julius G. Neville, en servicio en la l├¡nea de Torrero. Si bien el Ayuntamiento hab├¡a autorizado en 1898 el cambio de sistema de tracci├│n para seguir as├¡ el modelo de la pionera Bilbao, en la imagen este coche sigue estando traccionado por una pareja de machos que le daban una velocidad media de 10-15 km/hora. En primer t├®rmino, la Fuente de la Princesa, sobre la que ya desde 1886 pend├¡a la amenaza de desmonte y sustituci├│n primero por otra fuente "m├ís c├│moda y m├ís art├¡stica", una estatua del Justicia Juan Lanuza luego, y finalmente el monumento que hoy ocupa su lugar. Por ello, no eran extra├▒os los abundantes y denigrantes ep├¡tetos difundidos en la prensa de la ├®poca y dedicados a ella como cada vez que en esta ciudad se quiere derribar o desmontar alg├║n edificio o monumento: "antigua", "antiest├®tica", "horrible", "vetusta"... En la imagen puede apreciarse que le falta el brazo derecho, efecto derivado de la agresi├│n de un paisano pasado de algo. Parece ser magn├®tica la presencia de este bulto redondo, se encuentre ubicado donde sea, a las agresiones en su contra, bien centradas en su extendido brazo derecho o bien en el tridente que porta. Ya en 1860 se le tuvo que reponer este mismo brazo con motivo de la visita de la reina Isabel II que tuvo lugar ese a├▒o.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65220100, -0.88104400, '0101000020E6100000E7C8CA2F8331ECBF91B586527BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54776029575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54776029575.webp', 'https://www.flickr.com/photos/zaragozaantigua/54776029575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24124, 'La Lonja 1966', 'Imagen capturada en la Lonja durante la "presentaci├│n en sociedad" de treinta y cinco "damitas zaragozanas" pertenecientes a la alta sociedad local en la "Gran Gala de Debutantes" organizada por la Comisi├│n de Fiestas el 8 de octubre de ese a├▒o. La fiesta escenific├│ que estas j├│venes de la Zaragoza de bien vest├¡an "sus primeras galas de mujer" por primera vez en un festejo colectivo que tradicionalmente se realizaba de forma individual, bien en el Casino Mercantil, bien en la propia Lonja municipal. El inusual n├║mero de "jovencitas" participantes en 1966 fue sustancialmente reducido en a├▒os siguientes, probablemente para conferir al acto un car├ícter m├ís exclusivo y menos colectivo, o tal vez por el creciente desapego social a este tipo de ceremoniales tan carpetovet├│nicos. En la imagen posan escalonadas las treinta y cinco "bell├¡simas se├▒oritas debutantes en primorosos modelos de noche" portando una rosa roja. Las flanquean elementos de la Polic├¡a Municipal en traje de gala. A la izquierda y ante el micr├│fono, Demetrio Gal├ín Bergua pronuncia un discurso "dedicado a exaltar las virtudes y belleza de nuestras mujeres" y donde les advert├¡a que "de ahora en adelante deb├¡an ser modelos y prototipos de damas aragonesas", sea lo que sea que significara esta aserci├│n.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54664598920.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54664598920.webp', 'https://www.flickr.com/photos/zaragozaantigua/54664598920/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24125, 'La Lonja 1967', 'Imagen capturada en la Lonja durante la exclusiva e inici├ítica "gran gala de debutantes" que tuvo lugar el 7 de octubre de ese a├▒o organizada por el Ayuntamiento en beneficio de la Asociaci├│n Nacional de la Lucha Contra el C├íncer. La habitual presencia de las primeras autoridades locales fue eclipsada por acudir a ella para presidir el acto en carne mortal la unig├®nita Mar├¡a del Carmen Franco Mart├¡nez-Bordi├║, consorte X marquesa de Villaverde, en su calidad de presidenta de la referida asociaci├│n anticancer├¡gena, acompa├▒ada por su esposo el docto marqu├®s, al que las malas lenguas calificaban por razones que no vienen al cuento como "El Yern├¡simo", "marqu├®s de Vespaverde" o "marqu├®s de Vayavida". En esta ocasi├│n fueron quince las "se├▒oritas debutantes vestidas de blanco y magn├¡ficas en su juventud y belleza" que "vistieron sus primeras galas de mujer". En la imagen algunas de ellas posan ordenadas en filas tras saludar personalmente y recibir de manos de la marquesa de Villaverde sus "carnets de baile" y antes de su desfile tras el que se sentar├¡an para dar inicio a la cena y el posterior baile que dur├│ hasta las primeras horas de la madrugada, amenizado por las orquestas "Los Magos y Farr├®s" y el conjunto "Los Sarakostas" y que cont├│ adem├ís con las actuaciones de Mar├¡a Dolores Pradera, acompa├▒ada de los Gemelos; el d├║o Juan y Junior, y el Quinteto del Club de Jazz de Radio Zaragoza.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65581500, -0.87657800, '0101000020E61000002D944C4EED0CECBFF59CF4BEF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54668742814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54668742814.webp', 'https://www.flickr.com/photos/zaragozaantigua/54668742814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24138, 'Feria de Muestras 1934', 'Foto A. de la Barrera, 1934. Interior de la Lonja de Zaragoza durante la celebraci├│n de la I Feria de Muestras Regional Aragonesa. Vemos la esquina suroeste del edificio, con el stand de la Sociedad General de Esterilizaci├│n, cuyo domicilio social estaba en la calle de Joaqu├¡n Costa 16. El procedimiento dom├®stico Foncal, patentado por esa empresa, consegu├¡a matar las bacterias del agua mediante un proceso catal├¡tico, al instalar en las tuber├¡as un ingenio met├ílico. Fuente: Revista Arag├│n, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65585400, -0.87681500, '0101000020E61000003B8DB454DE0EECBFB3791C06F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20031364553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20031364553.webp', 'https://www.flickr.com/photos/zaragozaantigua/20031364553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24143, 'Feria de Muestras 1934', 'Plano del recinto de la I Feria de Muestras Regional Aragonesa, 1934. La Sociedad Econ├│mica Aragonesa de Amigos del Pa├¡s organiz├│ en 1934 la primera Feria de Muestras Aragonesa en el palacio de la Lonja y sus jardines adyacentes. Se trataba de un muestrario de empresas de industria y comercio, que aparecen en el listado bajo el gr├ífico. La entrada ten├¡a lugar en el edificio, por la calle Don Jaime I, y la salida por los jardines. Al a├▒o siguiente se celebr├│ la segunda, en la ├║ltima zona de cubrimiento del r├¡o Huerva, cercana a la plaza de Para├¡so. No hubo m├ís, hasta 1941. Fuente: Revista Arag├│n, diciembre de 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65592600, -0.87654600, '0101000020E610000056116E32AA0CECBF4D4C1762F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20465197289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20465197289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20465197289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24154, 'Expo 1919', 'Medalla en bronce realizada por el escultor Jos├® Clara para conmemorar la Exposici├│n Hispano-Francesa de Bellas Artes celebrada en la Lonja durante los meses de mayo y junio de ese a├▒o, en cuya secci├│n espa├▒ola se pudo ver obras de, entre otros, Nonell, Picasso, Regoyos, Zuloaga, Benlliure, Gargallo, Julio Antonio, y Macho. De la parte francesa, la representaci├│n incluy├│, entre otros, a los pintores Vlaminck, Friesz, Camoin, siendo la primera vez que en Zaragoza se ve├¡an sus obras "fauves". Esta exposici├│n, a diferencia de la de 1908, apenas fue cubierta por los medios de comunicaci├│n, de forma que casi nadie se enter├│, ni antes, durante, ni despu├®s. La medalla de la imagen representa idealmente a Francia, con Marianne, y a Espa├▒a, con una baturra, tal vez de nombre Pilar. Fuente visual: www.museunacional.cat/', 1919, 1919, 1919, 'Anos 10', 'CASCO HIST├ôRICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30144516644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30144516644.webp', 'https://www.flickr.com/photos/zaragozaantigua/30144516644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22315, 'Calle de Pedro Cubero c.1965', 'Procesi├│n de Santa Rosa de Lima, patrona del barrio de Las Fuentes, a cargo de los tranviarios residentes en el Grupo Vizconde de Escoriaza, pasando por la calle de Pedro Cubero en direcci├│n a la de Salvador Minguij├│n, procedente la parroquia del mencionado Grupo de viviendas, levantado en 1953 para los trabajadores de la sociedad Tranv├¡as de Zaragoza. Su presidente, ├üngel Escoriaza Castill├│n, introdujo el culto a la santa peruana en el barrio.', 1965, 1965, 1965, 'Anos 60', 'LAS FUENTES', 41.64783000, -0.86011000, '0101000020E61000004BCD1E680586EBBF10AFEB17ECD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15759816212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15759816212.webp', 'https://www.flickr.com/photos/zaragozaantigua/15759816212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24155, 'La Lonja 1919', 'Imagen del interior de la antigua Lonja, como escenario de la Exposici├│n Hispano-Francesa de Bellas Artes celebrada durante los meses de mayo y junio de ese a├▒o. La toma longitudinal (posiblemente con el lienzo este al fondo), ilustra la disposici├│n espacial de algunos de los bultos redondos y cuadros de la exposici├│n, la decoraci├│n con motivos florales, y la iluminaci├│n por medio de grandes l├ímparas que penden de las renacentistas b├│vedas. De entre los bultos redondos que aparecen en la imagen, destacamos las dos obras de Jos├® Clar├í: "El crep├║sculo", y "La diosa". Del local escultor Jos├® Bueno, que entonces estaba terminando su recreaci├│n del rey Alfonso I "El Batallador" para el monumento del cabezo de Buenavista, esta muestra cont├│ con sus obras "La tarde", y "Humanidad". La primera decorar├¡a un jard├¡n urbano cerca de la plaza de Arag├│n, y la segunda ser├¡a colocada en la "fosa com├║n" del cementerio. Fuente visual: Foto Cepero, revista "La Esfera", en hemerotecadigital.bne.es/', 1919, 1919, 1919, 'Anos 10', 'CASCO HIST├ôRICO', 41.65580900, -0.87663000, '0101000020E6100000CC28965B5A0DECBF13B69F8CF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30752746936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30752746936.webp', 'https://www.flickr.com/photos/zaragozaantigua/30752746936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24163, 'Feria de Muestras 1934', 'Imagen con uno de los carteles anunciadores de la primera Feria de Muestras organizada en octubre de 1934 en el recinto de la Lonja y sus adyacentes jardines, en una instalaci├│n coordinada por el arquitecto Borobio. El cartel, dise├▒ado por Guillermo P├®rez, recoge precisamente la antigua Lonja como escenario central de la muestra, y se centra en su fachada recayente a la calle de Don Jaime I. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36522148345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36522148345.webp', 'https://www.flickr.com/photos/zaragozaantigua/36522148345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24165, 'Paseo del Ebro 1934', 'Excepcional imagen capturada en el paseo del Ebro y centrada en el cruce con la calle de Don Jaime I, donde destaca el montaje realizado con motivo de la I Feria de Muestras Regional Aragonesa, celebrada entre el 5 y el 20 de octubre de 1934 en el espacio de la antigua Lonja, con 51 "stands", y los jardines inmediatos, donde se dio cabida a otros 27 "stands" adem├ís de un bar y un tablado para m├║sica. Junto a la zona de los pabellones montados donde estuviera la antigua Casa Consistorial, delimitados por numerosas banderas y banderolas festivas, la caseta de consumos de la Puerta del ├üngel y el quiosco de la Sociedad Protectora de Animales. De fondo, la monumental fachada al paseo formada por las traseras de la calle del Pilar, con la Posada del Rey y el palacio de los marqueses de Ayerbe, y el templo del Pilar. Por el paseo circula un tranv├¡a de la l├¡nea "6. Magdalena-Mercado". En primer t├®rmino y a la izquierda, esquina del Seminario conciliar. Hacia la derecha, acceso al Puente de Piedra.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65605600, -0.87621300, '0101000020E6100000C18F6AD8EF09ECBF1B2C9CA4F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52278034883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52278034883.webp', 'https://www.flickr.com/photos/zaragozaantigua/52278034883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24219, 'Comparsa 1901', 'Gigantes y Cabezudos junto a la Lonja en 1901. La comparsa est├í viniendo por la calle del Pilar (a la izquierda) hacia la de Don Jaime I. La imagen est├í tomada desde la plaza de La Seo. En primer t├®rmino, el cabezudo Robaculeros.', 1901, 1901, 1901, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65546700, -0.87647600, '0101000020E61000001E537765170CECBFBA4DB857E6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246931012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246931012.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246931012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24226, 'Timbaleros 1891', '"Los timbaleros de la ciudad de Zaragoza", ├│leo sobre lienzo, Anselmo Gasc├│n de Gotor, 1891. Los timbaleros, al frente de una comitiva de ministriles seguida de los maceros. Tras ellos, los oficios concejiles con sombreros de copa. Salen del Ayuntamiento, a la derecha de la Lonja y fuera de la imagen. Al fondo, la calle del Pilar. Fuente: "El municipio en Arag├│n", DPZ, 2004.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65553200, -0.87653900, '0101000020E6100000B66455849B0CECBFA1BDFA78E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20532962772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20532962772.webp', 'https://www.flickr.com/photos/zaragozaantigua/20532962772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24233, 'Gigantes y cabezudos 1859', 'Dibujo alusivo a las fiestas del Pilar de 1859, con la comparsa de gigantes y cabezudos, proveniente de la calle del Pilar y situada en la plaza de La Seo, con vistas a la Lonja (al fondo a la derecha). Estas figuras ser├ín remplazadas al a├▒o siguiente por las dise├▒adas por F├®lix Oroz. Tambi├®n el edificio de la izquierda desaparecer├í en poco tiempo.', 1859, 1859, 1859, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29398419343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29398419343.webp', 'https://www.flickr.com/photos/zaragozaantigua/29398419343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24385, 'Calle del Pilar 1931', 'En el contexto de la celebraci├│n del Centenario IV del nacimiento de Teresa de Cepeda y Ahumada, la Compa├▒├¡a de Santa Teresa de Jes├║s proyecta en 1915 una expansi├│n que incluye la estrat├®gica plaza de Zaragoza, con la idea de fundar una escuela de formaci├│n de maestras cat├│licas. En setiembre de ese a├▒o llegan a la ciudad las primeras HH. Teresianas a buscar ubicaci├│n, mientras se alojan donde las Oblatas (P┬║ de las Damas). El Arzobispo Soldevila les ofrece las ruinas del antiguo convento de las Adoratrices, en San Juan de los Panetes, mas se inclinan por un piso de alquiler en la calle del Pilar, con el azulejo n├║mero 19, en el edificio esquinero justo antes de la Seo, donde confluye la calle de Bayeu. Establecidas ya al comienzo de ese curso, el piso qued├│ pronto peque├▒o, debiendo expandirse al entresuelo y a dos pisos extra del mismo edificio para dar cabida tanto a las alumnas internas de magisterio, como al alumnado externo de primeras ense├▒anzas. La demanda de plazas continuaba, y resultaba imposible continuar all├¡, de forma que a comienzos de los a├▒os 20 se busc├│ una nueva ubicaci├│n, m├ís espaciosa, que se encontr├│ en los promisorios terrenos en urbanizaci├│n de la antigua huerta de Santa Engracia, en el entorno de la nueva plaza de Castelar. La imagen de Roisin est├í realizada desde la plaza de la Seo, cuando el Colegio Teresiano estaba ya en su nueva ubicaci├│n de la calle Sanclemente, aunque la fenomenal fotograf├¡a recoge tal vez la mejor instant├ínea con detalle del edificio de la calle del Pilar (donde la panader├¡a) que acogi├│ la primera sede zaragozana del Colegio Teresiano del Pilar. Como todos sus vecinos de zona, a excepci├│n de la Lonja, este edificio ser├¡a demolido a finales de d├®cada. Fuente visual: Lucien Roisin, "Lonja y torres del Pilar", en "Zaragoza, a├▒os veinte. 81 fotograf├¡as de Roisin (1925-1931)", Instituci├│n Fernando el Cat├│lico, 2014. Fuente textual: Exposici├│n "Centenario Compa├▒├¡a Santa Teresa de Jes├║s - Zaragoza", y la muy amable colaboraci', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST├ôRICO', 41.65574200, -0.87692200, '0101000020E6100000BC92E4B9BE0FECBF8B4E965AEFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23134325411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23134325411.webp', 'https://www.flickr.com/photos/zaragozaantigua/23134325411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24586, 'Lonja con andamio 1889', 'J. L├®vy et Cie. "Palais de la bourse" (Palacio de la Bolsa), 1889 Podemos ver la Lonja con andamiaje, un tranv├¡a "de sangre" y un heterog├®neo conjunto de viandantes por el final de la calle de Don Jaime.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65550300, -0.87646400, '0101000020E61000000DE2033BFE0BECBF07B7B585E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794547078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794547078.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794547078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24587, 'Lonja de Mercaderes. Interior. 1885', 'A.M.Z. Sign. 0913. La Lonja, Zaragoza. [1885] Magn├¡fico edificio civil renacentista que albergaba las reuniones de los pr├│ceres mercantiles de la ciudad (1551). Hoy sigue en pie en la plaza del Pilar, mostrando exposiciones municipales.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65577200, -0.87651500, '0101000020E610000095826E2F690CECBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858893205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858893205.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858893205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24590, 'Lonja c.1877', 'Jean Laurent, "Zaragoza-La Lonja". Al principio de la antigua calle de la Cuchiller├¡a, otra de las im├ígenes de la Lonja capturadas por Jean Laurent, en tiempos en que era utilizada como espacio para actos p├║blicos varios, incluyendo el sorteo de "los Quintos" (Servicio Militar Obligatorio para quienes no pod├¡an pagarse el no hacerlo), y algunas representaciones teatrales. A su derecha, y pegado, el edificio de la Casa Consistorial levantado unas d├®cadas antes, con resabios dieciochescos, y puerta principal de acceso arquitrabado y en orden d├│rico. Fuente: "Mirar el mundo otra vez. 25 a├▒os de fotograf├¡a en la galer├¡a Spectrum".', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16610030380.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16610030380.webp', 'https://www.flickr.com/photos/zaragozaantigua/16610030380/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24593, 'Puerta del ├üngel c.1865', 'Vista de la ├║ltima versi├│n de la Puerta del ├üngel, con la Lonja en primer plano a la izquierda, seguida de las casas consistoriales. Fuente: Instant├íneas zaragozanas, CAMPZAR, 1982.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65590200, -0.87614900, '0101000020E6100000118AADA06909ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24865007091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24865007091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24865007091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24595, 'La Lonja 1991', 'Imagen de la escultura en bronce titulada "Caballito", con posado de su autor, el modelista Francisco Rallo Lahoz, en las traseras de la Lonja. El bronc├¡neo equino fue concebido como homenaje de la ciudad al fot├│grafo Angel Cordero Gracia, que ejerci├│ de "minutero" en los jardines de la plaza de la Lonja recayentes al paseo del Ebro, entre 1925 y 1978, en el entorno donde fue ubicado este bulto redondo. El original caballito era de cart├│n piedra, y en ├®l se sentaban las ni├▒as y ni├▒os que iban a ser retratados. Posiblemente esta imagen fuera capturada en la inauguraci├│n oficial de esta obra. Fuente visual: Antonio Calvo Pedr├│s, AMZ.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65610300, -0.87648200, '0101000020E6100000A60BB1FA230CECBF5CE7DF2EFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30491155170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30491155170.webp', 'https://www.flickr.com/photos/zaragozaantigua/30491155170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24596, 'La Lonja c.1902', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el n┬║ 134 de las im├ígenes de "Zaragoza" incluidas en la serie postal de Espa├▒a para la Uni├│n Postal Universal, que captura una vista canicular de la Lonja desde cierta altura, en la arbolada plaza de la Seo. A la izquierda, la ensanchada esquina del final de la calle del Pilar. A la derecha, en la calle de Don Fernando el Cat├│lico, la Casa del Ayuntamiento. Al fondo, el puente de Piedra y casas del Arrabal. Fuente visual: www.todocoleccion.net/', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33908400994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33908400994.webp', 'https://www.flickr.com/photos/zaragozaantigua/33908400994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24598, 'La Lonja c.1892', 'Imagen editada por la Fototipia Hauser y Menet (Madrid) con el n┬║ 287 entre las im├ígenes de "Zaragoza" incluidas en la serie postal de Espa├▒a, que captura una vista de la Lonja desde la zona de sombra ma├▒anera de la plaza de la Seo. A la izquierda, la esquina del final de la calle del Pilar. A la derecha, las Casas de la Ciudad, o ayuntamiento. En la plaza, a la derecha, e inmediatas, un grupo de mujeres se abastecen de agua en la fuente de la Samaritana (fuera de plano). Fuente visual: www.todocoleccion.net/', 1892, 1892, 1892, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34673697456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34673697456.webp', 'https://www.flickr.com/photos/zaragozaantigua/34673697456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24599, 'La Lonja 1844', '"Sal├│n de la Lonja", como parte integrante de las Casas de la Ciudad, o Ayuntamiento. Fuente visual: "Recuerdos y Bellezas de Espa├▒a. Obra destinada a dar a conocer sus monumentos, antig├╝edades y vistas pintorescas en l├íminas dibujadas del natural y litografiadas por F. J. Parcerisa, acompa├▒adas de texto por P. Piferrer y J. M. Quadrado. Arag├│n: Jos├® Mar├¡a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65582800, -0.87662300, '0101000020E61000002D7C7DAD4B0DECBF8AE6012CF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34737152251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34737152251.webp', 'https://www.flickr.com/photos/zaragozaantigua/34737152251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24600, 'Marqu├®s de Almenara 1591', '"El pueblo zaragozano hiere al marqu├®s de Almenara". Ilustraci├│n de F. Blanch que recrea el ataque de algunos ciudadanos en 1591 contra ├ì├▒igo Hurtado de Mendoza y de la Cerda, marqu├®s de Almenara, enviado por Felipe II a Zaragoza en 1588. Muri├│ en la c├írcel dos semanas despu├®s. Al fondo, la calle del Pilar, la Lonja y las casas consistoriales. A la derecha, fragmento de la Diputaci├│n del Reino en la plaza de la Seo. Fuente visual: Historia de Espa├▒a, Miguel Segu├¡, 1910, en todocoleccion.net.', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65548300, -0.87641700, '0101000020E6100000E01115AA9B0BECBFBF0AF0DDE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40204809215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40204809215.webp', 'https://www.flickr.com/photos/zaragozaantigua/40204809215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24601, 'Plaza del Pilar 1981', 'Imagen capturada en la plaza del Pilar junto al ingreso principal a la Lonja, escenario de la Exposici├│n "50 aniversario del Cuerpo de Bomberos de Zaragoza", donde se conmemoraba a constituci├│n de este Cuerpo como servicio profesional de extinci├│n de incendios a cargo del Ayuntamiento en el a├▒o 1931. El veh├¡culo de primer t├®rmino formaba parte de la exposici├│n de material hist├│rico de bomberos, y se trata de un cami├│n que transportaba una escalera m├│vil Magirus E-1 que estuvo en servicio desde 1937 y hasta 1966. Se considera que el ├®xito de esta exposici├│n fue el germen del Museo del Fuego inaugurado en 2012.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.65567900, -0.87673900, '0101000020E61000007B1684F23E0EECBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50143937168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50143937168.webp', 'https://www.flickr.com/photos/zaragozaantigua/50143937168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24605, 'Plaza de la Seo 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Marzo 1974. Imagen de la Plaza de la Seo desde la calle Don Jaime. La fuente que aparece fue la que sustituy├│ a la de La Samaritana, cuando fue desmontada y trasladada, primero al Parque Bruil, luego a la Plaza del Justicia. M├ís tardes, a finales de los a├▒os 80, la Plaza de la Seo hab├¡a alcanzado un lamentable estado que llev├│ a redactar un proyecto de remodelaci├│n que inclu├¡a el regreso de La Samaritana, pero el hallazgo de los restos del Foro Romano obligaron a transformar el proyecto en lo que hoy vemos.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65551100, -0.87642200, '0101000020E610000052D66F26A60BECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14718879029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14718879029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14718879029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24608, 'La Seo a├▒os 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. [Plaza del Pilar] La Torre de la Seo [o La Catedral del Salvador en su Epifan├¡a y Puerta de San Bartolom├® en la fachada principal o neoc├ísica]". Imagen tomada desde la calle el Pilar. Fuente visual: Archivo W├╝nderlich (WUN-05810) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65570300, -0.87679200, '0101000020E6100000309FAC18AE0EECBFCE716E13EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877342207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877342207.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877342207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24612, '├üngel Cordero Gracia 1974', '├üngel Cordero Gracia ejerci├│ de fot├│grafo minutero desde 1925, retratando ni├▒os y ni├▒as sobre un caballito de madera en los jardines traseros de la Lonja. Era Minutero porque entre el posado, la instant├ínea, y el revelado, se suced├¡an escasos minutos, una pr├íctica que estuvo realizando hasta 1978, y por la que pasaron varias generaciones de j├│venes, y no tan j├│venes, bien locales, o de paso por la ciudad. En 1991 el Ayuntamiento homenaje├│ su memoria instalando, en el mismo espacio donde estuvo trabajando tanto tiempo, una escultura en bronce sobre pedestal circular de granito rosa, obra de Francisco Rallo Lahoz, que representa al caballito protagonista de tantas instant├íneas. En la imagen, ├üngel Cordero se encamina, cargado con sus herramientas de trabajo recogidas en la plaza de San Bruno n┬║ 3, hacia la Lonja cruzando por la plaza de La Seo. El objetivo de la c├ímara, aun cubierto, nos observaÔÇª', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65551100, -0.87617000, '0101000020E6100000EF8FF7AA9509ECBF8995D1C8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15047796462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15047796462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15047796462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24627, 'Calle del Pilar 1920', 'Foto: Julio Requejo. Aspecto de la calle del Pilar con la Seo al fondo, en junio de 1920. La imagen ha sido volteada horizontalmente para su correcta visualizaci├│n. Fuente: DARA/AHPZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65572700, -0.87652800, '0101000020E6100000BCE7C072840CECBF560DC2DCEED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21193339789.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21193339789.webp', 'https://www.flickr.com/photos/zaragozaantigua/21193339789/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24658, 'Plaza de La Seo c.1942', 'Imagen capturada desde la altura del inmueble del n┬║ 19 de la antigua calle del Pilar antes de su derribo para despejar de viejas casonas el tramo m├ís oriental de la ampliada plaza del Pilar, y dejar espacio a la nueva Casa Consistorial. Inmediata y a la izquierda, la Lonja, y al fondo, la plaza de La Seo. A la derecha y fuera de plano, el despejado solar sobre el que estaba proyectado construir, entre otros edificios, la nueva sede del Gobierno Civil.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST├ôRICO', 41.65578300, -0.87694200, '0101000020E610000083A44FABE80FECBFEA2285B2F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49305726783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49305726783.webp', 'https://www.flickr.com/photos/zaragozaantigua/49305726783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25198, 'Puerta del ├üngel 1851', '"Dibujos que representan dos proyectos para la Puerta del ├üngel de esta Ciudad, arreglados ├í lo mandado por M. II. SS. Gobernador de la Provincia, y Alcalde Corregidor de esta Capital". Zaragoza, 12 de septiembre de 1851. Ninguno de los dos proyectos de esta puerta, entre las Casas Consistoriales y el Seminario Conciliar, fue levantado. En 1860 se erigi├│ otro modelo, obra de Miguel Jeliner y Germ├í. Fuente: AMZ.', 1851, 1851, 1851, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32126168596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32126168596.webp', 'https://www.flickr.com/photos/zaragozaantigua/32126168596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25650, 'Don Jaime I c.1925', 'Archivo Municipal de Zaragoza. "Procesi├│n religiosa" en la que, aunque as├¡ lo parezca, quien va solemne bajo palio no es el tranv├¡a de la L├¡nea "Arrabal". Imagen tomada en la calle Don Jaime, con la Lonja a la izquierda, y la plaza de la Seo a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65562200, -0.87640700, '0101000020E6100000FD885FB1860BECBFE144F46BEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14964558620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14964558620.webp', 'https://www.flickr.com/photos/zaragozaantigua/14964558620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25671, 'Don Jaime I, c.1925', '"Zaragoza II. [La Lonja]". Captura visual del entronque de la calle de don Jaime I, la calle del Pilar, a la izquierda, y la arbolada plaza de la Seo, a la derecha. Al fondo, el puente de Piedra. Vertebra la imagen el sencillo e imponente edificio de la antigua Lonja de mercaderes, ya despejada de las derribadas Casas de la Ciudad. A la izquierda, el antiguo n┬║ 6 de la calle Don Jaime I, derribado durante la radical creaci├│n de la gran plaza del Pilar. Incrustados en el firme, los ra├¡les tranviarios de las ya electrificadas l├¡neas "Arrabal" y "G├íllego". La circulaci├│n rodada, fluida. Fuente visual: Archivo del Conde de Polentinos (Aurelio de Colmenares y Orgaz), Fototeca del Patrimonio Art├¡stico', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65550100, -0.87642800, '0101000020E6100000DA8EA9BBB20BECBF66BFEE74E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27785373001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27785373001.webp', 'https://www.flickr.com/photos/zaragozaantigua/27785373001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25673, 'Don Jaime I, 1968', 'Imagen de la unidad n┬║ 164 (serie 150, o topolinos), de la l├¡nea tranviaria 4 ("Arrabal") encaminada hacia la plaza de la Seo. Esta unidad se activaba cuando las dos tranv├¡as "oficiales" de la l├¡nea (el 223, y el 228) estaban averiados, como parece ser el caso. A la izquierda, el acceso desde el puente de Piedra. Detr├ís, el multifuncional edificio del arzobispado, antiguo Seminario Conciliar, ahora ocupado, entre otros, por Radio Popular, y por el cine Pax. A la derecha, quiosco y densa arboleda de la plaza de la Seo. Fuente visual: trotskeetravel.com/, a trav├®s de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65549100, -0.87638700, '0101000020E61000003677F4BF5C0BECBF42E90B21E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31170380711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31170380711.webp', 'https://www.flickr.com/photos/zaragozaantigua/31170380711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25676, 'Lonja c.1925', 'Imagen de la Lonja, despejada de las antiguas Casas de la Ciudad (ayuntamiento), estrat├®gica entre las calles de don Jaime I y del Pilar, y el paseo del Ebro. Fuente visual: "Casa Lonja. Exterior", en ÔÇ£El arte en Espa├▒a. Zaragoza, con texto de Anselmo Gasc├│n de Gotor. Edici├│n Thomas. Patronato Nacional de Turismo.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65596400, -0.87608600, '0101000020E61000007978CF81E508ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33515081093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33515081093.webp', 'https://www.flickr.com/photos/zaragozaantigua/33515081093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25683, 'Calle de Don Jaime I 1968', 'Veraniega imagen capturada en la calle de Don Jaime I ( (original cardo de la Cesaraugusta romana) y centrada en el troleb├║s n┬║ 14 modelo BUT London (ubicaci├│n del volante a la diestra) de un piso realizando el trayecto de regreso en la l├¡nea G├íllego y en direcci├│n al tramo medio del Coso. De fondo edilicio, el antiguo seminario metropolitano, que entonces albergaba diversas dependencias del arzobispado, como Radio Popular y el cine Pax (que reestrenaba la comedia "Tres en un sof├í"), am├®n de la sucursal de una importante local caja de ahorros. Hacia la derecha se abre la plaza de La Seo.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65552700, -0.87653500, '0101000020E61000005B94D920930CECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51570599902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51570599902.webp', 'https://www.flickr.com/photos/zaragozaantigua/51570599902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20883, 'La Seo s. XIV', 'Dibujo de Francisco ├ì├▒iguez, 1937. La recreaci├│n representa el templo en su ├®poca mud├®jar. La tesis oficial no contempla que la actual torre barroca utilizara el emplazamiento del alminar octogonal de la mezquita mayor de Saraqusta, pero algunos investigadores sostienen esa opci├│n. Fuente: sites.google.com/site/zagralandalus/los-alminares-de-la-seo, a trav├®s de www.facebook.com/photo.php?fbid=1864645023755215&set=...', 1350, 1300, 1399, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65524300, -0.87609700, '0101000020E610000073F56393FC08ECBF6AF7AB00DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30682686311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30682686311.webp', 'https://www.flickr.com/photos/zaragozaantigua/30682686311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20891, 'Gran Cloaca ca. 20', 'La ┬½Gran Cloaca┬╗ del foro romano de Caesaraugusta resurgi├│ al levantar en 1982 la plaza de La Seo. Un siglo antes (1870) ya se dio con ella. Hoy se encuentra conservada como una estructura m├ís del Museo del Foro de Caesaraugusta. Fue realizada a finales del reinado de Augusto, o comienzos del de Tiberio, entre el a├▒o 10 y el 20 de la Era, como parte del sistema de saneamiento y evacuaci├│n de aguas del nuevo foro. Construida en opus caementicium, se cubri├│ con b├│veda de medio ca├▒├│n. La altura interior es de 2.64 m. y la luz de 1.78 m. El espesor de las paredes es de 60 cm. En la imagen, vista parcial de los restos de la "Gran Cloaca" al aire en la plaza de la Seo. Archivo Luis Serrano. Fuente: "El Ebro", Ediciones Oroel, 1986.', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16814002841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16814002841.webp', 'https://www.flickr.com/photos/zaragozaantigua/16814002841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21138, 'Plaza de La Seo c.1895', '"Vista de la Catedral de San Salvador (La Seo)", y de la Plaza de la Seo, desde altura. Fuente visual: Esudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65516600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFBFB9BF7ADCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14745087029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14745087029.webp', 'https://www.flickr.com/photos/zaragozaantigua/14745087029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21139, 'Plaza de La Seo c.1895', 'Vista de la Lonja de mercaderes desde la plaza de La Seo. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65519000, -0.87621800, '0101000020E61000003354C554FA09ECBF47551344DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750916237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750916237.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750916237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21150, 'Plaza de La Seo c.1895', '"La Lonja". Foto Colecci├│n Universidad Michel de Montaigne, Burdeos. Toma de la plaza de la Seo de Zaragoza, mirando hacia la Lonja, cuando el antiguo edificio de viviendas (esquina entre la calle del Pilar y Don Jaime, a la izquierda) a├║n estaba intacto. A la derecha, edificio del arzobispado. La fuente de la Samaritana, con utilidad no s├│lo est├®tica. Mediados de la d├®cada de 1890. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704539937.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704539937.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704539937/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21166, 'Plaza de La Seo c.1895', 'Imagen de la plaza de la Seo centrada en la fuente de la Samaritana cuando era el acu├ítico epicentro de una notable foresta, y a su funci├│n est├®tica se un├¡a la funcional de proveedora de agua. Hab├¡a sido instalada en 1866. A la izquierda, la Lonja y la Casa Consistorial. Enfrente, tras la de Samaria, el Seminario Conciliar. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23025287529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23025287529.webp', 'https://www.flickr.com/photos/zaragozaantigua/23025287529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21198, 'Plaza de La Seo 1890', 'Coloreada imagen capturada desde la altura del inmueble del n┬║ 3 de la plaza de La Seo con una interesante vista de la antigua plaza y su entorno, dominado por la esbelta torre barroca de la catedral del Salvador en su Epifan├¡a y su clasicista fachada que decora el ingreso por la puerta occidental del templo. A la izquierda, el Arco del Arzobispo que comunica con el hom├│nimo palacio. La plaza aparece vertebrada alrededor, en primer t├®rmino, de la fuente de la Samaritana, realizada en la fundici├│n Averly.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65534200, -0.87643800, '0101000020E6100000BE175FB4C70BECBFFDD8243FE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51425457922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51425457922.webp', 'https://www.flickr.com/photos/zaragozaantigua/51425457922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21241, 'Calle Don Jaime c.1900', 'Grupo de tres hombres caminando tranquilamente por la calle de Don Jaime I de Zaragoza. Al fondo, el cruce con la calle del Pilar y la Lonja. Fuente: www.facebook.com/photo.php?fbid=1668897606655861&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19894433228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19894433228.webp', 'https://www.flickr.com/photos/zaragozaantigua/19894433228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21242, 'Plaza de La Seo c.1900', 'Plaza de La Seo de Zaragoza, vista desde la calle de Don Jaime I. A la izquierda, el Palacio Arzobispal y el Arco del Arzobispo. En el centro, la estatua de la Samaritana ante la catedral. Fuente: www.facebook.com/photo.php?fbid=1668896829989272&set=...', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65528000, -0.87662200, '0101000020E610000016889E94490DECBF87DC0C37E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057509096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057509096.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057509096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22482, 'Av. Compromiso de Caspe 1962', 'Tranquila imagen capturada en el antiguo camino de las Fuentes, ya redenominado como avenida del Compromiso de Caspe y centrada en el tramo de los impares (a la derecha) entre las recientes calles Doctor Iranzo y Obispo Laplana, poco antes de Salvador Minguij├│n, que entonces se├▒alaba el "nec plus ultra" de la ciudad en esta perif├®rica barriada. Hacia el fondo de la imagen, el lejano principio de la avenida desde la calle de Miguel Servet. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64538000, -0.86299400, '0101000020E61000007C9DD497A59DEBBF0ABFD4CF9BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39282866304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39282866304.webp', 'https://www.flickr.com/photos/zaragozaantigua/39282866304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23647, 'Aer├│dromo Sanjurjo 1939', 'El Aer├│dromo Sanjurjo, en Garrapinillos, fue habilitado como base a├®rea a comienzos de 1937 por los nacionalistas, en un estrat├®gico emplazamiento desde el que poder intervenir r├ípidamente en los principales frentes de guerra. En ├®l se aposent├│ importante n├║mero y calidad de aviones de la Legi├│n C├│ndor alemana, y de la Legionaria italiana. Fue tal su importancia, que en octubre de 1937 un escuadr├│n de "Chatos" y "Moscas" republicanos lo atacaron, destruyendo y da├▒ando entre 17 y 30 aviones de los facciosos. En la imagen, una l├¡nea de cazas Fiat CR-32 de la Aviaci├│n Legionaria Italiana, en los ├║ltimos d├¡as de la guerra. Al fondo, un polivalente Ju-52 y un bombardero He-111 de la Legi├│n C├│ndor. A├▒os despu├®s, a los aviones alemanes e italianos se les a├▒adir├¡an los de la fuerza a├®rea de los Estados Unidos de Norteam├®rica. Fuente visual: www.aviationcorner.net/', 1939, 1939, 1939, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18009158285.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18009158285.webp', 'https://www.flickr.com/photos/zaragozaantigua/18009158285/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21335, 'Plaza de La Seo 1903', 'Grabado que recoge el paso del Rosario que, proveniente de la calle de Don Jaime I, da una vueltecilla a la plaza de la Seo para encaminarse luego a la calle del Pilar la noche del 18 de octubre de 1903, en el marco de la visita a Zaragoza del rey Alfonso XIII, que presidi├│ su paso desde el balc├│n central del Palacio Arzobispal (a la izquierda) habilitado como morada real durante su estancia de tres d├¡as. La plaza de La Seo y la fachada del palacio fueron iluminadas para tal ocasi├│n por la compa├▒├¡a Electro Peral Zaragozana. En el centro de la escena aparece la carroza titulada "la Venida de la Virgen", tallada en madera por el escultor Francisco de Borja ese mismo a├▒o y que hac├¡a aqu├¡ su estreno, siendo la ├║nica figura de este Rosario que no es de cristal. Aparece portada por 32 j├│venes con t├║nicas blancas y escoltados por todos los ac├│litos de los templos de Zaragoza que portaban pebeteros en los que se quemaba incienso y mirra. Tras ella, la carroza que representa a la bas├¡lica del Pilar, creada por Policarpo Valero y Bernab├® y ampliado a las cuatro torres en 1895 por Le├│n Quintana y Bianchi. A la derecha, vista de uno de los dos faroles con forma de le├│n, obra del taller de hojalateros y vidrieros de los Tiesto y construido en 1865-1866.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65527000, -0.87635200, '0101000020E61000001A187959130BECBF64062AE3DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52539891386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52539891386.webp', 'https://www.flickr.com/photos/zaragozaantigua/52539891386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21358, 'Plaza de La Seo 1900', 'Imagen centrada en la fachada occidental de la Seo, flanqueada por el Arco del Arzobispo a la izquierda y la torre del templo. La escena incluye una vista parcial de la plaza de La Seo y, en primer t├®rmino, el empedrado paso peatonal por el arranque de la calle de Don Jaime I, donde destaca el tendido tranviario que por 10 c├®ntimos y desde la plaza de la Constituci├│n conduce hacia la izquierda al Arrabal por el Puente de Piedra.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54785682811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54785682811.webp', 'https://www.flickr.com/photos/zaragozaantigua/54785682811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21363, 'Plaza de La Seo c.1910', 'AHPZ-Archivo Coyne, 1907-1930. Plaza de la Seo.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65509400, -0.87628300, '0101000020E6100000F94D61A5820AECBF25E7C41EDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877890581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877890581.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877890581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21744, 'La Seo 1938', 'Tras dos a├▒os de ocultamiento por parte del bando franquista, en 1938 se revel├│ la muerte de Jos├® Antonio Primo de Rivera, l├¡der de la Falange fusilado en Alicante el 20 de noviembre de 1936. En la imagen, profusi├│n de coronas de flores al pie de la torre de la Seo, con motivo del funeral celebrado en noviembre de 1938 en memoria del pol├¡tico fascista. Fuente: Archivo Heraldo de Arag├│n.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST├ôRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21841817375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21841817375.webp', 'https://www.flickr.com/photos/zaragozaantigua/21841817375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21772, 'Plaza La Seo 1932', 'Plaza de la Seo y Fuente de la Samaritana. Al fondo, el Pilar. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22854992097.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22854992097.webp', 'https://www.flickr.com/photos/zaragozaantigua/22854992097/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21814, 'Calle Pabostr├¡a 1934', 'Imagen de la procesi├│n del Domingo de Ramos 25 de marzo de 1934, reproducida en la revista Blanco y Negro en abril de 1935. Los palmeros desfilan por la calle de la Pabostr├¡a, con la de Diego Dormer al fondo. Fuente: www.todocoleccion.net', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65444100, -0.87617200, '0101000020E61000001C78B5DC9909ECBFAD1402B9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30702428252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30702428252.webp', 'https://www.flickr.com/photos/zaragozaantigua/30702428252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21965, 'Plaza del Pilar 1949', 'Imagen de la despejada plaza del Pilar en su reciente ampliaci├│n por derribo entre Don Jaime I (izquierda), y el edificio del Gobierno Civil en construcci├│n (a la derecha, fuera de plano). La imagen se ha capturado desde la puerta de la Lonja. Enfrente, el nuevo edificio del n┬║ 16 de la plaza, esquinero con Don Jaime I, el primero de los tres de ese tramo. A su derecha, las traseras de los nuevos 25 y 27 de la calle Santiago, y por el solar del 23, visual de las antiguas viviendas a├║n sin derribar del 30-32, a la derecha del Palacio de Montemuzo. En la plaza, autobuses de l├¡nea regular entre Zaragoza y el entorno municipal y provincial. Fuente Visual: Fotos Ysa, Archivo P├║blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65541700, -0.87696300, '0101000020E610000061AA99B51410ECBF081F4AB4E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22177307702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22177307702.webp', 'https://www.flickr.com/photos/zaragozaantigua/22177307702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22081, 'Calle Pabostr├¡a 1951', 'Archivo Municipal. Archivo Juan Mora. 1951 Imagen de la calle Pabostria, capturada desde su arranque en la calle Dormer n┬║ 8. A la izquierda, la Puerta Sur, o de la Pabostr├¡a de la Catedral de El Salvador, medieval acceso en desuso. La denominaci├│n de "pabostr├¡a" hac├¡a referencia a la cercana residencia del encargado de la hacienda y los bienes temporales de la catedral. Desde antiguo, este cargo fue teniendo varias denominaciones: "Procuraci├│n", "Mensa Com├║n", "Mensa Capitular", "Prepositura", y "Pabostr├¡a". El que tiene la llave de la caja, en plata.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65446100, -0.87629900, '0101000020E6100000658F5033A40AECBFF4C0C760C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15760216592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15760216592.webp', 'https://www.flickr.com/photos/zaragozaantigua/15760216592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22128, 'Pl. de la Seo c.1959', 'Plaza de La Seo. Al fondo, el edificio sin terminar del nuevo Ayuntamiento, y el Pilar. En primer t├®rmino, las v├¡as de la tranviaria l├¡nea del Arrabal. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159778261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159778261.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159778261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22200, 'Pl. de La Seo 1954', 'Imagen de la plaza de la Seo capturada desde los jardines que hubiera en la ampliada plaza del Pilar, en el tramo desde la nueva Casa Consistorial, y hasta la calle de Don Jaime I, al fondo. Por esta calle, precisamente, transita un troleb├║s (posiblemente el n┬║ 15, un Vectra-Escoriaza) de la l├¡nea del G├íllego, en su retorno a la terminal del Coso. Fuente visual: archivo Heraldo de Arag├│n, en "Padre Ebro. El r├¡o Ebro y el siglo XX".', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33572915190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33572915190.webp', 'https://www.flickr.com/photos/zaragozaantigua/33572915190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22359, 'Plaza de La Seo 1961', '"Plaza de la Catedral", ├│leo sobre lienzo, Alberto P├®rez Piqueras, 1961. Premio Goya en el concurso Arte zaragozano actual de 1962. Representaci├│n neocubista de la plaza de La Seo de Zaragoza, con el Palacio Arzobispal al fondo, la fuente de la Samaritana y la entrada a la catedral. Fuente: Colecci├│n del Ayuntamiento de Zaragoza.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST├ôRICO', 41.65530900, -0.87635300, '0101000020E6100000310C5872150BECBF22E3512AE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20886096742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20886096742.webp', 'https://www.flickr.com/photos/zaragozaantigua/20886096742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22833, 'Foro Romano c.1989', 'En 1980, durante los trabajos de restauraci├│n en La Seo, se hall├│ una cloaca cuya funci├│n era la de recoger las aguas ca├¡das de la plaza del templo del Foro romano. Ese mismo a├▒o se hallaba tambi├®n otra cloaca en la calle de Don Jaime. En 1982, los arque├│logos localizaron el sistema de desag├╝e de las termas que se hallan (musealizadas) en la calle de San Juan y San Pedro. Entre 1988 y 1994, con las excavaciones arqueol├│gicas en la plaza de La Seo (1988-1991) y solares contiguos (1991-1994), se complet├│ el conocimiento de los canales y cloacas al servicio del Foro de Caesaraugusta. Hay 30 cloacas registradas arqueol├│gicamente en la ciudad, cuyo conjunto es superior a los 600 metros de longitud. En la imagen, el subsuelo de la Plaza de la Seo levantado, excavado, y estudiado. A la izquierda, fuera del per├¡metro arqueol├│gico, la base de la Torre de la Seo.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65524600, -0.87616500, '0101000020E61000007DCB9C2E8B09ECBFDB6AD619DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754262510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754262510.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754262510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22911, 'Plaza La Seo c.1988', 'Excavaci├│n arqueol├│gica del foro romano en la plaza de La Seo. Al fondo, en el centro, calle de Don Jaime I. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150712055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150712055.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150712055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22912, 'Plaza La Seo c.1988', 'Excavaci├│n arqueol├│gica del foro romano. Al fondo, la plaza del Pilar. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23186574831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23186574831.webp', 'https://www.flickr.com/photos/zaragozaantigua/23186574831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22935, 'La Seo 1989', 'Vista nocturna de las excavaciones arqueol├│gicas en la plaza de La Seo, con la catedral al fondo, en 1989. Esta prospecci├│n tuvo lugar entre 1988 y 1991, dando como resultado el museo del Foro Romano. Fuente: "La plaza de La Seo. Zaragoza. Investigaciones Hist├│rico-Arqueol├│gicas". Ayuntamiento de Zaragoza, 1989.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32171401686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32171401686.webp', 'https://www.flickr.com/photos/zaragozaantigua/32171401686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23850, 'Pl. de la Seo c.1955', 'Imagen de la nocturna procesionaria confesional del Rosario de Cristal, con detalle del "paso" del legendario (fant├ístico) ni├▒o-m├írtir Dominguito de Val, santificado por la rama m├ís antisemita y medieval del catolicismo, que lo mantiene en su devocionario aun despu├®s del Concilio Vaticano II. A su vera, sus patrocinados y canoros "infanticos". La captura se ha realizado en la plaza de la Seo, junto a las desaparecidas Casas de los Infantes de la Seo, que quedan a la izquierda, fuera de plano. Al fondo, a la derecha, las a├®reas y visuales jaculatorias de ne├│n instaladas en el templo metropolitano del Pilar al comienzo de la d├®cada, para facilitar el acompa├▒amiento a la jaculatoria oral que suena, tres veces al d├¡a, desde el a├▒o del se├▒or de 1940, A├▒o II de la Victoria. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26620438382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26620438382.webp', 'https://www.flickr.com/photos/zaragozaantigua/26620438382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23994, 'Milagro del Ni├▒o-Hostia 1427', 'Pintura del siglo XVII situada en el pa├▒o lateral izquierdo de la capilla de Santo Dominguito de Val de la Seo de Zaragoza, atribuida por Jos├® Cam├│n Aznar a Bartolom├® Vicente. Procesi├│n en la plaza del la Seo de Zaragoza, en la que el arzobispo Alonso de Arg├╝ello, que lo fue entre 1419 y 1429, porta en brazos bajo palio al Ni├▒o Jes├║s, para llevarlo a la catedral. La leyenda narra que una mujer casada consult├│ a un alfaqu├¡ (doctor en leyes musulm├ín, considerado mago) para eliminar los malos tratos que le propinaba su marido. El remedio aconsejado fue procurarse una hostia consagrada. La mujer comulg├│ en San Miguel sin tragarse la hostia, y la meti├│ en un cofre. Al abrirlo hab├¡a un ni├▒o, que el alfaqu├¡ orden├│ quemar. El ni├▒o sali├│ ileso y se lo contaron al obispo, que organiz├│ la procesi├│n. Dejaron al ni├▒o en el altar de la capilla de San Valero y al d├¡a siguiente en una misa, el ni├▒o se volvi├│ a convertir en hostia y el obispo se la trag├│. En la imagen, la comitiva municipal sigue al palio detr├ís de un grupo de capitulares. A la derecha, los maceros. Al fondo, la supuesta puerta de la Seo, aunque la c├║pula que se ve detr├ís recuerda a la que ten├¡a la Diputaci├│n del Reino. Fuente visual: "El municipio en Arag├│n", DPZ, 2004.', 1427, 1427, 1427, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20549754211.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20549754211.webp', 'https://www.flickr.com/photos/zaragozaantigua/20549754211/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24227, 'Pl. de la Seo c.1955', '"Rosario de Cristal. Paso de Santo Dominguito de Val. Infanticos. Gente". De las antiguas (y desaparecidas) Casas de los Infantes de la Seo, en la plaza de la Seo, sale el procesional y confesional paso del legendario ni├▒o-m├írtir. El artificio luminario para capturar la nocturna escena atrae miradas y gestos. La del guardia, no. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65504000, -0.87637300, '0101000020E6100000F71DC3633F0BECBF32C9C859D8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22463231459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22463231459.webp', 'https://www.flickr.com/photos/zaragozaantigua/22463231459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23685, 'Aer├│dromo Sanjurjo 1939', 'Imagen capturada en el Aer├│dromo Sanjurjo y centrada en un aeroplano alem├ín modelo Messerschmitt Bf 108 B, utilizado en funciones de comunicaci├│n, enlace y correo por el Grupo de Bombardeo K-88 de la Legi├│n Condor. Desde finales de 1937, durante la Batalla de Teruel, y hasta la campa├▒a de Catalu├▒a, a principios de 1939, este fue uno de los aer├│dromos utilizados por el contingente alem├ín enviado por la Alemania nazi para respaldar a los sublevados nacionalistas en la guerra civil, sobre todo como base de bombarderos.', 1939, 1939, 1939, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49561229801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49561229801.webp', 'https://www.flickr.com/photos/zaragozaantigua/49561229801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24591, 'Plaza de la Seo 1976', 'Al fondo, la Lonja como espectacular marco esc├®nico de la exposici├│n Arte fara├│nico, organizada por la Direcci├│n General de Bellas Artes del Patrimonio Art├¡stico Cultural, e integrada por 219 piezas leg├¡timamente egipcias procedentes del antiguo territorio del Nilo, primero expuestas en Madrid, luego en Zaragoza, y finalmente en Barcelona. Por encima y a la izquierda, emerge la torre de Santa Leonor del Pilar, con su fluorescente jaculatoria. En primer t├®rmino, la plaza de La Seo con la humidificante fuente que en 1962 sustituy├│ a la entra├▒able y tradicional de La Samaritana, que primero viaj├│ al parque de Bruil para terminar en la plaza del Justicia. Tras ella, el tradicional quiosco de prensa anunciando entre otras las revistas masculina y femenina del boyante Opus Dei, y dos personas mayores tomando el sol en un banco, en una ma├▒ana bien fresca.', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST├ôRICO', 41.65529600, -0.87621900, '0101000020E61000004948A46DFC09ECBF8D9944BDE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16659900758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16659900758.webp', 'https://www.flickr.com/photos/zaragozaantigua/16659900758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24592, 'Lonja-Ayuntamiento c.1888', 'La calle de la Lonja con su activo ritmo vital cotidiano como continuaci├│n del puente de Piedra que comunica con el Arrabal, al fondo. Un tranv├¡a "de sangre", carros tirados por caballer├¡as, y un heterog├®neo grupo de viandantes, bullen en el entorno de la Lonja y la Casa Consistorial. La plaza de la Seo, inmediata, se abre a la derecha. La calle del Pilar, a la izquierda. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1888, 1888, 1888, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23366682236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23366682236.webp', 'https://www.flickr.com/photos/zaragozaantigua/23366682236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24594, 'La Lonja 1901', 'Grupo de personas ante la Lonja, en la confluencia de la calle de Don Jaime I con la del Pilar. Fuente: www.delcampe.net', 1901, 1901, 1901, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28512100995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28512100995.webp', 'https://www.flickr.com/photos/zaragozaantigua/28512100995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24597, 'Plaza de la Seo 1902', 'Imagen capturada junto a la fuente denominada Samaritana en la antigua plaza de la Seo, erigida no como mero ornato visual, sino como destacado punto de provisi├│n del l├¡quido elemento para consumo de boca, como manifiesta la nutrida parroquia congregada en torno a ella, si bien parece que son las mujeres las que, provistas de c├íntaros de diversas capacidades, efectivamente realizan esa funci├│n, mientras los ind├¡genas parecen estar vareando el agua de forma est├│lida. Al fondo de la imagen, la calle de la Lonja y el desemboque en ella de la estilizada calle del Pilar, donde destaca el edificio de la casa de la Lonja como antigua dependencia anexa a la casa del Ayuntamiento. Esta imagen fue comercializada como vista estereosc├│pica de la ciudad bajo el t├¡tulo "The old Exchange (1551) and Plaza de La Seo, Saragossa, Spain", cuando la Lonja era curiosamente catalogada como "mercado burs├ítil". Fuente visual: Underwood & Underwood Publishers (Estados Unidos de Norteam├®rica), en Zaragoza estereosc├│pica, fotograf├¡a profesional y comercial 1850-1970, PUZ.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34255489843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34255489843.webp', 'https://www.flickr.com/photos/zaragozaantigua/34255489843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24603, 'Plaza de La Seo 1902', 'Imagen estereosc├│pica capturada en la plaza de La Seo con el fondo de la "old Exchange" (Lonja) entre la calle del Pilar (cuya esquina aparece ensanchada tras el derribo de las inmediatas casas) y el paseo del Ebro. En primer t├®rmino, la fuente de la Samaritana en su original ubicaci├│n de la plaza como importante punto de suministro de agua. A la derecha, el seminario ,metropolitano conciliar.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65539800, -0.87639500, '0101000020E6100000EC17EC866D0BECBF91EEE714E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51422225697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51422225697.webp', 'https://www.flickr.com/photos/zaragozaantigua/51422225697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24604, 'Plaza de La Seo 1878', 'Imagen capturada por el fot├│grafo villanovense Gregorio Sabat├® F├®rriz e integrada en el ├ílbum "Vistas de Zaragoza", centrada en una vista del entorno de la plaza de La Seo tomada desde la altura de la vivienda del Cabildo adosada a la cara suroeste de la torre de la catedral y a la capilla de las santas Justa y Rufina. En primer t├®rmino, la plaza de La Seo con sus jardines y ├írboles vertebrados en torno a la Fuente de la Samaritana instalada en 1866. A la derecha, fachada del Seminario Conciliar construido sin demasiados remilgos sobre los restos del Palacio de la Diputaci├│n del Reino de Arag├│n, que fueron arrasados para la ocasi├│n. Al fondo y a la izquierda, viviendas de la manzana de la calle de Don Jaime I comprendida entre las calles del Pilar y de Juan Mart├¡n Goicoechea. Aqu├¡ figuran la n├║mero 7, esquinera con la calle del Pilar, y su vecina la n├║mero 9. Al otro lado de esa calle, la Casa-Lonja anexa a la Casa Consistorial como escenario de diversas actividades municipales y tambi├®n anual espacio donde se proced├¡a a la "declaraci├│n de soldados" de los individuos que de forma obligatorio formaban parte del reemplazo de quintas (incluyendo entre ellos a quienes no pod├¡an permitirse la redenci├│n en met├ílico del servicio o aquellos que acud├¡an como "sustitutos" de los se├▒oritos y privilegiados) y que deb├¡an "ingresar en caja" en torno al 1 de mayo para cumplir con los preceptivos cuatro a├▒os de "servicio activo".', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54760597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54760597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/54760597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24607, 'Calle Dormer a├▒os 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. Calle Diego Dormer y La Torre de la Seo [o Catedral del Salvador en su Epifan├¡a, al fondo]". A la izquierda, el Palacio renacentista conocido como casa de Miguel Donlope o de la Real Maestranza de Caballer├¡a, por servir de sede a esta Corporaci├│n zaragozana. Construido durante la tercera y cuarta d├®cada del siglo XVI es un ejemplo del modelo de casa-palacio aragon├®s. Fuente visual: Archivo W├╝nderlich (WUN-05815) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65435600, -0.87653500, '0101000020E61000005B94D920930CECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14876971170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14876971170.webp', 'https://www.flickr.com/photos/zaragozaantigua/14876971170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24609, 'Torre de la Seo sin chapitel 1860', 'Un rayo incendi├│ el chapitel de la torre de la Seo en 1850, matando al campanero. Hasta 1861 no se empez├│ a colocar el nuevo chapitel, fundido en los talleres Julio Goybet y C├¡a. de Zaragoza. La peque├▒a torrecilla a la izquierda de la demediada torre de La Seo ser├¡a la ins├│lita torre de la desaparecida iglesia de Santiago, sita en la calle Don Jaime I. M├ís informaci├│n sobre el suceso: tausiet.blogspot.com/2016/01/rayo-sobre-la-seo-muerte-de-... Fuente visual: Mariano J├║dez y Ortiz. 1859-1860. ├ülbum: Andr├®s Mart├¡n e Ip├ís. Col. Mariano Mart├¡n Casalderrey, Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65470400, -0.87610700, '0101000020E6100000567E198C1109ECBFBB473657CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14896850475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14896850475.webp', 'https://www.flickr.com/photos/zaragozaantigua/14896850475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24613, 'Palmeros en La Seo 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 07/04/1974. Palmeros en procesi├│n de palmas en la plaza de la Seo. A la izquierda, la catedral, con espacios se├▒alados en suelo para aparcar en bater├¡a. Al fondo, la callejuela Ram├│n Cu├®llar. A la derecha, antiguo edificio residencial de la plaza con el bar "La Cadiera" en la esquina.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65522200, -0.87608900, '0101000020E6100000BD546CCCEB08ECBF53CF8250DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048052115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048052115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048052115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24618, 'Calle del Pilar a├▒os 20', 'Calle del Pilar (derecha), esquina con la de Don Jaime I, desde la plaza de la Seo. El edificio comercial que centra la imagen tuvo distintos usos: aqu├¡ parece ofrecer obras art├¡sticas de recuerdo, o souvenirs, de escultura, pintura, artesan├¡a. Luego fue cafeter├¡a y tienda de ultramarinos (Pedro Santamera), hasta desaparecer con la manzana de la que formaba parte, cuando los numerosos derribos para dar paso a la nueva gran plaza del Pilar. Fuente visual: Cr├│nica de Zaragoza 1900-1920.', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65542400, -0.87667200, '0101000020E610000087342A70B20DECBFBA8102EFE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15472718210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15472718210.webp', 'https://www.flickr.com/photos/zaragozaantigua/15472718210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24619, 'Dormer 1973', 'Archivo Municipal. Gerardo Sancho Ramo. Julio 1973. Los "Gigantes", como los "Cabezudos", no pisan mucho las calles en julio, pero ese a├▒o estaba justificada la sofoquina: se estaban rodando im├ígenes para la pel├¡cula "Gigantes y Cabezudos", basada en la zarzuela del mismo t├¡tulo, y uno de los fragmentos recog├¡a, precisamente, la Salida de los Gigantes y Cabezudos en el entorno de La Seo y la actual plaza de San Bruno, mientras sonaban acordes musicales asociados, y la interpretaci├│n de ÔÇ£Cuando era ni├▒a y jugabaÔÇØ. Esta pel├¡cula estaba producida por TVE, dirigida por Jos├® Antonio P├íramo, y actuada (las piezas musicales estaban dobladas) por destacadas personalidades de la interpretaci├│n. Se estren├│ de octubre de ese a├▒o, con gran ├®xito. En la imagen, durante una pausa del rodaje la chiquiller├¡a juega entre los Gigantes, que descansan junto a la calle Dormer, en el antiguo barrio de la Seo.', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST├ôRICO', 41.65458900, -0.87626600, '0101000020E6100000761893FE5E0AECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476308213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476308213.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476308213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24625, 'Roscones 1916', 'Foto S├ínchez Rom├ín. La Hormiga de Oro, febrero de 1916. Venta de roscones el d├¡a de San Valero en la puerta de la Seo de Zaragoza, el 29 de enero de 1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST├ôRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18530408643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18530408643.webp', 'https://www.flickr.com/photos/zaragozaantigua/18530408643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24626, 'Gran cloaca de Caesar Augusta siglo I', '├ëpoca de Tiberio. 14-37 d.C. Detalle del interior de la gran cloaca de Caesar Augusta bajo la actual plaza de La Seo. Se halla musealizada junto a los restos del foro. Desde el Renacimiento se utiliz├│ como pasadizo subterr├íneo, bodegas y despensas. Fuente: Cat├ílogo Aquaria. DPZ, 2006', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18676012115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18676012115.webp', 'https://www.flickr.com/photos/zaragozaantigua/18676012115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24631, 'Calle Pabostr├¡a 1971', 'Vista de la calle Pabostr├¡a con la de Dormer al fondo. A la derecha, puerta meridional de la Seo. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST├ôRICO', 41.65444300, -0.87620300, '0101000020E6100000DD06B5DFDA09ECBF4E0CC9C9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528454243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528454243.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528454243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24634, 'Plaza La Seo ca. 1972', 'Plaza de la Seo, con imagen de la Lonja, el Ayuntamiento, y el Pilar. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22754253057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22754253057.webp', 'https://www.flickr.com/photos/zaragozaantigua/22754253057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24636, 'Calle Cisne 1972', 'Dos ni├▒as cargadas de libros caminan por la calle del Cisne, antigua de Zaporta hasta 1863, hacia el final de la calle de Diego Dormer, al fondo. A la izquierda, anexas dependencias de la Seo, y a la derecha, inmuebles de los n├║meros 2 y 4 de la calle, y tapia del patio del palacio de la Real Maestranza de Caballer├¡a. El recoleto barrio de La Seo, peque├▒o laberinto urbano milenario y descuidado, manten├¡a pese a ello la calma y el sabor.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65478000, -0.87649300, '0101000020E6100000A088450C3B0CECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23135317372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23135317372.webp', 'https://www.flickr.com/photos/zaragozaantigua/23135317372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24637, 'Plaza La Seo c.1972', 'Plaza de La Seo el d├¡a de San Valero. Al fondo, puente de Piedra. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150838895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150838895.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150838895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24638, 'Calle San Valero c.1972', 'La calle de San Valero, antigua de la Frener├¡a hasta 1863, se abre desde la de Don Jaime I, y conecta con la Seo. En la imagen, solares dejados tras derribo de los inmuebles de los n├║meros 5-7, 9 y 11, este ├║ltimo esquinero con la calle de Ram├│n Cu├®llar. A la derecha, r├│tulo de una popular taberna sita en el local del n┬║ 8, que perdura. Al fondo, rotunda, la catedral del Salvador, con a├▒ejos anexos en la calle del Cisne, luego derribados.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65501200, -0.87683600, '0101000020E61000001893FE5E0A0FECBF683EE76ED7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23158919212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23158919212.webp', 'https://www.flickr.com/photos/zaragozaantigua/23158919212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22737, 'C.┬║ de la Mosquetera 1973', 'Bicolor reba├▒o de ovejas ramonea en un campo inmediato al camino de la Mosquetera y compone una t├¡pica visi├│n de la periferia de la ciudad del momento, tomada a espaldas de la avenida de G├│mez Laguna. De fondo esc├®nico, y de izquierda a derecha, viviendas del principio de la calle de Mar├¡a Guerrero, en el barrio de La Bozada; pabell├│n de la Infanta Isabel y el de Pensionistas del arbolado Hospital Psiqui├ítrico Nuestra Se├▒ora del Pilar; grandes bloques en construcci├│n que a├▒os m├ís tarde quedar├ín en una esquinera ubicaci├│n entre la prolongaci├│n de la calle de la Duquesa de Villahermosa y la nueva V├¡a Universitas; y finalmente, a la derecha, el bloque del n┬║ 9 de la calle de Santa Rita de Casia. En el transcurso de unos cuantos a├▒os, este escenario conocer├¡a una radical transformaci├│n. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64267000, -0.90821600, '0101000020E6100000A58636001B10EDBF670FB40243D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31481183387.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31481183387.webp', 'https://www.flickr.com/photos/zaragozaantigua/31481183387/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24640, 'Plaza de Santa Marta 1976', 'Imagen, desde la plaza de Santa Marta, del antiguo palacio del marquesado de Huarte. Este edificio se├▒orial fue construido a principios del siglo XVI seg├║n la planta est├índar de las casonas nobles en la ciudad (gran patio central en torno al que se ordenan las estancias, con entrada por la antigua calle de Zaporta, luego Dormer, y esquina a Pabostria). A mediados del pasado siglo XX pas├│ a propiedad de una entidad local de ahorro, hasta que a finales de los a├▒os 70 ├®sta negoci├│ su conversi├│n en sede estable del Archivo Hist├│rico Provincial, hasta ese momento en el antiguo palacio de Sobradiel, sede del Colegio de Notarios. La imagen captura las obras de restauraci├│n y acondicionamiento del antiguo palacio, que comenzar├í a funcionar como AHPZ en 1980, con documentaci├│n desde el siglo X de la Era, hasta el XX. A la izquierda, la calle Dormer, el antiguo palacio de la Maestranza y, al fondo, la torre y catedral de la Seo. Fuente visual: Gerardo Sancho Ramo (Archivo P├║blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST├ôRICO', 41.65420600, -0.87650100, '0101000020E610000056293DD34B0CECBF6A6CAF05BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23454505874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23454505874.webp', 'https://www.flickr.com/photos/zaragozaantigua/23454505874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24642, 'La Samaritana c.1920', 'Estatua y fuente de La Samaritana, en la plaza de La Seo. Al fondo, edificio del arzobispado. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65531700, -0.87632100, '0101000020E610000059897956D20AECBFA4C16D6DE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24287218474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24287218474.webp', 'https://www.flickr.com/photos/zaragozaantigua/24287218474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24645, 'Plaza de La Seo c.1920', 'Plaza de La Seo, con la Lonja al fondo. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65542100, -0.87627800, '0101000020E610000087890629780AECBF490ED8D5E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619681880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619681880.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619681880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24646, 'Plaza de La Seo c.1920', 'Fuente de La Samaritana en la plaza de La Seo. Al fondo, edificio del arzobispado y Palacio Arzobispal. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803845901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803845901.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803845901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24647, 'Plaza de La Seo c.1920', 'Plaza de La Seo, con el palacio arzobispal y la portada de la catedral al fondo a la derecha, tras el arbolado. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65528500, -0.87650300, '0101000020E61000008411FB04500CECBF9947FE60E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803983471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803983471.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803983471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24648, 'La Seo 1945', 'Sello sin valor postal para recaudar fondos destinados a la construcci├│n del "Nuevo Seminario Conciliar de Casablanca" en 1945. En este caso, representa la plaza de La Seo, con un amenazante avi├│n que se dirige a la torre de la catedral. Parece ser que pas├│ de largo. Fuente: www.delcampe.net', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25475544561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25475544561.webp', 'https://www.flickr.com/photos/zaragozaantigua/25475544561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24649, 'Plaza de La Seo 1943', 'Foto: Josep Forns. Vista de la plaza de La Seo desde la del Pilar. Fuente: www.facebook.com/photo.php?fbid=10208829903638499&set...', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST├ôRICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28145625660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28145625660.webp', 'https://www.flickr.com/photos/zaragozaantigua/28145625660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24654, 'Plaza de La Seo 1945', 'Imagen capturada desde la altura de la torre "Nueva", o de Nuestra Se├▒ora del Pilar del hom├│nimo templo, con el objetivo puesto en la Lonja, la plaza de la Seo, y la fachada de la catedral de San Salvador. En primer├¡simo plano, a la izquierda, vista parcial del cerrado per├¡metral en el que estaba prevista la construcci├│n del nuevo ayuntamiento de la ciudad. Fuente visual: postal de la editorial "Soberanas", en www.ebay.es/', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34435973965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34435973965.webp', 'https://www.flickr.com/photos/zaragozaantigua/34435973965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24656, 'Vista desde la Seo c.1916', 'Imagen capturada desde la altura de la torre barroca de la Seo, centrada en una vista hacia el sur urbano. En primer t├®rmino, tejados en el entorno de la recoleta plaza de Santa Marta, y a la derecha, traza de la calle de Don Jaime I, donde destaca el solar dejado tras el derribo de la antigua casa del conde de Atar├®s, en la esquina con la calle de Espoz y Mina, donde poco despu├®s se construir├¡a el referencial inmueble dise├▒ado por Francisco Albi├▒ana, que perdura. Hacia el fondo y siguiendo al calle, atalaya de la iglesia parroquial de San Gil Abad. Hacia la izquierda, la calle de San Jorge, donde destaca la nueva sede central de la Caja de Ahorros de Zaragoza, en la esquina con la calle de San Andr├®s, donde despunta levemente la torrecilla de esta peque├▒a y hom├│nima iglesia. Siguiendo la calle de San Jorge hacia la izquierda, emerge rotunda la antigua iglesia de San Pedro Nolasco, de planta de cruz griega. M├ís hacia el fondo y a la derecha, el paseo de la Independencia. En el centro de la imagen, las torres de las dos centrales el├®ctricas sitas en el entorno de la calle de San Miguel, sobre el fondo despejado de la antigua huerta de Santa Engracia que alcanza hasta la hom├│nima iglesia parroquial.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST├ôRICO', 41.65455700, -0.87673900, '0101000020E61000007B1684F23E0EECBF162F1686C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49105600518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49105600518.webp', 'https://www.flickr.com/photos/zaragozaantigua/49105600518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24895, 'La Samaritana c.1958', 'Plaza de La Seo con la fuente de la Samaritana fundida en Averly, trasladada en 1962 a la plaza del Justicia. Fuente. www.facebook.com/photo.php?fbid=808979045791389&set=o...', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST├ôRICO', 41.65527500, -0.87619100, '0101000020E6100000CD9541B5C109ECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15204337611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15204337611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15204337611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25158, 'Calle Dormer a├▒os 30', 'Acuarela de Ambrosio Ruste, mostrando la calle de Diego Dormer desde la plazuela de Santa Marta. Al fondo, la torre de la Seo. A la derecha, el palacio de la Real Maestranza de Caballer├¡a. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65443300, -0.87652600, '0101000020E61000008FFF0241800CECBF2A36E675C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32061502870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32061502870.webp', 'https://www.flickr.com/photos/zaragozaantigua/32061502870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25159, 'Calle Cu├®llar a├▒os 30', 'Acuarela de Ambrosio del Ruste. Calle de Ram├│n Cu├®llar, con la de San Valero al fondo. A la izquierda, calle del Cisne. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65481800, -0.87641900, '0101000020E61000000DFAD2DB9F0BECBF836A8313D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062251320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062251320.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062251320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25161, 'Calle Pabostr├¡a a├▒os 30', 'Acuarela de Ambrosio Ruste, con una vista del palacio de la Real Maestranza de Caballer├¡a en la calle de Diego Dormer, al fondo, desde la de la Pabostr├¡a. A la derecha, puerta sur de la Seo. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65446500, -0.87630100, '0101000020E610000092770E65A80AECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062694170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062694170.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062694170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25165, 'Calle San Valero a├▒os 30', 'Acuarela de Ambrosio Ruste. Al fondo de la calle San Valero, se distingue el lateral sur de la Seo. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65490600, -0.87673000, '0101000020E6100000AE81AD122C0EECBF22FAB5F5D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32318536381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32318536381.webp', 'https://www.flickr.com/photos/zaragozaantigua/32318536381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25185, 'Plaza de La Seo 1909', '"Plaza de la Seo (Zaragoza)", ├│leo sobre lienzo, Rafael Aguado Arnal, 1909. Colecci├│n particular, Bilbao. Vista de la arbolada plaza de La Seo, con la catedral al fondo.', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65528900, -0.87634200, '0101000020E6100000368FC360FE0AECBFDB368C82E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52490931279.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52490931279.webp', 'https://www.flickr.com/photos/zaragozaantigua/52490931279/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25516, 'Paza de La Seo c.1897', 'Imagen capturada en la arbolada plaza de la Seo con motivo de la Solemnidad del Cuerpo y la Sangre de Cristo durante el protocolario desfile del Ayuntamiento en Corporaci├│n, que abre una secci├│n de la Guardia Municipal montada en traje de gala. Al fondo, fachada e ingreso principal de la Seo, desde donde sale la procesionaria. A la izquierda, el seminario conciliar, el palacio arzobispal y el arco del Arzobispo. Fuente visual: cesbor.blogspot.com.es/', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65536900, -0.87608300, '0101000020E6100000349C3237DF08ECBFF7E7A221E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25562239067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25562239067.webp', 'https://www.flickr.com/photos/zaragozaantigua/25562239067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25907, 'Plaza de la Seo 1970', 'Apacible imagen de la plaza de la Seo, cuando el articulado tranv├¡a 253, de la L├¡nea 10 "Academia" est├í presto a girar por la derecha para encaminarse al Puente de Piedra, tal y como ven├¡a haciendo desde los a├▒os sesenta. Un a├▒o despu├®s de esta captura fotogr├ífica, la l├¡nea ser├¡a clausurada, tras algo m├ís de cuarenta a├▒os de servicio. Justo detr├ís del tranv├¡a, el cine "Pax" proyecta el musical "Funny Girl", con Barbra Streisand, y Omar Sharif. En la arbolada plaza, los sombreados bancos presentan notable parroquia. Fuente visual: Familia Cuy├ás (cartotecadigital.icc.cat/)', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24329925710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24329925710.webp', 'https://www.flickr.com/photos/zaragozaantigua/24329925710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22004, 'Colegio Santa In├®s 1941', 'Dibujo del proyecto de nuevo edificio para el colegio de Santa In├®s, por Lorenzo Moncl├║s, agosto de 1941. Ser├í levantado en 1942, en el chafl├ín entre las calles de Santa In├®s y Boggiero, sobre terrenos del convento de Santa In├®s. En 1949 fue ampliado y traspasado a las dominicas de la Anunciata. Fuente: www.ebay.es', 1941, 1941, 1941, 'Anos 40', 'CASCO HIST├ôRICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36109225604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36109225604.webp', 'https://www.flickr.com/photos/zaragozaantigua/36109225604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23029, 'Calle del Conde de Aranda 1992', 'La calle del Conde de Aranda, tradicional salida hacia el oeste desde el centro de la ciudad, con sus 740 metros de longitud, vista desde las inmediaciones de la calle de Santa In├®s, a la izquierda, con el Coso Alto al fondo. Su configuraci├│n cambi├│ a├▒os despu├®s, en virtud de una remodelaci├│n que, finalizada en 2004, incluy├│ aceras m├ís anchas y una medianera ajardinada con palmeras.', 1992, 1992, 1992, 'Anos 90', 'CASCO HIST├ôRICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207027816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207027816.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207027816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23919, 'Tranv├¡a l├¡nea 5 1967', 'A├▒o 1967. Tranv├¡a de la l├¡nea 5 (Venecia-Delicias), a su paso por la calle "General Franco". Detr├ís del tranv├¡a, los restos de la manzana donde estuvo ubicada la antigua Casa de la Galera, como c├írcel correcional de mujeres durante los siglos XVII-XIX, que luego fue c├írcel masculina, y tambi├®n escuela de ni├▒os. Fuente visual: J. Ib├í├▒ez - Colecci├│n Asociaci├│n Filat├®lica Zaragozana "Gregorio Sierra".', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887018912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887018912.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887018912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23928, 'Calle Santa In├®s 1886', 'Vista de la calle de Santa In├®s de Zaragoza desde la iglesia del Portillo. A la derecha, calle del Portillo (hoy Conde de Aranda), flanqueada por la Casa de la Galera, reconvertida en colegio infantil en 1883. Abajo a la izquierda, huertas del convento de Santa In├®s. Al fondo, las torres de la ciudad: el Pilar, San Pablo, Santa Isabel, la Seo, la Torre Nueva...', 1886, 1886, 1886, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21002883458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21002883458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21002883458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23940, 'Calle General Franco 1971', 'Vista de la calle del General Franco, esquina con la de Santa In├®s, en julio de 1971. A la derecha, los restos de la antigua Casa de la Galera, despu├®s colegio. Tras la valla con carteles comerciales, el colegio del Carmen y San Jos├® de las Hijas de la Caridad de San Vicente de Pa├║l, en funcionamiento en ese lugar desde 1947, ocupando parte del terreno del convento de Santa In├®s. En el centro, unidad tranviaria n├║mero 80 de la l├¡nea 5, "Venecia-Delicias", proveniente del barrio de las Delicias. Al fondo, edificios desaparecidos de la esquina de la avenida de Madrid con el paseo de Mar├¡a Agust├¡n. A la izquierda, vista parcial de la agencia urbana n├║mero 1 de la Caja de Ahorros de Zaragoza y de la torre derecha de la iglesia del Portillo. Fuente visual: www.facebook.com/photo.php?fbid=1433912296624611&set=...', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST├ôRICO', 41.65580400, -0.89130000, '0101000020E6100000F697DD938785ECBF024BAE62F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30125233381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30125233381.webp', 'https://www.flickr.com/photos/zaragozaantigua/30125233381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24416, 'Convento de Santa In├®s 1930', 'Defectuosa pero interesante vista de 1930 del final de la calle de San Pablo, donde tambi├®n terminaba la de Santa In├®s. Al fondo, portada del convento de Santa In├®s, enclavado ah├¡ desde el siglo XIV, y ocupado por monjas dominicas contemplativas. A partir de 1835, se dedicaron a la ense├▒anza. En 1942 se construy├│ un edificio de nueva planta, en el chafl├ín entre Santa In├®s y Boggiero. En 1949 se ampl├¡a y traspasa a las dominicas de la Anunciata. Fuente visual: Colecci├│n Particular.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65684600, -0.89083800, '0101000020E6100000EC1681B1BE81ECBF14419C8713D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33500671741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33500671741.webp', 'https://www.flickr.com/photos/zaragozaantigua/33500671741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25827, 'Calle de Boggiero 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Boggiero." Esta es una calle que nace en la calle Escuelas P├¡as y termina en la de Santa In├®s. Imagen del tramo entre la calle de Santa In├®s hasta la de Mayoral. A la derecha, un pedazo de la antigua Casa de la Penitencia, habilitada en el siglo XVII en un edificio del siglo XV, derribada para construir la cosa que hoy hay.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65625600, -0.89075000, '0101000020E61000001B2FDD240681ECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15071262611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15071262611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15071262611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25849, 'Calle de Santa In├®s 1951', 'Imagen capturada en la calle de Santa In├®s y centrada en el tramo entre la calle de Boggiero y la de San Pablo. A la izquierda, el moderno colegio de Santa In├®s, levantado en 1941 en una peque├▒a parte del antiguo convento de Santa In├®s de las Madres Dominicas. A la derecha, original anchura de la calle definida por los antiguos inmuebles del n┬║ 164 de Boggiero, y del n┬║ 6, 8 y 10-12 de Santa In├®s. Al fondo, antiguo n┬║ 162 de la calle de San Pablo, donde la calle de Santa In├®s terminaba, desaparecido m├ís tarde con motivo de la prolongaci├│n de esa calle hasta la de Santa Luc├¡a. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41306896562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41306896562.webp', 'https://www.flickr.com/photos/zaragozaantigua/41306896562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25850, 'Calle del General Franco c.1955', 'Imagen capturada desde la altura del inmueble del n┬║ 81 de la calle del General Franco, y centrada en el moderno colegio de Nuestra Se├▒ora del Carmen y San Jos├®, esquinero con la calle de Santa In├®s en primer t├®rmino y a la derecha. Casualmente y a su lado, transita una composici├│n tranviaria M+R (posiblemente motor de la serie 60, y remolque de la 80) en servicio en la l├¡nea 5 "Venecia-Delicias", encaminada hacia la moderna plaza de Huesca, antigua de Rocasolano. Fuente visual: Ediciones DARVI, en www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46246198735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46246198735.webp', 'https://www.flickr.com/photos/zaragozaantigua/46246198735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20872, 'Dominguito y los barqueros 1250', 'Recuperaci├│n del cad├íver de Santo Dominguito de Val. Museo de Huesca, siglo XVI. El ni├▒o de siete a├▒os Dominguito de Val, infantico (monaguillo cantante) de La Seo, fue raptado por el jud├¡o Albayuceto, que lo entreg├│ a sus correligionarios para que lo crucificaran (en el palacio de Sora o Salabert). Luego ocultaron su cuerpo en la ribera del Ebro tras cortarle los pies y la cabeza. Unas luces divinas mostraron el lugar a unos barqueros, que recuperaron el cuerpo. Como reza la pintura, "No es la primera ocasi├│n que para hallar un infante se muestra el cielo radiante". Los caballeros de la barca son las autoridades que acudieron a dar fe. Esta leyenda fue creada en 1643, a imitaci├│n de otras similares. A la izquierda, desembocadura del Huerva en el Ebro. Al fondo, puente de Tablas, puente de Piedra y Arrabal. Fuente: www.facebook.com/photo.php?fbid=10203933800178773&set...', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208940932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208940932.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208940932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20877, 'Dominguito de Val 1250', 'Santo Dominguito de Val. Grabado de Mateo Gonz├ílez, 1793. Museo de Zaragoza. Ni├▒o legendario zaragozano del que se relataba su muerte violenta, situ├índola en 1250, cuyo culto fue suprimido por el Concilio Vaticano II (1965). En el fondo de la imagen principal vemos una representaci├│n del paso del r├¡o Ebro por Zaragoza. En el ├íngulo inferior derecho, el cad├íver mutilado luminoso en la desembocadura del r├¡o Huerva. A la izquierda, el Puente de Tablas y un embarcadero de dudosa verosimilitud.', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19054241565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19054241565.webp', 'https://www.flickr.com/photos/zaragozaantigua/19054241565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22310, 'Parque Bruil c.1969', 'Imagen del "Parque Torre de Bruil" de Zaragoza, inaugurado en 1965. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15679984796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15679984796.webp', 'https://www.flickr.com/photos/zaragozaantigua/15679984796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22376, 'Vista a├®rea Ebro 1964', 'Vista a├®rea del r├¡o Ebro a su paso por Zaragoza, desde el este. En primer t├®rmino, la desembocadura del r├¡o Huerva, en la margen derecha. Fuente: Colecci├│n Rafael Margal├®.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST├ôRICO', 41.65381700, -0.86519600, '0101000020E610000017299485AFAFEBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22129071029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22129071029.webp', 'https://www.flickr.com/photos/zaragozaantigua/22129071029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22446, 'Aloy Sala 1960', 'Imagen a├®rea capturada desde las alturas del este de la ciudad, centrada en el reciente Grupo Aloy Sala, construido en terrenos del arrabal de las Tener├¡as lindantes con el talud del r├¡o Huerva, que de izquierda a derecha, y en primer t├®rmino, desemboca en el Ebro; los campos de cultivos inmediatos a las traseras del militar Dep├│sito de Sementales y los terrenos de la antigua Torre de Bruil (izquierda); y la f├íbrica de armamento Instalaza, en el indefinido espacio hasta el cauce del r├¡o Ebro (derecha). Este Grupo preve├¡a la construcci├│n de 1579 viviendas, locales comerciales y servicios varios, incluyendo escuelas, ocio e iglesia cat├│lica, como g├®nesis de un nuevo barrio completo destinado a la clase media, y en r├®gimen de alquiler, a realizar en varias fases, de las que s├│lo se completaron las dos primeras. En beneficio de todos, gratis et amore, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65209000, -0.86674900, '0101000020E61000000CE71A6668BCEBBF3A0664AF77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31051119443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31051119443.webp', 'https://www.flickr.com/photos/zaragozaantigua/31051119443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23686, 'Aer├│dromo Sanjurjo 1938', 'Imagen capturada en el aer├│dromo Sanjurjo de Zaragoza con un contundente primer plano de bombas de 50 kg. apiladas y listas para cargarlas en los bombarderos operativos. Tras ellas y en la pista, un Junkers Ju-W 34 Hi, aparato de enlace, entrenamiento y servicio meteorol├│gico, y varios Dornier Do-17 E.1, modernos bombarderos ligeros con capacidad de cargar 15 de estas bombas que los alemanes de la Legi├│n C├│ndor denominaban "Fliegender Bleistift" (l├ípiz volador) por su alargado fuselaje, y que los nacionalistas espa├▒oles redenominaron m├ís castizamente "Bacalao". Al fondo, l├¡nea de ├írboles que se├▒ala el curso del Canal Imperial de Arag├│n.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50301123318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50301123318.webp', 'https://www.flickr.com/photos/zaragozaantigua/50301123318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23057, 'Cuartel de Sementales 1994', 'Imagen capturada en el solar dejado tras el derribo de las instalaciones del cuartel 5┬║ Dep├│sito de Sementales sito en la calle del Asalto, entre el parque de Bruil y el Grupo de Viviendas Aloy Sala. Esta dependencia militar no fue incluida en la Operaci├│n Cuarteles a pesar de las gestiones del Ayuntamiento al principio de los a├▒os 80 por las reclamaciones realizadas por el ramo de la Guerra, tanto econ├│micas como que all├¡ se levantaran viviendas militares. En paralelo, el vecindario del barrio de las Tener├¡as promovi├│ gestiones para solicitar el traslado de este cuartel por sus afecciones insalubres, nocivas y molestas. Finalmente, en 1994 se lleg├│ a un acuerdo y el cuartel fue desmantelado y trasladado a unas nuevas instalaciones en Garrapinillos. El solar resultante ser├¡a objeto de un Plan Especial del ├ürea de Intervenci├│n U-7-2 aprobado en 1996 del que resultar├¡a la urbanizaci├│n actual de este espacio. En la escena, vista del solar dejado tras el derribo del cuartel, con el parque de Bruil al fondo, sobre el que emergen los bloques de la calle de Alvira Lasierra. A la derecha, viviendas de la calle del Asalto esquineras con la calle de Cant├¡n y Gamboa y vecinas del convento de las madres agustinas de Santa M├│nica. M├ís a la derecha, se destaca la torre del antiguo convento de San Agust├¡n.', 1994, 1994, 1994, 'Anos 90', 'CASCO HIST├ôRICO', 41.65102200, -0.86845600, '0101000020E6100000AF7AC03C64CAEBBFFE7C5BB054D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449979087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449979087.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449979087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23201, 'Calle Vicente L├│pez Abad├¡a 2010', 'Foto: Oliver Duch. Solar entre las calles de Vicente L├│pez Abad├¡a (al fondo) y Pascual Albero Burillo, junto al parque Bruil. All├¡ se construy├│ en 2010 la Escuela Infantil Municipal Parque Bruil, inaugurada en octubre de 2012 con domicilio en la calle Vicente L├│pez Abad├¡a 4. En su subsuelo est├í previsto un aparcamiento subterr├íneo. Fuente: Heraldo de Arag├│n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65156300, -0.86685900, '0101000020E6100000D2C8E7154FBDEBBF4F24986A66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32518208074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32518208074.webp', 'https://www.flickr.com/photos/zaragozaantigua/32518208074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24706, 'Prolongaci├│n Echegaray 1989', 'Vista a├®rea de las obras de 1989 en el entorno de la desembocadura del r├¡o Huerva, en lo que ser├í la prolongaci├│n del paseo de Echegaray y Caballero. En primer t├®rmino, construcci├│n del puente de La Uni├│n. En el centro, puente sobre el Huerva. Al fondo a la derecha, puentes del Pilar, de Piedra y de Santiago. Fuente: www.eszaragoza.eu/2017/06/lo-que-sucedia-en-zaragoza-dura...', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65240600, -0.86526100, '0101000020E6100000DD2230D637B0EBBF6ADB300A82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36403250961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36403250961.webp', 'https://www.flickr.com/photos/zaragozaantigua/36403250961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24736, 'El Huerva llega al Ebro 1977', 'Imagen de la desembocadura del Huerva en el Ebro. Pocos cambios en este entorno desde que el Huerva abandonara, hace ya bastante tiempo, su antiguo cauce, por la actual calle del Asalto, y se desviara hacia la derecha, hacia tierras m├ís bajas, dejando el meandro del actual Parque Bruil como un lugar muy favorable para la agricultura. En la margen izquierda, panorama de las diferentes urbanizaciones, en este caso con grandes bloques habitacionales que iban surgiendo desde mediados de los a├▒os 70. En primer t├®rmino, sobresaliendo detr├ís de naves y almacenes, la urbanizaci├│n Vadorrey. A la izquierda, m├ís al fondo, la urbanizaci├│n denominada "El Colector", actual Manuel Viola. El alto bloque que sobresale por encima de todos, es el edificio "La Estrella", de 14 alturas, junto a la Avenida de Catalu├▒a. Fuente visual: "La evoluci├│n urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65295400, -0.86484000, '0101000020E610000078B988EFC4ACEBBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15139541264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15139541264.webp', 'https://www.flickr.com/photos/zaragozaantigua/15139541264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24961, 'Al norte del Parque Bruil 1974', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Noviembre 1974. La Torre de Bruil-Parque Bruil, el Dep├│sito de Sementales del Ej├®rcito de Tierra, el Grupo de Viviendas "Aloy Sala" (Arrabal de las Tener├¡as), y el r├¡o Huerva ya casi desembocando en el Ebro, delimitaban una interesante y poco visitada zona de antiguos campos de cultivo, a escasos minutos del centro de la ciudad. Dos principales caminos de servicio de fincas hac├¡an las funciones de irregular cardo y decumano para un llano per├¡metro donde cereales y herb├íceas se suced├¡an seg├║n el a├▒o. Un riego derivado de acequia, y un desag├╝e de viejos lavaderos, vert├¡an aguas a la trinchera del Huerva (a la izquierda). El desarrollo urbano de la ciudad hab├¡a sido orientado hacia otras latitudes, y el entorno no se consideraba de la suficiente calidad como para esperar una revalorizaci├│n suficiente y r├ípida del precio del suelo agr├¡cola. Pese a tener de vecino al nov├¡simo y espectacular Parque Bruil, la inmediatez del cuartel del Ej├®rcito (caballer├¡a), las viviendas baratas de los 50, y que las Tener├¡as no era precisamente el Soho zaragozano, mantuvo en barbecho espectante esta zona durante alguna d├®cada m├ís. Ahora esto es otra cosa, distinta. En la imagen, vista de los campos de cultivo desde la actual calle Alto Arag├│n. De izquierda a derecha, el r├¡o Huerva, el reciente edificio H├íbitat Don 2000 (1973), y tras el muro de delimitaci├│n, los ├írboles y fronda del Parque Bruil, y las arom├íticas instalaciones del cuartel de caballer├¡a. Justo detr├ís, las ruinas del antiguo convento de S. Agust├¡n y su caracter├¡stica y desmochada torre, y la confluencia viaria de Alonso V con la calle Asalto.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65139800, -0.86796800, '0101000020E6100000552FBFD364C6EBBF0457790261D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849195251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849195251.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849195251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24963, 'Parque Bruil 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/julio 1965. Tras m├ís de diez a├▒os de gestiones, inauguraci├│n del municipal Parque Bruil, entre el r├¡o Huerva (este), la calle Asalto (oeste), el cuartel de Sementales y unos campos de cultivos (norte), y un vial que poco despu├®s se denominar├í Mariano Alvira Lasierra.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14850897742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14850897742.webp', 'https://www.flickr.com/photos/zaragozaantigua/14850897742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24974, 'Parque Bruil 1970', 'Piscinas del parque Bruil de Zaragoza. Postal, ed. Zerkowitz, serie 82, n┬║ 1.074, 1970. Fuente: www.todocoleccion.net', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19585124351.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19585124351.webp', 'https://www.flickr.com/photos/zaragozaantigua/19585124351/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25421, 'R├¡o Ebro y murallas s.XVII', 'Trascoro de la Seo de Zaragoza. Siglo XVII. Relieve de la vista del r├¡o Ebro y las murallas de Zaragoza con la puerta del ├üngel junto al puente de Piedra, y el puente de Tablas en primer t├®rmino. Escena de la leyenda del hallazgo del los restos de Santo Dominguito de Val decapitado. Fuente: Cat├ílogo El municipio en Arag├│n, DPZ, 2004.', NULL, NULL, NULL, NULL, 'CASCO HIST├ôRICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18672417202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18672417202.webp', 'https://www.flickr.com/photos/zaragozaantigua/18672417202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25536, 'Colector del Huerva 1934', 'El emisario del alcantarillado al r├¡o Ebro en la margen izquierda de la desembocadura del Huerva fue construido en 1907 y ampliado en 1934, momento que recoge la foto. Entre los trabajadores, algunas bestias de carga. Hasta la urbanizaci├│n reciente de la zona en el siglo XXI, el colector vert├¡a las aguas residuales al descubierto, dejando un olor caracter├¡stico. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65312700, -0.86547500, '0101000020E6100000E02D90A0F8B1EBBF3A9160AA99D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18701889484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18701889484.webp', 'https://www.flickr.com/photos/zaragozaantigua/18701889484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23059, 'Vuelta ciclista a Espa├▒a 1990', 'El 13 de mayo de 1990 se celebr├│ la etapa 19 de la Vuelta ciclista a Espa├▒a, con un recorrido de 30 km contrarreloj dentro de la ciudad de Zaragoza. El ganador de la prueba fue Peio Ruiz Cabestany, y el de la Vuelta, Marco GIovannetti. La imagen est├í extra├¡da del v├¡deo de la retransmisi├│n en TVE, y muestra al ciclista Pedro Delgado atravesando el puente de la Uni├│n o de Las Fuentes sobre el Ebro, con el Pilar al fondo.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65246900, -0.86273700, '0101000020E6100000A79201A08A9BEBBFB153AC1A84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50494089228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50494089228.webp', 'https://www.flickr.com/photos/zaragozaantigua/50494089228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21222, 'R├¡o Ebro c.1905', 'Photoglob Z├╝rich. Ca.1905. "R├¡o Ebro y Nuestra Se├▒ora del Pilar". Imagen del Ebro, con el fluvial paso en barca, por a├®reo camino de sirga, del "T├¡o Toni". Al fondo, el puente de las piedras, con sus pretiles y sus leones. Detr├ís, el de hierros. Fuente: www.el-trastero.eu/caddie/images/zaragoza-0010.webp', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15934073422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15934073422.webp', 'https://www.flickr.com/photos/zaragozaantigua/15934073422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21442, 'R├¡o Ebro c.1910', 'Imagen capturada junto a la ribera del r├¡o Ebro inmediata a la arboleda de Macanaz, en la margen izquierda, y centrada en una vista que incluye al Puente de Piedra y el Puente de Hierro m├ís al fondo, y el templo del Pilar con las dos torres recayentes a la hom├│nima plaza. En primer t├®rmino, embarcadero del paso de barcas que d├®cadas m├ís tarde se├▒alar├¡a la ubicaci├│n de una pasarela peatonal permanente. Sobre el Puente de Piedra transita un coche posiblemente de la tranviaria l├¡nea del Arrabal. A la derecha, entre el Pilar y la ribera de la margen derecha, el recoleto espacio junto a la Puerta del Fin y la Escuela Normal de Maestras utilizado como ferial de ganado.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65886900, -0.88098700, '0101000020E6100000D66F26A60B31ECBF93ACC3D155D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49334482061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49334482061.webp', 'https://www.flickr.com/photos/zaragozaantigua/49334482061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21502, 'Almadieros 1923', 'Miguel Faci Abad. 1923. "Zaragoza. Ba├▒os del Ebro y navatas." En la imagen, tomada desde la margen izquierda del r├¡o Ebro, aspecto de la arboleda de Macanaz cuando a├║n era utilizada para desembarcar los maderos que los almadieros del Valle del Roncal tra├¡an a la ciudad. Los maderos, una vez sacados del agua, se dejaban "en cuarentena", para que se secaran completamente antes de su uso, o distribuci├│n. Mientras los almadieros descansan al sol de la tarde, unos chavales en pelota picada se remojan para refrescarse, mientras otros, vestidos, se van a remojar sin pretenderlo. El uso del Ebro como fluvial ruta de transporte de madera fue posible hasta la puesta en funcionamiento de la presa de Yesa (1959-1960). Fuente visual: "Miguel y Gabriel Faci. Fot├│grafos fundadores de la Real Sociedad Fotogr├ífica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci├│n Provincial de Zaragoza, 1999.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST├ôRICO', 41.65911000, -0.88090100, '0101000020E61000003370404B5730ECBFB83B6BB75DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15516887172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15516887172.webp', 'https://www.flickr.com/photos/zaragozaantigua/15516887172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21685, 'El paso del Ebro 1939', 'Albert Louis Deschamps. Cruzando el Ebro a mano, a la altura de San Juan de los Panetes y la Zuda, una maniobra de la Barca del T├¡o Toni, al precio de cinco c├®ntimos de peseta la persona. El Torre├│n de la Zuda se encontraba entre diversas viviendas que se le hab├¡an ido adosando a lo largo del tiempo. En 1931 comenzar├í una intervenci├│n en la zona, con la ampliaci├│n de la avenida de Nuestra Se├▒ora del Pilar, las murallas romanas, el torre├│n de la Zuda y la iglesia de San Juan de los Panetes. Luego vendr├í la idea de la V├¡a Imperial, y luego la de C├®sar Augusto... En la imagen a├║n no estaba construida la Pasarela Peatonal sobre el Ebro, que se iniciar├í en 1940, y se inaugurar├í en 1941.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65835600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14903094946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14903094946.webp', 'https://www.flickr.com/photos/zaragozaantigua/14903094946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21734, 'El Ebro y el Pilar a├▒os 30', 'Foto: Miguel Mar├¡n Chivite. Panorama del r├¡o Ebro con el Pilar al fondo. A la izquierda, puente de piedra y ni├▒o bebiendo. La embarcaci├│n que aparece es un modelo motorizado que efect├║a el recorrido tradicional de la barca del T├¡o Toni, que seguir├í prestando sus servicios mediante sirga a mano hasta la construcci├│n de la pasarela peatonal en los a├▒os 40. Fuente: Archivo Heraldo de Arag├│n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21351091648.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21351091648.webp', 'https://www.flickr.com/photos/zaragozaantigua/21351091648/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21773, 'R├¡o Ebro 1932', 'R├¡o Ebro. Al fondo, el puente del Ferrocarril. A la derecha, la arboleda de Macanaz, la Caseta de Ba├▒os, y la ÔÇ£Sociedad Naturista HeliosÔÇØ. Una barca cruza el r├¡o. Fuente visual: Foto Conrado Barl├®s, donada por Daniel Barl├®s y digitalizada por Jos├® Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65854900, -0.88066500, '0101000020E61000003C6BB75D682EECBF21E868554BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22855738617.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22855738617.webp', 'https://www.flickr.com/photos/zaragozaantigua/22855738617/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21829, 'Embarcadero 1933', 'Embarcadero en el r├¡o Ebro. Al fondo, el Pilar. Fuente: Heraldo de Arag├│n.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65897000, -0.88242700, '0101000020E6100000C16F438CD73CECBFC685032159D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935400752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935400752.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935400752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21842, 'Pasarela de Macanaz 1933', 'Dibujo representando la pasarela peatonal sobre el r├¡o Ebro proyectada por el ingeniero Luis de Fuentes L├│pez como forma de conectar la calle de Antonio P├®rez con la arboleda de Macanaz. El antropol├│gico y ├║nico paso de sirga del t├¡o Toni ya hab├¡a dado paso a la introducci├│n por ├üngel Bag├╝├®s de las modernas barcas a gasolina que cubr├¡an el tr├ínsito de personas entre las dos orillas mediante varios embarcaderos. Tras los diversos procesos de embellecimiento de ambas riberas del Ebro, ahora parec├¡a tocarle el turno a la construcci├│n de un paso peatonal estable de orilla a orilla, si bien la idea finalmente ser├¡a materializada al principio de la siguiente d├®cada, tan cercana, y tan diferente. En el dibujo, la proyectada pasarela representada entre la orilla derecha (a la izquierda) con el final de la calle de Antonio P├®rez, y la orilla izquierda (a la derecha) con la arboleda de Macanaz y su acceso casi cinco metros m├ís bajo a salvar mediante escaleras. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65843900, -0.88113600, '0101000020E61000001381EA1F4432ECBF9AB4A9BA47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35569416784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35569416784.webp', 'https://www.flickr.com/photos/zaragozaantigua/35569416784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21844, 'Calle de Demetrio Gal├ín 1934', 'Imagen capturada en la despejada calle de Demetrio Gal├ín, paralela a la arboleda de Macanaz, y centrada en la f├íbrica de lavaje y apartado de lanas de Jaime Corcoy, que inici├│ su actividad en 1917 como Manufactura de Lanas de Mor├│n y An├│s, con dise├▒o de Miguel ├üngel Navarro, en el entonces camino de Ranillas. De esta instalaci├│n perdura la chimenea, en un entorno descontextualizado, bastante diferente. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.66064300, -0.88270300, '0101000020E61000004698A25C1A3FECBF69AA27F38FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35653992904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35653992904.webp', 'https://www.flickr.com/photos/zaragozaantigua/35653992904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22037, 'R├¡o Ebro c.1942', 'Acuarela del prol├¡fico dibujante, poeta y periodista Ambrosio Ruste Alonso (1871-1955) titulada "El Pilar" porque este templo centra desde el fondo de la escena una fluvial vista capturada desde un embarcadero recreativo en la arboleda de Macanaz. Apenas esbozada, la pasarela del Ebro aparece levemente tendida sobre el r├¡o. Fue proyectada en 1933 por el ingeniero Luis de Fuentes L├│pez como forma de conectar la calle de Antonio P├®rez con la arboleda de Macanaz, si bien su construcci├│n se demor├│ en el tiempo para ser finalmente bendecida e inaugurada el 25 de febrero de 1941, terminando as├¡ con la tradicional barca de sirga que desde el siglo XIX conectaba las dos riberas y que desde los a├▒os 30 fue sustituida por "gasolineras" o barcazas a motor. Como siempre, una mejora en esta ciudad que conlleva un derribo o una desaparici├│n de un elemento previo fue ardorosamente aplaudida en la prensa de la ├®poca, donde se sentenci├│ que la referida barca era "vieja", "antiest├®tica" y "lenta", mientras que la nueva pasarela era "m├ís l├│gica, c├│moda y eficaz". As├¡ las cosas y de forma no menos l├│gica, esta situaci├│n se repetir├¡a casi un cuarto de siglo despu├®s, cuando esta pasarela fue desmontada para dar paso a un nuevo puente m├ís c├│modo y eficaz.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST├ôRICO', 41.65914200, -0.88259600, '0101000020E6100000C59272F7393EECBFC4B5DAC35ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54754018338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54754018338.webp', 'https://www.flickr.com/photos/zaragozaantigua/54754018338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22082, 'Pasarela sobre el Ebro a├▒os 50', 'Magn├¡fica imagen del acceso desde la Arboleda de Macanaz a la pasarela sobre el r├¡o Ebro construida en 1941, que desapareci├│ para dar paso al puente de Santiago en 1967. Al fondo, la iglesia de San Juan de los Panetes. Fuente: www.facebook.com/photo.php?fbid=643306315778704&set=p...', 1950, 1950, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15783586076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15783586076.webp', 'https://www.flickr.com/photos/zaragozaantigua/15783586076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22095, 'Pasarela 1955', '"Saliendo de la escuela", foto de Jos├® Antonio Duce, 1955. Ni├▒os sobre la pasarela peatonal del Ebro que ser├í sustituida por el puente de Santiago. Al fondo, San Juan de los Panetes. Fuente: rafaelcastillejo.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20090004454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20090004454.webp', 'https://www.flickr.com/photos/zaragozaantigua/20090004454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22230, 'Helios c.1959', 'Imagen capturada desde el campin de Helios y orientada hacia el este, con vista parcial de la original piscina y la pista de baloncesto. Hacia el fondo, la arboleda de Macanaz, flanqueada por viviendas del Arrabal a la izquierda, y el templo del Pilar a la derecha.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.66000800, -0.88296100, '0101000020E61000003197546D3741ECBF978C63247BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49911991977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49911991977.webp', 'https://www.flickr.com/photos/zaragozaantigua/49911991977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22289, 'Puente de Santiago 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 23/01/1965. "Crecida del r├¡o Ebro." 1965 fue otro a├▒o de crecida destacable del r├¡o Ebro. A su paso por la ciudad, la altura del agua fluyendo alcanz├│ los cinco metros de altura. En la imagen, aspecto del puente de Santiago en construcci├│n, mientras el cauce se hinchaba y desbordaba all├¡ donde las riberas lo permit├¡an, como en la zona de Helios.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65856500, -0.88158800, '0101000020E61000003A799109F835ECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208136758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208136758.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208136758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22313, 'Pasarela Ebro 1962', 'Jos├® Antonio Duce. 1962. Imagen de la Pasarela Peatonal del Ebro. Captura de imagen desde la Margen Izquierda. En la ribera derecha, marcado contraluz para la fachada de edificios al paseo del Ebro. Entre las sombras, el dieciochesco antiguo Almac├®n de la Sal, junto a algunas otras edificaciones que siglo de las Luces, que a├▒os despu├®s terminar├¡an cayendo derrumbados por piquetas y mec├ínicos ingenios. Fuente visual: www.gozazaragoza.com/contenido.php?id=9799', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15747149020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15747149020.webp', 'https://www.flickr.com/photos/zaragozaantigua/15747149020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22356, 'El Pilar a├▒os 60', 'Foto: Colecci├│n Adolfo Mart├¡nez. Pirag├╝istas en el r├¡o Ebro, con el Pilar al fondo. Fuente: rafaelcastillejo.com', 1960, 1960, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20712101535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20712101535.webp', 'https://www.flickr.com/photos/zaragozaantigua/20712101535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22357, 'Puente Santiago 1964', 'Foto: Emilio Gil. Construcci├│n del Puente de Santiago de Zaragoza, con los restos de la estructura de la pasarela en primer plano y la Margen Izquierda al fondo. Fuente: rafaelcastillejo.com', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20715635991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20715635991.webp', 'https://www.flickr.com/photos/zaragozaantigua/20715635991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22364, 'Esqu├¡ acu├ítico c.1969', 'Postal, finales de los a├▒os 60. Vista del puente de Santiago sobre el r├¡o Ebro en Zaragoza, con baturros en primer plano y una lancha practicando esqu├¡ acu├ítico, deporte que no ha llegado a cuajar entre los tradicionales aragoneses. Fuente: www.facebook.com/photo.php?fbid=10201037600339410&set...', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21268207276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21268207276.webp', 'https://www.flickr.com/photos/zaragozaantigua/21268207276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22431, 'Vista a├®rea 1966', 'Canicular vista a├®rea centrada en la construcci├│n del nuevo puente sobre el r├¡o Ebro y la apertura en la margen izquierda de la avenida de los Pirineos como inicio de la moderna carretera hacia Huesca. En la margen derecha, aun con los derribos de viviendas de la antigua calle de Antonio P├®rez (moderna V├¡a Imperial y luego avenida de C├®sar Augusto), el tr├ínsito rodado se habr├¡a de topar, indefectiblemente, con el Mercado Central (en primer t├®rmino), construido en los albores del siglo cuando ninguna mente con visi├│n de futuro pudo siquiera so├▒ar que las necesidades de movilidad de un gran parque autom├│vil habr├¡an de requerir practicar cirug├¡a urban├¡stica radical en el casco antiguo de la ciudad. No pasar├¡an muchos a├▒os hasta que se fomentara la bochornosa campa├▒a que exig├¡a derribar el Mercado Central para dar paso a la modernidad identificada con la hegemon├¡a del veh├¡culo privado, y la adecuaci├│n viaria a sus exponenciales necesidades de espacio. Fuente: TAF Helic├▓pters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65858700, -0.88163100, '0101000020E61000000C7904375236ECBF0E492D944CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29290884717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29290884717.webp', 'https://www.flickr.com/photos/zaragozaantigua/29290884717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22434, 'Puente de Santiago 1966', 'Imagen capturada durante la construcci├│n del "Nuevo puente sobre el r├¡o Ebro" por el M.O.P., con interesante vista en la margen izquierda del barrio de la Hortilla (antes de perder la "h") y aun del de Ranillas, el ribere├▒o camping de Helios, el antiguo edificio de los "Ba├▒os del Ebro" y, sobresaliendo entre la foresta, la chimenea de la antigua "Manufacturas de lanas de Mor├│n y An├│s", en el Camino de Ranillas. Al fondo, a la izquierda, el puente del ferrocarril. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30235519295.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30235519295.webp', 'https://www.flickr.com/photos/zaragozaantigua/30235519295/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22451, 'Puente de Santiago 1966', 'Imagen, capturada desde la margen izquierda, durante la construcci├│n del nuevo puente sobre el r├¡o Ebro que sustituy├│ a la pasarela peatonal. A la izquierda, vista parcial de la obra de la piscina cubierta del Club Nataci├│n Helios, ubicada donde estuviera el antiguo edificio de los Ba├▒os del Ebro. Una interesante crecida del r├¡o pone a prueba las obras, aunque no tiene la descomunal categor├¡a de las de 1643, o 1871, entre otras cosas, por las obras de regulaci├│n en cabecera de cuenca. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31407744436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31407744436.webp', 'https://www.flickr.com/photos/zaragozaantigua/31407744436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22488, 'Puente de Santiago 1966', 'Veraniega vista panor├ímica capturada en altura y centrada en la construcci├│n del nuevo puente sobre el r├¡o Ebro que, denominado de Santiago, supuso el desmontaje de la previa pasarela peatonal de pago, la apertura para el tr├ífico rodado en la margen izquierda de la gran avenida de los Pirineos como inicio de la moderna carretera hacia Huesca, y en la margen derecha la consolidaci├│n de la avenida de C├®sar Augusto como v├¡a de alta capacidad que habr├¡a de conducir el tr├ífico, tras despejar el camino por una parte de la antigua ciudad, hasta la misma puerta del Carmen. En primer t├®rmino, la arbolada zona oriental de la gran plaza del Pilar determinada por el referencial monumento "A los h├®roes y m├írtires de Zaragoza ca├¡dos en nuestra Gloriosa Cruzada de Liberaci├│n 1936-1939", la iglesia de San Juan de los Panetes y el torre├│n de la Zuda. En la margen izquierda, la arboleda de Macanaz, el Club Nataci├│n Helios en proceso de ampliaci├│n de instalaciones, la antigua factoria "Manufacturas de lanas de Mor├│n y An├│s", el barrio de la Ortilla y el tendido del enlace ferroviario hacia Alsasua. Fuente: TAF Helic├▓pters SA, en Arxiu Nacional de Catalunya.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44125666581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44125666581.webp', 'https://www.flickr.com/photos/zaragozaantigua/44125666581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22569, 'Vista del Ebro c.1977', 'Postal. Vista a├®rea del r├¡o Ebro cruzado por el puente de Santiago, desde la margen izquierda. La masa frondosa dividida por el Segundo Cintur├│n es la Arboleda de Macanaz. A la derecha, el Club Nataci├│n Helios, con su piscina cubierta construida en 1976. Al fondo, la vieja ciudad, con el Pilar como referencia vertical. Fuente visual: www.delcampe.net/', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65910000, -0.88142000, '0101000020E61000004D4A41B79734ECBF956588635DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15295952888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15295952888.webp', 'https://www.flickr.com/photos/zaragozaantigua/15295952888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22918, 'Baturros y Pilar a├▒os 80', 'Pareja de baturros con el Pilar al fondo. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1980, 1980, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65910700, -0.87989500, '0101000020E6100000D53E1D8F1928ECBF47C8409E5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422065605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422065605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422065605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22956, 'Av. de los Pirineos 1981', 'Imagen capturada durante la salida desde Zaragoza de la antorcha que anunciaba la celebraci├│n de la Universiada de Invierno en el Pirineo Aragon├®s, en instalaciones de Formigal, Candanch├║, Ast├║n, Panticosa, y Jaca, donde se celebrar├¡an entre otros actos las ceremonias de apertura, el d├¡a 24 de febrero, y la de clausura, el 4 de marzo. El fallido Golpe de Estado del 23 de febrero estuvo a punto de hacer que se suspendiera este evento deportivo, que finalmente tuvo lugar las fechas previstas con m├ís que notable presencia de Polic├¡a, Guardia Civil, y Ej├®rcito. Este "Circo Blanco" fue el pistoletazo de salida de la carrera en pos del sue├▒o, o pesadilla, de organizar una Olimpiada de Invierno en la Jacetania, que se prolongar├í en el tiempo. Al fondo de la imagen, arboleda de Macanaz y el templo metropolitano del Pilar.', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST├ôRICO', 41.66020700, -0.88126600, '0101000020E61000009F7422C15433ECBF8ECBB8A981D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48641710017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48641710017.webp', 'https://www.flickr.com/photos/zaragozaantigua/48641710017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23818, 'Paseo del Ebro 1927', 'Marcelino Secorum, 1927. Dibujo del anteproyecto (no realizado) de embellecimiento del paseo del Ebro. Perspectiva de conjunto. Fuente: Archivo Municipal de Zaragoza.', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST├ôRICO', 41.65837200, -0.88201700, '0101000020E6100000568330B77B39ECBF124DA08845D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18650377766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18650377766.webp', 'https://www.flickr.com/photos/zaragozaantigua/18650377766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23826, 'El Pilar c.1864', 'Vista del Pilar desde la Margen Izquierda. Fuente visual: original de Ferrier et Soulier editada por J. L├®vy & C├¡a, publicada en el libro de viajes "Spain and the spaniards", Edmondo De Amicis, edici├│n 1895. ("Espa├▒a", viaje durante el reinado de Amadeo I de Saboya).', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65864200, -0.88221200, '0101000020E6100000A87004A9143BECBFD2E28C614ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20725320782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20725320782.webp', 'https://www.flickr.com/photos/zaragozaantigua/20725320782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24355, 'Barca y pasarela 1940', 'Construcci├│n de la pasarela sobre el Ebro a la altura de San Juan de los Panetes, que estar├í en servicio hasta la inauguraci├│n del puente de Santiago, en 1967. Mientras van acab├índola, la c├®lebre barca del T├¡o Toni contin├║a llevando de orilla a orilla a la gente, con su sirga. En 1935 el MOPU hab├¡a otorgado una concesi├│n para la construcci├│n de una pasarela que comunica ambas orillas del Ebro. Se construy├│ en 1940, y se abri├│ al servicio p├║blico en 1941. El proyecto fue del ingeniero Luis Fuentes L├│pez. La construcci├│n y montaje de la parte met├ílica de la pasarela se hizo por "Maquinista y Fundiciones del Ebro, S.A." Dirigi├│ la obra de f├íbrica complementaria Enrique Bressel. Funcionaba la pasarela d├¡a y noche.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65832400, -0.88150600, '0101000020E6100000F14927124C35ECBF0116F9F543D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14934310221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14934310221.webp', 'https://www.flickr.com/photos/zaragozaantigua/14934310221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24675, 'Puente Santiago c.1979', 'Un hombre pasea una mula por el puente de Santiago de Zaragoza. Al fondo, la Cruz de los Ca├¡dos, San Juan de los Panetes, el torre├│n de la Zuda y el Mercado Central. Fuente: www.facebook.com/photo.php?fbid=1578563142386483&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST├ôRICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20723475792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20723475792.webp', 'https://www.flickr.com/photos/zaragozaantigua/20723475792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24681, 'R├¡o Ebro 1872', '"R├¡o Ebro y San Juan de los Panetes", ├│leo sobre tabla, Francisco Pradilla, 1872. Vista del r├¡o Ebro desde la arboleda de Macanaz, con la silueta de San Juan de los Panetes al fondo. Fuente: Zaragoza vista por los artistas, 1908-2008.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65853000, -0.88008800, '0101000020E6100000FA43334FAE29ECBFAAB706B64AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32234419582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32234419582.webp', 'https://www.flickr.com/photos/zaragozaantigua/32234419582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24738, 'Puente de Santiago 1967', '"Gente en el reci├®n inaugurado Puente de Santiago." Aun la gente ind├¡gena, tres semanas despu├®s de su oficial inauguraci├│n, y hasta la normalizaci├│n del tr├ífico rodado a motor de explosi├│n (ese era el principal horizonte funcional del puente), se quedaba en medio un ratico "a ver si el puente aguanta". Otros, m├ís prudentes, observaban la riesgosa probanza desde la ribera. En la margen izquierda, imagen del barrio de la Hortilla, antes de perder la "h", del camping de Helios y, sobresaliendo de los ├írboles, de la chimenea de la antigua Manufacturas de lanas de Mor├│n y An├│s, en el Camino de Ranillas. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65835600, -0.88148800, '0101000020E610000058207A522635ECBF0C90680245D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181013490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181013490.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181013490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24739, 'Ba├▒os p├║blicos 1930', 'Foto colecci├│n Luis Rasal, 1930. Edificio de los ba├▒os p├║blicos de Zaragoza a orillas del Ebro (durante la riada de 1930). Situado en la actual ubicaci├│n del Club Nataci├│n Helios, en la margen izquierda. Al fondo, el Pilar. Fuente: www.facebook.com/photo.php?fbid=820302567992370&set=o...', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65915600, -0.88227400, '0101000020E61000002A8E03AF963BECBF297B4B395FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259142238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259142238.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259142238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24782, 'Camino de Ranillas 1977', 'Imagen del pluricentenario camino de Ranillas, tras el cruce de la reciente avenida de los Pirineos abierta para tr├ífico rodado. A la izquierda, prolongaci├│n de la densa arboleda de Macanaz, y muros perimetrales de las instalaciones del C.N. Helios. A la derecha, el barrio de la Ortilla. Al fondo, la huerta y soto de Ranillas. El camino de Ranillas aparece muy despejado tras el derribo de las antiguas "Manufacturas de lanas de Mor├│n y An├│s", de las que s├│lo se dej├│ en pie su estilita chimenea, ya fuera de plano, hacia la derecha, como la recientemente clausurada y desmantelada l├¡nea del ferrocarril de los Enlaces. El crecimiento urban├¡stico de la Margen Izquierda, desde la construcci├│n del puente de Santiago y la apertura de la avenida de los Pirineos, en progresi├│n geom├®trica y en unos pocos a├▒os transform├│, de forma radical, toda esta parte de la periferia rururbana de la ciudad, hasta dejarla irreconocible. Una supuesta "actuaci├│n urgente" urban├¡stica supuso la desaparici├│n de los barrios de la Ortilla, y de Ranillas. Alguna d├®cada m├ís tarde, un gran evento expositivo se termin├│ de llevar por delante la tradicional huerta. Fuente visual: amable aportaci├│n personal de Pablo Vald├®s.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.66025800, -0.88142600, '0101000020E6100000D6027B4CA434ECBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27263779605.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27263779605.webp', 'https://www.flickr.com/photos/zaragozaantigua/27263779605/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25417, 'Pasarela Ebro 1945', 'Imagen de la Pasarela Peatonal del Ebro. Se construy├│ en 1941, y comenz├│ a dar servicio en febrero de 1942, como forma de comunicar las dos riberas, entre el puente de las piedras, y el puente del ferrocarril.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15748629947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15748629947.webp', 'https://www.flickr.com/photos/zaragozaantigua/15748629947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25431, 'Pasarela de Macanaz a├▒os 40', 'Foto: Miguel Mar├¡n Chivite. Vista de la pasarela sobre el Ebro tomada desde la arboleda de Macanaz. Adem├ís del Torre├│n de la Zuda, podemos ver los edificios del paseo Echegaray y Caballero. Fuente: Archivo Heraldo de Arag├│n.', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21549406816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21549406816.webp', 'https://www.flickr.com/photos/zaragozaantigua/21549406816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25432, 'Pasarela Ebro c.1957', 'Imagen capturada en altura, desde el inmediato torre├│n de la Zuda, de la moderna pasarela peatonal para cruce en seco del r├¡o Ebro, entre la densa arboleda de Macanaz, al fondo, y la confluencia del paseo de Echegaray y Caballero y la V├¡a Imperial, antigua calle de Antonio P├®rez, en primer plano, donde la taquilla de peaje. A la izquierda, humea la chimenea fabril de "Manufacturas de lanas de Mor├│n y An├│s". Fuente visual: Teodoro Naranjo Dom├¡nguez, para ABC.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24392641973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24392641973.webp', 'https://www.flickr.com/photos/zaragozaantigua/24392641973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25443, 'Pasarela del Ebro 1945', 'Imagen con el sonriente posado de varios oficiales del ej├®rcito de tierra (posiblemente, tenientes), en la pasarela peatonal recientemente tendida sobre el Ebro. Al fondo, el Pilar, y la nov├¡sima y enorme Hospeder├¡a del Pilar, cuyas dependencias se abren a tres fachadas, y con tres patios interiores. A su izquierda, m├ís tarde, se construir├¡a el edificio de las viviendas del Cabildo, y la nueva Casa de Infantes. A la derecha, fuera de plano, la iglesia de San Juan de los Panetes, y el antiguo embarcadero que, con la entrada en servicio de la pasarela, qued├│ obsoleto. Fuente visual: www.todocoleccion.net/', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30901004865.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30901004865.webp', 'https://www.flickr.com/photos/zaragozaantigua/30901004865/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25447, 'R├¡o Ebro 1921', 'Dibujo del arquitecto Antonio Seti├®n, realizado en Hernani en 1921. Ofrece un proyecto de navegabilidad del r├¡o Ebro, con un puente colgante. A la izquierda, c├║pulas y torre del Pilar. En la margen izquierda, un gran parque en los terrenos del futuro Club de Nataci├│n Helios. Fuente visual: Revista Relieves, n├║m. 2, 1933.', 1921, 1921, 1921, 'Anos 20', 'CASCO HIST├ôRICO', 41.65843000, -0.88077700, '0101000020E61000002F35423F532FECBF475A2A6F47D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32425819744.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32425819744.webp', 'https://www.flickr.com/photos/zaragozaantigua/32425819744/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25457, 'Pasarela de Macanaz 1949', 'Dibujo incluido en un art├¡culo referido a "La arquitectura de Zaragoza en estos ├║ltimos a├▒os", y justificado por la presencia de la pasarela de Macanaz, inaugurada en 1941. Bajo ella se representa la tradicional pr├íctica del transporte de maderas por el r├¡o Ebro, si bien en esta l├ímina la conducci├│n recae en embarcaciones a motor. Esta actividad fue realizada, entre otras cosas, hasta que la construcci├│n del embalse de Yesa cerr├│ el paso a los almadieros del valle del Roncal, que hasta aqu├¡ descend├¡an sus troncos. Tras la pasarela y en la margen derecha, el templo del Pilar y la tambi├®n reciente y hom├│nima Hospeder├¡a. Al fondo, el puente de Piedra. A la izquierda y en primer t├®rmino, un par de jubilados sentados en la arboleda de Macanaz contemplan la escena.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65852500, -0.88135200, '0101000020E61000004374081C0934ECBF984C158C4AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50010448192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50010448192.webp', 'https://www.flickr.com/photos/zaragozaantigua/50010448192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25527, 'Puente de Santiago 1968', 'AHPZ. Foto Coyne. 1968. Imagen del Puente de Santiago, inaugurado en marzo de 1967. A la izquierda, Echegaray y Caballero conduce al Paso a Nivel de la Almozara, la puerta de la Qu├¡mica. A la derecha, la Margen Izquierda con Helios, y las parcelas de la Ortilla. El meandro de Ranillas, una colecci├│n de huertas.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65856500, -0.88158800, '0101000020E61000003A799109F835ECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14803772520.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14803772520.webp', 'https://www.flickr.com/photos/zaragozaantigua/14803772520/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25528, 'Pontoneros 1982', 'Pontoneros del regimiento de Monzalbarba venidos del moderno cuartel de Sangenis, junto a un pont├│n con funciones de muelle sobre el r├¡o Ebro durante una demostraci├│n con notable expectaci├│n de p├║blico. La imagen ha sido capturada dando la espalda al Club Nataci├│n Helios. A la izquierda, el puente de Santiago. Al fondo, torres de la iglesia de Santa Isabel, el colegio Valent├¡n Zabala, y varias construcciones en el entorno de la calle de Escobar, de Ab├®n Aire y de los Predicadores.', 1982, 1982, 1982, 'Anos 80', 'CASCO HIST├ôRICO', 41.65903300, -0.88172500, '0101000020E61000006519E2581737ECBF0DFE7E315BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14922153074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14922153074.webp', 'https://www.flickr.com/photos/zaragozaantigua/14922153074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25534, 'Pasarela sobre Ebro 1958', 'C├®sar Gracia Jarque. 1958. "R├¡o Ebro. La Pasarela". Imagen de la Pasarela desde la altura de la Hospeder├¡a del Pilar.', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST├ôRICO', 41.65902300, -0.88117100, '0101000020E61000002FE065868D32ECBFE9279CDD5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15936514862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15936514862.webp', 'https://www.flickr.com/photos/zaragozaantigua/15936514862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25537, 'R├¡o Ebro 1931', 'Grupo de ba├▒istas en el r├¡o Ebro a su paso por Zaragoza, en 1931. Al fondo, el Pilar. Fuente: Revista Cr├│nica. Madrid, 1931', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST├ôRICO', 41.65908400, -0.88194800, '0101000020E610000034B91803EB38ECBF8FA850DD5CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18765210669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18765210669.webp', 'https://www.flickr.com/photos/zaragozaantigua/18765210669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25543, 'Pasarela 1958', 'Pasarela peatonal tendida sobre el r├¡o Ebro en 1941, tambi├®n conocida como de Macanaz, y que supuso el final de los embarcaderos de la zona que hasta entonces se dedicaban al transporte de personas entre una y otra orilla, generalmente para acceder a la arboleda de Macanaz. Se mantuvo la navegaci├│n recreativa. Esta paralela fue desmantelada en 1967 con motivo de la construcci├│n del moderno puente de Santiago. En el Pilar, la obra de la nueva torre de San Francisco de Borja progresa m├ís r├ípido que la de Santa Leonor. Al fondo, el puente de Piedra y el de Hierro. Fuente visual: foto Jos├® Antonio Duce, en rafaelcastillejo.com', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST├ôRICO', 41.65859700, -0.88151900, '0101000020E610000019AF79556735ECBF321F10E84CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20525679189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20525679189.webp', 'https://www.flickr.com/photos/zaragozaantigua/20525679189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25570, 'R├¡o Ebro c.1931', 'Imagen capturada desde la arboleda de Macanaz y centrada en la barca del "T├¡o Toni" que con nutrida parroquia cruza el r├¡o de forma no mecanizada, a punto de llegar al embarcadero donde descender├í el pasaje venido de la margen derecha. La a├®rea sirga que posibilita la singladura aparece tendida y jalonando el recorrido. Otras embarcaciones recreativas, de menor tama├▒o, hacia el fondo del cauce fluvial. Encuadra la escena la tradicional estampa del templo del Pilar con dos torres (la de Santiago, en primer t├®rmino, y la de Nuestra se├▒ora del Pilar, junto a la c├║pula mayor)', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST├ôRICO', 41.65871900, -0.88053700, '0101000020E6100000DD5F3DEE5B2DECBF7D2079E750D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48881459702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48881459702.webp', 'https://www.flickr.com/photos/zaragozaantigua/48881459702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25576, 'Embarcadero del Ebro 1932', 'Imagen capturada en el embarcadero que en la margen izquierda y desde 1929 daba servicio al nuevo transbordo del r├¡o Ebro mediante la lancha-gasolinera "Nuestra se├▒ora del Pilar", aguas arriba del antiguo paso que mediante tradicional sirga realizaba la barca del T├¡o Toni, que en la fotograf├¡a se ve al fondo. Este nuevo servicio, asumido por Francisco S├ínchez en r├®gimen de concesi├│n, era muy apreciado por los vecinos del barrio de Macanaz y por los usuarios del Centro Deportivo "Helios". Se trata de una imagen tomada durante el viaje de bodas del autor de la misma, que en ella retrata a su esposa Emilia Marimon Rovira con el tradicional fondo edilicio de un brumoso templo del Pilar y los puentes de Piedra y de Hierro.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65911800, -0.88200600, '0101000020E61000005B069CA56439ECBF3B1A87FA5DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52993273588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52993273588.webp', 'https://www.flickr.com/photos/zaragozaantigua/52993273588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25975, 'Riada de 1961', 'Vista general de la margen izquierda durante la gran riada del Ebro de 1961. En primer plano se distinguen el edificio de los ba├▒os de las playas del Ebro y la torre de Helios. Fuente: Foto Mar├¡n Chivite. AMZ.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST├ôRICO', 41.65933400, -0.88266000, '0101000020E610000074982F2FC03EECBF0892770E65D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15134684919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15134684919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15134684919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26064, 'Vista a├®rea c.1968', 'Imagen capturada desde notable altura sobre el barrio de la Ortilla, con una interesante vista a├®rea del tramo urbano del r├¡o Ebro comprendido entre el Puente de Santiago, en primer t├®rmino, y el puente de Hierro, alcanzando incluso hasta el nuevo Puente del Ferrocarril, al fondo. A la izquierda, la feraz arboleda de Macanaz sigue delimitada en buena parte por el enlace ferroviario. A la derecha y al fondo, en el barrio de Las Fuentes comienzan a surgir tambi├®n inmuebles que rompen la tradicional barrera de las 4-5 alturas, como el que se destaca en la plaza del Monasterio de San Victori├ín. En esta perif├®rica ubicaci├│n este fen├│meno llama la atenci├│n, aunque nada comparado con los ejemplos que comenzaban a proliferar de forma salvaje en la ciudad consolidada.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65856500, -0.88030000, '0101000020E6100000CF66D5E76A2BECBF27A5A0DB4BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49223352466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49223352466.webp', 'https://www.flickr.com/photos/zaragozaantigua/49223352466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20947, 'San Juan de los Panetes 1855', 'Dibujada desde el "paseo de Macanaz", esta vista de la orilla derecha reproduce el campanario y la cabecera de la iglesia de San Juan de los Panetes, el torre├│n de la Zuda con piso a├▒adido y con un edificio de casi el mismo tama├▒o adosado a su izquierda, junto al que destaca al fondo la Torre Nueva. En la muralla al Ebro, la puerta de San Ildefonso o de la Triper├¡a. Fuente visual de la imagen: Valent├¡n Carderera, en "Viaje art├¡stico por Arag├│n de Valent├¡n Carderera", Jos├® Mar├¡a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaci├│n L├ízaro Galdiano, 2013), recopilada, editada y comentada de forma exclusiva por el Gran Archivo Zaragoza Antigua (GAZA).', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65790400, -0.88140300, '0101000020E6100000CB1473107434ECBF2CF4C13236D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15082762216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15082762216.webp', 'https://www.flickr.com/photos/zaragozaantigua/15082762216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21058, 'Torre├│n de la Zuda c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1860-1886. "Torre de la Calle de Antonio P├®rez", o Torre├│n de la Zuda (ss. I-XVI).', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866141862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866141862.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866141862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21076, 'Calle Antonio P├®rez c.1877', 'Los descartes desechados por Laurent y C├¡a para editar, al principio de la d├®cada de 1870, la producida imagen final de la "Torre de la calle de Antonio P├®rez", los reutilizamos para unos interesantes rescates visuales, incluyendo los m├írgenes marginados. A la izquierda, la nave de la nueva f├íbrica barroca de la iglesia de San Juan de los Panetes, con sus contrafuertes de apoyo a la nave central. En primer plano, los edificios a ambos lados de la calle de Antonio P├®rez, los n├║meros pares adosados a la muralla romana y al torre├│n de la Zuda (ya despejado del parasitario torre├│n que ten├¡a adosado), y los impares de la manzana de Paseo del Ebro-Antonio P├®rez-Culebra, desde donde se ha capturado la fotograf├¡a. A la derecha, torreones y remates del antiguo complejo hospitalario de la orden de San Juan, que en el momento de la captura visual era convento de las MM. Adoratrices Esclavas del Sant├¡simo Sacramento y de la Caridad. Y al fondo, la sorpresa final: emerge un pedacito del triple chapitel de la Torre Nueva. Fuente visual: Jean Laurent y C├¡a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Hist├│rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22095267584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22095267584.webp', 'https://www.flickr.com/photos/zaragozaantigua/22095267584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21186, 'La Zuda 1890', 'Imagen centrada en el antiguo torre├│n de la Zuda, integrado desde 1857 como parte del convento de la congregaci├│n de las Adoratrices Esclavas del Sant├¡simo Sacramento y de la Caridad. Delante de ├®l, vista parcial de los edificios de viviendas a ├®l adosados desde la calle de Antonio P├®rez, n├║meros 16, y 18. Fuente visual: "Torre├│n del Palacio de la Azuda", fototipia de Joarizti y Mariezcurrena, en ÔÇ£Zaragoza Art├¡stica, Monumental e Hist├│ricaÔÇØ, Anselmo y Pedro Gasc├│n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34457567312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34457567312.webp', 'https://www.flickr.com/photos/zaragozaantigua/34457567312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22548, 'Colegio Santo Domingo de Silos c.1975', 'El colegio Obra Diocesana de Santo Domingo de Silos fue inaugurado en 1959. El enorme complejo, hoy ampliado con zonas deportivas junto al Tercer Cintur├│n, est├í situado en el barrio de Las Fuentes, en la calle de la Amistad 9 (derecha de la foto a├®rea). En primer plano, la calle Fray Luis Urbano; en el lateral izquierdo, Rodrigo Rebolledo. Los edificios de la derecha, el Grupo Jos├® Antonio Gir├│n. Fuente visual: AMZ.', 1975, 1975, 1975, 'Anos 70', 'LAS FUENTES', 41.64646000, -0.85990600, '0101000020E61000002B4B74965984EBBF09168733BFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022288080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022288080.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022288080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21269, 'Ribera del Ebro 1900', 'Imagen de la habitual feria del ganado en la ribera del Ebro, desde la calle del Fin, y hasta San Juan de los Panetes (al fondo), que con motivo de las Fiestas del Pilar, convert├¡a Zaragoza en un gran mercado, o feria ganadera, con participaci├│n de bestias y personas de casi toda la ribera del Ebro, resultando un importante nivel de transacciones econ├│micas. Como suele ser norma en la vegetaci├│n de la ribera, ├®sta va y viene seg├║n tiempos, y momentos. En este caso, la feria se pudo hacer bajo la sombra del extra├▒o sol de octubre. Fuente visual: Diario "ABC".', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21637391743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21637391743.webp', 'https://www.flickr.com/photos/zaragozaantigua/21637391743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21564, 'Pilar 1929', '"Una vista de las torres del Pilar de Zaragoza", porque dos ya es plural, desde la foresta de la arboleda de Macanaz. A la derecha, el abigarrado conjunto de edificaciones entre la calle de los Agustinos, del Fin, el paseo del Ebro, y San Juan de los Panetes. Fuente visual: Ricardo Schmelz, revista "La Esfera" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22586884107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22586884107.webp', 'https://www.flickr.com/photos/zaragozaantigua/22586884107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21682, 'La Zuda 1930', 'Fotograf├¡a original de la imagen del Torre├│n de la Zuda y San Juan de los Panetes, que, coloreada, apareci├│ en la portada de la revista "Arag├│n" en mayo de ese a├▒o. Fuente visual: Archivo Juan Mora, AMZ.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877891000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877891000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877891000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21704, 'Riada de 1930', 'Gran riada en el Ebro, vista por un grupo de personas desde el paseo de la Ribera. El barrio de Ranillas, a la izquierda, inundado. Las instalaciones de la Sociedad Naturista Helios, y Macanaz, a la derecha, tambi├®n. Fuente: foto Gil Marraco, en "El Ebro desbordado: una historia de las crecidas del r├¡o en Zaragoza". Ayuntamiento de Zaragoza, 2011.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65809700, -0.88189000, '0101000020E61000000D6C95607138ECBF404CC2853CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15752575315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15752575315.webp', 'https://www.flickr.com/photos/zaragozaantigua/15752575315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21789, 'San Juan de los Panetes 1934', 'Imagen capturada durante el largo, complicado y pol├®mico proceso de transformaci├│n del antiguo, laber├¡ntico y enorme conjunto de la "iglesia de San Juan de los Panetes de la Religi├│n de San Juan de Jerusal├®n, y la Casa y Palacio de la Castellan├¡a de Amposta". En esos momentos se estaba procediendo a derribar algunas dependencias del antiguo convento, cuyas ├║ltimas inquilinas hab├¡an sido miembros de la Congregaci├│n de Adoratrices Esclavas del Sant├¡simo Sacramento y de la Caridad. El acceso a la iglesia se realizaba, bien por el peque├▒o callej├│n que desde la derecha comunicaba con la calle de los Agustinos, la plaza de Huesca, y la calle de la Zuda; o bien por otro estrecho callej├│n que comunicaba con la plaza de San Ant├│n. Fuente visual: Miguel Mar├¡n Chivite, Archivo P├║blico Municipal.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23964636033.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23964636033.webp', 'https://www.flickr.com/photos/zaragozaantigua/23964636033/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21817, 'Embarcadero del Ebro a├▒os 30', 'Foto: Miguel Mar├¡n Chivite. Vista del embarcadero con una embarcaci├│n a motor que cubr├¡a el recorrido de orilla a orilla del r├¡o Ebro. Estaba situado a la altura de la calle de Antonio P├®rez, en el desag├╝e del Mercado Central. Arriba se puede ver la sirga de las barcas de tracci├│n humana. Fuente: Heraldo de Arag├│n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65801300, -0.88124900, '0101000020E61000001C3F541A3133ECBFE2AB1DC539D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31221034973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31221034973.webp', 'https://www.flickr.com/photos/zaragozaantigua/31221034973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21901, 'San Juan de los Panetes c.1932', 'Imagen centrada en la barroca fachada y torre de la iglesia de San Juan de los Panetes durante el proceso de derribo del antiguo convento hospitalario de la castellan├¡a de Amposta donde estaba inserta. A la derecha y en la umbr├¡a, callej├│n de acceso desde la plaza de Huesca y traseras del inmueble del n┬║ 11 de la calle de la Zuda. En primer t├®rmino la chavaler├¡a juega en el talud producido durante la excavaci├│n arqueol├│gica realizada entre la iglesia y el tramo de murallas romanas de la Zuda.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65745900, -0.88155600, '0101000020E610000062F6B2EDB435ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51421564681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51421564681.webp', 'https://www.flickr.com/photos/zaragozaantigua/51421564681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23689, 'Aer├│dromo Sanjurjo 1937', 'Imagen capturada en el aer├│dromo Sanjurjo tras el ataque que la Fuerza A├®rea Republicana llev├│ a cabo el d├¡a 15 de octubre de 1937. Este "raid" estuvo protagonizado de buena madrugada por dos escuadrillas de cazas Polikarpov I-15 ("Chatos") con 21 aparatos, provenientes de Bujaraloz y Sari├▒ena, y 5 escuadrillas de Polikarpov I-16 ("Moscas") con 64 aparatos provenientes de Caspe, H├¡jar, Escatr├│n y Puig Moreno. Tras cuatro minutos de breve ataque, quedaron destruidos doce aparatos entre Ju-52 y He-46 alemanes, y Fiat CR-32 italianos, adem├ís de afectar en distinto grado a varias decenas de otros. En la imagen, tres Fiat CR-32 "Chirri" destruidos sobre la pista del aer├│dromo Sanjurjo de Zaragoza en Garrapinillos.', 1937, 1937, 1937, 'Anos 30', NULL, 41.66927300, -1.02867100, '0101000020E6100000737FF5B86F75F0BF438CD7BCAAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52037632159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52037632159.webp', 'https://www.flickr.com/photos/zaragozaantigua/52037632159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21908, 'P.┬║ del Ebro c.1934', 'Imagen capturada en el paseo del Ebro junto al embarcadero ubicado a la altura de la calle de Antonio P├®rez cuando una "canoa autom├│vil" maniobra posiblemente para dirigirse a la otra orilla del r├¡o, zona de la arboleda de Macanaz pr├│xima a la municipal Caseta de los Ba├▒os. Este servicio funcionaba en el tramo fluvial comprendido entre el puente de Piedra y el puente del ferrocarril del Norte y estaba gestionado por un grupo de barqueros entre los que se encontraba Carlos Mar Sau, hijo del famoso "T├¡o Toni", barquero que desde mediados del siglo XIX y hasta pocos a├▒os antes de esta foto hizo historia en el imaginario popular de la ciudad. Esta moderna "canoa autom├│vil" a motor, capaz de transportar hasta cien pasajeros por viaje, supuso en 1930 un gran cambio respecto a la barca que hasta entonces se desplazaba manualmente por el tradicional camino de sirga. Por ello el fot├│grafo titul├│ esta imagen, de forma algo m├ís rom├íntica, "Ferry with engine on Ebro. Formerly used current and wind" (Ferry con motor en el Ebro. Antes usaba la corriente y el viento). En primer t├®rmino, algunos espectadores contemplan desde la orilla las evoluciones de esta moderna barca motora.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65804400, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF1DAA29C93AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51745928448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51745928448.webp', 'https://www.flickr.com/photos/zaragozaantigua/51745928448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21917, 'La Zuda c.1932', 'In├®dita imagen capturada junto a la portada de la iglesia de San Juan de los Panetes tras el derribo de buena parte del complejo ocupado por la congregaci├│n de las Adoratrices hasta 1909. La fotograf├¡a se centra en el torre├│n de la Zuda con el aspecto de su cara este que, en la parte inferior y junto a la puerta que aparece "colgada" en altura tras el derribo, se intuye el vano que alberga la placa instalada en 1885 que recordaba la reparaci├│n del torre├│n acometida "a expensas de la Casa de Mar├¡a Sant├¡sima de las Desamparadas" (referencia a las Adoratrices aqu├¡ establecidas en 1857). Tras la restauraci├│n integral del torre├│n en los a├▒os 40 esta placa fue recolocada un poco m├ís hacia la esquina de la derecha, tal y como es visible desde entonces.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53241623602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53241623602.webp', 'https://www.flickr.com/photos/zaragozaantigua/53241623602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21934, 'La Zuda 1943', 'Archivo Municipal de Zaragoza. Archivo Mora "Torre├│n de la Zuda."', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST├ôRICO', 41.65749100, -0.88157200, '0101000020E6100000CE37A27BD635ECBF093543AA28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15066894912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15066894912.webp', 'https://www.flickr.com/photos/zaragozaantigua/15066894912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21943, 'Vista de Zaragoza 1940', 'Ayuntamiento de Zaragoza. Alberto Duce Baquero. 1940. Vista de Zaragoza Fuente: zaragozacool.blogspot.com.es/2010_05_01_archive.html', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65801200, -0.88167400, '0101000020E6100000DD787764AC36ECBF1230BABC39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15699718410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15699718410.webp', 'https://www.flickr.com/photos/zaragozaantigua/15699718410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21964, 'Plaza del Pilar 1949', 'Imagen de la ampliada y nueva plaza del Pilar en la zona de la antigua plaza de Huesca, despejada para ampliar la antigua plaza del Pilar, desde donde se realiza la captura, junto a uno de los ├írboles que le daban sombra. A la izquierda, el nuevo edificio para la Tienda Econ├│mica y el Convento de las Hijas de la Caridad de Santa Ana, en cuya portada se incrustar├ín los barrocos restos del ingreso al derribado Palacio de Sora. Enfrente, el "Monumento a los h├®roes y m├írtires de Zaragoza. Ca├¡dos en la Cruzada de Liberaci├│n 1936-1939", en obras desde 1946, a├║n sin la cruz que lo coronar├í. Detr├ís, la iglesia de San Juan de los Panetes, y la fachada del nuevo convento de las Hermanas Misioneras Eucar├¡sticas de Nazareth, finalizando las obras de construcci├│n. A la derecha, la Hospeder├¡a del Pilar, construida para la Sociedad Ang├®lica del Sagrado Coraz├│n de Jes├║s. Un muestrario significativo de los valores de la Nueva Espa├▒a victoriosa del comunismo. Fuente Visual: Fotos Ysa, Archivo P├║blico Municipal.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21596013953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21596013953.webp', 'https://www.flickr.com/photos/zaragozaantigua/21596013953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22035, 'San Juan de los Panetes 1941', 'In├®dita imagen capturada desde el solar que ocupara el antiguo hospital de San Juan de la Orden del Temple, centrada en la barroca iglesia de San Juan de los Panetes originalmente de la Religi├│n de San Juan de la Castellan├¡a de Amposta, tras el derribo de buena parte de los edificios que albergaron el convento de las Adoratrices aqu├¡ establecido desde 1857 y hasta 1909. Destaca el aspecto "colgado" de la iglesia tras el rebaje del solar originario para igualarlo al de la nueva gran plaza del Pilar proyectada para por la derecha llegar hasta la calle de Don Jaime I. Algo m├ís tarde aqu├¡ se instalar├¡a una escalinata de piedra para poder acceder a la iglesia desde la altura del nuevo entorno. La precariedad del estado del templo queda evidenciada por el arbolito que despunta a la derecha del remate de su fachada, mientras que la torrecilla de la derecha apenas quedaba soportada por el muro al que estaba adosada, de forma que tuvo que ser apuntalada por detr├ís. A la derecha, restos de la antigua muralla de piedra "aparecida" inopinadamente durante el derribo de las antiguas viviendas de ese lado de la calle de Antonio P├®rez, y al fondo, leve vista de uno de los postes met├ílicos que soportaban la pasarela peatonal tendida sobre el r├¡o Ebro y funcional desde el d├¡a 8 de febrero de 1941.', 1941, 1941, 1941, 'Anos 40', 'CASCO HIST├ôRICO', 41.65734600, -0.88138400, '0101000020E61000001AF7E6374C34ECBF0514EAE923D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53238458580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53238458580.webp', 'https://www.flickr.com/photos/zaragozaantigua/53238458580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22226, 'Plaza del Pilar c.1951', 'Imagen capturada desde cierta altura en la calle Imperial con vistas a la moderna plaza del Pilar. En primer t├®rmino y a la izquierda, la barroca iglesia de San Juan de los Panetes. Centran la escena las traseras del Monumento a los H├®roes y M├írtires de Nuestra Gloriosa Cruzada, flanqueado por la Hospeder├¡a del Pilar y la Tienda Econ├│mica en el Convento de las Hijas de la Caridad de Santa Ana, donde destaca la reubicada puerta principal de acceso a la derribada casa de los marqueses de Torrecilla. Al fondo y tras la cruz, andamios de obra durante la construcci├│n de la Casa del Cabildo, el Museo Catedralicio y el nuevo Colegio de los Infantes. La ampliada plaza del Pilar todav├¡a conserva el arbolado espacio que significaba la plaza del Pilar de toda la vida.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65721000, -0.88084800, '0101000020E61000007DE71725E82FECBF554D10751FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49189141817.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49189141817.webp', 'https://www.flickr.com/photos/zaragozaantigua/49189141817/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23744, 'Marlofa 1962', 'John "Ganso" Kovatch, militar del ej├®rcito de los EE.UU de Norteam├®rica destinado en la Base A├®rea de Zaragoza, haciendo turismo rural un d├¡a de permiso junto al r├│tulo de Marlofa (La Joyosa), localidad apenas distante 500 metros de Zaragoza (Villarrapa). El r├│tulo, rotulado convenientemente.', 1962, 1962, 1962, 'Anos 60', NULL, 41.73924000, -1.06816200, '0101000020E61000007C478D093117F1BF91F2936A9FDE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15211408905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15211408905.webp', 'https://www.flickr.com/photos/zaragozaantigua/15211408905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22239, 'Calle Imperial c.1951', 'Imagen capturada sobre las murallas de piedra romanas de la calle Imperial durante los trabajos de restauraci├│n y recreaci├│n de la misma. Un poco m├ís adelante, traseras de las viviendas recayentes a la plaza de san Antonio Abad, luego derribadas. A la derecha, viviendas de la antigua calle de Antonio P├®rez, m├ís tarde tambi├®n derribadas. Al fondo, el Mercado Central de Lanuza, luego propuesto para ser derribado, aunque felizmente no fue as├¡. Esta intervenci├│n reconstructora aparece delimitada por un "muro de contenci├│n" dentro del cual se obraba tambi├®n en la restauraci├│n del Torre├│n de la Zuda.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65723400, -0.88196300, '0101000020E61000008A0629780A39ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50949972821.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50949972821.webp', 'https://www.flickr.com/photos/zaragozaantigua/50949972821/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22248, 'Plaza del Pilar 1954', 'Imagen capturada en la plaza del Pilar durante la ceremonia de "consagraci├│n de Espa├▒a al inmaculado coraz├│n de Mar├¡a" realizada como culminaci├│n del Congreso Mariano celebrado en el marco de las fiestas del Pilar de ese a├▒o. Un altar fue habilitado a tal efecto en el "monumento a los H├®roes de Zaragoza de la Gloriosa Cruzada", y una vez terminada la misa el "Jefe del Estado y General├¡simo" Francisco Franco Bahamonde, de rodillas, dio lectura ante la imagen procesional en plata de la virgen del Pilar del texto por el que se consagraba a Espa├▒a "de manera solemne, oficial e irrevocable" a la referida advocaci├│n. Al fondo, la Hospeder├¡a del Pilar, junto a la que aparece una tribuna cubierta ocupada por los arzobispos y obispos de toda Espa├▒a.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65724200, -0.88094400, '0101000020E61000000470B378B130ECBF60C77F8120D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52272184910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52272184910.webp', 'https://www.flickr.com/photos/zaragozaantigua/52272184910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22271, 'La riada de 1961', 'Ayuntamiento de Zaragoza/Mar├¡n Chivite. Enero 1961. Se esperaba una crecida normalica, pero fue de a├║pa: el Ebro se hizo mar y se subi├│ hasta casi los 6,5 metros. Esta riada era solo comparable a aquella de enero de 1871, que dicen las cr├│nicas que fue la madre de todas las crecidas. Los barrios m├ís afectados fueron Ranillas, la Ortilla, Jes├║s, Arrabal. La magnitud no solo se debi├│ a la cantidad de agua que llev├│ el r├¡o (en Zaragoza se midieron m├ís de 4 millones de litros por segundo), sino tambi├®n a su permanencia: hasta el 7 de enero no se apreci├│ un decrecimiento notable. As├¡ es el Ebro, ni m├ís ni menos que un r├¡o mediterr├íneo, con un caudal de agua tan variable que la siguiente riada nos parecer├í noticia. En la imagen, la crecida que convirti├│ a la Pasarela en un ol├¡mpico trampol├¡n.', 1961, 1961, 1961, 'Anos 60', 'CASCO HIST├ôRICO', 41.65794000, -0.88119100, '0101000020E6100000F5F1D077B732ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14920612362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14920612362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14920612362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22273, 'Margen Izquierda desde El Pilar 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. "Vistas de Zaragoza desde la torre del Pilar." Panor├ímica perge├▒ada para la ocasi├│n, en una composici├│n in├®dita, democr├ítica, cient├¡fica y popular, generada en los laboratorios del', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65794000, -0.88119100, '0101000020E6100000F5F1D077B732ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940178856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940178856.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940178856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22274, 'Glorieta P├¡o XII 1960', '1960. Heraldo de Arag├│n. La Glorieta de P├¡o XII estaba situada entre el torre├│n de la Zuda y San Juan de los Panetes, en una zona con pozo ornamental (hoy en el parque Grande, junto al jard├¡n bot├ínico) y jardines. Vemos la pasarela previa al puente de Santiago, al fondo. Hoy la zona est├í arqueologizada, mostrando restos de la muralla romana.', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65759500, -0.88144400, '0101000020E61000006F2C280CCA34ECBFAE81AD122CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14948092592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14948092592.webp', 'https://www.flickr.com/photos/zaragozaantigua/14948092592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22329, 'Pl. del Pilar 1965', 'Como ven├¡a siendo tradicional-de toda la vida desde 1939, el 20-N era el d├¡a de Jos├® Antonio y de los "ca├¡dos". Por ello, desde la Jefatura Provincial del Movimiento se organiz├│ un programa de actos a tono, con un car├ícter marcadamente nacional-cat├│lico que implicaba a las organizaciones del ramo: FET y JONS, Vieja Guardia, Frente de Juventudes, Secci├│n Femenina, SEU, SEM, Asociaci├│n de ex Cautivos, Asociaci├│n de ex Combatientes. Perfectamente uniformados con su identitaria camisa azul, acudir├¡an a todos los frentes ordenados: concentraciones ante el monumento a los "ca├¡dos"; rezo del rosario; toque de silencio, oraci├│n y colocaci├│n de corona de flores; canto del "Cara al sol"; misa, y solemne funeral. En la imagen, nocturna concentraci├│n marcial del Frente de Juventudes ante el monumento a los "ca├¡dos" de la plaza del Pilar. Fue el 19 de noviembre, como antesala a lo programado para el d├¡a siguiente, desde el punto de la ma├▒ana. Mientras tanto, y en su Escuela Hogar sita en el paseo de M┬¬ Agust├¡n, la Secci├│n Femenina estaba haciendo cosas de chicas: rezar el rosario, y leyendo el testamento de Primo de Rivera. Fuente visual: Archivo Municipal. Gerardo Sancho. 1965.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18523692289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18523692289.webp', 'https://www.flickr.com/photos/zaragozaantigua/18523692289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22440, 'San Juan de los Panetes 1965', 'Imagen del entorno de la iglesia de San Juan de los Panetes, capturada desde la altura de la antigua muralla de piedra de la ciudad, con el objetivo enfocando hacia el sureste, con el Altar de la Patria del R├®gimen, y la gran plaza del Pilar, hasta la Seo, al fondo. Fuente: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30962775146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30962775146.webp', 'https://www.flickr.com/photos/zaragozaantigua/30962775146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22697, 'Glorieta de P├¡o XII c.1972', 'Seis baturros con copla alusiva a la indumentaria de ellos, junto al Torre├│n de la Zuda (izquierda). Al fondo, glorieta de P├¡o XII y arranque del Puente de Santiago. Tras la copla, espectadores. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65755400, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF4FADBEBA2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27347800801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27347800801.webp', 'https://www.flickr.com/photos/zaragozaantigua/27347800801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22707, 'La Zuda 1971', 'Calle Imperial, antigua de Antonio P├®rez y actual tramo de la avenida de C├®sar Augusto, con el renovado Torre├│n de la Zuda y el tramo reconstruido de la antigua muralla de piedra, tras la que se encuentra la iglesia de San Juan de los Panetes, cuya torre despunta m├¡nimamente a la derecha. Al fondo, el paseo de Echegaray y Caballero y la arboleda de Macanaz, ya al otro lado del r├¡o Ebro y con acceso mediante el reciente puente de Santiago.', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST├ôRICO', 41.65730800, -0.88196200, '0101000020E610000073124A5F0839ECBF18B325AB22D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27824111111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27824111111.webp', 'https://www.flickr.com/photos/zaragozaantigua/27824111111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22901, 'Plaza C├®sar Augusto 1989', 'Instant├ínea de excavaciones arqueol├│gicas en la plaza de C├®sar Augusto de Zaragoza, con el Torre├│n de la Zuda y la iglesia de San Juan de los Panetes al fondo, el 2 de marzo de 1989. Fueron hallados mosaicos romanos, como el llamado "de las Musas", sobre el que vemos a los operarios. Ese mismo a├▒o tambi├®n se hallaron y soterraron las cimentaciones de la puerta de Toledo, cerca de aqu├¡. En 1944 y en esta misma plaza apareci├│ tambi├®n una villa romana, llamada Casa de Orfeo por el importante mosaico que albergaba (www.flickr.com/photos/zaragozaantigua/19113797851). Fuente: "Memoria de las calles de Zaragoza", Juli├ín Ruiz Mar├¡n, Librer├¡a General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65725700, -0.88162100, '0101000020E610000028F04E3E3D36ECBF960854FF20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21350613044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21350613044.webp', 'https://www.flickr.com/photos/zaragozaantigua/21350613044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23098, 'Av. de C├®sar Augusto 2000', 'A├®rea visual centrada en el entorno de la Zuda y San Juan de los Panetes durante las excavaciones arqueol├│gicas realizadas a finales del pasado siglo XX en la glorieta de P├¡o XII para dejar al aire restos de la muralla romana e isl├ímica. Fuente visual: AMZ.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23894210767.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23894210767.webp', 'https://www.flickr.com/photos/zaragozaantigua/23894210767/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23105, 'Torre├│n de la Zuda 2000', 'Aspecto del acceso al Torre├│n de la Zuda en 2000, durante su restauraci├│n, que sac├│ a la luz restos de las murallas romanas bajo la glorieta de P├¡o XII. Al fondo, lienzo musealizado en los a├▒os 50 en la calle Murallas Romanas. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24349171610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24349171610.webp', 'https://www.flickr.com/photos/zaragozaantigua/24349171610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23813, 'Hospeder├¡a del Pilar 1940', 'Fase avanzada de construcci├│n de la Hospeder├¡a del Pilar, junto a la Bas├¡lica (al fondo a la derecha). Ser├í inaugurada en enero de 1941. En el horizonte, el puente de Piedra sobre el Ebro. Fuente visual: "Una mirada a trav├®s de la arquitectura: Regino y Jos├® Borobio Ojeda", Daniel Estab├®n Boldova, 2013.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST├ôRICO', 41.65743500, -0.88004100, '0101000020E6100000CD7344BE4B29ECBF751F80D426D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15726203761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15726203761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15726203761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23830, 'Paseo del Ebro 1907', 'Perspectiva del paseo del Ebro, desde las traseras del convento de San Juan de los Panetes (tras la caseta de consumos). Aqu├¡ estaba la Puerta del Fin, y el desemboque de la calle del mismo nombre, y era lugar de posadas (como la de la imagen, en el n┬║ 39, donde la acumulaci├│n de carros, recientemente proyectada por Jos├® de Yarza, y denominada "Posada de Huesca"), caballerizas, veterinarios, aperos met├ílicos, y ferias de ganado. Fuente visual: Fototeca del Patrimonio Art├¡stico (www.mcu.es/)', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21949447688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21949447688.webp', 'https://www.flickr.com/photos/zaragozaantigua/21949447688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23832, 'Calle del Fin, 1939', 'Imagen, en su ubicaci├│n original, del escudo de armas del bar├│n Don Hugo de Urri├®s y Veintemilla, un altorrelieve en piedra situado encima de la puerta de acceso a la iglesia del antiguo colegio de San Nicol├ís Tolentino, en la desaparecida calle del Fin. Tras la Desamortizaci├│n del siglo XIX, el edificio fue utilizado como almac├®n y reconvertido a casa de vecinos, y con el proyecto de la nueva y gran plaza del Pilar, el conjunto del colegio, la iglesia, y el anexo palacio de los patronos Urri├®s, fueron derribados y explanados en 1939, y sobre ellos se construyeron la nueva Hospeder├¡a para peregrinos, y la residencia del Cabildo de El Pilar, inaugurada en 1941. Seg├║n la prensa de la ├®poca, el Ayuntamiento decidi├│ preservar este escudo. Fuente visual: Juan Mora Insa, AMZ.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21953131280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21953131280.webp', 'https://www.flickr.com/photos/zaragozaantigua/21953131280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23897, 'Pl. del Pilar 1954', 'Imagen capturada durante el homenaje del Ej├®rcito espa├▒ol a la Sant├¡sima Virgen celebrado en el marco del Congreso Mariano que tuvo lugar en la ciudad en octubre de ese a├▒o. El altar de la marcial ceremonia se ubic├│ en la altura del reci├®n terminado "Monumento a los h├®roes y m├írtires de Zaragoza. Ca├¡dos en la Cruzada de Liberaci├│n 1936-1939", al oeste de la plaza del Pilar, tambi├®n denominada de las Catedrales desde que se culmin├│ "la iniciativa de derribar casas viejas y barrios enteros para conseguir esta inmensa explanada en la que pueden celebrarse concentraciones de esta importancia, teniendo como fondo las dos catedrales zaragozanas: el Pilar y La Seo" (ABC, 9 de octubre de 1954). La imagen se ha tomado, precisamente, desde el referido monumento, con el fondo doblemente catedralicio, adem├ís de los nuevos inmuebles del Gobierno Civil, y del Ayuntamiento (a├║n en construcci├│n). Fuente visual: fondo Julio S├ínchez Mill├ín, en Ministerio de Cultura y Deporte.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65720400, -0.88098600, '0101000020E6100000C07B478D0931ECBF7366BB421FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45297598391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45297598391.webp', 'https://www.flickr.com/photos/zaragozaantigua/45297598391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23958, 'Avenida C├®sar Augusto 1987', 'Cortejo mortuorio y sentada para protestar contra la reforma universitaria del PSOE, durante unas de las numerosas movilizaciones que, tras las luchas estudiantiles en Francia e Italia de finales de 1986, en confluencia con las ense├▒anzas medias, y con el respaldo del rector, Vicente Camarena, caracterizaron los primeros meses de 1987. La escena tiene lugar donde la avenida de C├®sar Augusto desemboca en el paseo de Echegaray. A la derecha, el colegio Valent├¡n Zabala. Fuente: Zaragozarebelde.org', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65761900, -0.88182300, '0101000020E61000001A8A3BDEE437ECBF361D01DC2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822243977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822243977.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822243977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23983, 'Plaza C├®sar Augusto 1987', 'Foto: ├üngel de Castro. Atentado de ETA contra un autob├║s de la Academia General Militar el 30 de enero de 1987 en la plaza C├®sar Augusto de Zaragoza. A la derecha, el Torre├│n de la Zuda y la iglesia de San Juan de los Panetes. Fuente: Heraldo de Arag├│n.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65722000, -0.88135200, '0101000020E61000004374081C0934ECBF7923F3C81FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15411932322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15411932322.webp', 'https://www.flickr.com/photos/zaragozaantigua/15411932322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23747, 'Movera 1970', 'Grupo escolar y parroquial de la iglesia de Nuestra Se├▒ora de Movera, reci├®n inaugurados, en la plaza de Espa├▒a del hom├│nimo barrio rural. Fuente visual: www.barriodemovera.es/', 1970, 1970, 1970, 'Anos 70', NULL, 41.64952200, -0.82180900, '0101000020E6100000F0DE5163424CEABF2904728923D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15500088328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15500088328.webp', 'https://www.flickr.com/photos/zaragozaantigua/15500088328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24078, 'Puente de Santiago 1967', 'Imagen capturada durante la inauguraci├│n oficial del Puente de Santiago (13 de marzo) y centrada en el carrion├®s arzobispo de Zaragoza, Excelent├¡simo y Reverend├¡simo Se├▒or Pedro Cantero Cuadrado, cuando proced├¡a a rociar con agua bendita al nuevo nexo de uni├│n entre ambas riberas del r├¡o Ebro que sustituy├│ a la peatonal pasarela en servicio desde los a├▒os cuarenta. Mediante este sencillo acto el puente qued├│ exortizado, purificado y pleno de gracia santificante. Tras el arzobispo complementan el cortejo inaugural diversas autoridades militares y civiles. Al fondo, legi├│n de parroquianos que observan atentamente el ceremonial desde la elevada replaceta junto a la barroca iglesia de San Juan de los Panetes. Unos meses despu├®s, Pedro Cantero Cuadrado ser├¡a designado procurador en las Cortes Espa├▒olas por el Jefe del Estado, Francisco Franco Bahamonde. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38431721346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38431721346.webp', 'https://www.flickr.com/photos/zaragozaantigua/38431721346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24344, 'S. Juan de los Panetes 1930', '"Iglesia de San Juan. La Torre". La nueva fabrica de la antigua iglesia templaria de San Juan, en el primer cuarto del siglo XVIII, supuso la reorientaci├│n de su planta, la construcci├│n de su caracter├¡stica torrecilla, y de un arco de acceso a la parroquia, denominado de San Juan, desde la calle de los Agustinos. En la imagen, el arco presenta en su parte superior una hornacida votiva barroca. La di├ífana y soleada plaza de Huesca, previa al arco, era consecuencia del derribo de la antigua manzana de edificios entre las calles de Agustinos, Danzas, y San Juan de los Panetes.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65733800, -0.88108900, '0101000020E6100000E6B0FB8EE131ECBF8335CEA623D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688645699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688645699.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688645699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24354, 'Labordeta 1986', 'Foto: Rogelio Allepuz, febrero de 1986. Jos├® Antonio Labordeta posa ante la iglesia de San Juan de los Panetes de Zaragoza. Fuente: El Peri├│dico de Arag├│n', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST├ôRICO', 41.65730100, -0.88100600, '0101000020E6100000868DB27E3331ECBF65506D7022D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914840931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914840931.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914840931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24360, 'San Juan de los Panetes 1933', 'Entorno de la iglesia de San Juan de los Panetes en diciembre de 1933, tras el incendio provocado en su interior durante unos disturbios. Las tropas del Ej├®rcito de la Rep├║blica, desplegadas, montan guardia para prevenci├│n de nuevos atentados. Fuente visual: Heraldo de Arag├│n', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65729700, -0.88130000, '0101000020E6100000A4DFBE0E9C33ECBF2461DF4E22D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000690245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000690245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000690245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24364, 'Pilar y Panetes c.1915', 'AHPZ. Juan Mora Insa. SF "Zaragoza. Vista del Pilar por la ribera." Ribera derecha, con las traseras de San Juan de los Panetes detr├ís del ├írbol en primer├¡simo plano. Un par de carros aparcados, y un paisano buscando gamusinos.', 1915, 1915, 1915, 'Anos 10', 'CASCO HIST├ôRICO', 41.65792400, -0.88119100, '0101000020E6100000F5F1D077B732ECBF73A087DA36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15174618346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15174618346.webp', 'https://www.flickr.com/photos/zaragozaantigua/15174618346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24366, 'Puerta de San Ildefonso c.1900', '"Puerta de San Ildefonso", Antonio Callaved, 2010. Puerta de San Ildefonso o de la Triper├¡a, construida en ladrillo y abierta al paseo de la Ribera, en la zona de San Juan de los Panetes (izquierda) y el Torre├│n de la Zuda (a su derecha). Derribada en 1904. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65774400, -0.88172000, '0101000020E6100000F35487DC0C37ECBFF39194F430D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15275841691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15275841691.webp', 'https://www.flickr.com/photos/zaragozaantigua/15275841691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24373, 'San Juan de los Panetes a├▒os 30', 'Aspecto de la calle Agustinos, conducente al acceso a la iglesia parroquial de San Juan de los Panetes. Fuente visual: Ascensi├│n Hern├índez Mart├¡nez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15686649272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15686649272.webp', 'https://www.flickr.com/photos/zaragozaantigua/15686649272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24377, 'San Juan de los Panetes 1930', 'A mediados del siglo XIX comenz├│ un largo, complejo y discutido proceso de transformaci├│n del antiguo y enorme conjunto de la "iglesia de San Juan de los Panetes de la Religi├│n de San Juan de Jerusal├®n, y la Casa y Palacio de la Castellan├¡a de Amposta". La imagen captura la portada y torre de la iglesia resultantes de la nueva f├íbrica de 1720. En esos momentos se estaba procediendo a derribar algunas de las dependencias del antiguo convento, utilizado en ├║ltima instancia por la Congregaci├│n de Adoratrices Esclavas del Sant├¡simo Sacramento y de la Caridad. El acceso a la iglesia est├í al mismo nivel que la calle, y se accede por el peque├▒o callej├│n de la imagen, desde la calle de los Agustinos, y tambi├®n desde la plaza de San Ant├│n, fuera de plano, y a la derecha. Tras d├®cadas de actuaciones, al final la iglesia qued├│ exenta y elevada respecto del terreno que la rodea, el Torre├│n de la Sudda fue reinventado, y volvieron a ver la luz tres torreones y un buen pedazo de la antigua muralla romana, tanto la original, como la a├▒adida en el siglo III de la era.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19442963681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19442963681.webp', 'https://www.flickr.com/photos/zaragozaantigua/19442963681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24386, 'San Juan de los Panetes 1972', 'Torre├│n de la Zuda e iglesia de San Juan de los Panetes. Al fondo, el antiguo colegio Valent├¡n Zabala. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23146350105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23146350105.webp', 'https://www.flickr.com/photos/zaragozaantigua/23146350105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24390, 'San Juan de los Panetes a├▒os 30', 'Portada y torre de la iglesia de San Juan de los Panetes, desde las ruinas de las casas adosadas a las murallas romanas. Fuente: www.skyscrapercity.com/', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24759743661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24759743661.webp', 'https://www.flickr.com/photos/zaragozaantigua/24759743661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24411, 'San Juan de los Panetes a├▒os 30', 'Acuarela de Ambrosio Ruste representando la portada de la iglesia de San Juan de los Panetes. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65746300, -0.88131100, '0101000020E61000009E5C5320B333ECBF3FAA61BF27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32317797271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32317797271.webp', 'https://www.flickr.com/photos/zaragozaantigua/32317797271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24412, 'Plaza de Huesca a├▒os 30', 'Acuarela de Ambrosio Ruste, que muestra la torre de San Juan de los Panetes desde la plaza de Huesca, y el arco de San Juan. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32399025396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32399025396.webp', 'https://www.flickr.com/photos/zaragozaantigua/32399025396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24661, 'Torre├│n de la Zuda 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Noviembre 1972. El Torre├│n de la Zuda se levant├│ sobre la torre del homenaje del alc├ízar palacio de La Sudda, La Zuda o Azuda, construido a su vez sobre uno de los torreones de la muralla romana. La Sudda fue la residencia fortificada de los gobernadores musulmanes de la taifa de Sarakusta, hasta que trasladaron su residencia oficial al palacio de la Aljafer├¡a. Tras la conquista cristina, fue residencia de los monarcas aragoneses hasta el siglo XIII, en que tambi├®n se orientaron hacia la Aljafer├¡a. El torre├│n fue reedificado en la segunda mitad del siglo XVI. La imagen actual del torre├│n responde a la restauraci├│n llevada a cabo por Francisco I├▒iguez entre 1946 y 1952, quien dio prioridad a las formas renacentistas sobre las anteriores, en coherencia con la l├¡nea historicista-regionalista de la arquitectura del R├®gimen franquista en esos momentos. En la imagen de conjunto, el Torre├│n, las murallas romanas, y el pozo que en la pen├║ltima intervenci├│n fue llevado al Parque Grande.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65739300, -0.88151400, '0101000020E6100000A7EA1ED95C35ECBF46CF2D7425D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710521427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710521427.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710521427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24662, 'Puerta de San Ildefonso 1904', 'Colecci├│n Rafael Esteban. Foto: Agust├¡n Esteban, 1904. Vista cercana de la puerta de San Ildefonso o de la Triper├¡a, tomada desde la calle de este nombre, a la orilla del Ebro. Hacia dentro, la calle Antonio P├®rez hacia el Mercado, con el torre├│n de la Zuda arriba a la izquierda. La puerta ser├¡a derribada ese mismo a├▒o. En la puerta, un azulejo advierte que "EN ESTA CIUDAD NO SE TOLERA LA MENDICIDAD NI LA BLASFEMIA". Dicho queda.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65779400, -0.88163500, '0101000020E61000006649809A5A36ECBFA5C0029832D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919914990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919914990.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919914990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24664, 'Embarcadero del Ebro c.1925', 'Imagen de las escaleras de acceso al servicio de barca que en este tramo del r├¡o permit├¡a su paso. Al fondo, San Juan de los Panetes, el torre├│n de la Zuda, la calle de Antonio P├®rez conducente al Mercado Central, y el colegio Valent├¡n Zabala. Fuente visual: Archivo Coyne, en "El Ebro y sus riberas", Ayuntamiento de Zaragoza.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65800400, -0.88137300, '0101000020E6100000207A52263534ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15121638044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15121638044.webp', 'https://www.flickr.com/photos/zaragozaantigua/15121638044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24665, 'San Juan de los Panetes 1927', '"Rodio" (Luis Pablo Sanz Lafita) dibuja con trazos modernos y atinados una visual de San Juan de los Panetes desde la inmediata ribera del Ebro, y la acompa├▒a de un ├írbol retorcido, una anciana crepuscular, un viejo "Ford", y un carro a la funerala. Hay nubes, sombras y claros para una composici├│n propia de un d├¡a de difuntos, tanto para los que ya lo son, como para los que lo seremos. Fuente visual: "Arag├│n : revista gr├ífica de cultura aragonesa" (A├▒o III, N┬║ 20, mayo 1927).', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST├ôRICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480634399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480634399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480634399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24666, 'La Zuda 1987', 'Luis M├¡nguez. 1987. Desde el Torre├│n de la Zuda, un vistazo al Suroeste, siguiendo la Avenida de C├®sar Augusto, por encima de los cubos ultrasemicirculares de la Murallas Romanas del s.III, la antigua plaza de Lanuza, el Mercado Central, hasta llegar a la c├║pula de Santiago el Mayor, al fondo. A su derecha, la iglesia de los Escolapios. Hegemon├¡a espacial del tr├ífico rodado, en movimiento, y aparcado. Solares en barbecho.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15667970199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15667970199.webp', 'https://www.flickr.com/photos/zaragozaantigua/15667970199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24667, 'Plaza de Huesca 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antigua plaza Huesca ante la iglesia de San Juan de los Panetes". La plaza de Huesca era una placica al lado de la plaza del Pilar, entre las calles de la Zuda (izquierda), de la Regla (donde los adoquines), de Agustinos (enfrente a ├®sta), y del Fin (derecha). Esta ├║ltima comunicaba, por medio de un antiguo trenque, con el paseo de la ribera. Al fondo, otra puerta daba entrada al recinto donde se levantaba San Juan de los Panetes. La clase social que aqu├¡ viv├¡a era sustancialmente diferente a la de la vecina plaza del Pilar, como reflejan los tipos y situaciones que la imagen captura, impensables apenas 100 metros hacia la derecha, en el "sal├│n de la ciudad". Es uno de esos d├¡as en que la sombra apetece m├ís que la solana, y un cabrero orde├▒a a una chiva del reba├▒o, mientras unos chavales callejean a su gusto. Estos ├írboles no eran tampoco como los de la plaza del Pilar. Fuente visual: "Miguel y Gabriel Faci. Fot├│grafos fundadores de la Real Sociedad Fotogr├ífica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci├│n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15789998832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15789998832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15789998832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24669, 'Murallas romanas 1987', 'Luis M├¡nguez. 1987. Desde un ├│culo de la octogonal, barroca, inclinada y enladrillada torre de San Juan de los Panetes, una ins├│lita mirada sobre el entorno. Inmediato, el incontingente aparcamiento. A la izquierda, el salvado Mercado Central. Enfrente, los recios lienzos de la muralla de piedra, y el vac├¡o dejado en su pedestal por el casi semoviente C├®sar Augusto primaportado y mussol├¡niano. Al fondo, la rotunda fachada de la original "Poblaci├│n" (San Pablo), y su inmemorial acceso por la calle de Predicadores. Plagado de publicidad comercial, un enorme solar esquinado a la avenida y a la calle Ben Aire, en modo espera.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65723400, -0.88186700, '0101000020E6100000027E8D244138ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15834431621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15834431621.webp', 'https://www.flickr.com/photos/zaragozaantigua/15834431621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24670, 'San Juan de los Panetes 1927', 'Imagen a cierta altura de la octogonal y barroca torre de San Juan de los Panetes, emergente en el entorno de callejas y recovecos que caracterizaba esta zonba, junto a la plaza de Huesca, desde la que se acced├¡a por la calle de Agustinos (izquierda), tras cruzar un peque├▒o arco de medio punto. Esta torre se apoyaba en construcciones que se le hab├¡an ido anexando en el transcurso de los siglos. La imagen est├í tomada, precisamente, desde la altura de una de estas viviendas, la n┬║ 35 recayente al paseo del Ebro. A la derecha destaca por su altura el tejado a doble vertiente de la nave central de la iglesia, y algunos de sus contrafuertes de refuerzo. Enfrente, viviendas del n┬║ 11 de la calle de La Zuda y dependencias del, hasta hace poco, antiguo convento de las Adoratrices. El Torre├│n de la Zuda queda un poco hacia la derecha, y, como las murallas romanas, rodeado de un compost de edificaciones. Cuando unos a├▒os despu├®s, se inicien obras para abrir calles y despejar la zona, la torre presentar├í graves problemas de estabilidad por la merma de sus tradicionales apoyos. El Ayuntamiento del momento estaba decidido a su derribo para construir un mercado en el lugar, pero mientras tanto, se proclam├│ la Segunda Rep├║blica, y el nuevo Gobierno declar├│ el templo como Monumento Nacional. Fuente visual: Instituto Amatller de Arte Hisp├ínico (Arxiu Mas). Fuente textual: Ascensi├│n Hern├índez Mart├¡nez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15893540992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15893540992.webp', 'https://www.flickr.com/photos/zaragozaantigua/15893540992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24105, 'Jard├¡n de Invierno 1960', 'Imagen capturada en el "auditorium" (sic) del Jard├¡n de Invierno en el parque de Primo de Rivera durante la solemne celebraci├│n del aniversario 55 de la "coronaci├│n can├│nica de la Virgen del Pilar" que, a iniciativa del Ayuntamiento, consisti├│ en una misa con rito pontifical oficiada por el arzobispo Casimiro Morcillo. Al fondo, escenario donde se instal├│ el altar con la imagen procesional en plata de la Virgen, y una gran cruz de cinco metros de altura iluminada por reflectores que presid├¡a la ceremonia. A la derecha, banderas de Acci├│n Cat├│lica, y a la izquierda, representaci├│n de seminaristas. Sobre el firme, espacio para el p├║blico asistente, al frente del cual se colocaron bancos para las autoridades (entre ellas la Corporaci├│n municipal encabezada por el alcalde Luis G├│mez Laguna; la Corporaci├│n provincial con el presidente Antonio Zubiri Vidal; el gobernador civil y jefe provincial del "Movimiento" Jos├® Manuel Pardo de Santayana; y autoridades militares encabezadas por el capit├ín general Manuel Baturone Colombo), adem├ís de mil sillas de pago. Este evento comenz├│ a las 20:00h. y termin├│ a las 22:00h. del d├¡a 20 de mayo de ese a├▒o.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63175500, -0.89290700, '0101000020E6100000B7D26BB3B192ECBFD00A0C59DDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51653859433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51653859433.webp', 'https://www.flickr.com/photos/zaragozaantigua/51653859433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24671, 'Paseo del Ebro c.1900', 'Tener el Pilar a las espaldas, tras el Callej├│n del Retiro Alto, tampoco es mala cosa a la hora de capturar instant├íneas en Zaragoza, en este caso, desde altura, y mirando hacia el Puente del Ferrocarril (al fondo). A la derecha, Macanaz-Ranillas, con un brazal de la acequia de Juslibol desaguando al Ebro. En el despejado Paseo, una unidad de la L├¡nea de Circunvalaci├│n, a propulsi├│n de sangre, dirigi├®ndose hacia la mitad de su periplo a lo S├¡sifo. Un jinete solitario completa el tr├ífico rodado en velocidad. A la izquierda, junto a la Puerta del Fin, un destacado concesionario de ├®quidos, mulos, y carros, con alto y animado volumen comercial. Al otro lado de la calle del Fin, el entramado de calles que configura las traseras de la plaza de Huesca: Agustinos, de la Regla, de la Zuda, de las Flores... un espacio urbano complejo e irrepetible, con elementos desaparecidos, como el Colegio de los Agustinos Descalzos de San Nicol├ís de Tolentino, la iglesia de San Ant├│n, el Hospital de San Juan de los Panetes... adem├ís de todas las casas donde los prostituidores desfog├íbanse a sus anchas, a cambio de unos dineros, en otro tipo de comercio de la carne. Superviven la reorientada, modificada y barroca torre e iglesia de San Juan de los Panetes, y el torre├│n de la Zuda, que sobresale tras la iglesia, por encima de vestigios de muralla romana. Fuente visual: AHPZ, Archivo Coyne, ca. 1900', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16451696592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16451696592.webp', 'https://www.flickr.com/photos/zaragozaantigua/16451696592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24672, 'Plaza del Mercado 1975', 'Desde el Torre├│n de la Zuda, vista de la plaza de Lanuza. Estamos en la linde entre la parroquia del Pilar, a la izquierda, y la de San Pablo, a la derecha. Al fondo, la c├║pula de Santiago el Mayor y siluetas de los monstruos edilicios que van surgiendo como edificios singulares y actuaciones aisladas. En primer t├®rmino, las murallas romanas, seguidas del Mercado Central, y de la manzana entre las calles de Cerd├ín y de las Escuelas P├¡as.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST├ôRICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19025863396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19025863396.webp', 'https://www.flickr.com/photos/zaragozaantigua/19025863396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24673, 'Puerta del Fin 1922', 'Dibujo de D├¡az Dom├¡nguez del rinc├│n del paseo del Ebro de Zaragoza a la altura de la calle del Fin (tras la garita del fielato). Esta calle era uno de los accesos a la ciudad, cerrado con su puerta, que daba nombre a toda la explanada, utilizada como feria del ganado. El edificio donde se encuentra el negocio del veterinario Remacha hab├¡a sido Colegio de los Agustinos, vulgo Agustinicos. Al fondo, la torreta de la c├║pula de San Juan de los Panetes. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057942382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057942382.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057942382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24674, 'San Juan de los Panetes 1988', 'Foto Eduardo Zamarripa, 1988. Vista a├®rea del torre├│n de la Zuda y la iglesia de San Juan de los Panetes de Zaragoza en 1988. Fuente: Arag├│n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CASCO HIST├ôRICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20325163741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20325163741.webp', 'https://www.flickr.com/photos/zaragozaantigua/20325163741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24677, 'Paseo del Ebro 1926', 'Imagen del paseo del Ebro en la zona cercana a las traseras del convento de San Juan de los Panetes, entre las calles de Antonio P├®rez, y la del Fin, con notable proliferaci├│n de caballer├¡as y carros. Despunta la linterna y el ├íbside principal de la barroca iglesia de San Juan. Al fondo, el chafl├ín del colegio Valent├¡n Zabala. Fuente visual: Miguel Mar├¡n Chivite, AMZ', 1926, 1926, 1926, 'Anos 20', 'CASCO HIST├ôRICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24505950831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24505950831.webp', 'https://www.flickr.com/photos/zaragozaantigua/24505950831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24679, 'Cruz de los ca├¡dos 1971', 'Foto: I├▒aki Urbez. Vista de la Cruz de los ca├¡dos y el entorno de San Juan de los Panetes, desde la torre de San Francisco de Borja del Pilar. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST├ôRICO', 41.65726000, -0.88086300, '0101000020E6100000D234289A0730ECBF077C7E1821D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29653584062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29653584062.webp', 'https://www.flickr.com/photos/zaragozaantigua/29653584062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24680, 'San Juan de los Panetes c.1925', 'Imagen capturada desde la margen izquierda del r├¡o Ebro, en la arboleda de Macanaz, frente a la iglesia de San Juan de los Panetes y la embocadura a la calle de Antonio P├®rez. A la derecha, asoma levemente el torre├│n de la Zuda. Destacan las escaleras de acceso a las barcas que daban servicio de paso en este tramo del r├¡o. El gran agujero abovedado en el pretil recuerda el antiguo desag├╝e que aqu├¡ vert├¡a desde la antigua plaza del Mercado. Fuente: fotograf├¡a de Claudi Carbonell Flo, en www.museunacional.cat/', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30134489963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30134489963.webp', 'https://www.flickr.com/photos/zaragozaantigua/30134489963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24683, 'La Zuda 1882', 'Grabado con dise├▒o de Bernardo Rico, basado en una fotograf├¡a de Jean Laurent capturada en la calle de Antonio P├®rez, y titulado "Zaragoza.-El torre├│n de la Azuda donde se firm├│ la rendici├│n de la ciudad ├í Don Alfonso I ┬½El Batallador┬╗ (1118)". Fuente visual: La Ilustraci├│n espa├▒ola y americana (1882)', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34638029461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34638029461.webp', 'https://www.flickr.com/photos/zaragozaantigua/34638029461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24685, 'Torre├│n de la Zuda 1890', '"Torre├│n del Palacio Real de la Azuda donde, al tomar Zaragoza, se aposent├│ Alfonso el Batallador". Ilustraci├│n de Ambrosio del Ruste, 1948, basada en una fotograf├¡a de 1890. Fuente: "Conquista de Zaragoza por Don Alfonso I el Batallador", La Cadiera, 1948.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65756000, -0.88163100, '0101000020E61000000C7904375236ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41407425642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41407425642.webp', 'https://www.flickr.com/photos/zaragozaantigua/41407425642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24686, 'Murallas romanas ca. 2005', 'Vista desde el torre├│n de la Zuda de los restos de las murallas romanas, con la calle hom├│nima a la izquierda y la avenida de C├®sar Augusto a la derecha. Se est├í procediendo a su restauraci├│n, que incluye la retirada del pedestal con dos columnas que sostuvo la estatua de C├®sar Augusto. Entre 2012 y 2013, esta zona se ver├í modificada por el paso del tranv├¡a y la retirada de los arcos "Alegor├¡a de la Puerta de la Paz", entre las murallas y el Mercado Central. Al fondo, la c├║pula de la iglesia de Santiago el Mayor. Fuente: Archivo Antonio Tausiet.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41597324550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41597324550.webp', 'https://www.flickr.com/photos/zaragozaantigua/41597324550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24687, 'Plaza de Huesca 1914', 'Foto: Serrano Sancho. "Hundimiento de una casa en Zaragoza. Estado en que qued├│ la casa de la plaza de Huesca que se derrumb├│ el mi├®rcoles ├║ltimo", 28 de enero de 1914. Al fondo, la c├║pula de la torre de San Juan de los Panetes. Fuente: Diario ABC, 31-1-1914.', 1914, 1914, 1914, 'Anos 10', 'CASCO HIST├ôRICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43256261372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43256261372.webp', 'https://www.flickr.com/photos/zaragozaantigua/43256261372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24688, 'Avenida de C├®sar Augusto 1999', 'La avenida de C├®sar Augusto, en su tramo adyacente a las Murallas Romanas, entre el paseo de Echegaray y Caballero y el Mercado Central. A la izquierda, el Torre├│n de la Zuda, y tras el lienzo de muralla, la iglesia de San Juan de los Panetes. Este entorno, olivos incluidos, ser├í trocado en otro distinto con el paso de la nueva l├¡nea de tranv├¡a en 2013.', 1999, 1999, 1999, 'Anos 90', 'CASCO HIST├ôRICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50210619061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50210619061.webp', 'https://www.flickr.com/photos/zaragozaantigua/50210619061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24689, 'San Juan de los Panetes 1990', 'En el proyecto de rehabilitaci├│n y embellecimiento de la plaza del Pilar, cuyas obras comenzaron tras las Fiestas del Pilar de 1990, estaba incluido el desmantelamiento del "Monumento a los h├®roes y m├írtires de Zaragoza ca├¡dos en la Cruzada de Liberaci├│n 1936-1939", que ser├¡a trasladado al cementerio cat├│lico de Torrero y sustituido por una fuente alusiva a la "Hispanidad". En la imagen, montaje de los andamios previo al desmontaje de este monumental cenotafio terminado en 1954, quince a├▒os despu├®s del oficial final de la guerra, como muestra de que el r├®gimen franquista no pasaba p├ígina ni a sus or├¡genes ni a sus s├¡mbolos fundacionales, ni a la memoria de sus muertos. Este tr├ínsito edilicio apenas suscit├│ pol├®mica o resiliencia social.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65725800, -0.88091200, '0101000020E61000002DEDD45C6E30ECBF6684B70721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50374895517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50374895517.webp', 'https://www.flickr.com/photos/zaragozaantigua/50374895517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23749, 'Torre de Santa Engracia 1972', 'Torre de Santa Engracia era una finca del barrio rural de Movera que fue adquirida en 1970 por el Ayuntamiento, mediante permuta con la papelera La Monta├▒anesa. El edificio responde a la tipolog├¡a de las agr├¡colas torres de la periferia de Zaragoza, y est├í datada en el siglo XVII, cuando era propiedad del monasterio de Santa Engracia. En el siglo XIX fue desamortizada y muy modificada. Desde 2015 acoge a la Escuela Agr├¡cola Municipal Km 0.', 1972, 1972, 1972, 'Anos 70', NULL, 41.64234700, -0.80543500, '0101000020E610000067B8019F1FC6E9BF84D72E6D38D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15795238915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15795238915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15795238915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24692, 'Torre├│n de la Zuda c.1885', 'Imagen capturada desde la altura del inmueble del n┬║ 25 de la calle de Antonio P├®rez y centrada en el Torre├│n de la Zuda reci├®n restaurado y al que se ha incorporado una nueva cubierta a cuatro aguas proyectada por el arquitecto municipal Ricardo Magdalena. Este torre├│n despunta de las instalaciones del antiguo palacio de la Castellan├¡a de Amposta de san Juan de Jerusal├®n, desde unos pocos a├▒os antes convertido en convento de las Madres Adoratrices, y con varias casas adosadas recayentes al lado de los pares de la calle de Antonio P├®rez. Tras el torre├│n y a la izquierda aparece la iglesia de san Juan de los Panetes, y a la derecha la antigua torre inacabada de Santiago del templo del Pilar. M├ís al fondo, la barroca torre de la Seo.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52286836398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52286836398.webp', 'https://www.flickr.com/photos/zaragozaantigua/52286836398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24865, 'P.┬║ del Ebro 1929', 'Imagen centrada en el antiguo paseo del Ebro, en la zona comprendida entre la calle del Fin y la iglesia de San Juan de los Panetes, al fondo, con el firme pendiente de embellecimiento, y notable tr├ífico de veh├¡culos tirados por caballer├¡a. Este tramo de la antigua l├¡nea tranviaria de Circunvalaci├│n estaba suprimido desde 1925, cuando entr├│ en servicio la l├¡nea del Ayuntamiento. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65750100, -0.87988100, '0101000020E610000097E5EB32FC27ECBF2D0B26FE28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35307218056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35307218056.webp', 'https://www.flickr.com/photos/zaragozaantigua/35307218056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25131, 'Calle del Fin a├▒os 30', 'Acuarela de Ambrosio Ruste. Portada de la iglesia del antiguo Convento y colegio de San Nicol├ís de Tolentino de los Agustinos, situado en la calle del Fin, uno de los postigos abiertos en la antigua muralla romana, que anteriormente fue conocido como "Postigo de Montaner", y luego "de la madera", por el tr├ífago de este material desde la ribera del Ebro hacia el interior de la ciudad. Este colegio fue abierto en 1605, y ten├¡a una peque├▒a iglesia que conectaba con el inmediato palacio de los Ayerbe, sus grandes financiadores. El colegio dio nombre ("Agustinos") a la calle que desde la plaza del Pilar conduc├¡a a San Juan de los Panetes. Como todas las dem├ís construcciones de la zona, fueran palacios, colegios, o sencillas viviendas, fue arrasado cuando la plaza del Pilar fue retro-evolucionada del barroco, al nacional-catolicismo. En la imagen, la sencilla portada de la iglesia del colegio-convento. Destaca el escudo nobiliario en altorrelieve del bar├│n don Hugo de Urri├®s y su mujer, do├▒a Beatriz de Cardona y Requesens, patrocinadores del colegio. Por la izquierda se acced├¡a a la "puerta del Fin" que daba acceso al paseo de la ribera. Por la derecha, a la calle Agustinos. Fuente visual: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18546963160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18546963160.webp', 'https://www.flickr.com/photos/zaragozaantigua/18546963160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25153, 'Torre├│n de la Zuda a├▒os 30', 'Acuarela de Ambrosio Ruste representando el torre├│n de la Zuda, con la iglesia de San Juan de los Panetes a la derecha. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627244013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627244013.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627244013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25406, 'Pasarela sobre el Ebro c.1945', 'Aguas arriba del puente de Piedra, estuvo en servicio esta pasarela peatonal sobre el Ebro, con taquillas en ambos m├írgenes, desde el 25 de febrero de 1941 hasta la inauguraci├│n del puente de Santiago en 1967. Conocida como pasarela de Macanaz.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65787500, -0.88078600, '0101000020E6100000FBC9181F662FECBF91ED7C3F35D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14899757335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14899757335.webp', 'https://www.flickr.com/photos/zaragozaantigua/14899757335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25419, 'Echegaray y Caballero 1956', 'Foto Jos├® Antonio Duce, 1956. D├¡a de niebla en el Paseo de Echegaray y Caballero de Zaragoza, junto al Ebro, a la altura de la pasarela de Macanaz (al fondo). Fuente: www.rafaelcastillejo.com/zaraduce.htm', 1956, 1956, 1956, 'Anos 50', 'CASCO HIST├ôRICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15842183336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15842183336.webp', 'https://www.flickr.com/photos/zaragozaantigua/15842183336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25453, 'Pasarela de Macanaz 1950', 'Imagen estival centrada en la pasarela peatonal tendida sobre el r├¡o Ebro en 1941, tambi├®n conocida como de Macanaz, flanqueada por los escalonados descensos hacia los embarcaderos, y con una vista del antiguo colector de la Triper├¡a. La escena se ha capturado desde uno de los embarcaderos recreativos de la Margen Izquierda. El fondo edilicio viene determinado por el templo del Pilar con sus dos torres, como desde principios de siglo, la gran Hospeder├¡a del Pilar de la Sociedad Ang├®lica del Sagrado Coraz├│n de Jes├║s, el nuevo convento de las Hermanas Misioneras Eucar├¡sticas de Nazareth, adosado a la iglesia de San Juan de los Panetes, y el Grupo Escolar de Valent├¡n Zabala, sobre el que emerge el Torre├│n de la Zuda. Fuente visual: AMZ', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST├ôRICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39994558783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39994558783.webp', 'https://www.flickr.com/photos/zaragozaantigua/39994558783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25554, 'Puente de Santiago 2012', 'Obras para la segunda fase de la l├¡nea 1 del tranv├¡a, a su paso por el puente de Santiago. Al fondo, la margen izquierda del Ebro. Fuente: www.skyscrapercity.com/', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65821000, -0.88163300, '0101000020E61000003961C2685636ECBF38F3AB3940D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24825966856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24825966856.webp', 'https://www.flickr.com/photos/zaragozaantigua/24825966856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20894, 'Puerto fluvial siglo I', 'Maqueta del edificio de acceso del puerto fluvial de Caesaraugusta, siglo I. Al derribar las casas de la plaza de San Bruno en 1989 para construir las actuales viviendas de protecci├│n oficial, se descubrieron los vestigios de una edificaci├│n al nordeste del foro. Consta de una serie de vanos pertenecientes a una fachada de arquer├¡as orientada hacia el r├¡o Ebro, por las que se alcanzaba un vest├¡bulo y desde ├®ste una escalinata que comunicaba los muelles del puerto fluvial con la plaza del foro. Hoy es un museo visitable, en la plaza de San Bruno 8. Fuente: www.zaragoza.es/ciudad/museos/es/puerto', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19783359583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19783359583.webp', 'https://www.flickr.com/photos/zaragozaantigua/19783359583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20895, 'Puerto fluvial 1989', 'Estructura del puerto fluvial romano del siglo I en el entorno de la plaza de San Bruno de Zaragoza. Al fondo, la calle Arcedianos. Fuente: dp-foto.blogspot.com', 1989, 1989, 1989, 'Anos 80', 'CASCO HIST├ôRICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20082409184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20082409184.webp', 'https://www.flickr.com/photos/zaragozaantigua/20082409184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20903, 'Puerto fluvial siglo I', 'Recreaci├│n infogr├ífica del puerto fluvial de Caesaraugusta y su entorno junto al r├¡o Ebro. A la derecha, el puente romano. Tras el gran edificio del puerto, el foro con su templo.', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65592200, -0.87462000, '0101000020E61000003EAE0D15E3FCEBBF0B5D8940F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54170714151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54170714151.webp', 'https://www.flickr.com/photos/zaragozaantigua/54170714151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20925, 'Casa Diputados Reino 1539', 'Dibujo de Valent├¡n Carderera y Solano, del "patinejo" de la antigua Casa hospedaje de los Diputados del Reino de Arag├│n, en la calle del General del Reino, un palacio del siglo XVI demolido parcialmente en 1863-64, cuando el patio fue desmontado, y completamente en la d├®cada de los a├▒os 40 del siglo XX, cuando el entorno de la Seo, como la calle de Palafox, fue "reordenado". Este palacio hab├¡a sido adquirido como residencia de los Diputados del Reino que no viv├¡an en Zaragoza, mientras su estancia en la ciudad. El dibujo est├í tomado al natural, y datado en torno a 1860, poco antes del desmontaje del patio, aunque el autor parece situarlo en "1539", fecha de la talla del patio por Ren├® Trayanus, introduciendo para ambientar dos ficcionados personajes de esa ├®poca. Cuatro columnas, cuatro pilastras, y algunos fragmentos del arquitrabe, en alabastro ensuciado, perduran en el Museo de Zaragoza, recompuestos desordenadamente. Fuente visual: ceres.mcu.es/', 1539, 1539, 1539, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357296016.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357296016.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357296016/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20943, 'Monasterio de Santo Sepulcro 1855', '"Muralla romana y monasterio del Santo Sepulcro de Zaragoza." 28 de mayo 1855. Fuente visual: "Viaje art├¡stico por Arag├│n de Valent├¡n Carderera", Jos├® Mar├¡a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaci├│n L├ízaro Galdiano, 2013.', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65424600, -0.87208200, '0101000020E6100000CAC4AD8218E8EBBFF8C43A55BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14868828807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14868828807.webp', 'https://www.flickr.com/photos/zaragozaantigua/14868828807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20985, 'Puente de Tablas 1803', '"Plan y elevaci├│n general y perfiles por mayor del puente de madera proyectado sobre el r├¡o Ebro en el mismo sitio que estaba el antiguo para paso de la carretera real de Madrid a Barcelona", Fernando Mart├¡nez Corc├¡n, Zaragoza, 13 de junio de 1803. La avenida del Ebro del 10 de junio de 1801 da├▒├│ por en├®sima vez el Puente de Tablas de Zaragoza, que hab├¡a sido reconstruido tras la riada del 23 de junio de 1775. En 1803 se proyecta de nuevo, aprob├índose la obra al a├▒o siguiente, aunque no se llev├│ a cabo. En 1895 se inaugur├│ en sus inmediaciones el Puente del Pilar o de Hierro. Fuente visual: Fondo del Intendente. Secci├│n de Obras Municipales. Diputaci├│n Provincial de Zaragoza.', 1803, 1803, 1803, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65580700, -0.87212500, '0101000020E61000009CC420B072E8EBBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24088066161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24088066161.webp', 'https://www.flickr.com/photos/zaragozaantigua/24088066161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21057, 'Vista desde Altab├ís c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1872-1879. Vista general de la ribera derecha, desde la Iglesia de Altab├ís, trozo 1.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65567900, -0.87385200, '0101000020E6100000056A317898F6EBBF45D61A4AEDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14865823302.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14865823302.webp', 'https://www.flickr.com/photos/zaragozaantigua/14865823302/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21105, 'San Nicol├ís 1889', '"Saragosse. ├ëglise St-Nicolas". Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22104618133.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22104618133.webp', 'https://www.flickr.com/photos/zaragozaantigua/22104618133/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21170, 'Puente de Hierro 1894', 'Para aligerar al puente de Piedra de una parte de su tr├ínsito, y dar nuevo paso a la carretera de Madrid a Francia por la Junquera, en 1877 fue aprobada la construcci├│n de un nuevo puente sobre el Ebro. Dise├▒ado por el ingeniero Antonio Fern├índez de Navarrete, y tras un dilatado proceso de construcci├│n que comenz├│ en 1887, fue inaugurado en octubre de 1895 con el nombre de "puente de Nuestra Se├▒ora del Pilar". En la imagen, captura de las obras de este nuevo puente de Hierro, con el Pilar y el paseo del Ebro a la izquierda, el puente de Piedra detr├ís, y la arboleda y lavaderos de la calle de Jes├║s a la derecha, en la margen izquierda. Fuente visual: Archivo Coyne, en "Zaragoza. Dos milenios de agua", Carlos Bl├ízquez, 2006.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29292358483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29292358483.webp', 'https://www.flickr.com/photos/zaragozaantigua/29292358483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21195, 'Paseo del Ebro c.1893', 'Imagen capturada posiblemente desde la estructura en construcci├│n del nuevo puente sobre el r├¡o Ebro que con la denominaci├│n de puente de N┬¬ S┬¬ del Pilar, fue iniciado en 1887 e inaugurado en 1895. Con el fondo edilicio del barrio de La Seo y el paseo del Ebro, destaca en primer t├®rmino y a la izquierda, el estribo sure├▒o del antiguo puente de Tablas o Madera. Tras ├®l, el emboque con la calle del Conde de Alperche. Hacia la derecha, del caser├¡o emerge el cimborrio y la torre de la Seo, seguido a continuaci├│n por el Palacio Arzobispal y el Seminario Conciliar de San Valero y de San Braulio.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65539000, -0.87388500, '0101000020E6100000F4E0EEACDDF6EBBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50639375491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50639375491.webp', 'https://www.flickr.com/photos/zaragozaantigua/50639375491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21419, 'Convento de Jes├║s c.1910', 'Imagen centrada en el puente nuevo, de N┬¬ S┬¬ del Pilar, o de Hierro, capturada desde la margen derecha del Ebro. Al fondo, la torre del antiguo convento franciscano de N┬¬ S┬¬ de Jes├║s. En beneficio de todos, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65562800, -0.87081800, '0101000020E61000008194D8B5BDDDEBBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30950627624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30950627624.webp', 'https://www.flickr.com/photos/zaragozaantigua/30950627624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21475, 'Calle Palafox 1929', 'Imagen de la calle de Palafox desde la calle del Chantre, tras el derribo del antiguo edificio de la Aduana Vieja, o Casa de los Diputados del Reino. A la izquierda, el antiguo palacio de los Laz├ín. Al fondo, la catedral de la Seo. Justo enfrente, las casas del cabildo que fueran del Arcediano de Belchite, con la fachada que daba a la plazuela de la Aduana, desde donde se acced├¡a al derribado edificio. Esta demolici├│n permiti├│ realinear ese lado de la calle Palafox, retranque├índola y haci├®ndola m├ís ancha, y sobre el solar se construir├í inmediatamente el Grupo Escolar Marcelino L├│pez Ornat. Fuente visual: Archivo Jos├® Galiay (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65403600, -0.87439400, '0101000020E61000002B323A2009FBEBBF0D349F73B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700854338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700854338.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700854338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21477, 'Calle Sepulcro 1925', 'Foto Roisin, 1925. Toma de la torre de la Seo desde la confluencia de la calle del Sepulcro con el callej├│n de Ezmir, con su palacio hom├│nimo, de Esmir o de los marqueses de Almonacid, a la derecha.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65464000, -0.87397100, '0101000020E610000098E0D40792F7EBBFA453573ECBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14798514377.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14798514377.webp', 'https://www.flickr.com/photos/zaragozaantigua/14798514377/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21480, 'Aduana Vieja 1929', 'Imagen de la Plaza o Plazuela de la Aduana, a la izquierda, y la portada de ingreso a la "Aduana Vieja", antigua Casa de hospedaje de la Diputaci├│n del Reino para diputados foranos de Zaragoza. La callecita de la derecha, antigua del "General del Reino", luego "Palafox", conectaba esta plaza con la Plaza del Reino, y la calle del Chantre, al fondo de la imagen. A la derecha, fuera de plano, el Palacio del Marqu├®s de Laz├ín. Esta imagen est├í datada oficialmente en 1949, aunque es improbable que esa sea la fecha: en 1929 se acometieron obras para una nueva alineaci├│n de la calle Palafox (ensanchamiento), y de un a├▒o despu├®s (1930) es el proyecto de Marcelino Carqu├® para el nuevo "Grupo Escolar Marcelino L├│pez Ornat", escuela municipal levantada en la esquina de Palafox con la calle del Chantre (luego San Vicente de Pa├║l), ocupando todo el espacio del muro de la imagen, el solar del antigua Aduana, y la mayor parte de la plazuela. La imagen parece realizada, por todo ello, en el tiempo de otras im├ígenes de esta zona (Julio Requejo, Miguel Faci, Ant├│nio Passaporte). Fuente visual: Archivo Mora. Ayuntamiento de Zaragoza. "Antigua Aduana. Calle de Palafox".', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65399600, -0.87433500, '0101000020E6100000EDF0D7648DFAEBBF7FDB1324B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957567152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957567152.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957567152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21481, 'Antigua Aduana 1929', '"Portada Antigua Aduana. Calle de Palafox". Antigua Casa de los Diputados (foranos) del Reino, frente al Palacio de Palafox, que queda a su derecha. Fuente visual: Ayuntamiento de Zaragoza/Archivo Mora.', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65402800, -0.87437300, '0101000020E61000004D2CF015DDFAEBBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958019132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958019132.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958019132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21538, 'Paseo del Ebro 1922', 'Dibujo de D├¡az Dom├¡nguez del paseo del Ebro a la altura del Palacio Arzobispal (derecha). Al fondo, la Seo. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65552600, -0.87444400, '0101000020E61000009CDEC5FB71FBEBBFBFD6A546E8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19870797930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19870797930.webp', 'https://www.flickr.com/photos/zaragozaantigua/19870797930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21543, 'Soto del Ca├▒ar 1925', 'Zaragoza desde el soto del Ca├▒ar, Lucien Roisin, 1925. Vista de Zaragoza desde el soto del Ca├▒ar, con el puente del Pilar o de Hierro al fondo. Se pueden ver las torres de San Nicol├ís, la Seo (bajo la cual, los restos del estribo derecho del puente de Tablas) y el Pilar. Fuente: "Zaragoza, a├▒os veinte. 81 fotograf├¡as de Roisin (1925-1931)", Instituci├│n Fernando el Cat├│lico, 2014.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65567700, -0.86822200, '0101000020E6100000E65DF58079C8EBBFA4DE5339EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20095777311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20095777311.webp', 'https://www.flickr.com/photos/zaragozaantigua/20095777311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21558, 'Aduana Vieja 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antiguo edificio de la Aduana, en la plaza del Reino" (sic). Imagen de la Plaza o Plazuela de la Aduana, a la izquierda, y la portada de ingreso a la "Aduana Vieja", antigua Casa de hospedaje de la Diputaci├│n del Reino para diputados foranos de Zaragoza, y luego pluriempleada como almac├®n, ret├®n militar, y aun de bomberos. La callecita de la derecha, antigua del "General del Reino", luego "Palafox", conectaba esta plaza con la Plaza del Reino, y la calle del Chantre, al fondo de la imagen. A la derecha, fuera de plano, el Palacio del Marqu├®s de Laz├ín. Las caballer├¡as son dirigidas hacia la doble plaza de San Bruno. Unos pocos a├▒os despu├®s (1929-30) este edificio ser├í derribado para ensanchar la calle, y construir sobre su solar el nuevo "Grupo Escolar Marcelino L├│pez Ornat". Fuente visual: Fuente visual: "Miguel y Gabriel Faci. Fot├│grafos fundadores de la Real Sociedad Fotogr├ífica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci├│n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21768175313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21768175313.webp', 'https://www.flickr.com/photos/zaragozaantigua/21768175313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21570, 'Calle de Pallaruelo, c.1929', '"Zaragoza. Calle del Pallazuelo." (sic) La antigua e irregular calle de Pallaruelo, en el barrio del Boter├│n, ven├¡a a ser la natural continuidad de la calle de Gav├¡n, pasada la del Sepulcro, si bien terminaba en un fondo de saco sin conexi├│n directa con el paseo del Ebro. Para salir de ella hab├¡a que tomar la calleja del Retiro y enlazar con la del Garro para desembocar en la del Conde Alperche, que s├¡ ten├¡a salida a la ribera. La otra opci├│n era volverse por donde se hab├¡a entrado. El nombre de Pallaruelo, antes Bual, le fue dado por el paisano que, enriquecido tras la batalla de Zaragoza de 1710, mediante el despojo de cuanto cad├íver se le puso por delante, pudo comprarse una casa en esta c├®ntrica zona de la ciudad. Esta calle perdur├│, en forma y fondo, hasta que la remodelaci├│n de la zona supuso su alineamiento ortogonal y apertura por Echegaray y Caballero. Entonces, fue redenominada "Boter├│n". En la imagen, vista de la calle desde su entrada por la del Sepulcro. Al fondo, hacia la izquierda, el fondo de saco de su final, y la conexi├│n con la calle del Retiro. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65444700, -0.87320800, '0101000020E6100000D06053E751F1EBBF8FFB56EBC4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23785233172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23785233172.webp', 'https://www.flickr.com/photos/zaragozaantigua/23785233172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21572, 'Calle de Monserrate c.1929', '"Zaragoza. Calle de Monserrate." La antigua calle de Monserrate recib├¡a ese nombre por el importante postigo del mismo nombre que se abr├¡a a la ribera y daba conexi├│n con la calle del Sepulcro. De traza irregular, era "paralela" a la calle de Pallaruelo, y presentaba un peculiar ensanchamiento denominado "del Lobo". Esta calle perdur├│ hasta que la reordenaci├│n urban├¡stica de la zona supuso su desaparici├│n. En la imagen, vista de la calle desde su estrecha entrada por la del Sepulcro. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST├ôRICO', 41.65426200, -0.87295000, '0101000020E6100000E561A1D634EFEBBFFE8172DBBED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23867860796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23867860796.webp', 'https://www.flickr.com/photos/zaragozaantigua/23867860796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21602, 'Puente de Hierro c.1920', 'Imagen del puente sobre el r├¡o Ebro levantado en 1895 donde, aproximadamente, estuviera el antiguo puente de Tablas. Fue realizado en materiales mucho m├ís perdurables que las antiguas versiones en madera, siempre a merced de los desmadres de un r├¡o natural. Como no pod├¡a ser de otra forma en esta ciudad, recibi├│ la corporativa denominaci├│n de "N┬¬ S┬¬ del Pilar", si bien el com├║n se refiere a ├®l con m├ís utilitarismo: es el puente "de Hierro", para diferenciarlo del "de Piedra" caracole├▒a. En la imagen, capturada desde la margen izquierda, el puente queda contrastado por el modesto fondo de la antigua parroquia de San Nicol├ís (con detalle de la sede de la Cruz Roja), y la barriada de las Ta├▒er├¡as. En el centro, despuntan la torre de San Nicol├ís y, por un capricho visual, la de la Magdalena. Fuente visual: Archivo Coyne, en "Zaragoza dos milenios de agua", Carlos Bl├ízquez.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26255917471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26255917471.webp', 'https://www.flickr.com/photos/zaragozaantigua/26255917471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21632, 'Calle Sepulcro 1922', 'Dibujo de D├¡az Dom├¡nguez de la calle del Sepulcro en 1922, con la torre de la Seo al fondo y el palacio de Esmir a la derecha. Fuente: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65471400, -0.87396000, '0101000020E61000009D6340F67AF7EBBFDE1D19ABCDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42289443685.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42289443685.webp', 'https://www.flickr.com/photos/zaragozaantigua/42289443685/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21913, 'Calle del Sepulcro 1932', 'Imagen capturada en el tramo de la calle del Sepulcro que se ensanchaba de forma notable junto a la casa de los Esmir, cuya fachada queda a la derecha. Al fondo emerge la gran torre barroca de la Seo.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65496600, -0.87414200, '0101000020E6100000C8EBC1A4F8F8EBBFF8FE06EDD5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52507636009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52507636009.webp', 'https://www.flickr.com/photos/zaragozaantigua/52507636009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21950, 'Calle de Arcedianos 1949', 'Irrepetible captura de la antigua calle de Arcedianos, cuando a├║n era reflejo de la abigarrada calleja que conectaba la doble plaza de San Bruno con la calle del Chantre. La calle del Chantre (a la derecha) ya no exist├¡a, pues hab├¡a sido sustituida por un moderno vial para veh├¡culos (San Vicente de Pa├║l), mas a├║n quedaban en pie los edificios de la calle, con trazas desde del siglo XVI en adelante, que culminaban, casi tocando a la sacrist├¡a de la Seo (al fondo), en la antigua Hospeder├¡a de la Cartuja de la Concepci├│n, cuya imagen de San Bruno, en una hornacina sobre la puerta, daba nombre a la irregular plaza del mismo nombre. La desconsideraci├│n para con el patrimonio que no fue afectado por los dos sitios de 1808-1809, convirti├│ en potencial carne de derribo a todo aquel edificio que no tuviera incrustada una bala francesa (o espa├▒ola, qu├® m├ís da), como es el caso. Nada queda de esta vista, salvo la Seo, al fondo, y una plaza de San Bruno endurecida, recrecida y convertida en ocasional mercado y escenario de conciertos. Fuente visual: Archivo Municipal, Archivo Mora, 1949.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65461300, -0.87459300, '0101000020E6100000D8EF8975AAFCEBBFAA44D95BCAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18557291260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18557291260.webp', 'https://www.flickr.com/photos/zaragozaantigua/18557291260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21985, 'Calle Sepulcro C.1949', 'Dibujo de Esteban representando la calle del Sepulcro, con el palacio de Esmir a la derecha y la torre de la Seo al fondo. Fuente: www.facebook.com/photo.php?fbid=1156035214477222&set=...', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29122370861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29122370861.webp', 'https://www.flickr.com/photos/zaragozaantigua/29122370861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22038, 'Muralla ind├¡gena 1990', 'Muralla ind├¡gena de Salduie, aparecida en 1990 en la excavaci├│n de la calle del Sepulcro 1 -15, solar del antiguo palacio de Esmir, en el entorno de la plaza de San Bruno correspondiente a los aleda├▒os noroccidentales de la plaza porticada identificada con el posterior foro comercial romano. Se conservan 34 metros de longitud y 1 metro de altura. Es de yeso alabastrino y tiene una orientaci├│n este-oeste, paralela al curso del Ebro, del que dista ocho metros. Forma parte del lienzo norte de la muralla de Salduie, resultando uno de los hallazgos m├ís importantes de la arqueolog├¡a zaragozana. Al fondo, el palacio Arzobispal. Fuente visual: Zaragoza. prehistoria y arqueolog├¡a. Ayuntamiento de Zaragoza, 1991.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65525400, -0.87461400, '0101000020E6100000B6F5D37FD6FCEBBF5E49F25CDFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14971051956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14971051956.webp', 'https://www.flickr.com/photos/zaragozaantigua/14971051956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22067, 'Maderas Nicol├ís Hermanos 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Puente del Pilar." El negocio de maderas para la construcci├│n de la empresa "Nicol├ís Hermanos" arranca en la d├®cada de los 80 del XIX. En 1900 construyeron sus propios locales en el Paseo del Ebro n┬║ 70 (Barrio de las Tener├¡as), en un solar contiguo al nuevo puente de hierro del Pilar, que inauguraron en 1901. La nueva planta se compon├¡a de dos naves y un notable edificio destinado a vivienda y oficinas. El cartel anunciador informaba "Maderas y serrer├¡a Nicol├ís Hermanos". All├¡ estuvieron hasta que la f├íbrica fue piqueteada. Al fondo, el puente de Hierro. En el suelo, los ra├¡les de la l├¡nea de tranv├¡a del G├íllego, hacia el puente, con la derivaci├│n hacia la izquierda de la L├¡nea de Circunvalaci├│n. En primer plano, el edificio central de la f├íbrica, muy pr├│ximo a la plaza de Tener├¡as.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65379500, -0.87158900, '0101000020E6100000FEB4519D0EE4EBBFE8A4F78DAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085373488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085373488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085373488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22077, 'San Nicol├ís a├▒os 50', 'Archivo Municipal. Gerardo Sancho Ramo. A├▒os 50. Plazuela de San Nicol├ís, con la iglesia de San Nicol├ís de Bari, en la calle del Sepulcro.', 1950, 1950, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15688929496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15688929496.webp', 'https://www.flickr.com/photos/zaragozaantigua/15688929496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22084, 'Plazuela de San Nicol├ís c.1950', 'Plazuela de San Nicol├ís con imagen de la fachada y torrecilla campanario de la barroca iglesia de San Nicol├ís de Bari, junto al convento de las Madres Comendadoras Canonesas Regulares del Santo Sepulcro. Un rinc├│n de la antigua Zaragoza que perdura, salvo las viviendas de la izquierda, desaparecidas en reformas posteriores. Fuente visual: Archivo Coyne, AHPZ.', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST├ôRICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16331827354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16331827354.webp', 'https://www.flickr.com/photos/zaragozaantigua/16331827354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22227, 'R├¡o Ebro 1954', 'Imagen capturada desde el Puente de Hierro y centrada en la inmediata ribera de la margen derecha del r├¡o Ebro. En primer t├®rmino destacan los restos del antiguo estribo sur del Puente de Tablas (desaparecido definitivamente durante la riada de 1801). Por encima emerge la barroca torre y el cimborrio mud├®jar de la catedral del Salvador en su Epifan├¡a. En el centro de la escena, los dos torreones del Palacio Arzobispal, la estructura en obras de la nueva Casa Consistorial, y el templo del Pilar, con las dos torres ribere├▒as en construcci├│n. Hacia la derecha, el Puente de Piedra, sobre el que transita un tranv├¡a de la serie de los 40 en servicio en la l├¡nea 9. G├íllego, antes de ser sustituida por una nueva l├¡nea de trolebuses; a su izquierda, una composici├│n motor+remolque de la serie 100 de la tranviaria l├¡nea 10. Academia.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST├ôRICO', 41.65595200, -0.87218900, '0101000020E61000004BCADDE7F8E8EBBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49300702786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49300702786.webp', 'https://www.flickr.com/photos/zaragozaantigua/49300702786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22300, 'Arco del De├ín 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1968. Aprovechando el derribo de un edificio anexo a las dependencias arzobispales de la calle De├ín, y al que tambi├®n se pod├¡a acceder por un a├®reo pasaje, se tom├│ esta imagen del Arco y Casa del De├ín de la Seo (restaurados la d├®cada anterior) desde una perspectiva interesante. Al fondo, la esquina de la calle de Palafox.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546947427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546947427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546947427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22420, 'Coso Bajo 1967', 'Imagen capturada en el tramo final del Coso Bajo, junto a las Tener├¡as, durante el paso de la banda de m├║sica de la 8.┬¬ Divisi├│n de Infanter├¡a del ej├®rcito de los Estados Unidos de Am├®rica del Norte, que participar├¡a en las Fiestas de Primavera de ese a├▒o. Esta unidad militar, estacionada habitualmente en territorio de la Rep├║blica Federal de Alemania, recay├│ temporalmente en Zaragoza por su participaci├│n en las maniobras conjuntas con el ej├®rcito espa├▒ol denominadas Pathfinder Express, desarrolladas en diversas localizaciones de Zaragoza, Calatayud y Daroca, y en las que la base a├®rea de Valenzuela tuvo un papel fundamental. La Pathfinder Express se basaba en el supuesto de que la naci├│n imaginaria de "Iberia" era invadida por una "Rep├║blica Agresora", de forma que el Gobierno de Iberia ped├¡a apoyo militar al Gobierno de "Iberia occidental", que se lo conced├¡a para repeler la agresi├│n. El General Mayor Cassidy, comandante de la 8.┬¬ Divisi├│n de infanter├¡a norteamericana participante en esa operaci├│n, hab├¡a desembarcado en 1944 en Normand├¡a como miembro de la 101.┬¬ divisi├│n aerotransportada para luchar contra los nazis. El Capit├ín General Mu├▒oz Grandes, asistente a estas maniobras en su calidad de vicepresidente del Gobierno espa├▒ol, luc├¡a la Cruz de Caballero de la Cruz de Hierro con hojas de roble que le fue concedida personalmente por Adolf Hitler por comandar la Divisi├│n Azul part├¡cipe de la agresi├│n nazi a la URSS. En la imagen, a la izquierda, las traseras del Real Monasterio de Comendadoras Canonesas de la Orden Militar y Pontificia del Santo Sepulcro, integrado en un pa├▒o de las antiguas murallas de piedra de la ciudad. Sobre el firme, rieles de la antigua l├¡nea tranviaria 12 Barrio de Jes├║s. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65413700, -0.87187000, '0101000020E6100000F5A10BEA5BE6EBBF410DDFC2BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26741753949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26741753949.webp', 'https://www.flickr.com/photos/zaragozaantigua/26741753949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22514, 'Puente de Hierro c.1965', 'Imagen capturada junto al cuartel de automovilismo de las Tener├¡as. Al fondo, el puente de N┬¬ S┬¬ del Pilar, sobre el que se dispone a cruzar una motocicleta. Destaca el tendido tranviario tambi├®n utilizado por trolebuses.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65417200, -0.87151400, '0101000020E61000005532005471E3EBBFBEFA78E8BBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51356559226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51356559226.webp', 'https://www.flickr.com/photos/zaragozaantigua/51356559226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22680, 'Puente de Hierro 1970', 'Imagen capturada desde el Puente de Hierro durante las obras de restauraci├│n de su desgastado firme, que aqu├¡ se muestra transparente y produce vertiginosas sensaciones, tal que si de un felino caminando sobre un cristal se tratase. Al fondo, entre, y sobre, la met├ílica barandilla, las instalaciones fabriles de una familiar e influyente empresa local de colchones, en el barrio de Jes├║s, unos a├▒os antes de trasladarse a la carretera de Logro├▒o. Bajo del puente, un Ebro de aguas tranquilas fluye presocr├íticamente hacia el Mediterr├íneo. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.13 Sobre 118267', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65628200, -0.87028900, '0101000020E61000008331225168D9EBBF0B7A6F0C01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26311542452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26311542452.webp', 'https://www.flickr.com/photos/zaragozaantigua/26311542452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22725, 'Puente de Hierro 1972', 'Foto centrada en la unidad 201 de la l├¡nea 35 de los autobuses urbanos, "Ver├│nica-Arrabal". Est├í circulando por el puente del Pilar o de Hierro, en direcci├│n a la margen izquierda. Fuente: Colecci├│n Daniel Andr├®s.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65562800, -0.87081800, '0101000020E61000008194D8B5BDDDEBBFC32B499EEBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30552364404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30552364404.webp', 'https://www.flickr.com/photos/zaragozaantigua/30552364404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22793, 'Calle del Sepulcro c.1978', 'Vista de los grandes solares resultantes de los derribos realizados la d├®cada anterior en el entorno de la calle del Sepulcro, del palacio Arzobispal (a la derecha, con la fachada en reformas) y de la peque├▒a plaza de San Bruno (a la izquierda, inmediata a la Seo). El solar de la derecha es el de la antigua y gran casa de los Esmir, y el de la izquierda el que en tiempos albergara el hospicio de la Cartuja de la Concepci├│n y la carnicer├¡a del Cabildo. La imagen ha sido capturada posiblemente desde la altura del n┬║ 49 de la calle de San Vicente de Pa├║l. De fondo esc├®nico, la iglesia metropolitana del Salvador en su Epifan├¡a. Tras ella, despuntan hitos verticales como la c├║pula del Banco Zaragozano, la torre de San Gil, el Edificio Ebrosa, la torre de San Pablo y las de Santa Isabel. A la derecha, la torre de Nuestra Se├▒ora del Pilar del hom├│nimo templo.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST├ôRICO', 41.65509600, -0.87481700, '0101000020E6100000BE839F3880FEEBBFC6DE8B2FDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41676464952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41676464952.webp', 'https://www.flickr.com/photos/zaragozaantigua/41676464952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23003, 'R├¡o Ebro a├▒os 90', 'Vista del r├¡o Ebro a su paso por Zaragoza. En primer t├®rmino, puente de Piedra y torre noreste del Pilar. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1990, 1990, 1999, 'Anos 90', 'CASCO HIST├ôRICO', 41.65639800, -0.87268500, '0101000020E61000005BB6D61709EDEBBF759483D904D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27385635046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27385635046.webp', 'https://www.flickr.com/photos/zaragozaantigua/27385635046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23209, 'Puente de Hierro 2010', 'Foto: Carlos Monc├¡n. Mayo de 2010. Obras de restauraci├│n y cambio de color del puente de Nuestra Se├▒ora del Pilar, vulgo de Hierro. El "verde tradicional" que hab├¡a sustituido en los a├▒os setenta al gris, se troc├│ por el azul y blanco, tras una consulta populista. Fuente: Heraldo de Arag├│n.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65577200, -0.87071100, '0101000020E6100000008FA850DDDCEBBFF6D03E56F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33225069960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33225069960.webp', 'https://www.flickr.com/photos/zaragozaantigua/33225069960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23437, 'Aduana Vieja 1922', 'Fachada del edificio donde estaba ubicado el primer ret├®n de Bomberos de Zaragoza, en la plazuela de la Aduana, junto a la calle de Palafox. La antigua Casa de los Diputados del Reino fue construida en el siglo XVI por Marcos de Ma├▒aria, y comprada en 1590 para estancia temporal en Zaragoza de los diputados no residentes. En el siglo XIX, ya propiedad del Ayuntamiento pas├│ a denominarse Aduana Vieja, con usos varios, incluyendo alojamiento de un ret├®n militar, dep├│sito municipal, c├írcel y cuartelillo, y ret├®n de bomberos. Un acta municipal de 1862 indica que el edificio est├í en ruina, y al a├▒o siguiente el ret├®n de bomberos es desalojado. En 1863-64 el edificio es parcialmente derribado, y el resto perdura hasta la reordenaci├│n de la calle a finales de la d├®cada de los a├▒os 20, y principios de la de los 30. Quedan restos del patio interior, recompuestos en desordenado tetris, en el Museo de Zaragoza. Fuente visual: Julio Requejo.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65399100, -0.87437800, '0101000020E6100000BFF04A92E7FAEBBF6D7022FAB5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14771318117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14771318117.webp', 'https://www.flickr.com/photos/zaragozaantigua/14771318117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23445, 'Plaza del Reino 1930', 'Ayuntamiento de Zaragoza/Archivo Mora, 1930 Sede de la Real Sociedad Econ├│mica Aragonesa de Amigos del Pa├¡s, en la plaza del Reino 5 de Zaragoza. De 1876 a 1905, sede tambi├®n de la Caja de Ahorros de Zaragoza. En esa misma plaza se encontraban adem├ís la Real Academia de Nobles y bellas Artes de San Luis (1792) y el Seminario de Pobres de San Francisco de Paula (1886).', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65401300, -0.87439500, '0101000020E6100000422619390BFBEBBF5514AFB2B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14982089722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14982089722.webp', 'https://www.flickr.com/photos/zaragozaantigua/14982089722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23472, 'Aduana Vieja a├▒os 30', 'Acuarela de Ambrosio Ruste identificada como "palacio de Palafox". Muestra el palacio de la Aduana Vieja, en la plazuela de la Aduana. A la derecha, antigua calle del General del Reino, luego Palafox. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65448500, -0.87478600, '0101000020E6100000FDF49F353FFEEBBF7D5C1B2AC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31596397224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31596397224.webp', 'https://www.flickr.com/photos/zaragozaantigua/31596397224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23486, 'Plaza del Reino 1881', 'Grabado que reproduce de forma parcial el patio de la "Escuela de Artes y Oficios en Zaragoza", sita en la antigua Casa del Rey recayente a la plazuela o plaza del Reino, que desde finales del siglo XVIII era la sede de la Sociedad Econ├│mica de Amigos del Pa├¡s, bajo cuyo impulso hab├¡a sido constituida. A├▒os despu├®s conocer├¡a el inicio de una nueva ├®poca en un moderno y estiloso edificio de la antigua huerta de Santa Engracia construido al albur de la Exposici├│n Hispano-Francesa de 1908.', 1881, 1881, 1881, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65380300, -0.87446400, '0101000020E610000063F030ED9BFBEBBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46846621125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46846621125.webp', 'https://www.flickr.com/photos/zaragozaantigua/46846621125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22048, 'Romareda 1956', 'A├®rea vista de Isabel la Cat├│lica, caracterizada por campos de cultivo y las torres agr├¡colas en el espacio delimitado por el Cuartel Palafox, la Feria de Muestras, la "Casa Grande", el Convento de Jerusal├®n y el Seminario Conciliar.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63757500, -0.90280000, '0101000020E610000088855AD3BCE3ECBFA4DFBE0E9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14869951680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14869951680.webp', 'https://www.flickr.com/photos/zaragozaantigua/14869951680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23488, 'Calle de Palafox c.1933', 'Imagen capturada en la calle del Chantre y centrada en la gran casa de los marqueses de Laz├ín (luego de los Palafox) sita en la antigua calle del General (luego de Palafox). A la izquierda, vista parcial de la plaza del Reino. A la derecha, la esquina del nov├¡simo Grupo Escolar Marcelino L├│pez Ornat, donde aparecen reunidos efectivos del Cuerpo de Seguridad y Asalto, posiblemente como consecuencia de los disturbios acontecidos durante la insurrecci├│n anarquista de diciembre de 1933, que tuvo en esta zona uno de sus epicentros m├ís violentos.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65400400, -0.87438900, '0101000020E6100000B96DDFA3FEFAEBBF02BA2F67B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49630271236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49630271236.webp', 'https://www.flickr.com/photos/zaragozaantigua/49630271236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23539, 'Sitio de Zaragoza 1808', 'Si├¿ge de Saragosse, Jules Girardet, 1906. Royal Albert Museum. En esta delirante pintura, que fue realizada un siglo despu├®s de los hechos que narra, podemos ver a la derecha la iglesia zaragozana de San Nicol├ís, ubicada en un entorno de fantas├¡a.', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65398600, -0.87261000, '0101000020E6100000B13385CE6BECEBBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15054009109.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15054009109.webp', 'https://www.flickr.com/photos/zaragozaantigua/15054009109/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23540, 'Maderas Nicol├ís Hermanos c.1965', 'AHPZ. Archivo fotogr├ífico Coyne. "Paso del Se├▒or Atado a la Columna. Cofrad├¡a del Se├▒or Atado a la Columna y de Nuestra Se├▒ora de la Fraternidad en el Mayor Dolor. Cofrades." Nocturno paso de la cofrad├¡a con el fondo de la antigua empresa de maderas "Nicol├ís Hermanos", sita en el Barrio de las Tener├¡as, entre la plaza del mismo nombre y el Puente de Hierro, que queda a la izquierda de la imagen.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65379500, -0.87158900, '0101000020E6100000FEB4519D0EE4EBBFE8A4F78DAFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085644857.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085644857.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085644857/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23558, 'Monasterio de Santo Sepulcro 1966', 'Vista desde el Coso Bajo de las traseras del Monasterio del Santo Sepulcro y su iglesia de San Nicol├ís, en un conjunto construido en la antigua muralla de la ciudad. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65404100, -0.87206300, '0101000020E61000001AA721AAF0E7EBBF1F9F909DB7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22735616658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22735616658.webp', 'https://www.flickr.com/photos/zaragozaantigua/22735616658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23563, 'Plaza San Nicol├ís 1965', 'Vista parcial de la plaza de San Nicol├ís, con la calle del Sepulcro a la izquierda. A la derecha, fuera de campo, iglesia de San Nicol├ís. Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65402100, -0.87257100, '0101000020E61000003A048E041AECEBBFD8F2CAF5B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23165553771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23165553771.webp', 'https://www.flickr.com/photos/zaragozaantigua/23165553771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23567, 'Tumultos 1705', '"Tumultos en Zaragoza contra las tropas francesas", ilustraci├│n de Fernando Fern├índez Mota que prentende recrear el "mot├¡n de Zaragoza" de 1705, cuando en el marco de la Guerra de Sucesi├│n, austracistas locales, en la imagen con aires de baturros decimon├│nicos, atacaron a un regimiento borb├│nico franc├®s que pasaba por la ciudad camino del frente de guerra en Catalu├▒a. El marco elegido es la plazuela de San Nicol├ís, junto a la hom├│nima iglesia parroquial. Este episodio redundaba en la idea que presentaba al "pueblo" (concepto inexistente antes de la Revoluci├│n Francesa de 1789) como globalmente partidario del bando austracista, lo que en el caso de la Zaragoza de la ├®poca es muy temerario de afirmar, dados los bandazos o cambios de bander├¡a que las elites locales realizaron en funci├│n del sentido de la guerra. Fuente visual: Historia de Espa├▒a, Miguel Segu├¡, 1910, en todocoleccion.net.', 1705, 1705, 1705, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65409700, -0.87266200, '0101000020E610000050C8CEDBD8ECEBBFB3B45373B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27226658288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27226658288.webp', 'https://www.flickr.com/photos/zaragozaantigua/27226658288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23570, 'Monasterio del Santo Sepulcro a├▒os 30', 'Acuarela de Ambrosio Ruste que muestra las traseras del Monasterio del Santo Sepulcro, en la antigua muralla a la salida al Ebro del Coso Bajo. Al fondo, torre de la iglesia de San Nicol├ís. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65387200, -0.87211700, '0101000020E6100000E62329E961E8EBBF93E2E313B2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31597369614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31597369614.webp', 'https://www.flickr.com/photos/zaragozaantigua/31597369614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23579, 'Tener├¡as 1930', 'Imagen centrada en la isleta reci├®n embellecida que triangulaba el encuentro de la ribera del Ebro y las traseras del convento del Santo Sepulcro (a la derecha), el acceso al puente del Pilar, y el final del Coso Bajo. A la izquierda, los almacenes y serrer├¡a de Maderas Hermanos Nicol├ís, el ingreso a la calle de Monreal y, al fondo, la plazuela de las Tener├¡as. En el extremo superior de la isleta, la garita del Fielato de las Tener├¡as Fuente visual: www.mecd.gob.es/.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65413700, -0.87187000, '0101000020E6100000F5A10BEA5BE6EBBF410DDFC2BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36454484001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36454484001.webp', 'https://www.flickr.com/photos/zaragozaantigua/36454484001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23596, 'El Boter├│n 1958', 'Ruinosa escena capturada durante el proceso de derribo de los antiguos inmuebles del barrio del Boter├│n vertebrados por las calles del Garro, Retiro, Pallaruelo, Grillo, Monserrate y Lobo, que tras el derribo desaparecer├¡an del nomencl├ítor urbano, sustituidas por la calle del Boter├│n y la plaza de N.┬¬ S.┬¬ de la Piedad. Al fondo, alzado de los modernos edificios construidos y en construcci├│n en torno al final de la calle de San Vicente de Pa├║l, que en este tramo antes se llamara del Conde de Alperche y que a la derecha chaflanea con el paseo de Echegaray y Caballero. En primer t├®rmino y a la izquierda, un par de ni├▒as sentadas sobre una viga de madera de un edificio derribado, contemplan el arruinado escenario de este tradicional enclave zaragozano.', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST├ôRICO', 41.65457800, -0.87315500, '0101000020E61000001BD82AC1E2F0EBBF2E573F36C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52138231161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52138231161.webp', 'https://www.flickr.com/photos/zaragozaantigua/52138231161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23803, 'Vista de Zaragoza 1861', 'Vista de Zaragoza desde la margen izquierda del Ebro. "La torre campanil de La Seo, andamiada, despu├®s de que un rayo incendiase y arruinase su chapitel (1850), permite establecer con precisi├│n la cronolog├¡a de la fotograf├¡a, puesto que la torre permaneci├│ andamiada y todav├¡a sin el nuevo chapitel, entre enero y marzo de 1861." Jos├® Antonio Hern├índez Latas. Fuente: Fot├│grafo: Mariano J├║dez y Ortiz, 1861. ├ülbum de Andr├®s Mart├¡n e Ip├ís. Colecci├│n Mariano Mart├¡n Casalderrey, Zaragoza. Libro Primeros tiempos de la fotograf├¡a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65660300, -0.87030900, '0101000020E61000004A438D4292D9EBBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217164370.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217164370.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217164370/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24097, 'Calle del Sepulcro c.1959', 'Imagen capturada durante el recorrido que la procesi├│n de la Cofrad├¡a de Nuestra Se├▒ora de la Piedad y del Santo Sepulcro realiza entre la iglesia de Santa Isabel de Portugal y la de San Nicol├ís de Bari la madrugada del d├¡a 15 de abril, como es tradicional desde 1937. La escena, centrada en el paso de la carroza de la Virgen de la Piedad dise├▒ada por los arquitectos Regino Borobio Ojeda y Jos├® Beltr├ín Navarro, tiene lugar con el fondo edilicio de la antigua casa del siglo XVI que fuera de Juan Manente, luego de los marqueses de Almonacid, y desde finales del siglo XVII de los Esmir, en el tramo de la calle del Sepulcro entre la plaza de San Bruno y la moderna calle de San Vicente de Pa├║l. Esta vieja casona ser├¡a derribada a├▒os despu├®s para modernizar la zona y desprovincionarla. Hemos volteado horizontalmente la original imagen para que tenga sentido arquitect├│nico y visual, y la procesionaria pueda llegar correctamente a su destino.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65499800, -0.87447500, '0101000020E61000005D6DC5FEB2FBEBBF037976F9D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50117608373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50117608373.webp', 'https://www.flickr.com/photos/zaragozaantigua/50117608373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24234, 'P.┬║ del Ebro 1895', '&quot;Orillas del Ebro en fiestas&quot;, imagen para tarjeta postal de Uni├│n Universal de Correos. Toma de un grupo de personas, durante las fiestas del Pilar de 1895, posiblemente en la inauguraci├│n del puente del Pilar, desde el que estar├¡a hecha la foto. Detr├ís, edificios del tramo del paseo del Ebro entre la calle del Conde Alperche y la Puerta del Sol. Se non ├¿ vero, ├¿ ben trovato. Fuente: <a href=&quot;', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65512300, -0.87226700, '0101000020E61000003929CC7B9CE9EBBFC0ED0912DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30808921363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30808921363.webp', 'https://www.flickr.com/photos/zaragozaantigua/30808921363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24616, 'Plaza del Reino c.1945', 'Captura desde la calle del Chantre. Al fondo, la Plaza del Reino, donde estuvo la Real Sociedad Econ├│mica de Amigos del Pa├¡s. De derecha a izquierda cruza la calle Palafox. En la esquina de la derecha, chafl├ín de la Casa de los Laz├ín (luego, Palafox). Donde el se├▒or de brazos cruzados, pared del Grupo Escolar Marcelino L├│pez Ornat. A├▒os despu├®s todo esto cambiar├í radicalmente, con la apertura de la calle San Vicente de Pa├║l. Fuente Visual: ZARAGOZA instant├íneas grises, Miguel Gay Berges.', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST├ôRICO', 41.65397500, -0.87443200, '0101000020E61000008B6D52D158FBEBBF68B3EA73B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15225525578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15225525578.webp', 'https://www.flickr.com/photos/zaragozaantigua/15225525578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24622, 'Calle del Sepulcro c.1950', 'La calle del Sepulcro con la fachada de la antigua casa del siglo XVI que fuera de Juan Manente, de los marqueses de Almonacid, y desde finales del siglo XVII de los Esmir. Hacia la izquierda, la plaza de San Bruno. Esta gran casa con jard├¡n, derribada a├▒os despu├®s, llegaba por la parte de atr├ís hasta el paseo de Echegaray y Caballero. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST├ôRICO', 41.65491800, -0.87462500, '0101000020E6100000B0726891EDFCEBBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15728954176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15728954176.webp', 'https://www.flickr.com/photos/zaragozaantigua/15728954176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24624, 'Calle Sepulcro 1914', 'Resultado del hundimiento del edificio de la calle Sepulcro 24 de Zaragoza, a causa de los fuertes vientos desatados el lunes 25 de mayo de 1914. La imagen fue portada del diario ABC del jueves 28 de mayo de 1914.', 1914, 1914, 1914, 'Anos 10', 'CASCO HIST├ôRICO', 41.65464000, -0.87397100, '0101000020E610000098E0D40792F7EBBFA453573ECBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15903940602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15903940602.webp', 'https://www.flickr.com/photos/zaragozaantigua/15903940602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24641, 'Calle Palafox 1972', 'Imagen de la antigua casona de los marqueses de Laz├ín, como remozo neocl├ísico de un inmueble anterior del siglo XVI sito en una de las calles principales de la vieja capital del Reino. Su casual emplazamiento la salv├│ de la piqueta que ejerci├│ de bistur├¡ cuando la apertura de la preciosa calle de San Vicente de Pa├║l reorden├│ buena parte del antiguo barrio de la Seo. En la imagen, el antiguo palacio esquinero entre la calle de Palafox y la nueva v├¡a de comunicaci├│n rodada. Al fondo, la catedral de San Salvador. Fuente visual: Gerardo Sancho Ramo (Archivo P├║blico Municipal).', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST├ôRICO', 41.65407500, -0.87451900, '0101000020E6100000466117450FFCEBBFCB10C7BAB8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24128479981.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24128479981.webp', 'https://www.flickr.com/photos/zaragozaantigua/24128479981/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24652, 'Casa de los Laz├ín c.1947', 'Imagen parcial del gran patio interior de la antigua casa de los Laz├ín, desde 1890 usufructuado por la Hijas de la Caridad de San Vicente de Pa├║l, y centrada en las escaleras de acceso al Asilo de la Coronaci├│n de la Virgen del Pilar, fundado en 1909 por el cardenal Soldevila, para ni├▒os marginados y excluidos. Cuando las condiciones materiales del antiguo palacio ya no den m├ís de s├¡ (poco despu├®s de esta captura visual), y requieran una intervenci├│n restauradora importante, el usufructo del edificio fue cedido a los herededos legales. Este espacio interior, luego, ha mutado a otra cosa. En la imagen, y a la izquierda, posiblemente el acceso desde la calle de Palafox, antigua del General del Reino. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1947, 1947, 1947, 'Anos 40', 'CASCO HIST├ôRICO', 41.65419800, -0.87476300, '0101000020E6100000F20698F90EFEEBBFE78D93C2BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32640854293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32640854293.webp', 'https://www.flickr.com/photos/zaragozaantigua/32640854293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24770, 'Ribera del Ebro 1977', 'Durante los prodigiosos a├▒os del verticalismo y desarrollismo de los sesenta-setenta del siglo XX, con el ladrillo, el hormig├│n y la especulaci├│n desatada como se├▒as de identidad, la ciudad fue objeto de una transformaci├│n festejada en publirreportajes, no-dos, y preciosas postales que mostraban una nueva cara urbana moderna, avanzada, lustrosa, y joven. La construcci├│n de infraestructuras y edificaciones de nueva planta, am├®n de la ingente demolici├│n y piqueteo de inmuebles viejos, generaron un Everest de residuos que fueron gestionados a la brava, sin molestas perturbaciones legislativas, o pol├¡ticas p├║blicas, que trabaran el progreso. Tonelada tras tonelada, las riberas fluviales y la periferia periurbana fueron recrecidas en altura, y cientos de miles de deposiciones con cascotes de obra se convirtieron en la nueva especie dominante de esos parajes. En la imagen, captura del paisaje que mostraba la ribera del Ebro junto al Camino del Vado y la calle Lourdes. Al fondo, la ciudad de las torres catedralicias, tras el puente de hierros. Hubo un tiempo en que esto formaba parte del denominado "Soto del Ca├▒ar". Fuente visual: Archivo P├║blico Municipal, Gerardo Sancho Ramo.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65502200, -0.86585900, '0101000020E6100000FD4FFEEE1DB5EBBF8C14CAC2D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21656419220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21656419220.webp', 'https://www.flickr.com/photos/zaragozaantigua/21656419220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25149, 'Puente de las Tener├¡as 1887', '"Inauguraci├│n del puente de las Tener├¡as". Medalla de bronce conmemorativa de la colocaci├│n de la primera piedra del "puente de las Tener├¡as", el 7 de mayo de 1887. Este proyecto no comenz├│ a realizarse hasta 1891, inaugur├índose en 1895 con el nombre de puente de Nuestra Se├▒ora del Pilar, m├ís conocido como de Hierro. Fuente visual: www.todocoleccion.net/', 1887, 1887, 1887, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65546400, -0.87088500, '0101000020E6100000757632384ADEEBBF49DA8D3EE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31030640815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31030640815.webp', 'https://www.flickr.com/photos/zaragozaantigua/31030640815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25160, 'Calle Monserrate a├▒os 30', 'Acuarela de Ambrosio Ruste. Calle de Monserrate, que un├¡a la del Sepulcro con la ribera del Ebro. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65485800, -0.87329700, '0101000020E6100000B83CD68C0CF2EBBF11C30E63D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062439830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062439830.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062439830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25168, 'Calle Retiro a├▒os 30', 'Acuarela de Ambrosio Ruste. Confluencia de las calles del Retiro y del Garro (a la izquierda). Estas callejas se situar├¡an hoy en el entorno de la calle del Boter├│n. Fuente: L├íminas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST├ôRICO', 41.65445700, -0.87324300, '0101000020E6100000ECBFCE4D9BF1EBBFB3D1393FC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32440628885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32440628885.webp', 'https://www.flickr.com/photos/zaragozaantigua/32440628885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25182, 'Puente de las Tener├¡as 1887', 'Grabado basado en una fotograf├¡a que ilustra la ceremonia de colocaci├│n de la primera piedra del nuevo puente de las Tener├¡as sobre el r├¡o Ebro, el 7 de mayo de 1887. La escena tiene lugar en el punto de arranque del primer estribo del nuevo puente en el barrio de las Tener├¡as, en el tramo de la ribera comprendido entre las puertas del ├üngel y del Sol. A este lugar todav├¡a se lo denominaba como de "Los Maderos", una reminiscencia del puente de Tablas o de Madera desaparecido en los albores del siglo. La ceremonia se desarrolla a primera hora de la tarde, con presencia del ministro de Fomento, Carlos Navarro Rodrigo, adem├ís de la Corporaci├│n municipal, encabezada por su alcalde-presidente Sim├│n S├íinz de Varanda, representantes de la Diputaci├│n provincial y nutrida parroquia de p├║blico asistente. Al fondo de la imagen, la margen izquierda, con el molino de harina, un lavadero y la Torre de Sala. Tras ellos deber├¡a despuntar la torre del antiguo convento de Jes├║s, pero no lo hace. Este puente, como es usual en la ciudad, tiene una buena relaci├│n de nombres que lo identifican: nuevo sobre el Ebro, de las Tener├¡as, de la Virgen del Pilar, de Nuestra se├▒ora del Pilar, y de Hierro, que suele ser la m├ís extendida y funcional.', 1887, 1887, 1887, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65426800, -0.87173900, '0101000020E610000052BAF42F49E5EBBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49822067107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49822067107.webp', 'https://www.flickr.com/photos/zaragozaantigua/49822067107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25414, 'Ampliaci├│n Puente de Hierro 1990', 'Vicente Modesto Locual. 1990 Desde 1895 el Puente de Hierro era uno uno de los principales accesos a la ciudad desde el norte (incluso tras la construcci├│n del puente de Santiago), muy mayoritariamente para el gran anarquizante y devorador de espacios p├║blicos que es el veh├¡culo privado. En la ├║ltima d├®cada del XX, el puente es profundamente remodelado bajo direcci├│n de Javier Manterola: la estructura met├ílica se repara, limpia y pinta, y se le a├▒aden dos tableros laterales en forma de arco para derivar por ellos el paso de veh├¡culos. La plataforma central se reserva para uso peatonal, ese gran desconocido del urbanismo desarrollista y postdesarrollista franquista. La remodelaci├│n finaliz├│ en 1991. En la imagen, a├®rea visual desde la margen izquierda de la implementaci├│n de los tableros laterales. Desde ese punto de vista, a la izquierda, estado de la ribera con las instalaciones fabriles de Pikol├¡n. En la otra orilla, a la derecha, la plaza de San Bruno sin las nuevas viviendas protegidas y, l├│gicamente, convertida en aparcamiento en superficie.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65590700, -0.87050700, '0101000020E6100000E10CFE7E31DBEBBFD61BB5C2F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15182757080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15182757080.webp', 'https://www.flickr.com/photos/zaragozaantigua/15182757080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25434, 'Puente de Hierro 2011', 'Foto: Oliver Duch. Singular instant├ínea tomada desde el puente de Nuestra Se├▒ora del Pilar o de Hierro, el jueves 13 de octubre de 2011, al paso de la maqueta en cristal o "farol" de la bas├¡lica del Pilar, con ella detr├ís. Esta confluencia se dio, por primera vez, por el desv├¡o del Rosario de Cristal a causa de las obras del tranv├¡a. Participaron en la procesi├│n las m├íximas autoridades en plaza: Luisa Fernanda Rudi, presidenta del Gobierno de Arag├│n; Luis Mar├¡a Beamonte, presidente de la Diputaci├│n Provincial; y Juan Alberto Belloch, alcalde de Zaragoza. Fuente: Heraldo de Arag├│n.', 2011, 2011, 2011, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65532300, -0.87140600, '0101000020E6100000BD38F1D58EE2EBBF87A8C29FE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24763765578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24763765578.webp', 'https://www.flickr.com/photos/zaragozaantigua/24763765578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25442, 'Puente de Hierro 1991', 'Imagen capturada durante las pruebas de carga al final de las obras de ampliaci├│n del puente de Hierro, denominada "abrazo del Ebro" por el amable acompa├▒amiento de los dos nuevos viales para circulaci├│n rodada, uno en cada direcci├│n, al antiguo puente, cuyo uso fue reservado a viandantes, bicicletas, y animales irracionales. La toma se ha realizado desde las torres edilicias inmediatas al puente en la margen izquierda. Al otro lado del r├¡o, visual del colegio de las Tener├¡as, y a su izquierda, el solar sobre el que m├ís tarde se construir├¡a el Pabell├│n Deportivo Municipal de las Tener├¡as, el Centro de Salud de la Reboler├¡a, y algunas nuevas viviendas recayentes a la antigua calle del R├¡o. A la derecha, la glorieta donde estuviera la antigua Portaza, luego puerta del Sol. Fuente visual: "Asociaci├│n de Vecinos Barrio de Jes├║s. 30 a├▒os de Historia".', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST├ôRICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30532659566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30532659566.webp', 'https://www.flickr.com/photos/zaragozaantigua/30532659566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25450, 'Puente de Hierro 1990', 'Imagen capturada durante las obras de ampliaci├│n del puente de Hierro mediante el a├▒adido de dos tableros laterales en forma de arco por los que derivar el paso de la circulaci├│n rodada (uno de ellos, a la derecha), mientras que la plataforma central, el hist├│rico puente (izquierda), se reserv├│ para uso peatonal. En la imagen, tomada desde la margen derecha, y al fondo, destacan algunas de las instalaciones de la antigua f├íbrica de colchones de Alfonso Solans, en la antigua calle del puente del Pilar, luego redenominada en homenaje a este local pr├│cer. Detr├ís, en el camino del Vado, puede verse el colegio de la Pur├¡sima y San Antonio. Fuente visual: archivo Heraldo de Arag├│n, en "Padre Ebro. El r├¡o Ebro y el siglo XX".', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65546400, -0.87088500, '0101000020E6100000757632384ADEEBBF49DA8D3EE6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33960709815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33960709815.webp', 'https://www.flickr.com/photos/zaragozaantigua/33960709815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25458, 'Puente de Hierro 1990', 'Imagen capturada en el arranque del puente de Hierro o de Nuestra Se├▒ora del Pilar desde la margen izquierda durante las obras de remodelaci├│n que, bajo la direcci├│n de Javier Manterola, repararon la estructura del puente inaugurado en 1895, y se le a├▒adieron dos tableros laterales en forma de arco para derivar por ellos el tr├ínsito rodado. La plataforma central fue reservada para uso peatonal. En primer t├®rmino, detalle del antiguo adoquinado del puente al descubierto por el desgaste de la superficial capa de asfalto a causa del intenso tr├ífico.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65648100, -0.87022600, '0101000020E6100000EB1F4432E4D8EBBF02B9C49107D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50308819236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50308819236.webp', 'https://www.flickr.com/photos/zaragozaantigua/50308819236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25459, 'Puente de Hierro 1990', 'Imagen capturada durante la remodelaci├│n del puente de Nuestra Se├▒ora del Pilar o de Hierro, que proyectada por el arquitecto Javier Manterola inclu├¡a dos tableros laterales en forma de arco para el paso de veh├¡culos. Aqu├¡ figura el tablero occidental, tras el que al fondo y en la margen izquierda destacan los bloques de viviendas de las calles de Cecilio Navarro, Nicol├ís de Funes y de Jes├║s, recayentes a la hom├│nima plaza.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65539000, -0.87129900, '0101000020E61000003C33C170AEE1EBBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50460967823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50460967823.webp', 'https://www.flickr.com/photos/zaragozaantigua/50460967823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25531, 'Ribera del Ebro c.1966', 'Fototeca Universidad de Sevilla. A├▒os 60. "Vista de Zaragoza". Imagen capturada desde la ribera izquierda del Ebro, entre el Puente del Pilar, o de Hierro, y el antiguo Molino de San L├ízaro, en un espacio entonces ocupado por lo que vemos. Al fondo, la soledad del enorme bloque 47-49 de San Vicente de Pa├║l (construido en 1954), y la fachada al Ebro de la Seo, el Palacio Arzobispal, la Lonja, el nuevo Ayuntamiento, y el Pilar. Fuente visual: fototeca.us.es/imagen.jsp?id=43768&tipo=v&elto=0&...', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65658600, -0.87148500, '0101000020E6100000C18BBE8234E3EBBF778192020BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15644187735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15644187735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15644187735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21679, 'La Aljafer├¡a 1930', '"Castillo de la Aljafer├¡a".', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14872302961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14872302961.webp', 'https://www.flickr.com/photos/zaragozaantigua/14872302961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25547, 'Vista R├¡o Ebro 1932', 'Desde el puente del Pilar, imagen panor├ímica de la ciudad, el r├¡o Ebro y el puente de Piedra. A la izquierda, la fachada del paseo de la Ribera, desde el convento del Sepulcro, y las ruinas del estribo en piedra del antiguo puente de Tablas, pasando por la Seo, el palacio Esmir y el palacio Arzobispal, hasta el Pilar. A la derecha, la arboleda de Macanaz. Composici├│n in├®dita, democr├ítica, cient├¡fica y popular, generada en los laboratorios del', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65580700, -0.87212500, '0101000020E61000009CC420B072E8EBBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23224165536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23224165536.webp', 'https://www.flickr.com/photos/zaragozaantigua/23224165536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25549, 'Ebro c.1909', 'Desde el puente de Hierro una interesante vista hacia el r├¡o Ebro y el puente de Piedra, con restos, a la derecha, del conglomerado p├®treo, o estribo, sobre el que descansaba el acceso del antiguo puente de Tablas a la margen izquierda. A su lado, el que fuera Molino de San L├ízaro, ya en su dieciochesca ubicaci├│n. Fuente visual: Estudio Coyne (DARA-AHPZ)', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23884124486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23884124486.webp', 'https://www.flickr.com/photos/zaragozaantigua/23884124486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25550, 'Puente de Hierro 1975', 'Turbamulta de ba├▒istas haciendo uso, en sus diversas modalidades, de una de las dom├®sticas playas del r├¡o Ebro en su domesticado paso estival por la ciudad. Esta era la tradicional "Playa de las Hojalatas", cari├▒oso apodo por la simp├ítica y met├ílica proliferaci├│n de recipientes (usados) elaborados en hoja de lata, en el pedazo de ribera aleda├▒a al entronque del puente del Pilar, o de Hierro, en la margen derecha. Al fondo, el torreado recept├ículo de N┬¬ S┬¬ del Pilar, y el puente de Piedra. Un troleb├║s de la l├¡nea del "G├íllego" transita por el puente, camino del G├íllego, unos meses antes de ser desmantelada por el progreso y los autobuses a ├®l asociados. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST├ôRICO', 41.65453500, -0.87085800, '0101000020E61000000FB8AE9811DEEBBF2F8B89CDC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24223990960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24223990960.webp', 'https://www.flickr.com/photos/zaragozaantigua/24223990960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25551, 'Vista desde la Seo 1906', 'Vista desde la torre de la Seo del r├¡o Ebro, en su crecida de 1906, con el puente de Hierro y el detalle del abigarrado caser├¡o cercano a la ribera, entre la catedral y el Coso Bajo. Al fondo se puede leer el cartel de "Maderas Nicol├ís Hermanos". Fuente: www.zaragoza.es/contenidos/medioambiente/.../otros/catalo...', 1906, 1906, 1906, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65452200, -0.87358600, '0101000020E610000064CA87A06AF4EBBF9A417C60C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24314983084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24314983084.webp', 'https://www.flickr.com/photos/zaragozaantigua/24314983084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25552, 'Vista Ebro 1907', 'Foto: Petit. Vista de la margen derecha del r├¡o Ebro a su paso por Zaragoza, tomada desde el puente del Pilar en el oto├▒o de 1907. A la izquierda, restos del estribo sobre el que se asentaba el antiguo puente de Tablas de la ciudad. Fuente: Minist├¿re de la Culture (France) - M├®diath├¿que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24571307164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24571307164.webp', 'https://www.flickr.com/photos/zaragozaantigua/24571307164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25556, 'Vista desde el Ebro 1907', 'Foto: Petit. Vista de Zaragoza desde la margen izquierda del r├¡o Ebro en el oto├▒o de 1907. A la derecha, restos del estribo sobre el que se asentaba el antiguo puente de Tablas de la ciudad. Fuente: Minist├¿re de la Culture (France) - M├®diath├¿que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25108644621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25108644621.webp', 'https://www.flickr.com/photos/zaragozaantigua/25108644621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25560, 'R├¡o Ebro 1910', 'Foto: Charles Jacquin. Placa autocroma de una vista de Zaragoza desde la margen izquierda del r├¡o Ebro y a espaldas del puente de N.┬¬ S.┬¬ del Pilar. En primer t├®rmino y a la derecha, restos del estribo norte del antiguo puente de Tablas donde terminaba el hom├│nimo camino que conectaba con la calle de Jes├║s, junto al lavadero de Modesto Andr├®s. Detr├ís de este estribo se encontraba el antiguo molino de sal de San L├ízaro alimentado por la acequia del Rabal, que desde 1907 funcionaba como molino harinero del Puente de Tablas accionado adem├ís por un motor el├®ctrico, lo que le permit├¡a moler el grano ÔÇ£a cualquier hora del d├¡a y en toda ├®pocaÔÇØ. Al fondo, el puente de Piedra donde destaca el aspecto de su tercera pila, con bloques de piedra sobre su baja estructura. Por encima suyo, aspecto de la fachada al r├¡o del tramo edilicio entre el Seminario y el templo del Pilar. Fuente visual: bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65653600, -0.87131900, '0101000020E610000002452C62D8E1EBBFC652245F09D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28396195976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28396195976.webp', 'https://www.flickr.com/photos/zaragozaantigua/28396195976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25566, 'R├¡o Ebro 1910', 'Placa autocroma de una vista capturada desde el puente de Hierro, con interesante visual del r├¡o Ebro, el puente de Piedra, restos del estribo sur del antiguo puente de Tablas, y el correspondiente tramo de la margen derecha. Al fondo, la torre de la Seo y las dos del Pilar. Fuente visual: Charles Jacquin photographe bibliotheques-specialisees.paris.fr/', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65560300, -0.87195100, '0101000020E610000027DD96C805E7EBBF6A1492CCEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32935866406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32935866406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32935866406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25575, 'R├¡o Ebro 1909', 'Imagen capturada en la margen izquierda, donde la playa de cantos rodados a espaldas del lavadero de la calle de Jes├║s inmediato al puente de N.┬¬ S.┬¬ del Pilar, con una interesante vista del r├¡o Ebro con el fondo del tramo de la margen derecha con el que confrontaba. En la orilla y al fondo a la izquierda destacan los restos del estribo del antiguo puente de Tablas o Madera. Tras el arbolado paseo del Ebro, edificios comprendidos entre ├®ste y las calles de Monserrate, Grillo, Silencio y Conde de Alperche, en cuyos bajos se abr├¡an varios establecimientos de construcci├│n y alquiler de carros, adem├ís de tratantes de caballer├¡as. A continuaci├│n, la gran casa que fuera de los Esmir (donde emerge al fondo el cimborrio de la Seo), seguida por el palacio Arzobispal (donde destaca la barroca torre de la Seo).', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65614400, -0.87287600, '0101000020E610000052D32EA699EEEBBFBABBCE86FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52235254996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52235254996.webp', 'https://www.flickr.com/photos/zaragozaantigua/52235254996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25996, 'Vista Puente Hierro c.1942', 'Vista a├®rea de la zona del Puente del Pilar, o de Hierro. En la margen derecha, visual del edificio de la Serrer├¡a Nicol├ís (a la derecha del jard├¡n triangular) y el complejo de los edificios de nuevo y ribere├▒o Cuartel de Automovilismo. En la margen izquierda, el Barrio de Jes├║s, los enormes lavaderos de Modesto Andr├®s, y el cuartel de San L├ízaro.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST├ôRICO', 41.65554800, -0.87099000, '0101000020E6100000C993A46B26DFEBBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20892928843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20892928843.webp', 'https://www.flickr.com/photos/zaragozaantigua/20892928843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26010, 'Vista a├®rea 2006', 'Foto: Juan Carlos Arcos. Panor├ímica de Zaragoza desde el paseo de Echegaray y Caballero, con parte de las instalaciones de la f├íbrica de armamento Instalaza, a la izquierda. A la derecha, antes del puente de Hierro a├║n sin pintar de azul, el reci├®n creado parque ribere├▒o que ser├í desmantelado poco despu├®s para hacer otro similar, en un ejercicio de lucrativo quita y pon propio del per├¡odo. Fuente: Heraldo de Arag├│n, 18 de junio de 2006.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65381700, -0.86929500, '0101000020E6100000377172BF43D1EBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22299638391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22299638391.webp', 'https://www.flickr.com/photos/zaragozaantigua/22299638391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26050, 'Vista panor├ímica c.1904', 'Postal panor├ímica coloreada que muestra la margen derecha del r├¡o Ebro, desde el puente del Pilar hasta el de Piedra. Se distinguen las torres de San Nicol├ís, la Magdalena, la Seo y el Pilar. Fuente: www.todocoleccion.net', 1904, 1904, 1904, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65607300, -0.87354600, '0101000020E6100000D7A6B1BD16F4EBBFF1643733FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32022513125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32022513125.webp', 'https://www.flickr.com/photos/zaragozaantigua/32022513125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21020, 'San Pablo &quot;antigua mezquita&quot; 1869', 'Tomando como referencia un dibujo de Genaro P├®rez de Villa-Amil realizado la d├®cada anterior, la revista "El Museo Universal" en su n├║mero 46 (14-XI-1869) public├│ esta ilustraci├│n con un intrigante pie de imagen que asevera que la iglesia parroquial de San Pablo fue "antigua mezquita". El cuerpo del texto del reportaje ahonda m├ís en el misterio, al apuntar "un car├ícter oriental, imposible de confundir con ningun (sic) otro estilo arquitect├│nico", que despojado "de los revestimientos modernos" muestra "las l├¡neas magistrales de la ya purificada mezquita". Por supuesto, mezquita, o no, la dataci├│n cronol├│gica sigue siendo la can├│nica cristiana: comienzos del siglo XII, tras la conquista cristiana, cuando en pocos a├▒os, y por arte de "birlibirloque", Sarago├ºa se convirti├│, seg├║n los grandes estudiosos locales del arte cristiano, en el n├║cleo m├ís densamente poblado por iglesias, parroquias y ermitas rom├ínicas de nueva planta de todo el occidente cristiano europeo, en paralelo a la fant├ística desaparici├│n de todos los edificios religiosos de la Saraqusta musulmana que hab├¡an prestado servicio durante los 400 a├▒os anteriores. No obstante, cuando siglos despu├®s se ha procedido a restaurar algunos de estos edificios "rom├ínicos", no se han detectado apenas trazas rom├ínicas de relieve, y s├¡, de siglos anteriores. El texto apunta una posibilidad menos delirante, cuando introduce el concepto "purificada mezquita": mediante ceremoniales rituales, se despoja a un edificio o estructura de sus efluvios moriscos, y se le reconvierte en un edificio cristiano "de toda la vida". Una aplicaci├│n del arte de reciclar y reutilizar, "avant la lettre", que fue aplicado cient├¡ficamente en esta ciudad, comenzando por su referencial Mezquita Aljama construida por Hanas ibn cAbd Allah as-Sanc├íni, y ampliada luego, que tras su "purificaci├│n" ser├í denominada por los invasores cristianos como "Seo de San Salvador". Esta nueva versi├│n del dibujo muestra algunas variaciones respecto del original, com', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19921997159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19921997159.webp', 'https://www.flickr.com/photos/zaragozaantigua/19921997159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21033, 'Plaza del Mercado 1868', 'Plaza del Mercado capturada desde la altura de las calles Cerd├ín y Escuelas P├¡as. Al fondo, la calle de Antonio P├®rez, conducente a la puerta de San Ildefonso y el paseo del Ebro. De la macizada manzana entre la plaza de San Ant├│n y San Juan de los Panetes emerge la Zuda. Fuente visual: Frank Mason Good, en la exposici├│n ''Zaragoza estereosc├│pica. Fotograf├¡a profesional y comercial''', 1868, 1868, 1868, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65614200, -0.88307000, '0101000020E6100000E08442041C42ECBF1AC40776FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26477064146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26477064146.webp', 'https://www.flickr.com/photos/zaragozaantigua/26477064146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21042, 'Procesi├│n del Pilar 1860', 'Dibujo de la procesi├│n de la Virgen del Pilar realizada la desapacible tarde del 12 de octubre e inmortalizada pues tuvo como part├¡cipes a la reina Isabel II, al rey Francisco de As├¡s de Borb├│n, y al pr├¡ncipe de Asturias Alfonso de Borb├│n, ya que coincidi├│ con su viaje oficial a Zaragoza realizado ese a├▒o. Esta nutrida procesi├│n sali├│ del templo del Pilar y recorri├│ las c├®ntricas calles de la Sombrerer├¡a, de la Virgen y del Arco de Toledo, la plaza del Mercado, las calles de la Albarder├¡a y del Coso, la plaza de la Constituci├│n, las calles de San Gil, de San Pedro, de la Virgen del Rosario, de la Cuchiller├¡a, del Pilar, hasta desembocar en la plaza del Pilar. En el dibujo destaca la imagen en plata de la Virgen del Pilar precedida de los Infanticos y conducida en andas entre las filas de can├│nigos que portan el palio. Siguen despu├®s los concejales precedidos de los maceros municipales, las autoridades de la Diputaci├│n provincial y la familia Real. La Reina destaca con traje cubierto de encajes blancos y la corona real sobre sus sienes. Junto a ella, el Rey vestido en uniforme de Capit├ín general del Ej├®rcito. En el Gran Archivo Zaragoza Antigua (GAZA) ubicamos este dibujo, posiblemente, en la plaza del Mercado. Fuente visual: dibujo y litograf├¡a de Vicente Urrabieta realizada en el establecimiento litogr├ífico de Jos├® Don├│n (Madrid), aparecida en "Cr├│nica del viaje de sus Majestades Altezas reales a las Islas Baleares, Catalu├▒a y Arag├│n en 1860" (Antonio Flores Algovia, 1861), y coloreada en echosinhache.blogspot.com/', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65607400, -0.88306700, '0101000020E61000009CA8A5B91542ECBFC1E09A3BFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45402694302.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45402694302.webp', 'https://www.flickr.com/photos/zaragozaantigua/45402694302/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21051, 'San Pablo ca. 1870', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1860-1886. "Torre de la Iglesia de San Pablo".', 1870, 1870, 1870, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65607200, -0.88608900, '0101000020E61000000F0D8B51D75AECBF21E9D32AFAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14680088698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14680088698.webp', 'https://www.flickr.com/photos/zaragozaantigua/14680088698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21085, 'Calle San Blas 1871', '"Zaragoza. Algunos habitantes disponen su marcha huyendo de la inundaci├│n". Dibujo alusivo a las inundaciones del r├¡o Ebro de enero de 1871. Al fondo, la torre de la iglesia de San Pablo. Fuente: Revista La Ilustraci├│n, Madrid. A trav├®s de www.facebook.com/photo.php?fbid=10205887851115259&set...', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65676600, -0.88832800, '0101000020E6100000F4DF83D72E6DECBFF78F85E810D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30944154665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30944154665.webp', 'https://www.flickr.com/photos/zaragozaantigua/30944154665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21110, 'San Pablo 1889', '"Saragosse. Tour de l''Eglise St-Paul". Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22725342475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22725342475.webp', 'https://www.flickr.com/photos/zaragozaantigua/22725342475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21197, 'Calle de las Escuelas P├¡as c.1898', 'Imagen con la primera ubicaci├│n productiva y comercial de la empresa Chocolates Or├║s establecida por Joaqu├¡n Or├║s Abad├¡a en 1898 en el n┬║ 19 de la calle de las Escuelas P├¡as, chaflanera con el n┬║ 2 de la calle de Basilio Boggiero (a la izquierda). Aqu├¡ estuvo previamente la f├íbrica de chocolates y tienda de ultramarinos de Pedro G├│mez, y en la imagen albergaba la factor├¡a de Or├║s y el comercio La Abeja Colonial de Seuba&Carbonell.', 1898, 1898, 1898, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65491800, -0.88447400, '0101000020E61000009831056B9C4DECBFE7C75F5AD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51334556070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51334556070.webp', 'https://www.flickr.com/photos/zaragozaantigua/51334556070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21295, 'Plaza del Mercado c.1900', 'Imagen de la antigua plaza del Mercado, capturada desde cierta altura en la manzana entre las calles de las Escuelas P├¡as, y de Juan Jim├®nez Cerd├ín. El enfoque est├í centrado en la fachada oriental de la plaza, comprendida entre los n├║meros 41 (izquierda), junto a la calle Manifestaci├│n, y 69 (derecha), junto a la calle de la Torre Nueva. Destacan los soportales entoldados, a nivel de calle, entre los que se instalaban los puestos del mercado. Esta fachada formaba parte de la manzana de viviendas entre la plaza del Mercado y la calle de Lanuza, en cuya zona central, longitudinalmente, y enmascarado por las viviendas, estaba localizado uno de los tramos de la antigua muralla de piedra de la ciudad. Sobre el firme aparece el trazado de la tranviaria l├¡nea "Circunvalaci├│n", que ingresaba en la plaza por la calle de Cerd├ín. Poco tiempo despu├®s, esta manzana ser├¡a integralmente derribada para iniciar la construcci├│n del nuevo Mercado de la ciudad. Esta monumental imagen fue convertida por la Fototipia de Lucas Escol├í en comercial postal de la serie "Zaragoza", con el n├║mero 43, y titulada "Antiguo Mercado". Fuente visual: www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31215207052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31215207052.webp', 'https://www.flickr.com/photos/zaragozaantigua/31215207052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21471, 'San Pablo Ap├│stol 1912', 'Imagen de la iglesia parroquial de San Pablo Ap├│stol centrada en su singular atalaya.', 1912, 1912, 1912, 'Anos 10', 'CASCO HIST├ôRICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53580689263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53580689263.webp', 'https://www.flickr.com/photos/zaragozaantigua/53580689263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21843, 'Calle Conde de Aranda 1933', 'Imagen capturada en el interior del nuevo Monumental Cinema poco antes de su inauguraci├│n, cinemat├│grafo de la empresa de Herm├│genes Herrero proyectado por el arquitecto Marcelo Carqu├® con capacidad para 2319 personas. De estilo moderno, racionalista, y monumentales dimensiones, ten├¡a su entrada principal en la calle del Conde de Aranda n┬║ 32, y contaba con una salida en la calle de Boggiero n┬║ 47. Fue clausurado 39 a├▒os desp├╣├®s, y su enorme solar reurbanizado de forma bien provechosa. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST├ôRICO', 41.65514400, -0.88703700, '0101000020E610000045F12A6B9B62ECBFD71533C2DBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35602884753.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35602884753.webp', 'https://www.flickr.com/photos/zaragozaantigua/35602884753/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21846, 'Calle de Cerd├ín 1934', 'Imagen capturada en el tramo de la calle de Cerd├ín conducente al Mercado Central, y centrada en la modern├¡sima fachada (tras reciente reforma) de la gran zapater├¡a Calzados el Siglo XX, de la viuda de Miguel Ferrer, que vio iniciar su actividad en las postrimer├¡as del siglo XIX. El tradicional y muy demandado g├®nero de las alpargatas y zapatillas ten├¡a un acceso propio desde la trasera calle de las Escuelas P├¡as, junto a la entrada a la calle de San Pablo. Este establecimiento estaba especializado en un nuevo tipo de zapato para la se├▒ora y el ni├▒o (sic) denominado "Checo". Sobre el firme, en primer t├®rmino, y hacia la derecha, tendido tranviario de la l├¡nea Ayuntamiento-Portillo, originalmente de la l├¡nea Circunvalaci├│n como ramal plaza de la Constituci├│n-Puente de Piedra por el Mercado. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST├ôRICO', 41.65520000, -0.88392600, '0101000020E6100000EAB0C22D1F49ECBF6B2BF697DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35661297254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35661297254.webp', 'https://www.flickr.com/photos/zaragozaantigua/35661297254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21854, 'Calle de Torre Nueva 1932', 'Imagen centrada en la gran fachada de la casa de los condes de Bureta en el n┬║ 6 de la calle de Torre Nueva cuando ya pend├¡a sobre ella la amenaza de derribo, algo que se consumar├¡a tres a├▒os despu├®s. Ya en el siglo XV y cuando la calle se denominaba Nueva del Mercado, esta era la casa de los L├│pez de Villanova, que en el siglo XVII pas├│ a los condes de Bureta. La original y tradicional fachada de la casona era en ladrillo caravista y culminaba en galer├¡a de arquillos y alero saliente. Fue revocada despu├®s en yeso, abri├®ndose grandes balcones y ventanales regulares, como la imagen ilustra. A la derecha del edificio, e inmediato, el acceso a la empinada calle de Ant├│n Trillo y a la plaza de Lanuza. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST├ôRICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35882023093.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35882023093.webp', 'https://www.flickr.com/photos/zaragozaantigua/35882023093/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21937, 'San Pablo a├▒os 40', 'San Pablo, aguafuerte, Jes├║s Fern├índez Barrio, Diputaci├│n de Zaragoza, c. 1945-1947. Iglesia de San Pablo de Zaragoza. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CASCO HIST├ôRICO', 41.65621600, -0.88624400, '0101000020E6100000D4D688601C5CECBF548EC9E2FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15257156253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15257156253.webp', 'https://www.flickr.com/photos/zaragozaantigua/15257156253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22073, 'San Pablo 1953', 'Imagen de la puerta principal y la torre de la parroquia de San Pablo. La p├®trea fachada y los jarrones incrustados que luce son una impostaci├│n del siglo XVIII, cuando se recubri├│ con piedra el ladrillo de la f├íbrica original. Fuente visual: "Arag├│n : revista gr├ífica de cultura aragonesa" (A├▒o XXVIII, N┬║ 227, abril-junio 1953).', 1953, 1953, 1953, 'Anos 50', 'CASCO HIST├ôRICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15507137488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15507137488.webp', 'https://www.flickr.com/photos/zaragozaantigua/15507137488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22206, 'San Pablo 1955', '"Nocturno en San Pablo", ├│leo sobre lienzo, Jos├® Baqu├® Xim├®nez, 1955. Vista del caser├¡o del barrio de San Pablo, con la torre mud├®jar de la iglesia hom├│nima presidiendo rotunda el paisaje. Fuente: baqueximenez.weebly.com', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST├ôRICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40209712155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40209712155.webp', 'https://www.flickr.com/photos/zaragozaantigua/40209712155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22297, 'San Pablo c.1965', 'Plaza e iglesia de San Pablo. Fuente: AMZ.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65577800, -0.88585100, '0101000020E6100000EB1F4432E458ECBFD8B79388F0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480355226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480355226.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480355226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22389, 'Calle Zamoray 1968', 'Chafl├ín entre las calles de Agustina de Arag├│n (izquierda) y Jos├® Zamoray (derecha). Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65473200, -0.88824100, '0101000020E610000039ECBE63786CECBF85D21742CED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22727732317.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22727732317.webp', 'https://www.flickr.com/photos/zaragozaantigua/22727732317/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22452, 'Calle General Franco 1967', 'Foto: Emilio Aure Durb├ín. Vista de la calle del General Franco, con la zona del Portillo al fondo. A la derecha, en el n├║mero 32, cartel del Cine Monumental, inaugurado en 1933 como "Monumental Cinema" y clausurado en 1972. Fuente visual: www.facebook.com/photo.php?fbid=1802072866697326&set=...', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65493800, -0.88719100, '0101000020E6100000F3C64961DE63ECBF2E742502D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31419929176.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31419929176.webp', 'https://www.flickr.com/photos/zaragozaantigua/31419929176/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22458, 'Iglesia de San Pablo c.1963', 'Iglesia de San Pablo. ├ôleo de Juli├ín Borreguero. Vista de la plaza de San Pablo, con la fachada de la iglesia adornada con los a├▒adidos del siglo XVIII que ser├ín retirados en 1977. Fuente: www.arteinformado.com/', 1963, 1963, 1963, 'Anos 60', 'CASCO HIST├ôRICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31810772780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31810772780.webp', 'https://www.flickr.com/photos/zaragozaantigua/31810772780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22492, 'Calle del General Franco 1968', 'Imagen capturada en el adoquinado tramo inicial de la calle del General Franco, entre el colegio de los Escolapios y el inmueble del n┬║ 28, a la izquierda. Centra la escena la composici├│n tranviaria M59+R87 de la l├¡nea 5 "Venecia-Delicias" encaminada hacia la terminal de la plaza de Huesca. Tras ella, la desaparecida fachada edilicia de la manzana entre la calle de Miguel de Ara y la de Ram├│n y Cajal. A la derecha extrema sobresale el torre├│n occidental del palacio de la Audiencia, y algunos de los anuncios comerciales que culminaban el arranque de la desaparecida manzana entre la calle de Cerd├ín y la de las Escuelas P├¡as. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65473500, -0.88642500, '0101000020E6100000E86A2BF6975DECBFF645425BCED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46933109132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46933109132.webp', 'https://www.flickr.com/photos/zaragozaantigua/46933109132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22568, 'Rastro del Mercado 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Junio 1975. "Rastro del Mercado." Zaragoza 100%: est├í pegando un sol enorme, pero no por ello hay que buscar la sombra: con ponerse un peri├│dico en la cabeza, vale. Imagen del rastro, secci├│n sables, braseros, candelabros y quincalla varia, en el entorno de la puerta principal de acceso al Mercado Central, inmediata a la calle Cerd├ín, calle a la que le quedaba apenas una legislatura de vida.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST├ôRICO', 41.65559900, -0.88345500, '0101000020E6100000139B8F6B4345ECBF292504ABEAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15246198251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15246198251.webp', 'https://www.flickr.com/photos/zaragozaantigua/15246198251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22646, 'Calle Cerd├ín 1977', 'Foto: Colecci├│n Antonio G├ímez. Calle Cerd├ín de Zaragoza, vista desde el Mercado Central, en 1977. Fuente: rafaelcastillejo.com', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65562300, -0.88343900, '0101000020E6100000A759A0DD2145ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20683891666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20683891666.webp', 'https://www.flickr.com/photos/zaragozaantigua/20683891666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22655, 'San Pablo 1977', 'La iglesia parroquial de San Pablo ha sido objeto, a lo largo de su extensa historia desde que fuera alminar del arrabal musulm├ín al oeste de la ciudad, de numerosas modificaciones en su f├íbrica, aspecto, y espacio interior. A finales del siglo XVIII su fachada y portada de acceso principal, en la calle de San Pablo, fueron profusamente reformadas con elementos tardo-neocl├ísicos. As├¡, el muro fue revestido de piedra, y decorado con pilastras lisas, una cornisa superior y hornacinas con jarrones. Posteriores restauraciones han eliminado toda esta traza, excepto en la puerta de ingreso. En la imagen, captura del exterior del muro de la iglesia de San Pablo, con el arrasamiento de los a├▒adidos de finales del XVIII, en la b├║squeda del previo muro mud├®jar. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21655866670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21655866670.webp', 'https://www.flickr.com/photos/zaragozaantigua/21655866670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
